fn parse_readiness_check(args: impl Iterator<Item = String>) -> Result<CliCommand, String> {
    let mut output = ProbeOutputFormat::Text;
    let mut soak_connections = DEFAULT_READINESS_SOAK_CONNECTIONS;
    let mut first_byte_timeout = DEFAULT_FIRST_BYTE_TIMEOUT;
    let mut max_connection_workers = DEFAULT_MANAGED_MIXED_MAX_CONNECTION_WORKERS;
    let mut soak_min_duration = DEFAULT_MIXED_SOAK_MIN_DURATION;
    let mut skip_soak = false;
    let mut include_system_proxy_smoke = false;
    let mut include_tun_runtime_smoke = false;
    let mut tun_runtime_smoke_min_duration = DEFAULT_TUN_RUNTIME_SMOKE_MIN_DURATION;
    let mut args = args.peekable();

    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--format" => {
                output = parse_probe_output_format(
                    args.next()
                        .ok_or_else(|| "--format requires text or json".to_string())?,
                )?;
            }
            "--soak-connections" => {
                soak_connections = parse_positive_usize(
                    args.next()
                        .ok_or_else(|| "--soak-connections requires a value".to_string())?,
                    "--soak-connections",
                )?;
            }
            "--first-byte-timeout-ms" => {
                first_byte_timeout = parse_duration_ms(
                    args.next()
                        .ok_or_else(|| "--first-byte-timeout-ms requires a value".to_string())?,
                    "--first-byte-timeout-ms",
                )?;
            }
            "--max-connection-workers" => {
                max_connection_workers = parse_positive_usize(
                    args.next()
                        .ok_or_else(|| "--max-connection-workers requires a value".to_string())?,
                    "--max-connection-workers",
                )?;
            }
            "--soak-min-duration-ms" => {
                soak_min_duration = parse_duration_ms(
                    args.next()
                        .ok_or_else(|| "--soak-min-duration-ms requires a value".to_string())?,
                    "--soak-min-duration-ms",
                )?;
            }
            "--skip-soak" => skip_soak = true,
            "--include-system-proxy-smoke" | "--system-proxy-smoke" => {
                include_system_proxy_smoke = true;
            }
            "--include-tun-runtime-smoke" | "--tun-runtime-smoke" => {
                include_tun_runtime_smoke = true;
            }
            "--machine-takeover"
            | "--include-machine-takeover-smokes"
            | "--machine-takeover-smokes" => {
                include_system_proxy_smoke = true;
                include_tun_runtime_smoke = true;
            }
            "--tun-runtime-smoke-min-duration-ms" => {
                include_tun_runtime_smoke = true;
                tun_runtime_smoke_min_duration = parse_duration_ms(
                    args.next().ok_or_else(|| {
                        "--tun-runtime-smoke-min-duration-ms requires a value".to_string()
                    })?,
                    "--tun-runtime-smoke-min-duration-ms",
                )?;
            }
            other => return Err(format!("unknown readiness-check option: {other}")),
        }
    }

    Ok(CliCommand::ReadinessCheck {
        output,
        soak_connections,
        first_byte_timeout,
        max_connection_workers,
        soak_min_duration,
        skip_soak,
        include_system_proxy_smoke,
        include_tun_runtime_smoke,
        tun_runtime_smoke_min_duration,
    })
}

fn parse_default_core_certify(args: impl Iterator<Item = String>) -> Result<CliCommand, String> {
    let mut output = ProbeOutputFormat::Text;
    let mut soak_connections = DEFAULT_READINESS_SOAK_CONNECTIONS;
    let mut first_byte_timeout = DEFAULT_FIRST_BYTE_TIMEOUT;
    let mut max_connection_workers = DEFAULT_MANAGED_MIXED_MAX_CONNECTION_WORKERS;
    let mut soak_min_duration = DEFAULT_MIXED_SOAK_MIN_DURATION;
    let mut include_system_proxy_smoke = false;
    let mut include_tun_runtime_smoke = false;
    let mut tun_runtime_smoke_min_duration = DEFAULT_TUN_RUNTIME_SMOKE_MIN_DURATION;
    let mut require_machine_takeover_ready = false;
    let mut required_stability_window = None;
    let mut required_stability_connections = None;
    let mut soak_connections_explicit = false;
    let mut soak_min_duration_explicit = false;
    let mut tun_runtime_smoke_min_duration_explicit = false;
    let mut args = args.peekable();

    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--format" => {
                output = parse_probe_output_format(
                    args.next()
                        .ok_or_else(|| "--format requires text or json".to_string())?,
                )?;
            }
            "--soak-connections" => {
                soak_connections_explicit = true;
                soak_connections = parse_positive_usize(
                    args.next()
                        .ok_or_else(|| "--soak-connections requires a value".to_string())?,
                    "--soak-connections",
                )?;
            }
            "--first-byte-timeout-ms" => {
                first_byte_timeout = parse_duration_ms(
                    args.next()
                        .ok_or_else(|| "--first-byte-timeout-ms requires a value".to_string())?,
                    "--first-byte-timeout-ms",
                )?;
            }
            "--max-connection-workers" => {
                max_connection_workers = parse_positive_usize(
                    args.next()
                        .ok_or_else(|| "--max-connection-workers requires a value".to_string())?,
                    "--max-connection-workers",
                )?;
            }
            "--soak-min-duration-ms" => {
                soak_min_duration_explicit = true;
                soak_min_duration = parse_duration_ms(
                    args.next()
                        .ok_or_else(|| "--soak-min-duration-ms requires a value".to_string())?,
                    "--soak-min-duration-ms",
                )?;
            }
            "--include-system-proxy-smoke" | "--system-proxy-smoke" => {
                include_system_proxy_smoke = true;
            }
            "--include-tun-runtime-smoke" | "--tun-runtime-smoke" => {
                include_tun_runtime_smoke = true;
            }
            "--machine-takeover"
            | "--include-machine-takeover-smokes"
            | "--machine-takeover-smokes" => {
                include_system_proxy_smoke = true;
                include_tun_runtime_smoke = true;
            }
            "--require-machine-takeover" | "--require-machine-takeover-ready" => {
                require_machine_takeover_ready = true;
            }
            "--machine-takeover-gate" => {
                include_system_proxy_smoke = true;
                include_tun_runtime_smoke = true;
                require_machine_takeover_ready = true;
            }
            "--tun-runtime-smoke-min-duration-ms" => {
                include_tun_runtime_smoke = true;
                tun_runtime_smoke_min_duration_explicit = true;
                tun_runtime_smoke_min_duration = parse_duration_ms(
                    args.next().ok_or_else(|| {
                        "--tun-runtime-smoke-min-duration-ms requires a value".to_string()
                    })?,
                    "--tun-runtime-smoke-min-duration-ms",
                )?;
            }
            "--stability-gate-ms"
            | "--require-stability-window-ms"
            | "--release-stability-window-ms" => {
                required_stability_window = Some(parse_duration_ms(
                    args.next()
                        .ok_or_else(|| format!("{arg} requires a value"))?,
                    arg.as_str(),
                )?);
            }
            "--stability-gate-connections"
            | "--require-stability-connections"
            | "--release-stability-connections" => {
                required_stability_connections = Some(parse_positive_usize(
                    args.next()
                        .ok_or_else(|| format!("{arg} requires a value"))?,
                    arg.as_str(),
                )?);
            }
            other => return Err(format!("unknown default-core-certify option: {other}")),
        }
    }

    if let Some(required_window) = required_stability_window {
        if !soak_min_duration_explicit && soak_min_duration < required_window {
            soak_min_duration = required_window;
        }
        if include_tun_runtime_smoke
            && !tun_runtime_smoke_min_duration_explicit
            && tun_runtime_smoke_min_duration < required_window
        {
            tun_runtime_smoke_min_duration = required_window;
        }
    }
    if let Some(required_connections) = required_stability_connections {
        if !soak_connections_explicit && soak_connections < required_connections {
            soak_connections = required_connections;
        }
    }

    Ok(CliCommand::DefaultCoreCertify {
        output,
        soak_connections,
        first_byte_timeout,
        max_connection_workers,
        soak_min_duration,
        include_system_proxy_smoke,
        include_tun_runtime_smoke,
        tun_runtime_smoke_min_duration,
        require_machine_takeover_ready,
        required_stability_window,
        required_stability_connections,
    })
}

fn parse_tun_preflight(args: impl Iterator<Item = String>) -> Result<CliCommand, String> {
    let mut interface_name = DEFAULT_TUN_INTERFACE_NAME.to_string();
    let mut address_cidr = DEFAULT_TUN_ADDRESS_CIDR.to_string();
    let mut mtu = DEFAULT_TUN_MTU;
    let mut dns_hijack = false;
    let mut output = ProbeOutputFormat::Text;
    let mut args = args.peekable();

    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--interface" | "--interface-name" => {
                interface_name = args
                    .next()
                    .ok_or_else(|| "--interface requires a TUN interface name".to_string())?;
            }
            "--address" | "--address-cidr" => {
                address_cidr = args
                    .next()
                    .ok_or_else(|| "--address requires an IP CIDR".to_string())?;
            }
            "--mtu" => {
                mtu = args
                    .next()
                    .ok_or_else(|| "--mtu requires a value".to_string())?
                    .parse::<u16>()
                    .map_err(|_| "--mtu must be a non-zero u16 value".to_string())?;
            }
            "--dns-hijack" => dns_hijack = true,
            "--format" => {
                output = parse_probe_output_format(
                    args.next()
                        .ok_or_else(|| "--format requires text or json".to_string())?,
                )?;
            }
            other => return Err(format!("unknown tun-preflight option: {other}")),
        }
    }

    let config = TunDeviceConfig::new(interface_name, address_cidr, mtu)
        .map_err(|error| format!("invalid TUN preflight config: {error}"))?
        .with_dns_hijack(dns_hijack);
    Ok(CliCommand::TunPreflight { config, output })
}

