fn parse_tun_backend_install(args: impl Iterator<Item = String>) -> Result<CliCommand, String> {
    let mut source = None;
    let mut target_dir = None;
    let mut output = ProbeOutputFormat::Text;
    let mut args = args.peekable();

    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--source" => {
                if source.is_some() {
                    return Err(
                        "tun-backend-install accepts only one of --source or --source-dir"
                            .to_string(),
                    );
                }
                source = Some(TunBackendInstallSource::File(PathBuf::from(
                    args.next().ok_or_else(|| {
                        "--source requires a path to an extracted wintun.dll".to_string()
                    })?,
                )));
            }
            "--source-dir" => {
                if source.is_some() {
                    return Err(
                        "tun-backend-install accepts only one of --source or --source-dir"
                            .to_string(),
                    );
                }
                source = Some(TunBackendInstallSource::Directory(PathBuf::from(
                    args.next().ok_or_else(|| {
                        "--source-dir requires a path to an extracted Wintun package directory"
                            .to_string()
                    })?,
                )));
            }
            "--target-dir" => {
                target_dir =
                    Some(PathBuf::from(args.next().ok_or_else(|| {
                        "--target-dir requires a directory path".to_string()
                    })?));
            }
            "--format" => {
                output = parse_probe_output_format(
                    args.next()
                        .ok_or_else(|| "--format requires text or json".to_string())?,
                )?;
            }
            other => return Err(format!("unknown tun-backend-install option: {other}")),
        }
    }

    Ok(CliCommand::TunBackendInstall {
        source: source.ok_or_else(|| "--source or --source-dir is required".to_string())?,
        target_dir,
        output,
    })
}

