#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ReadinessGateReport {
    pub name: &'static str,
    pub category: &'static str,
    pub status: ReadinessGateStatus,
    pub detail: String,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ReadinessGateStatus {
    Passed,
    Failed,
    Warning,
    Skipped,
}

impl ReadinessGateStatus {
    fn label(self) -> &'static str {
        match self {
            Self::Passed => "passed",
            Self::Failed => "failed",
            Self::Warning => "warning",
            Self::Skipped => "skipped",
        }
    }
}

pub fn write_readiness_check_report(
    output: ProbeOutputFormat,
    soak_connections: usize,
    first_byte_timeout: Duration,
    max_connection_workers: usize,
    skip_soak: bool,
    mut writer: impl Write,
) -> Result<(), String> {
    write_readiness_check_report_with_soak_min_duration(
        output,
        soak_connections,
        first_byte_timeout,
        max_connection_workers,
        DEFAULT_MIXED_SOAK_MIN_DURATION,
        skip_soak,
        &mut writer,
    )
}

pub fn write_readiness_check_report_with_soak_min_duration(
    output: ProbeOutputFormat,
    soak_connections: usize,
    first_byte_timeout: Duration,
    max_connection_workers: usize,
    soak_min_duration: Duration,
    skip_soak: bool,
    mut writer: impl Write,
) -> Result<(), String> {
    write_readiness_check_report_with_options(
        output,
        soak_connections,
        first_byte_timeout,
        max_connection_workers,
        soak_min_duration,
        skip_soak,
        false,
        false,
        DEFAULT_TUN_RUNTIME_SMOKE_MIN_DURATION,
        &mut writer,
    )
}

pub fn write_readiness_check_report_with_options(
    output: ProbeOutputFormat,
    soak_connections: usize,
    first_byte_timeout: Duration,
    max_connection_workers: usize,
    soak_min_duration: Duration,
    skip_soak: bool,
    include_system_proxy_smoke: bool,
    include_tun_runtime_smoke: bool,
    tun_runtime_smoke_min_duration: Duration,
    mut writer: impl Write,
) -> Result<(), String> {
    let report = collect_readiness_check_report(
        soak_connections,
        first_byte_timeout,
        max_connection_workers,
        soak_min_duration,
        skip_soak,
        include_system_proxy_smoke,
        include_tun_runtime_smoke,
        tun_runtime_smoke_min_duration,
    )?;
    match output {
        ProbeOutputFormat::Text => write_readiness_check_text_report(&mut writer, &report),
        ProbeOutputFormat::Json => write_readiness_check_json_report(&mut writer, &report),
    }
}

