fn readiness_gate(
    name: &'static str,
    category: &'static str,
    passed: bool,
    detail: String,
) -> ReadinessGateReport {
    ReadinessGateReport {
        name,
        category,
        status: if passed {
            ReadinessGateStatus::Passed
        } else {
            ReadinessGateStatus::Failed
        },
        detail,
    }
}

fn readiness_soak_gate(
    name: &'static str,
    inbound: SmokeInboundKind,
    soak_connections: usize,
    first_byte_timeout: Duration,
    max_connection_workers: usize,
    soak_min_duration: Duration,
) -> ReadinessGateReport {
    match run_soak_mixed_with_min_duration(
        soak_connections,
        inbound,
        first_byte_timeout,
        max_connection_workers,
        soak_min_duration,
    ) {
        Ok(report) => readiness_gate(
            name,
            "stability",
            report.completed_connections == report.requested_connections
                && report.failed_connections == 0
                && report.connection_metrics.failure_count == 0
                && report.duration_target_met
                && !report.stop_drain.timed_out
                && report.stop_drain.workers_remaining == 0,
            format!(
                "inbound={} completed={}/{} failures={} elapsed_ms={} min_duration_ms={} duration_target_met={} stop_workers_remaining={} stop_timed_out={}",
                inbound.cli_value(),
                report.completed_connections,
                report.requested_connections,
                report.failed_connections,
                duration_millis_for_report(report.elapsed),
                duration_millis_for_report(report.min_duration),
                report.duration_target_met,
                report.stop_drain.workers_remaining,
                report.stop_drain.timed_out
            ),
        ),
        Err(error) => ReadinessGateReport {
            name,
            category: "stability",
            status: ReadinessGateStatus::Failed,
            detail: error,
        },
    }
}

fn collect_default_route_rule_smoke_report() -> RouteRuleSmokeReport {
    let mut cases = Vec::new();
    cases.push(run_http_route_rule_block_smoke_case(
        "domain-suffix-block",
        "domain-suffix",
        RouteMatcher::DomainSuffix("blocked.example".to_string()),
        "ads.blocked.example",
        443,
        None,
    ));
    cases.push(run_socks5_route_rule_block_smoke_case(
        "cidr-block",
        "ip-cidr",
        RouteMatcher::IpCidr(
            RouteIpCidr::new("127.42.0.1".parse().expect("valid smoke IP"), 8)
                .expect("valid smoke CIDR"),
        ),
        "127.42.0.1",
        443,
    ));

    match TcpListener::bind("127.0.0.1:0") {
        Ok(target) => {
            let target_port = match target.local_addr() {
                Ok(addr) => addr.port(),
                Err(error) => {
                    cases.push(route_rule_smoke_error_case(
                        "port-block",
                        "http-connect",
                        "port-exact",
                        "127.0.0.1:0".to_string(),
                        http_route_rule_smoke_expected_response(),
                        format!("read route-rule smoke target address: {error}"),
                    ));
                    return finalize_route_rule_smoke_report(cases);
                }
            };
            if let Err(error) = target.set_nonblocking(true) {
                cases.push(route_rule_smoke_error_case(
                    "port-block",
                    "http-connect",
                    "port-exact",
                    format!("127.0.0.1:{target_port}"),
                    http_route_rule_smoke_expected_response(),
                    format!("set route-rule smoke target nonblocking: {error}"),
                ));
            } else {
                cases.push(run_http_route_rule_block_smoke_case(
                    "port-block",
                    "port-exact",
                    RouteMatcher::PortExact(target_port),
                    "127.0.0.1",
                    target_port,
                    Some(&target),
                ));
            }
        }
        Err(error) => cases.push(route_rule_smoke_error_case(
            "port-block",
            "http-connect",
            "port-exact",
            "127.0.0.1:0".to_string(),
            http_route_rule_smoke_expected_response(),
            format!("bind route-rule smoke target: {error}"),
        )),
    }

    finalize_route_rule_smoke_report(cases)
}

fn finalize_route_rule_smoke_report(cases: Vec<RouteRuleSmokeCaseReport>) -> RouteRuleSmokeReport {
    let passed_count = cases.iter().filter(|case| case.passed).count();
    let failed: Vec<&str> = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect();
    let passed = failed.is_empty();
    RouteRuleSmokeReport {
        passed,
        detail: format!(
            "cases={} passed={} failed={} failed_cases={}",
            cases.len(),
            passed_count,
            failed.len(),
            if failed.is_empty() {
                "-".to_string()
            } else {
                failed.join(",")
            }
        ),
        cases,
    }
}

fn run_http_route_rule_block_smoke_case(
    name: &'static str,
    matcher_label: &'static str,
    matcher: RouteMatcher,
    target_host: &str,
    target_port: u16,
    target_listener: Option<&TcpListener>,
) -> RouteRuleSmokeCaseReport {
    let expected_response = http_route_rule_smoke_expected_response();
    let target = format!("{target_host}:{target_port}");
    let result = (|| -> Result<(Vec<u8>, Option<bool>), String> {
        let mut routes = RouteEngine::new(RouteAction::Direct);
        routes.add_rule(RouteRule {
            name: format!("route-smoke:{name}"),
            matcher,
            action: RouteAction::Block,
        });
        let runtime = MixedProxyRuntime::with_routes(routes);
        let listener = TcpListener::bind("127.0.0.1:0")
            .map_err(|error| format!("bind route-rule smoke listener: {error}"))?;
        let listen_addr = listener
            .local_addr()
            .map_err(|error| format!("read route-rule smoke listener addr: {error}"))?;
        let server = thread::spawn(move || -> io::Result<()> {
            let (mut stream, _) = listener.accept()?;
            handle_mixed_connection_with_routes(&mut stream, &runtime)
        });

        let mut client = TcpStream::connect(listen_addr)
            .map_err(|error| format!("connect route-rule smoke listener: {error}"))?;
        client
            .set_read_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set route-rule smoke read timeout: {error}"))?;
        client
            .set_write_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set route-rule smoke write timeout: {error}"))?;
        write!(
            client,
            "CONNECT {target} HTTP/1.1\r\nHost: {target}\r\n\r\n"
        )
        .map_err(|error| format!("write route-rule smoke HTTP CONNECT: {error}"))?;
        let response = read_route_rule_smoke_http_response(&mut client)?;
        client.shutdown(Shutdown::Both).ok();
        server
            .join()
            .map_err(|_| "route-rule smoke HTTP worker panicked".to_string())?
            .map_err(|error| format!("route-rule smoke HTTP worker failed: {error}"))?;
        Ok((
            response,
            target_listener.map(route_rule_smoke_target_contacted),
        ))
    })();

    route_rule_smoke_case_from_result(
        name,
        "http-connect",
        matcher_label,
        target,
        expected_response,
        result,
    )
}

fn run_socks5_route_rule_block_smoke_case(
    name: &'static str,
    matcher_label: &'static str,
    matcher: RouteMatcher,
    target_host: &str,
    target_port: u16,
) -> RouteRuleSmokeCaseReport {
    let expected_response =
        route_rule_smoke_response_label(&socks5_reply(Socks5ReplyCode::ConnectionNotAllowed));
    let target = format!("{target_host}:{target_port}");
    let result = (|| -> Result<(Vec<u8>, Option<bool>), String> {
        let mut routes = RouteEngine::new(RouteAction::Direct);
        routes.add_rule(RouteRule {
            name: format!("route-smoke:{name}"),
            matcher,
            action: RouteAction::Block,
        });
        let runtime = MixedProxyRuntime::with_routes(routes);
        let listener = TcpListener::bind("127.0.0.1:0")
            .map_err(|error| format!("bind route-rule smoke listener: {error}"))?;
        let listen_addr = listener
            .local_addr()
            .map_err(|error| format!("read route-rule smoke listener addr: {error}"))?;
        let server = thread::spawn(move || -> io::Result<()> {
            let (mut stream, _) = listener.accept()?;
            handle_mixed_connection_with_routes(&mut stream, &runtime)
        });

        let target = OutboundTarget::new(target_host, target_port);
        let mut client = TcpStream::connect(listen_addr)
            .map_err(|error| format!("connect route-rule smoke listener: {error}"))?;
        client
            .set_read_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set route-rule smoke read timeout: {error}"))?;
        client
            .set_write_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set route-rule smoke write timeout: {error}"))?;
        write_route_rule_smoke_socks5_connect(&mut client, &target)?;
        let mut response = vec![0; socks5_reply(Socks5ReplyCode::ConnectionNotAllowed).len()];
        client
            .read_exact(&mut response)
            .map_err(|error| format!("read route-rule smoke SOCKS5 block response: {error}"))?;
        client.shutdown(Shutdown::Both).ok();
        server
            .join()
            .map_err(|_| "route-rule smoke SOCKS5 worker panicked".to_string())?
            .map_err(|error| format!("route-rule smoke SOCKS5 worker failed: {error}"))?;
        Ok((response, None))
    })();

    route_rule_smoke_case_from_result(
        name,
        "socks5",
        matcher_label,
        target,
        expected_response,
        result,
    )
}

fn route_rule_smoke_case_from_result(
    name: &'static str,
    inbound: &'static str,
    matcher: &'static str,
    target: String,
    expected_response: String,
    result: Result<(Vec<u8>, Option<bool>), String>,
) -> RouteRuleSmokeCaseReport {
    match result {
        Ok((response, target_contacted)) => {
            let observed_response = route_rule_smoke_response_label(&response);
            let passed = observed_response == expected_response && target_contacted != Some(true);
            RouteRuleSmokeCaseReport {
                name,
                inbound,
                matcher,
                target,
                expected_response,
                observed_response: Some(observed_response),
                target_contacted,
                passed,
                error: None,
            }
        }
        Err(error) => {
            route_rule_smoke_error_case(name, inbound, matcher, target, expected_response, error)
        }
    }
}

fn route_rule_smoke_error_case(
    name: &'static str,
    inbound: &'static str,
    matcher: &'static str,
    target: String,
    expected_response: String,
    error: String,
) -> RouteRuleSmokeCaseReport {
    RouteRuleSmokeCaseReport {
        name,
        inbound,
        matcher,
        target,
        expected_response,
        observed_response: None,
        target_contacted: None,
        passed: false,
        error: Some(error),
    }
}

fn http_route_rule_smoke_expected_response() -> String {
    route_rule_smoke_response_label(http_forbidden_response())
}

fn read_route_rule_smoke_http_response(stream: &mut TcpStream) -> Result<Vec<u8>, String> {
    let mut response = Vec::new();
    let mut byte = [0; 1];
    while response.len() < 1024 {
        stream
            .read_exact(&mut byte)
            .map_err(|error| format!("read route-rule smoke HTTP response: {error}"))?;
        response.push(byte[0]);
        if response.ends_with(b"\r\n\r\n") {
            return Ok(response);
        }
    }
    Err("route-rule smoke HTTP response header is too large".to_string())
}

fn write_route_rule_smoke_socks5_connect(
    client: &mut TcpStream,
    target: &OutboundTarget,
) -> Result<(), String> {
    client
        .write_all(&[0x05, 0x01, 0x00])
        .map_err(|error| format!("write route-rule smoke SOCKS5 hello: {error}"))?;
    let mut hello = [0; 2];
    client
        .read_exact(&mut hello)
        .map_err(|error| format!("read route-rule smoke SOCKS5 hello response: {error}"))?;
    if hello != [0x05, 0x00] {
        return Err(format!(
            "unexpected route-rule smoke SOCKS5 hello response: {hello:?}"
        ));
    }

    let mut request = vec![0x05, 0x01, 0x00];
    match target.host.parse::<IpAddr>() {
        Ok(IpAddr::V4(ip)) => {
            request.push(0x01);
            request.extend_from_slice(&ip.octets());
        }
        Ok(IpAddr::V6(ip)) => {
            request.push(0x04);
            request.extend_from_slice(&ip.octets());
        }
        Err(_) => {
            let host = target.host.as_bytes();
            if host.len() > u8::MAX as usize {
                return Err(format!(
                    "route-rule smoke target host is too long: {}",
                    target.host
                ));
            }
            request.push(0x03);
            request.push(host.len() as u8);
            request.extend_from_slice(host);
        }
    }
    request.extend_from_slice(&target.port.to_be_bytes());
    client
        .write_all(&request)
        .map_err(|error| format!("write route-rule smoke SOCKS5 connect: {error}"))
}

fn route_rule_smoke_target_contacted(listener: &TcpListener) -> bool {
    match listener.accept() {
        Ok((stream, _)) => {
            stream.shutdown(Shutdown::Both).ok();
            true
        }
        Err(error) if error.kind() == io::ErrorKind::WouldBlock => false,
        Err(_) => false,
    }
}

fn route_rule_smoke_response_label(response: &[u8]) -> String {
    if response
        .iter()
        .all(|byte| byte.is_ascii_graphic() || matches!(byte, b'\r' | b'\n' | b' '))
    {
        String::from_utf8_lossy(response)
            .replace('\r', "\\r")
            .replace('\n', "\\n")
    } else {
        let mut output = String::new();
        for byte in response {
            output.push_str(&format!("{byte:02x}"));
        }
        output
    }
}

#[cfg(test)]
mod route_rule_smoke_tests {
    use super::*;

    #[test]
    fn default_route_rule_smoke_blocks_domain_cidr_and_port_cases() {
        let report = collect_default_route_rule_smoke_report();

        assert!(report.passed, "{}", report.detail);
        assert_eq!(report.cases.len(), 3);
        for case_name in ["domain-suffix-block", "cidr-block", "port-block"] {
            let case = report
                .cases
                .iter()
                .find(|case| case.name == case_name)
                .unwrap_or_else(|| panic!("missing route-rule smoke case {case_name}"));
            assert!(case.passed, "{case:?}");
            assert_eq!(
                case.observed_response.as_ref(),
                Some(&case.expected_response)
            );
        }

        let port_case = report
            .cases
            .iter()
            .find(|case| case.name == "port-block")
            .expect("port route-rule smoke case");
        assert_eq!(port_case.target_contacted, Some(false));
    }
}

fn collect_default_dns_policy_smoke_report() -> DnsPolicySmokeReport {
    let mut cases = Vec::new();
    cases.push(run_http_dns_policy_error_smoke_case(
        "prevent-public-leak-http-connect",
        "prevent-public-leak",
        MixedDnsOptions {
            local_resolution_policy: DnsLocalResolutionPolicy::PreventPublicLeak,
            ..MixedDnsOptions::default()
        },
        "public.example",
        443,
        None,
    ));

    match TcpListener::bind("127.0.0.1:0") {
        Ok(target) => {
            let target_port = match target.local_addr() {
                Ok(addr) => addr.port(),
                Err(error) => {
                    cases.push(dns_policy_smoke_error_case(
                        "address-family-http-connect",
                        "http-connect",
                        "ipv6-only",
                        "127.0.0.1:0".to_string(),
                        dns_policy_smoke_http_bad_request_expected_response(),
                        format!("read DNS policy smoke target address: {error}"),
                    ));
                    return finalize_dns_policy_smoke_report(cases);
                }
            };
            if let Err(error) = target.set_nonblocking(true) {
                cases.push(dns_policy_smoke_error_case(
                    "address-family-http-connect",
                    "http-connect",
                    "ipv6-only",
                    format!("127.0.0.1:{target_port}"),
                    dns_policy_smoke_http_bad_request_expected_response(),
                    format!("set DNS policy smoke target nonblocking: {error}"),
                ));
            } else {
                cases.push(run_http_dns_policy_error_smoke_case(
                    "address-family-http-connect",
                    "ipv6-only",
                    MixedDnsOptions {
                        address_family_policy: DnsAddressFamilyPolicy::Ipv6Only,
                        ..MixedDnsOptions::default()
                    },
                    "127.0.0.1",
                    target_port,
                    Some(&target),
                ));
            }
        }
        Err(error) => cases.push(dns_policy_smoke_error_case(
            "address-family-http-connect",
            "http-connect",
            "ipv6-only",
            "127.0.0.1:0".to_string(),
            dns_policy_smoke_http_bad_request_expected_response(),
            format!("bind DNS policy smoke target: {error}"),
        )),
    }

    cases.push(run_socks5_udp_dns_policy_smoke_case(
        "hijack-localhost-a",
        "prevent-public-leak+ipv4-only",
        MixedDnsOptions {
            local_resolution_policy: DnsLocalResolutionPolicy::PreventPublicLeak,
            address_family_policy: DnsAddressFamilyPolicy::Ipv4Only,
            ..MixedDnsOptions::default()
        },
        "localhost",
        1,
        0,
        1,
        Some(IpAddr::V4(Ipv4Addr::LOCALHOST)),
    ));

    cases.push(run_socks5_udp_dns_policy_smoke_case(
        "hijack-public-leak-nxdomain",
        "prevent-public-leak",
        MixedDnsOptions {
            local_resolution_policy: DnsLocalResolutionPolicy::PreventPublicLeak,
            ..MixedDnsOptions::default()
        },
        "public.example",
        1,
        3,
        0,
        None,
    ));

    finalize_dns_policy_smoke_report(cases)
}

fn finalize_dns_policy_smoke_report(cases: Vec<DnsPolicySmokeCaseReport>) -> DnsPolicySmokeReport {
    let passed_count = cases.iter().filter(|case| case.passed).count();
    let failed: Vec<&str> = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect();
    let passed = failed.is_empty();
    DnsPolicySmokeReport {
        passed,
        detail: format!(
            "cases={} passed={} failed={} failed_cases={}",
            cases.len(),
            passed_count,
            failed.len(),
            if failed.is_empty() {
                "-".to_string()
            } else {
                failed.join(",")
            }
        ),
        cases,
    }
}

fn run_http_dns_policy_error_smoke_case(
    name: &'static str,
    policy_label: &'static str,
    dns_options: MixedDnsOptions,
    target_host: &str,
    target_port: u16,
    target_listener: Option<&TcpListener>,
) -> DnsPolicySmokeCaseReport {
    let expected_response = dns_policy_smoke_http_bad_request_expected_response();
    let target = format!("{target_host}:{target_port}");
    let result = (|| -> Result<(Vec<u8>, Option<bool>), String> {
        let mut runtime = MixedProxyRuntime::with_routes(RouteEngine::new(RouteAction::Direct));
        runtime.dns_options = dns_options;
        let listener = TcpListener::bind("127.0.0.1:0")
            .map_err(|error| format!("bind DNS policy smoke listener: {error}"))?;
        let listen_addr = listener
            .local_addr()
            .map_err(|error| format!("read DNS policy smoke listener addr: {error}"))?;
        let server = thread::spawn(move || -> Result<(), String> {
            let (mut stream, _) = listener
                .accept()
                .map_err(|error| format!("accept DNS policy smoke connection: {error}"))?;
            match handle_mixed_connection_with_routes(&mut stream, &runtime) {
                Ok(()) => Err("DNS policy smoke worker unexpectedly succeeded".to_string()),
                Err(error) => {
                    let detail = error.to_string();
                    if detail.contains("DNS")
                        || detail.contains("dns")
                        || detail.contains("blocked")
                        || detail.contains("filtered")
                    {
                        Ok(())
                    } else {
                        Err(format!(
                            "unexpected DNS policy smoke worker error: {detail}"
                        ))
                    }
                }
            }
        });

        let mut client = TcpStream::connect(listen_addr)
            .map_err(|error| format!("connect DNS policy smoke listener: {error}"))?;
        client
            .set_read_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set DNS policy smoke read timeout: {error}"))?;
        client
            .set_write_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set DNS policy smoke write timeout: {error}"))?;
        write!(
            client,
            "CONNECT {target} HTTP/1.1\r\nHost: {target}\r\n\r\n"
        )
        .map_err(|error| format!("write DNS policy smoke HTTP CONNECT: {error}"))?;
        let response = read_route_rule_smoke_http_response(&mut client)
            .map_err(|error| error.replace("route-rule smoke", "DNS policy smoke"))?;
        client.shutdown(Shutdown::Both).ok();
        server
            .join()
            .map_err(|_| "DNS policy smoke HTTP worker panicked".to_string())??;
        Ok((
            response,
            target_listener.map(route_rule_smoke_target_contacted),
        ))
    })();

    dns_policy_smoke_case_from_result(
        name,
        "http-connect",
        policy_label,
        target,
        expected_response,
        result,
    )
}

fn run_socks5_udp_dns_policy_smoke_case(
    name: &'static str,
    policy_label: &'static str,
    dns_options: MixedDnsOptions,
    query_name: &str,
    query_type: u16,
    expected_rcode: u8,
    expected_answer_count: u16,
    expected_ip: Option<IpAddr>,
) -> DnsPolicySmokeCaseReport {
    let target = format!("{query_name}:{query_type}->8.8.8.8:53");
    let expected_response =
        dns_policy_smoke_dns_expected_response(expected_rcode, expected_answer_count, expected_ip);
    let result = (|| -> Result<(Vec<u8>, Option<bool>), String> {
        let mut runtime = MixedProxyRuntime::with_routes(RouteEngine::new(RouteAction::HijackDns));
        runtime.dns_options = dns_options;
        let listener = TcpListener::bind("127.0.0.1:0")
            .map_err(|error| format!("bind DNS policy smoke listener: {error}"))?;
        let listen_addr = listener
            .local_addr()
            .map_err(|error| format!("read DNS policy smoke listener addr: {error}"))?;
        let server = thread::spawn(move || -> io::Result<()> {
            let (mut stream, _) = listener.accept()?;
            handle_socks5_connection_with_routes(&mut stream, &runtime)
        });

        let mut client = TcpStream::connect(listen_addr)
            .map_err(|error| format!("connect DNS policy smoke listener: {error}"))?;
        client
            .set_read_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set DNS policy smoke TCP read timeout: {error}"))?;
        client
            .set_write_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set DNS policy smoke TCP write timeout: {error}"))?;
        client
            .write_all(&[0x05, 0x01, 0x00])
            .map_err(|error| format!("write DNS policy smoke SOCKS5 hello: {error}"))?;
        let mut hello = [0; 2];
        client
            .read_exact(&mut hello)
            .map_err(|error| format!("read DNS policy smoke SOCKS5 hello response: {error}"))?;
        if hello != [0x05, 0x00] {
            return Err(format!(
                "unexpected DNS policy smoke SOCKS5 hello response: {hello:?}"
            ));
        }
        client
            .write_all(&[0x05, 0x03, 0x00, 0x01, 127, 0, 0, 1, 0x00, 0x00])
            .map_err(|error| format!("write DNS policy smoke UDP associate: {error}"))?;
        let mut reply = [0; 10];
        client
            .read_exact(&mut reply)
            .map_err(|error| format!("read DNS policy smoke UDP associate response: {error}"))?;
        if reply[..4] != [0x05, 0x00, 0x00, 0x01] {
            return Err(format!(
                "unexpected DNS policy smoke UDP associate response: {reply:?}"
            ));
        }
        let relay_port = u16::from_be_bytes([reply[8], reply[9]]);
        if relay_port == 0 {
            return Err("DNS policy smoke UDP relay port is zero".to_string());
        }

        let udp_client = UdpSocket::bind("127.0.0.1:0")
            .map_err(|error| format!("bind DNS policy smoke UDP client: {error}"))?;
        udp_client
            .set_read_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set DNS policy smoke UDP read timeout: {error}"))?;
        let request = encode_socks5_udp_datagram(
            &Socks5Address::Ipv4(Ipv4Addr::new(8, 8, 8, 8)),
            53,
            &dns_policy_smoke_query(0x4b55, query_name, query_type),
        )
        .map_err(|error| format!("encode DNS policy smoke UDP request: {error}"))?;
        udp_client
            .send_to(&request, ("127.0.0.1", relay_port))
            .map_err(|error| format!("send DNS policy smoke UDP request: {error}"))?;
        let mut response = [0; 1500];
        let (size, _) = udp_client
            .recv_from(&mut response)
            .map_err(|error| format!("read DNS policy smoke UDP response: {error}"))?;
        let response = parse_socks5_udp_datagram(&response[..size])
            .map_err(|error| format!("parse DNS policy smoke UDP response: {error}"))?;
        if response.address != Socks5Address::Ipv4(Ipv4Addr::new(8, 8, 8, 8)) || response.port != 53
        {
            return Err(format!(
                "unexpected DNS policy smoke response source: {:?}:{}",
                response.address, response.port
            ));
        }
        client.shutdown(Shutdown::Both).ok();
        server
            .join()
            .map_err(|_| "DNS policy smoke SOCKS5 worker panicked".to_string())?
            .map_err(|error| format!("DNS policy smoke SOCKS5 worker failed: {error}"))?;
        Ok((response.payload, None))
    })();

    dns_policy_smoke_case_from_result(
        name,
        "socks5-udp-dns-hijack",
        policy_label,
        target,
        expected_response,
        result,
    )
}

fn dns_policy_smoke_case_from_result(
    name: &'static str,
    inbound: &'static str,
    policy: &'static str,
    target: String,
    expected_response: String,
    result: Result<(Vec<u8>, Option<bool>), String>,
) -> DnsPolicySmokeCaseReport {
    match result {
        Ok((response, target_contacted)) => {
            let observed_response = if inbound == "socks5-udp-dns-hijack" {
                dns_policy_smoke_dns_response_label(&response)
            } else {
                route_rule_smoke_response_label(&response)
            };
            let passed = observed_response == expected_response && target_contacted != Some(true);
            DnsPolicySmokeCaseReport {
                name,
                inbound,
                policy,
                target,
                expected_response,
                observed_response: Some(observed_response),
                target_contacted,
                passed,
                error: None,
            }
        }
        Err(error) => {
            dns_policy_smoke_error_case(name, inbound, policy, target, expected_response, error)
        }
    }
}

fn dns_policy_smoke_error_case(
    name: &'static str,
    inbound: &'static str,
    policy: &'static str,
    target: String,
    expected_response: String,
    error: String,
) -> DnsPolicySmokeCaseReport {
    DnsPolicySmokeCaseReport {
        name,
        inbound,
        policy,
        target,
        expected_response,
        observed_response: None,
        target_contacted: None,
        passed: false,
        error: Some(error),
    }
}

fn dns_policy_smoke_http_bad_request_expected_response() -> String {
    route_rule_smoke_response_label(http_connect_bad_request_response())
}

fn dns_policy_smoke_dns_expected_response(
    rcode: u8,
    answer_count: u16,
    expected_ip: Option<IpAddr>,
) -> String {
    format!(
        "id=0x4b55 rcode={} answers={} contains_expected_ip={}",
        rcode,
        answer_count,
        expected_ip.is_some()
    )
}

fn dns_policy_smoke_dns_response_label(response: &[u8]) -> String {
    if response.len() < 12 {
        return format!("dns-response-too-short bytes={}", response.len());
    }
    let id = u16::from_be_bytes([response[0], response[1]]);
    let flags = u16::from_be_bytes([response[2], response[3]]);
    let rcode = (flags & 0x000f) as u8;
    let answer_count = u16::from_be_bytes([response[6], response[7]]);
    let contains_localhost_v4 = response.windows(4).any(|window| window == [127, 0, 0, 1]);
    let contains_expected_ip = if answer_count == 0 {
        false
    } else {
        contains_localhost_v4
    };
    format!(
        "id=0x{id:04x} rcode={} answers={} contains_expected_ip={}",
        rcode, answer_count, contains_expected_ip
    )
}

fn dns_policy_smoke_query(id: u16, name: &str, qtype: u16) -> Vec<u8> {
    let mut query = Vec::new();
    query.extend_from_slice(&id.to_be_bytes());
    query.extend_from_slice(&0x0100u16.to_be_bytes());
    query.extend_from_slice(&1u16.to_be_bytes());
    query.extend_from_slice(&0u16.to_be_bytes());
    query.extend_from_slice(&0u16.to_be_bytes());
    query.extend_from_slice(&0u16.to_be_bytes());
    for label in name.split('.') {
        query.push(label.len() as u8);
        query.extend_from_slice(label.as_bytes());
    }
    query.push(0);
    query.extend_from_slice(&qtype.to_be_bytes());
    query.extend_from_slice(&1u16.to_be_bytes());
    query
}

#[cfg(test)]
mod dns_policy_smoke_tests {
    use super::*;

    #[test]
    fn default_dns_policy_smoke_covers_leak_prevention_address_family_and_hijack() {
        let report = collect_default_dns_policy_smoke_report();

        assert!(report.passed, "{}", report.detail);
        assert_eq!(report.cases.len(), 4);
        for case_name in [
            "prevent-public-leak-http-connect",
            "address-family-http-connect",
            "hijack-localhost-a",
            "hijack-public-leak-nxdomain",
        ] {
            let case = report
                .cases
                .iter()
                .find(|case| case.name == case_name)
                .unwrap_or_else(|| panic!("missing DNS policy smoke case {case_name}"));
            assert!(case.passed, "{case:?}");
            assert_eq!(
                case.observed_response.as_ref(),
                Some(&case.expected_response)
            );
        }

        let address_family = report
            .cases
            .iter()
            .find(|case| case.name == "address-family-http-connect")
            .expect("address-family DNS policy case");
        assert_eq!(address_family.target_contacted, Some(false));
    }
}

fn collect_default_tcp_relay_smoke_report() -> TcpRelaySmokeReport {
    let mut cases = Vec::new();
    let mut selected_outbound = None;
    let request_payload_bytes = TCP_RELAY_SMOKE_PAYLOAD.len();
    let mut response_payload_bytes = None;
    let mut round_trip_observed = false;
    let mut server_received_payload = false;
    let mut metrics_recorded = false;
    let mut metrics_total_connections = 0;
    let mut metrics_success_count = 0;
    let mut metrics_inbound_count = 0;
    let mut metrics_outbound_route_count = 0;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let (ss_port, ss_thread) = match spawn_tcp_relay_smoke_shadowsocks_server() {
        Ok(server) => server,
        Err(error) => {
            cases.push(tcp_relay_smoke_error_case(
                "start-shadowsocks-tcp-echo",
                "start-echo-server",
                error,
            ));
            return finalize_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };

    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let config = tcp_relay_smoke_config(ss_port);
    let relay_options = RelayOptions {
        first_byte_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
        idle_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
    };

    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some(TCP_RELAY_SMOKE_OUTBOUND.to_string()),
            relay_options,
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(tcp_relay_smoke_error_case(
                "start-tcp-relay-runtime",
                "start",
                error,
            ));
            let _ = join_tcp_relay_smoke_server(ss_thread);
            return finalize_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    selected_outbound = started.selected_outbound.clone();
    cases.push(tcp_relay_smoke_start_case(&started));

    if let Some(listen_addr) = started.listen_addr {
        let exchange_result = run_tcp_relay_smoke_socks5_exchange(listen_addr);
        let server_result = join_tcp_relay_smoke_server(ss_thread);
        if let Ok(exchange) = exchange_result.as_ref() {
            response_payload_bytes = Some(exchange.response_payload.len());
            round_trip_observed = exchange.response_payload == TCP_RELAY_SMOKE_RESPONSE;
        }
        if let Ok(server) = server_result.as_ref() {
            server_received_payload = server.received_expected_payload;
        }
        cases.push(tcp_relay_smoke_exchange_case(
            exchange_result,
            server_result,
            round_trip_observed,
            server_received_payload,
        ));

        let status = wait_for_udp_relay_smoke_status(&core, |status| {
            tcp_relay_smoke_metrics_recorded(&status.connection_metrics)
        });
        metrics_total_connections = status.connection_metrics.total_connection_count;
        metrics_success_count = status.connection_metrics.success_count;
        metrics_inbound_count = udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5");
        metrics_outbound_route_count =
            tcp_relay_smoke_outbound_route_count(&status.connection_metrics);
        metrics_recorded = tcp_relay_smoke_metrics_recorded(&status.connection_metrics);
        cases.push(tcp_relay_smoke_metrics_case(&status, metrics_recorded));
    } else {
        cases.push(tcp_relay_smoke_error_case(
            "tcp-relay-round-trip",
            "socks5-connect",
            "managed mixed runtime did not expose a listen address".to_string(),
        ));
        let _ = join_tcp_relay_smoke_server(ss_thread);
    }

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(tcp_relay_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(tcp_relay_smoke_stop_case(
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
            Some(error),
        )),
    }

    finalize_tcp_relay_smoke_report(
        cases,
        selected_outbound,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct TcpRelaySmokeExchangeObservation {
    response_payload: Vec<u8>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct TcpRelaySmokeServerObservation {
    received_expected_payload: bool,
}

fn tcp_relay_smoke_config(ss_port: u16) -> String {
    format!(
        r#"
proxies:
  - name: {TCP_RELAY_SMOKE_OUTBOUND}
    type: ss
    server: 127.0.0.1
    port: {ss_port}
    cipher: aes-256-gcm
    password: secret
"#
    )
}

fn finalize_tcp_relay_smoke_report(
    cases: Vec<TcpRelaySmokeCaseReport>,
    selected_outbound: Option<String>,
    request_payload_bytes: usize,
    response_payload_bytes: Option<usize>,
    round_trip_observed: bool,
    server_received_payload: bool,
    metrics_recorded: bool,
    metrics_total_connections: u64,
    metrics_success_count: u64,
    metrics_inbound_count: u64,
    metrics_outbound_route_count: u64,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> TcpRelaySmokeReport {
    let failed = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect::<Vec<_>>();
    let passed = failed.is_empty()
        && selected_outbound.as_deref() == Some(TCP_RELAY_SMOKE_OUTBOUND)
        && round_trip_observed
        && server_received_payload
        && metrics_recorded
        && clean_stop_observed;
    let target = tcp_relay_smoke_target();
    let detail = format!(
        "cases={} passed={} failed={} failed_cases={} selected={} target={} request_bytes={} response_bytes={} round_trip_observed={} server_received_payload={} metrics_recorded={} metrics_total={} metrics_success={} metrics_inbound_socks5={} metrics_outbound_route={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
        cases.len(),
        passed,
        failed.len(),
        if failed.is_empty() {
            "-".to_string()
        } else {
            failed.join(",")
        },
        selected_outbound.as_deref().unwrap_or("-"),
        target,
        request_payload_bytes,
        response_payload_bytes
            .map(|bytes| bytes.to_string())
            .unwrap_or_else(|| "-".to_string()),
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining
            .map(|workers| workers.to_string())
            .unwrap_or_else(|| "-".to_string()),
        stop_timed_out
            .map(|timed_out| timed_out.to_string())
            .unwrap_or_else(|| "-".to_string())
    );
    TcpRelaySmokeReport {
        passed,
        detail,
        selected_outbound,
        target,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

fn tcp_relay_smoke_start_case(status: &ManagedMixedStatusSnapshot) -> TcpRelaySmokeCaseReport {
    let selected = status.selected_outbound.clone();
    let passed = selected.as_deref() == Some(TCP_RELAY_SMOKE_OUTBOUND)
        && status.generation == 1
        && matches!(&status.status, RuntimeStatus::Running { .. });
    TcpRelaySmokeCaseReport {
        name: "start-tcp-relay-runtime",
        action: "start",
        expected_selected_outbound: Some(TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: selected,
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        target: tcp_relay_smoke_target(),
        expected_response: None,
        observed_response: None,
        request_payload_bytes: None,
        response_payload_bytes: None,
        runtime_running: Some(matches!(&status.status, RuntimeStatus::Running { .. })),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error: None,
    }
}

fn tcp_relay_smoke_exchange_case(
    exchange_result: Result<TcpRelaySmokeExchangeObservation, String>,
    server_result: Result<TcpRelaySmokeServerObservation, String>,
    round_trip_observed: bool,
    server_received_payload: bool,
) -> TcpRelaySmokeCaseReport {
    let error = match (&exchange_result, &server_result) {
        (Ok(_), Ok(_)) => None,
        (Err(exchange), Ok(_)) => Some(exchange.clone()),
        (Ok(_), Err(server)) => Some(server.clone()),
        (Err(exchange), Err(server)) => Some(format!("{exchange}; {server}")),
    };
    let exchange = exchange_result.ok();
    let passed = error.is_none() && round_trip_observed && server_received_payload;
    TcpRelaySmokeCaseReport {
        name: "socks5-tcp-shadowsocks-round-trip",
        action: "socks5-connect",
        expected_selected_outbound: Some(TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: tcp_relay_smoke_target(),
        expected_response: Some(String::from_utf8_lossy(TCP_RELAY_SMOKE_RESPONSE).to_string()),
        observed_response: exchange
            .as_ref()
            .map(|exchange| String::from_utf8_lossy(&exchange.response_payload).to_string()),
        request_payload_bytes: Some(TCP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: exchange
            .as_ref()
            .map(|exchange| exchange.response_payload.len()),
        runtime_running: None,
        round_trip_observed: Some(round_trip_observed),
        server_received_payload: Some(server_received_payload),
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error,
    }
}

fn tcp_relay_smoke_metrics_case(
    status: &ManagedMixedStatusSnapshot,
    metrics_recorded: bool,
) -> TcpRelaySmokeCaseReport {
    let metrics = &status.connection_metrics;
    let inbound_count = udp_relay_smoke_inbound_count(metrics, "socks5");
    let outbound_route_count = tcp_relay_smoke_outbound_route_count(metrics);
    TcpRelaySmokeCaseReport {
        name: "record-tcp-relay-metrics",
        action: "status",
        expected_selected_outbound: Some(TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: status.selected_outbound.clone(),
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        target: tcp_relay_smoke_target(),
        expected_response: None,
        observed_response: None,
        request_payload_bytes: Some(TCP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: Some(TCP_RELAY_SMOKE_RESPONSE.len()),
        runtime_running: Some(matches!(&status.status, RuntimeStatus::Running { .. })),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: Some(metrics_recorded),
        metrics_total_connections: Some(metrics.total_connection_count),
        metrics_success_count: Some(metrics.success_count),
        metrics_inbound_count: Some(inbound_count),
        metrics_outbound_route_count: Some(outbound_route_count),
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed: metrics_recorded,
        error: None,
    }
}

fn tcp_relay_smoke_stop_case(
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
    error: Option<String>,
) -> TcpRelaySmokeCaseReport {
    TcpRelaySmokeCaseReport {
        name: "stop-tcp-relay-runtime",
        action: "stop",
        expected_selected_outbound: None,
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: tcp_relay_smoke_target(),
        expected_response: None,
        observed_response: None,
        request_payload_bytes: None,
        response_payload_bytes: None,
        runtime_running: Some(false),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: Some(clean_stop_observed),
        stop_workers_remaining,
        stop_timed_out,
        passed: clean_stop_observed && error.is_none(),
        error,
    }
}

fn tcp_relay_smoke_error_case(
    name: &'static str,
    action: &'static str,
    error: String,
) -> TcpRelaySmokeCaseReport {
    TcpRelaySmokeCaseReport {
        name,
        action,
        expected_selected_outbound: Some(TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: tcp_relay_smoke_target(),
        expected_response: Some(String::from_utf8_lossy(TCP_RELAY_SMOKE_RESPONSE).to_string()),
        observed_response: None,
        request_payload_bytes: Some(TCP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: None,
        runtime_running: None,
        round_trip_observed: Some(false),
        server_received_payload: Some(false),
        metrics_recorded: Some(false),
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed: false,
        error: Some(error),
    }
}

fn run_tcp_relay_smoke_socks5_exchange(
    listen_addr: SocketAddr,
) -> Result<TcpRelaySmokeExchangeObservation, String> {
    let mut client = TcpStream::connect(listen_addr)
        .map_err(|error| format!("connect TCP smoke listener {listen_addr}: {error}"))?;
    client
        .set_read_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set TCP smoke client read timeout: {error}"))?;
    client
        .set_write_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set TCP smoke client write timeout: {error}"))?;
    let target = OutboundTarget::new(TCP_RELAY_SMOKE_TARGET_HOST, TCP_RELAY_SMOKE_TARGET_PORT);
    write_smoke_connect(&mut client, &target, SmokeInboundKind::Socks5)?;
    client
        .write_all(TCP_RELAY_SMOKE_PAYLOAD)
        .map_err(|error| format!("write TCP smoke payload: {error}"))?;
    let mut response = vec![0; TCP_RELAY_SMOKE_RESPONSE.len()];
    client
        .read_exact(&mut response)
        .map_err(|error| format!("read TCP smoke response: {error}"))?;
    client.shutdown(Shutdown::Both).ok();
    Ok(TcpRelaySmokeExchangeObservation {
        response_payload: response,
    })
}

fn spawn_tcp_relay_smoke_shadowsocks_server() -> Result<
    (
        u16,
        thread::JoinHandle<Result<TcpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    spawn_tcp_relay_smoke_shadowsocks_server_for(
        "TCP smoke",
        TCP_RELAY_SMOKE_TARGET_HOST,
        TCP_RELAY_SMOKE_TARGET_PORT,
        TCP_RELAY_SMOKE_PAYLOAD.to_vec(),
        TCP_RELAY_SMOKE_RESPONSE,
    )
}

fn spawn_tcp_relay_smoke_shadowsocks_server_for(
    label: &'static str,
    host: &'static str,
    target_port: u16,
    expected_payload: Vec<u8>,
    response_payload: &'static [u8],
) -> Result<
    (
        u16,
        thread::JoinHandle<Result<TcpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind {label} Shadowsocks server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set {label} Shadowsocks accept mode: {error}"))?;
    let listen_port = listener
        .local_addr()
        .map_err(|error| format!("read {label} Shadowsocks address: {error}"))?
        .port();
    let handle = thread::spawn(move || -> Result<TcpRelaySmokeServerObservation, String> {
        let deadline = Instant::now() + TCP_RELAY_SMOKE_TIMEOUT;
        let (mut stream, _) = loop {
            match listener.accept() {
                Ok(accepted) => break accepted,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err(format!("{label} Shadowsocks accept timed out"));
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => return Err(format!("accept {label} Shadowsocks server: {error}")),
            }
        };
        stream
            .set_nonblocking(false)
            .map_err(|error| format!("set {label} Shadowsocks stream blocking mode: {error}"))?;
        stream
            .set_read_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set {label} Shadowsocks read timeout: {error}"))?;
        stream
            .set_write_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set {label} Shadowsocks write timeout: {error}"))?;

        let kind = CipherKind::from_str("aes-256-gcm")
            .map_err(|error| format!("load {label} Shadowsocks cipher: {error}"))?;
        let key = udp_relay_smoke_shadowsocks_key(kind, "secret");

        let mut client_salt = vec![0; kind.salt_len()];
        stream
            .read_exact(&mut client_salt)
            .map_err(|error| format!("read {label} client salt: {error}"))?;
        let mut client_cipher = Cipher::new(kind, &key, &client_salt);
        let first_chunk = tcp_relay_smoke_read_ss_chunk(&mut stream, &mut client_cipher)?;
        let expected_header = tcp_relay_smoke_domain_plaintext_header(host, target_port);
        if !first_chunk.starts_with(&expected_header) {
            return Err(format!(
                "unexpected {label} Shadowsocks target header: expected {:?}, got {:?}",
                expected_header, first_chunk
            ));
        }
        let mut payload = first_chunk[expected_header.len()..].to_vec();
        while payload.len() < expected_payload.len() {
            payload.extend(tcp_relay_smoke_read_ss_chunk(
                &mut stream,
                &mut client_cipher,
            )?);
        }
        if payload != expected_payload {
            return Err(format!(
                "unexpected {label} Shadowsocks payload: expected {:?}, got {:?}",
                expected_payload, payload
            ));
        }

        let server_salt = vec![7; kind.salt_len()];
        stream
            .write_all(&server_salt)
            .map_err(|error| format!("write {label} server salt: {error}"))?;
        let mut server_cipher = Cipher::new(kind, &key, &server_salt);
        tcp_relay_smoke_write_ss_chunk(&mut stream, &mut server_cipher, response_payload)?;
        stream
            .flush()
            .map_err(|error| format!("flush {label} Shadowsocks response: {error}"))?;
        tcp_relay_smoke_wait_for_client_close(&mut stream);
        Ok(TcpRelaySmokeServerObservation {
            received_expected_payload: true,
        })
    });
    Ok((listen_port, handle))
}

fn join_tcp_relay_smoke_server(
    handle: thread::JoinHandle<Result<TcpRelaySmokeServerObservation, String>>,
) -> Result<TcpRelaySmokeServerObservation, String> {
    handle
        .join()
        .map_err(|_| "TCP smoke Shadowsocks server thread panicked".to_string())?
}

fn tcp_relay_smoke_read_ss_chunk(
    stream: &mut TcpStream,
    cipher: &mut Cipher,
) -> Result<Vec<u8>, String> {
    let mut encrypted_len = vec![0; 2 + cipher.tag_len()];
    stream
        .read_exact(&mut encrypted_len)
        .map_err(|error| format!("read TCP smoke encrypted chunk length: {error}"))?;
    if !cipher.decrypt_packet(&mut encrypted_len) {
        return Err("decrypt TCP smoke encrypted chunk length failed".to_string());
    }
    encrypted_len.truncate(2);
    let len = u16::from_be_bytes([encrypted_len[0], encrypted_len[1]]) as usize;
    let mut encrypted_payload = vec![0; len + cipher.tag_len()];
    stream
        .read_exact(&mut encrypted_payload)
        .map_err(|error| format!("read TCP smoke encrypted chunk payload: {error}"))?;
    if !cipher.decrypt_packet(&mut encrypted_payload) {
        return Err("decrypt TCP smoke encrypted chunk payload failed".to_string());
    }
    encrypted_payload.truncate(len);
    Ok(encrypted_payload)
}

fn tcp_relay_smoke_write_ss_chunk(
    stream: &mut TcpStream,
    cipher: &mut Cipher,
    payload: &[u8],
) -> Result<(), String> {
    let tag_len = cipher.tag_len();
    let mut encrypted_len = vec![0; 2 + tag_len];
    encrypted_len[..2].copy_from_slice(&(payload.len() as u16).to_be_bytes());
    cipher.encrypt_packet(&mut encrypted_len);
    stream
        .write_all(&encrypted_len)
        .map_err(|error| format!("write TCP smoke encrypted chunk length: {error}"))?;
    let mut encrypted_payload = vec![0; payload.len() + tag_len];
    encrypted_payload[..payload.len()].copy_from_slice(payload);
    cipher.encrypt_packet(&mut encrypted_payload);
    stream
        .write_all(&encrypted_payload)
        .map_err(|error| format!("write TCP smoke encrypted chunk payload: {error}"))
}

fn tcp_relay_smoke_wait_for_client_close(stream: &mut TcpStream) {
    let mut buffer = [0; 1];
    let _ = stream.read(&mut buffer);
}

fn tcp_relay_smoke_domain_plaintext_header(host: &str, port: u16) -> Vec<u8> {
    let mut plaintext = Vec::with_capacity(1 + 1 + host.len() + 2);
    plaintext.push(0x03);
    plaintext.push(host.len() as u8);
    plaintext.extend_from_slice(host.as_bytes());
    plaintext.extend_from_slice(&port.to_be_bytes());
    plaintext
}

fn tcp_relay_smoke_metrics_recorded(metrics: &ConnectionMetricsSnapshot) -> bool {
    metrics.total_connection_count >= 1
        && metrics.success_count >= 1
        && udp_relay_smoke_inbound_count(metrics, "socks5") >= 1
        && tcp_relay_smoke_outbound_route_count(metrics) >= 1
        && metrics.total_upload_bytes >= TCP_RELAY_SMOKE_PAYLOAD.len() as u64
        && metrics.total_download_bytes >= TCP_RELAY_SMOKE_RESPONSE.len() as u64
}

fn tcp_relay_smoke_outbound_route_count(metrics: &ConnectionMetricsSnapshot) -> u64 {
    metrics
        .route_action_counts
        .iter()
        .find(|entry| {
            entry.route_action == RouteAction::Outbound(TCP_RELAY_SMOKE_OUTBOUND.to_string())
        })
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn tcp_relay_smoke_target() -> String {
    format!("{TCP_RELAY_SMOKE_TARGET_HOST}:{TCP_RELAY_SMOKE_TARGET_PORT}")
}

#[cfg(test)]
mod tcp_relay_smoke_tests {
    use super::*;

    #[test]
    fn default_tcp_relay_smoke_proves_socks5_tcp_shadowsocks_round_trip() {
        let report = collect_default_tcp_relay_smoke_report();

        assert!(report.passed, "{report:#?}");
        assert_eq!(
            report.selected_outbound.as_deref(),
            Some(TCP_RELAY_SMOKE_OUTBOUND)
        );
        assert_eq!(report.target, tcp_relay_smoke_target());
        assert_eq!(report.request_payload_bytes, TCP_RELAY_SMOKE_PAYLOAD.len());
        assert_eq!(
            report.response_payload_bytes,
            Some(TCP_RELAY_SMOKE_RESPONSE.len())
        );
        assert!(report.round_trip_observed);
        assert!(report.server_received_payload);
        assert!(report.metrics_recorded);
        assert!(report.metrics_total_connections >= 1);
        assert!(report.metrics_success_count >= 1);
        assert!(report.metrics_inbound_count >= 1);
        assert!(report.metrics_outbound_route_count >= 1);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));

        let case_names = report
            .cases
            .iter()
            .map(|case| case.name)
            .collect::<Vec<_>>();
        for expected in [
            "start-tcp-relay-runtime",
            "socks5-tcp-shadowsocks-round-trip",
            "record-tcp-relay-metrics",
            "stop-tcp-relay-runtime",
        ] {
            assert!(
                case_names.contains(&expected),
                "missing TCP relay smoke case {expected}: {case_names:?}"
            );
        }
        let round_trip = report
            .cases
            .iter()
            .find(|case| case.name == "socks5-tcp-shadowsocks-round-trip")
            .expect("round trip case");
        assert_eq!(
            round_trip.observed_response.as_deref(),
            Some("keli-tcp-pong")
        );
        assert_eq!(round_trip.round_trip_observed, Some(true));
        assert_eq!(round_trip.server_received_payload, Some(true));
    }

    #[test]
    fn default_tcp_relay_smoke_is_stable_across_consecutive_runs() {
        let first = collect_default_tcp_relay_smoke_report();
        let second = collect_default_tcp_relay_smoke_report();

        assert!(first.passed, "{first:#?}");
        assert!(second.passed, "{second:#?}");
    }
}

fn collect_default_socks5_tcp_outbound_relay_smoke_report() -> TcpRelaySmokeReport {
    let mut cases = Vec::new();
    let mut selected_outbound = None;
    let request_payload_bytes = SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_PAYLOAD.len();
    let mut response_payload_bytes = None;
    let mut round_trip_observed = false;
    let mut server_received_payload = false;
    let mut metrics_recorded = false;
    let mut metrics_total_connections = 0;
    let mut metrics_success_count = 0;
    let mut metrics_inbound_count = 0;
    let mut metrics_outbound_route_count = 0;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let (socks5_port, socks5_thread) = match spawn_socks5_tcp_outbound_relay_smoke_server() {
        Ok(server) => server,
        Err(error) => {
            cases.push(socks5_tcp_outbound_relay_smoke_error_case(
                "start-socks5-tcp-outbound-proxy-server",
                "start-protocol-server",
                error,
            ));
            return finalize_socks5_tcp_outbound_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };

    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let config = socks5_tcp_outbound_relay_smoke_config(socks5_port);
    let relay_options = RelayOptions {
        first_byte_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
        idle_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
    };

    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some(SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_OUTBOUND.to_string()),
            relay_options,
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(socks5_tcp_outbound_relay_smoke_error_case(
                "start-socks5-tcp-outbound-relay-runtime",
                "start",
                error,
            ));
            let _ = join_tcp_relay_smoke_server(socks5_thread);
            return finalize_socks5_tcp_outbound_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    selected_outbound = started.selected_outbound.clone();
    cases.push(socks5_tcp_outbound_relay_smoke_start_case(&started));

    if let Some(listen_addr) = started.listen_addr {
        let exchange_result = run_socks5_tcp_outbound_relay_smoke_exchange(listen_addr);
        let server_result = join_tcp_relay_smoke_server(socks5_thread);
        if let Ok(exchange) = exchange_result.as_ref() {
            response_payload_bytes = Some(exchange.response_payload.len());
            round_trip_observed =
                exchange.response_payload == SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_RESPONSE;
        }
        if let Ok(server) = server_result.as_ref() {
            server_received_payload = server.received_expected_payload;
        }
        cases.push(socks5_tcp_outbound_relay_smoke_exchange_case(
            exchange_result,
            server_result,
            round_trip_observed,
            server_received_payload,
        ));

        let status = wait_for_udp_relay_smoke_status(&core, |status| {
            socks5_tcp_outbound_relay_smoke_metrics_recorded(&status.connection_metrics)
        });
        metrics_total_connections = status.connection_metrics.total_connection_count;
        metrics_success_count = status.connection_metrics.success_count;
        metrics_inbound_count = udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5");
        metrics_outbound_route_count =
            socks5_tcp_outbound_relay_smoke_outbound_route_count(&status.connection_metrics);
        metrics_recorded =
            socks5_tcp_outbound_relay_smoke_metrics_recorded(&status.connection_metrics);
        cases.push(socks5_tcp_outbound_relay_smoke_metrics_case(
            &status,
            metrics_recorded,
        ));
    } else {
        cases.push(socks5_tcp_outbound_relay_smoke_error_case(
            "socks5-tcp-outbound-relay-round-trip",
            "socks5-connect",
            "managed mixed runtime did not expose a listen address".to_string(),
        ));
        let _ = join_tcp_relay_smoke_server(socks5_thread);
    }

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(socks5_tcp_outbound_relay_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(socks5_tcp_outbound_relay_smoke_stop_case(
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
            Some(error),
        )),
    }

    finalize_socks5_tcp_outbound_relay_smoke_report(
        cases,
        selected_outbound,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn socks5_tcp_outbound_relay_smoke_config(socks5_port: u16) -> String {
    format!(
        r#"
proxies:
  - name: {SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_OUTBOUND}
    type: socks5
    server: 127.0.0.1
    port: {socks5_port}
    username: {SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_USERNAME}
    password: {SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_PASSWORD}
"#
    )
}

fn finalize_socks5_tcp_outbound_relay_smoke_report(
    cases: Vec<TcpRelaySmokeCaseReport>,
    selected_outbound: Option<String>,
    request_payload_bytes: usize,
    response_payload_bytes: Option<usize>,
    round_trip_observed: bool,
    server_received_payload: bool,
    metrics_recorded: bool,
    metrics_total_connections: u64,
    metrics_success_count: u64,
    metrics_inbound_count: u64,
    metrics_outbound_route_count: u64,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> TcpRelaySmokeReport {
    let failed = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect::<Vec<_>>();
    let passed = failed.is_empty()
        && selected_outbound.as_deref() == Some(SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_OUTBOUND)
        && round_trip_observed
        && server_received_payload
        && metrics_recorded
        && clean_stop_observed;
    let target = socks5_tcp_outbound_relay_smoke_target();
    let detail = format!(
        "cases={} passed={} failed={} failed_cases={} selected={} target={} request_bytes={} response_bytes={} round_trip_observed={} server_received_payload={} metrics_recorded={} metrics_total={} metrics_success={} metrics_inbound_socks5={} metrics_outbound_route={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
        cases.len(),
        passed,
        failed.len(),
        if failed.is_empty() {
            "-".to_string()
        } else {
            failed.join(",")
        },
        selected_outbound.as_deref().unwrap_or("-"),
        target,
        request_payload_bytes,
        response_payload_bytes
            .map(|bytes| bytes.to_string())
            .unwrap_or_else(|| "-".to_string()),
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining
            .map(|workers| workers.to_string())
            .unwrap_or_else(|| "-".to_string()),
        stop_timed_out
            .map(|timed_out| timed_out.to_string())
            .unwrap_or_else(|| "-".to_string())
    );
    TcpRelaySmokeReport {
        passed,
        detail,
        selected_outbound,
        target,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

fn socks5_tcp_outbound_relay_smoke_start_case(
    status: &ManagedMixedStatusSnapshot,
) -> TcpRelaySmokeCaseReport {
    let selected = status.selected_outbound.clone();
    let passed = selected.as_deref() == Some(SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_OUTBOUND)
        && status.generation == 1
        && matches!(&status.status, RuntimeStatus::Running { .. });
    TcpRelaySmokeCaseReport {
        name: "start-socks5-tcp-outbound-relay-runtime",
        action: "start",
        expected_selected_outbound: Some(SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: selected,
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        target: socks5_tcp_outbound_relay_smoke_target(),
        expected_response: None,
        observed_response: None,
        request_payload_bytes: None,
        response_payload_bytes: None,
        runtime_running: Some(matches!(&status.status, RuntimeStatus::Running { .. })),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error: None,
    }
}

fn socks5_tcp_outbound_relay_smoke_exchange_case(
    exchange_result: Result<TcpRelaySmokeExchangeObservation, String>,
    server_result: Result<TcpRelaySmokeServerObservation, String>,
    round_trip_observed: bool,
    server_received_payload: bool,
) -> TcpRelaySmokeCaseReport {
    let error = match (&exchange_result, &server_result) {
        (Ok(_), Ok(_)) => None,
        (Err(exchange), Ok(_)) => Some(exchange.clone()),
        (Ok(_), Err(server)) => Some(server.clone()),
        (Err(exchange), Err(server)) => Some(format!("{exchange}; {server}")),
    };
    let exchange = exchange_result.ok();
    let passed = error.is_none() && round_trip_observed && server_received_payload;
    TcpRelaySmokeCaseReport {
        name: "socks5-tcp-outbound-protocol-round-trip",
        action: "socks5-connect",
        expected_selected_outbound: Some(SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: socks5_tcp_outbound_relay_smoke_target(),
        expected_response: Some(
            String::from_utf8_lossy(SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_RESPONSE).to_string(),
        ),
        observed_response: exchange
            .as_ref()
            .map(|exchange| String::from_utf8_lossy(&exchange.response_payload).to_string()),
        request_payload_bytes: Some(SOCKS5_TCP_OUTBOUND_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: exchange
            .as_ref()
            .map(|exchange| exchange.response_payload.len()),
        runtime_running: None,
        round_trip_observed: Some(round_trip_observed),
        server_received_payload: Some(server_received_payload),
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error,
    }
}

