fn run_trojan_ws_tcp_relay_smoke_exchange(
    listen_addr: SocketAddr,
) -> Result<TcpRelaySmokeExchangeObservation, String> {
    let mut client = TcpStream::connect(listen_addr)
        .map_err(|error| format!("connect Trojan WS TCP smoke listener {listen_addr}: {error}"))?;
    client
        .set_read_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Trojan WS TCP smoke client read timeout: {error}"))?;
    client
        .set_write_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Trojan WS TCP smoke client write timeout: {error}"))?;
    let target = OutboundTarget::new(
        TROJAN_WS_TCP_RELAY_SMOKE_TARGET_HOST,
        TROJAN_WS_TCP_RELAY_SMOKE_TARGET_PORT,
    );
    write_smoke_connect(&mut client, &target, SmokeInboundKind::Socks5)?;
    client
        .write_all(TROJAN_WS_TCP_RELAY_SMOKE_PAYLOAD)
        .map_err(|error| format!("write Trojan WS TCP smoke payload: {error}"))?;
    let mut response = vec![0; TROJAN_WS_TCP_RELAY_SMOKE_RESPONSE.len()];
    client
        .read_exact(&mut response)
        .map_err(|error| format!("read Trojan WS TCP smoke response: {error}"))?;
    client.shutdown(Shutdown::Both).ok();
    Ok(TcpRelaySmokeExchangeObservation {
        response_payload: response,
    })
}

fn spawn_trojan_ws_tcp_relay_smoke_server() -> Result<
    (
        u16,
        thread::JoinHandle<Result<TcpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind Trojan WS TCP smoke server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set Trojan WS TCP smoke accept mode: {error}"))?;
    let listen_port = listener
        .local_addr()
        .map_err(|error| format!("read Trojan WS TCP smoke address: {error}"))?
        .port();
    let handle = thread::spawn(move || -> Result<TcpRelaySmokeServerObservation, String> {
        let deadline = Instant::now() + TCP_RELAY_SMOKE_TIMEOUT;
        let (mut stream, _) = loop {
            match listener.accept() {
                Ok(accepted) => break accepted,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err("Trojan WS TCP smoke accept timed out".to_string());
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => return Err(format!("accept Trojan WS TCP smoke server: {error}")),
            }
        };
        stream
            .set_nonblocking(false)
            .map_err(|error| format!("set Trojan WS TCP smoke stream blocking mode: {error}"))?;
        stream
            .set_read_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set Trojan WS TCP smoke read timeout: {error}"))?;
        stream
            .set_write_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set Trojan WS TCP smoke write timeout: {error}"))?;

        let request = read_websocket_smoke_http_request(&mut stream, "Trojan WS TCP smoke")?;
        validate_trojan_ws_tcp_relay_smoke_handshake(&request, &mut stream)?;

        let expected_header = encode_trojan_tcp_request_header(
            TROJAN_WS_TCP_RELAY_SMOKE_PASSWORD,
            &Endpoint::new(
                TROJAN_WS_TCP_RELAY_SMOKE_TARGET_HOST,
                TROJAN_WS_TCP_RELAY_SMOKE_TARGET_PORT,
            ),
        )
        .map_err(|error| format!("encode expected Trojan WS TCP smoke header: {error}"))?;
        let observed_header =
            read_websocket_smoke_binary_frame(&mut stream, "Trojan WS TCP smoke header")?;
        if observed_header != expected_header {
            return Err(format!(
                "unexpected Trojan WS TCP smoke header: expected {:?}, got {:?}",
                expected_header, observed_header
            ));
        }

        let payload =
            read_websocket_smoke_binary_frame(&mut stream, "Trojan WS TCP smoke payload")?;
        if payload != TROJAN_WS_TCP_RELAY_SMOKE_PAYLOAD {
            return Err(format!(
                "unexpected Trojan WS TCP smoke payload: expected {:?}, got {:?}",
                TROJAN_WS_TCP_RELAY_SMOKE_PAYLOAD, payload
            ));
        }

        write_websocket_smoke_binary_frame(
            &mut stream,
            TROJAN_WS_TCP_RELAY_SMOKE_RESPONSE,
            "Trojan WS TCP smoke response payload",
        )?;
        stream
            .flush()
            .map_err(|error| format!("flush Trojan WS TCP smoke response: {error}"))?;
        tcp_relay_smoke_wait_for_client_close(&mut stream);
        Ok(TcpRelaySmokeServerObservation {
            received_expected_payload: true,
        })
    });
    Ok((listen_port, handle))
}

fn validate_trojan_ws_tcp_relay_smoke_handshake(
    request: &str,
    stream: &mut TcpStream,
) -> Result<(), String> {
    let request_line = request.lines().next().unwrap_or_default();
    let expected_request_line = format!("GET {} HTTP/1.1", TROJAN_WS_TCP_RELAY_SMOKE_PATH);
    if request_line != expected_request_line {
        return Err(format!(
            "unexpected Trojan WS TCP smoke request line: expected {expected_request_line}, got {request_line}"
        ));
    }
    let host = http_header_value(request, "Host")
        .ok_or_else(|| "Trojan WS TCP smoke request missing Host header".to_string())?;
    if host != TROJAN_WS_TCP_RELAY_SMOKE_HOST {
        return Err(format!(
            "unexpected Trojan WS TCP smoke Host: expected {}, got {host}",
            TROJAN_WS_TCP_RELAY_SMOKE_HOST
        ));
    }
    let upgrade = http_header_value(request, "Upgrade")
        .ok_or_else(|| "Trojan WS TCP smoke request missing Upgrade header".to_string())?;
    if !upgrade.eq_ignore_ascii_case("websocket") {
        return Err(format!(
            "unexpected Trojan WS TCP smoke Upgrade: expected websocket, got {upgrade}"
        ));
    }
    let connection = http_header_value(request, "Connection")
        .ok_or_else(|| "Trojan WS TCP smoke request missing Connection header".to_string())?;
    if !connection
        .split(',')
        .any(|item| item.trim().eq_ignore_ascii_case("upgrade"))
    {
        return Err(format!(
            "unexpected Trojan WS TCP smoke Connection: expected Upgrade, got {connection}"
        ));
    }
    let version = http_header_value(request, "Sec-WebSocket-Version")
        .ok_or_else(|| "Trojan WS TCP smoke request missing Sec-WebSocket-Version".to_string())?;
    if version != "13" {
        return Err(format!(
            "unexpected Trojan WS TCP smoke version: expected 13, got {version}"
        ));
    }
    let key = http_header_value(request, "Sec-WebSocket-Key")
        .ok_or_else(|| "Trojan WS TCP smoke request missing Sec-WebSocket-Key".to_string())?;
    let accept = websocket_accept_for_key(&key);
    let response = format!(
        "HTTP/1.1 101 Switching Protocols\r\nUpgrade: websocket\r\nConnection: Upgrade\r\nSec-WebSocket-Accept: {accept}\r\n\r\n"
    );
    stream
        .write_all(response.as_bytes())
        .map_err(|error| format!("write Trojan WS TCP smoke handshake response: {error}"))
}

fn trojan_ws_tcp_relay_smoke_metrics_recorded(metrics: &ConnectionMetricsSnapshot) -> bool {
    metrics.total_connection_count >= 1
        && metrics.success_count >= 1
        && udp_relay_smoke_inbound_count(metrics, "socks5") >= 1
        && trojan_ws_tcp_relay_smoke_outbound_route_count(metrics) >= 1
        && metrics.total_upload_bytes >= TROJAN_WS_TCP_RELAY_SMOKE_PAYLOAD.len() as u64
        && metrics.total_download_bytes >= TROJAN_WS_TCP_RELAY_SMOKE_RESPONSE.len() as u64
}

fn trojan_ws_tcp_relay_smoke_outbound_route_count(metrics: &ConnectionMetricsSnapshot) -> u64 {
    metrics
        .route_action_counts
        .iter()
        .find(|entry| {
            entry.route_action
                == RouteAction::Outbound(TROJAN_WS_TCP_RELAY_SMOKE_OUTBOUND.to_string())
        })
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn trojan_ws_tcp_relay_smoke_target() -> String {
    format!(
        "{}:{}",
        TROJAN_WS_TCP_RELAY_SMOKE_TARGET_HOST, TROJAN_WS_TCP_RELAY_SMOKE_TARGET_PORT
    )
}

#[cfg(test)]
mod trojan_ws_tcp_relay_smoke_tests {
    use super::*;

    #[test]
    fn default_trojan_ws_tcp_relay_smoke_proves_websocket_trojan_round_trip() {
        let report = collect_default_trojan_ws_tcp_relay_smoke_report();

        assert!(report.passed, "{report:#?}");
        assert_eq!(
            report.selected_outbound.as_deref(),
            Some(TROJAN_WS_TCP_RELAY_SMOKE_OUTBOUND)
        );
        assert_eq!(report.target, trojan_ws_tcp_relay_smoke_target());
        assert_eq!(
            report.request_payload_bytes,
            TROJAN_WS_TCP_RELAY_SMOKE_PAYLOAD.len()
        );
        assert_eq!(
            report.response_payload_bytes,
            Some(TROJAN_WS_TCP_RELAY_SMOKE_RESPONSE.len())
        );
        assert!(report.round_trip_observed);
        assert!(report.server_received_payload);
        assert!(report.metrics_recorded);
        assert!(report.metrics_total_connections >= 1);
        assert!(report.metrics_success_count >= 1);
        assert!(report.metrics_inbound_count >= 1);
        assert!(report.metrics_outbound_route_count >= 1);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));

        let case_names = report
            .cases
            .iter()
            .map(|case| case.name)
            .collect::<Vec<_>>();
        for expected in [
            "start-trojan-ws-tcp-relay-runtime",
            "trojan-ws-tcp-protocol-round-trip",
            "record-trojan-ws-tcp-relay-metrics",
            "stop-trojan-ws-tcp-relay-runtime",
        ] {
            assert!(
                case_names.contains(&expected),
                "missing Trojan WS TCP relay smoke case {expected}: {case_names:?}"
            );
        }
        let round_trip = report
            .cases
            .iter()
            .find(|case| case.name == "trojan-ws-tcp-protocol-round-trip")
            .expect("round trip case");
        assert_eq!(
            round_trip.observed_response.as_deref(),
            Some("keli-trojan-ws-pong")
        );
        assert_eq!(round_trip.round_trip_observed, Some(true));
        assert_eq!(round_trip.server_received_payload, Some(true));
    }
}

fn collect_default_trojan_httpupgrade_tcp_relay_smoke_report() -> TcpRelaySmokeReport {
    let mut cases = Vec::new();
    let mut selected_outbound = None;
    let request_payload_bytes = TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD.len();
    let mut response_payload_bytes = None;
    let mut round_trip_observed = false;
    let mut server_received_payload = false;
    let mut metrics_recorded = false;
    let mut metrics_total_connections = 0;
    let mut metrics_success_count = 0;
    let mut metrics_inbound_count = 0;
    let mut metrics_outbound_route_count = 0;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let (trojan_port, trojan_thread) = match spawn_trojan_httpupgrade_tcp_relay_smoke_server() {
        Ok(server) => server,
        Err(error) => {
            cases.push(trojan_httpupgrade_tcp_relay_smoke_error_case(
                "start-trojan-httpupgrade-tcp-server",
                "start-protocol-server",
                error,
            ));
            return finalize_trojan_httpupgrade_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };

    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let config = trojan_httpupgrade_tcp_relay_smoke_config(trojan_port);
    let relay_options = RelayOptions {
        first_byte_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
        idle_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
    };

    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
            relay_options,
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(trojan_httpupgrade_tcp_relay_smoke_error_case(
                "start-trojan-httpupgrade-tcp-relay-runtime",
                "start",
                error,
            ));
            let _ = join_tcp_relay_smoke_server(trojan_thread);
            return finalize_trojan_httpupgrade_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    selected_outbound = started.selected_outbound.clone();
    cases.push(trojan_httpupgrade_tcp_relay_smoke_start_case(&started));

    if let Some(listen_addr) = started.listen_addr {
        let exchange_result = run_trojan_httpupgrade_tcp_relay_smoke_exchange(listen_addr);
        let server_result = join_tcp_relay_smoke_server(trojan_thread);
        if let Ok(exchange) = exchange_result.as_ref() {
            response_payload_bytes = Some(exchange.response_payload.len());
            round_trip_observed =
                exchange.response_payload == TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE;
        }
        if let Ok(server) = server_result.as_ref() {
            server_received_payload = server.received_expected_payload;
        }
        cases.push(trojan_httpupgrade_tcp_relay_smoke_exchange_case(
            exchange_result,
            server_result,
            round_trip_observed,
            server_received_payload,
        ));

        let status = wait_for_udp_relay_smoke_status(&core, |status| {
            trojan_httpupgrade_tcp_relay_smoke_metrics_recorded(&status.connection_metrics)
        });
        metrics_total_connections = status.connection_metrics.total_connection_count;
        metrics_success_count = status.connection_metrics.success_count;
        metrics_inbound_count = udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5");
        metrics_outbound_route_count =
            trojan_httpupgrade_tcp_relay_smoke_outbound_route_count(&status.connection_metrics);
        metrics_recorded =
            trojan_httpupgrade_tcp_relay_smoke_metrics_recorded(&status.connection_metrics);
        cases.push(trojan_httpupgrade_tcp_relay_smoke_metrics_case(
            &status,
            metrics_recorded,
        ));
    } else {
        cases.push(trojan_httpupgrade_tcp_relay_smoke_error_case(
            "trojan-httpupgrade-tcp-relay-round-trip",
            "socks5-connect",
            "managed mixed runtime did not expose a listen address".to_string(),
        ));
        let _ = join_tcp_relay_smoke_server(trojan_thread);
    }

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(trojan_httpupgrade_tcp_relay_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(trojan_httpupgrade_tcp_relay_smoke_stop_case(
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
            Some(error),
        )),
    }

    finalize_trojan_httpupgrade_tcp_relay_smoke_report(
        cases,
        selected_outbound,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn trojan_httpupgrade_tcp_relay_smoke_config(trojan_port: u16) -> String {
    format!(
        r#"
proxies:
  - name: {TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND}
    type: trojan
    server: 127.0.0.1
    port: {trojan_port}
    password: {TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PASSWORD}
    tls: false
    network: httpupgrade
    httpupgrade-opts:
      path: {TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PATH}
      host: {TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_HOST}
"#
    )
}

fn finalize_trojan_httpupgrade_tcp_relay_smoke_report(
    cases: Vec<TcpRelaySmokeCaseReport>,
    selected_outbound: Option<String>,
    request_payload_bytes: usize,
    response_payload_bytes: Option<usize>,
    round_trip_observed: bool,
    server_received_payload: bool,
    metrics_recorded: bool,
    metrics_total_connections: u64,
    metrics_success_count: u64,
    metrics_inbound_count: u64,
    metrics_outbound_route_count: u64,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> TcpRelaySmokeReport {
    let failed = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect::<Vec<_>>();
    let passed = failed.is_empty()
        && selected_outbound.as_deref() == Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND)
        && round_trip_observed
        && server_received_payload
        && metrics_recorded
        && clean_stop_observed;
    let target = trojan_httpupgrade_tcp_relay_smoke_target();
    let detail = format!(
        "cases={} passed={} failed={} failed_cases={} selected={} transport=httpupgrade host={} path={} target={} request_bytes={} response_bytes={} round_trip_observed={} server_received_payload={} metrics_recorded={} metrics_total={} metrics_success={} metrics_inbound_socks5={} metrics_outbound_route={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
        cases.len(),
        passed,
        failed.len(),
        if failed.is_empty() {
            "-".to_string()
        } else {
            failed.join(",")
        },
        selected_outbound.as_deref().unwrap_or("-"),
        TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_HOST,
        TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PATH,
        target,
        request_payload_bytes,
        response_payload_bytes
            .map(|bytes| bytes.to_string())
            .unwrap_or_else(|| "-".to_string()),
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining
            .map(|workers| workers.to_string())
            .unwrap_or_else(|| "-".to_string()),
        stop_timed_out
            .map(|timed_out| timed_out.to_string())
            .unwrap_or_else(|| "-".to_string())
    );
    TcpRelaySmokeReport {
        passed,
        detail,
        selected_outbound,
        target,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

fn trojan_httpupgrade_tcp_relay_smoke_start_case(
    status: &ManagedMixedStatusSnapshot,
) -> TcpRelaySmokeCaseReport {
    let selected = status.selected_outbound.clone();
    let passed = selected.as_deref() == Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND)
        && status.generation == 1
        && matches!(&status.status, RuntimeStatus::Running { .. });
    TcpRelaySmokeCaseReport {
        name: "start-trojan-httpupgrade-tcp-relay-runtime",
        action: "start",
        expected_selected_outbound: Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: selected,
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        target: trojan_httpupgrade_tcp_relay_smoke_target(),
        expected_response: None,
        observed_response: None,
        request_payload_bytes: None,
        response_payload_bytes: None,
        runtime_running: Some(matches!(&status.status, RuntimeStatus::Running { .. })),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error: None,
    }
}

fn trojan_httpupgrade_tcp_relay_smoke_exchange_case(
    exchange_result: Result<TcpRelaySmokeExchangeObservation, String>,
    server_result: Result<TcpRelaySmokeServerObservation, String>,
    round_trip_observed: bool,
    server_received_payload: bool,
) -> TcpRelaySmokeCaseReport {
    let error = match (&exchange_result, &server_result) {
        (Ok(_), Ok(_)) => None,
        (Err(exchange), Ok(_)) => Some(exchange.clone()),
        (Ok(_), Err(server)) => Some(server.clone()),
        (Err(exchange), Err(server)) => Some(format!("{exchange}; {server}")),
    };
    let exchange = exchange_result.ok();
    let passed = error.is_none() && round_trip_observed && server_received_payload;
    TcpRelaySmokeCaseReport {
        name: "trojan-httpupgrade-tcp-protocol-round-trip",
        action: "socks5-connect",
        expected_selected_outbound: Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: trojan_httpupgrade_tcp_relay_smoke_target(),
        expected_response: Some(
            String::from_utf8_lossy(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE).to_string(),
        ),
        observed_response: exchange
            .as_ref()
            .map(|exchange| String::from_utf8_lossy(&exchange.response_payload).to_string()),
        request_payload_bytes: Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: exchange
            .as_ref()
            .map(|exchange| exchange.response_payload.len()),
        runtime_running: None,
        round_trip_observed: Some(round_trip_observed),
        server_received_payload: Some(server_received_payload),
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error,
    }
}

fn trojan_httpupgrade_tcp_relay_smoke_metrics_case(
    status: &ManagedMixedStatusSnapshot,
    metrics_recorded: bool,
) -> TcpRelaySmokeCaseReport {
    let metrics = &status.connection_metrics;
    let inbound_count = udp_relay_smoke_inbound_count(metrics, "socks5");
    let outbound_route_count = trojan_httpupgrade_tcp_relay_smoke_outbound_route_count(metrics);
    TcpRelaySmokeCaseReport {
        name: "record-trojan-httpupgrade-tcp-relay-metrics",
        action: "status",
        expected_selected_outbound: Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: status.selected_outbound.clone(),
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        target: trojan_httpupgrade_tcp_relay_smoke_target(),
        expected_response: None,
        observed_response: None,
        request_payload_bytes: Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE.len()),
        runtime_running: Some(matches!(&status.status, RuntimeStatus::Running { .. })),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: Some(metrics_recorded),
        metrics_total_connections: Some(metrics.total_connection_count),
        metrics_success_count: Some(metrics.success_count),
        metrics_inbound_count: Some(inbound_count),
        metrics_outbound_route_count: Some(outbound_route_count),
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed: metrics_recorded,
        error: None,
    }
}

fn trojan_httpupgrade_tcp_relay_smoke_stop_case(
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
    error: Option<String>,
) -> TcpRelaySmokeCaseReport {
    TcpRelaySmokeCaseReport {
        name: "stop-trojan-httpupgrade-tcp-relay-runtime",
        action: "stop",
        expected_selected_outbound: None,
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: trojan_httpupgrade_tcp_relay_smoke_target(),
        expected_response: None,
        observed_response: None,
        request_payload_bytes: None,
        response_payload_bytes: None,
        runtime_running: Some(false),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: Some(clean_stop_observed),
        stop_workers_remaining,
        stop_timed_out,
        passed: clean_stop_observed && error.is_none(),
        error,
    }
}

fn trojan_httpupgrade_tcp_relay_smoke_error_case(
    name: &'static str,
    action: &'static str,
    error: String,
) -> TcpRelaySmokeCaseReport {
    TcpRelaySmokeCaseReport {
        name,
        action,
        expected_selected_outbound: Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: trojan_httpupgrade_tcp_relay_smoke_target(),
        expected_response: Some(
            String::from_utf8_lossy(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE).to_string(),
        ),
        observed_response: None,
        request_payload_bytes: Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: None,
        runtime_running: None,
        round_trip_observed: Some(false),
        server_received_payload: Some(false),
        metrics_recorded: Some(false),
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed: false,
        error: Some(error),
    }
}

fn run_trojan_httpupgrade_tcp_relay_smoke_exchange(
    listen_addr: SocketAddr,
) -> Result<TcpRelaySmokeExchangeObservation, String> {
    let mut client = TcpStream::connect(listen_addr).map_err(|error| {
        format!("connect Trojan HTTPUpgrade TCP smoke listener {listen_addr}: {error}")
    })?;
    client
        .set_read_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| {
            format!("set Trojan HTTPUpgrade TCP smoke client read timeout: {error}")
        })?;
    client
        .set_write_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| {
            format!("set Trojan HTTPUpgrade TCP smoke client write timeout: {error}")
        })?;
    let target = OutboundTarget::new(
        TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_HOST,
        TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_PORT,
    );
    write_smoke_connect(&mut client, &target, SmokeInboundKind::Socks5)?;
    client
        .write_all(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD)
        .map_err(|error| format!("write Trojan HTTPUpgrade TCP smoke payload: {error}"))?;
    let mut response = vec![0; TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE.len()];
    client
        .read_exact(&mut response)
        .map_err(|error| format!("read Trojan HTTPUpgrade TCP smoke response: {error}"))?;
    client.shutdown(Shutdown::Both).ok();
    Ok(TcpRelaySmokeExchangeObservation {
        response_payload: response,
    })
}

fn spawn_trojan_httpupgrade_tcp_relay_smoke_server() -> Result<
    (
        u16,
        thread::JoinHandle<Result<TcpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind Trojan HTTPUpgrade TCP smoke server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set Trojan HTTPUpgrade TCP smoke accept mode: {error}"))?;
    let listen_port = listener
        .local_addr()
        .map_err(|error| format!("read Trojan HTTPUpgrade TCP smoke address: {error}"))?
        .port();
    let handle = thread::spawn(move || -> Result<TcpRelaySmokeServerObservation, String> {
        let deadline = Instant::now() + TCP_RELAY_SMOKE_TIMEOUT;
        let (mut stream, _) = loop {
            match listener.accept() {
                Ok(accepted) => break accepted,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err("Trojan HTTPUpgrade TCP smoke accept timed out".to_string());
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => {
                    return Err(format!(
                        "accept Trojan HTTPUpgrade TCP smoke server: {error}"
                    ))
                }
            }
        };
        stream.set_nonblocking(false).map_err(|error| {
            format!("set Trojan HTTPUpgrade TCP smoke stream blocking mode: {error}")
        })?;
        stream
            .set_read_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set Trojan HTTPUpgrade TCP smoke read timeout: {error}"))?;
        stream
            .set_write_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set Trojan HTTPUpgrade TCP smoke write timeout: {error}"))?;

        let request =
            read_websocket_smoke_http_request(&mut stream, "Trojan HTTPUpgrade TCP smoke")?;
        validate_trojan_httpupgrade_tcp_relay_smoke_handshake(&request, &mut stream)?;

        let expected_header = encode_trojan_tcp_request_header(
            TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PASSWORD,
            &Endpoint::new(
                TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_HOST,
                TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_PORT,
            ),
        )
        .map_err(|error| format!("encode expected Trojan HTTPUpgrade TCP smoke header: {error}"))?;
        let mut observed_header = vec![0; expected_header.len()];
        stream.read_exact(&mut observed_header).map_err(|error| {
            format!("read Trojan HTTPUpgrade TCP smoke request header: {error}")
        })?;
        if observed_header != expected_header {
            return Err(format!(
                "unexpected Trojan HTTPUpgrade TCP smoke header: expected {:?}, got {:?}",
                expected_header, observed_header
            ));
        }

        let mut payload = vec![0; TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD.len()];
        stream
            .read_exact(&mut payload)
            .map_err(|error| format!("read Trojan HTTPUpgrade TCP smoke payload: {error}"))?;
        if payload != TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD {
            return Err(format!(
                "unexpected Trojan HTTPUpgrade TCP smoke payload: expected {:?}, got {:?}",
                TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD, payload
            ));
        }

        stream
            .write_all(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE)
            .map_err(|error| {
                format!("write Trojan HTTPUpgrade TCP smoke response payload: {error}")
            })?;
        stream
            .flush()
            .map_err(|error| format!("flush Trojan HTTPUpgrade TCP smoke response: {error}"))?;
        Ok(TcpRelaySmokeServerObservation {
            received_expected_payload: true,
        })
    });
    Ok((listen_port, handle))
}

fn validate_trojan_httpupgrade_tcp_relay_smoke_handshake(
    request: &str,
    stream: &mut TcpStream,
) -> Result<(), String> {
    let request_line = request.lines().next().unwrap_or_default();
    let expected_request_line = format!("GET {} HTTP/1.1", TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PATH);
    if request_line != expected_request_line {
        return Err(format!(
            "unexpected Trojan HTTPUpgrade TCP smoke request line: expected {expected_request_line}, got {request_line}"
        ));
    }
    let host = http_header_value(request, "Host")
        .ok_or_else(|| "Trojan HTTPUpgrade TCP smoke request missing Host header".to_string())?;
    if host != TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_HOST {
        return Err(format!(
            "unexpected Trojan HTTPUpgrade TCP smoke Host: expected {}, got {host}",
            TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_HOST
        ));
    }
    let upgrade = http_header_value(request, "Upgrade")
        .ok_or_else(|| "Trojan HTTPUpgrade TCP smoke request missing Upgrade header".to_string())?;
    if !upgrade.eq_ignore_ascii_case("websocket") {
        return Err(format!(
            "unexpected Trojan HTTPUpgrade TCP smoke Upgrade: expected websocket, got {upgrade}"
        ));
    }
    let connection = http_header_value(request, "Connection").ok_or_else(|| {
        "Trojan HTTPUpgrade TCP smoke request missing Connection header".to_string()
    })?;
    if !connection
        .split(',')
        .any(|item| item.trim().eq_ignore_ascii_case("upgrade"))
    {
        return Err(format!(
            "unexpected Trojan HTTPUpgrade TCP smoke Connection: expected Upgrade, got {connection}"
        ));
    }
    if http_header_value(request, "Sec-WebSocket-Key").is_some() {
        return Err("Trojan HTTPUpgrade TCP smoke unexpectedly sent Sec-WebSocket-Key".to_string());
    }
    if http_header_value(request, "Sec-WebSocket-Version").is_some() {
        return Err(
            "Trojan HTTPUpgrade TCP smoke unexpectedly sent Sec-WebSocket-Version".to_string(),
        );
    }
    stream
        .write_all(
            b"HTTP/1.1 101 Switching Protocols\r\nConnection: Upgrade\r\nUpgrade: websocket\r\n\r\n",
        )
        .map_err(|error| format!("write Trojan HTTPUpgrade TCP smoke handshake response: {error}"))
}

fn trojan_httpupgrade_tcp_relay_smoke_metrics_recorded(
    metrics: &ConnectionMetricsSnapshot,
) -> bool {
    metrics.total_connection_count >= 1
        && metrics.success_count >= 1
        && udp_relay_smoke_inbound_count(metrics, "socks5") >= 1
        && trojan_httpupgrade_tcp_relay_smoke_outbound_route_count(metrics) >= 1
        && metrics.total_upload_bytes >= TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD.len() as u64
        && metrics.total_download_bytes >= TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE.len() as u64
}

fn trojan_httpupgrade_tcp_relay_smoke_outbound_route_count(
    metrics: &ConnectionMetricsSnapshot,
) -> u64 {
    metrics
        .route_action_counts
        .iter()
        .find(|entry| {
            entry.route_action
                == RouteAction::Outbound(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND.to_string())
        })
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn trojan_httpupgrade_tcp_relay_smoke_target() -> String {
    format!(
        "{}:{}",
        TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_HOST,
        TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_PORT
    )
}

#[cfg(test)]
mod trojan_httpupgrade_tcp_relay_smoke_tests {
    use super::*;

    #[test]
    fn default_trojan_httpupgrade_tcp_relay_smoke_proves_upgraded_trojan_round_trip() {
        let report = collect_default_trojan_httpupgrade_tcp_relay_smoke_report();

        assert!(report.passed, "{report:#?}");
        assert_eq!(
            report.selected_outbound.as_deref(),
            Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND)
        );
        assert_eq!(report.target, trojan_httpupgrade_tcp_relay_smoke_target());
        assert_eq!(
            report.request_payload_bytes,
            TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD.len()
        );
        assert_eq!(
            report.response_payload_bytes,
            Some(TROJAN_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE.len())
        );
        assert!(report.round_trip_observed);
        assert!(report.server_received_payload);
        assert!(report.metrics_recorded);
        assert!(report.metrics_total_connections >= 1);
        assert!(report.metrics_success_count >= 1);
        assert!(report.metrics_inbound_count >= 1);
        assert!(report.metrics_outbound_route_count >= 1);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));

        let case_names = report
            .cases
            .iter()
            .map(|case| case.name)
            .collect::<Vec<_>>();
        for expected in [
            "start-trojan-httpupgrade-tcp-relay-runtime",
            "trojan-httpupgrade-tcp-protocol-round-trip",
            "record-trojan-httpupgrade-tcp-relay-metrics",
            "stop-trojan-httpupgrade-tcp-relay-runtime",
        ] {
            assert!(
                case_names.contains(&expected),
                "missing Trojan HTTPUpgrade TCP relay smoke case {expected}: {case_names:?}"
            );
        }
        let round_trip = report
            .cases
            .iter()
            .find(|case| case.name == "trojan-httpupgrade-tcp-protocol-round-trip")
            .expect("round trip case");
        assert_eq!(
            round_trip.observed_response.as_deref(),
            Some("keli-trojan-hu-pong")
        );
        assert_eq!(round_trip.round_trip_observed, Some(true));
        assert_eq!(round_trip.server_received_payload, Some(true));
    }
}

fn collect_default_trojan_grpc_tcp_relay_smoke_report() -> TcpRelaySmokeReport {
    let mut cases = Vec::new();
    let mut selected_outbound = None;
    let request_payload_bytes = TROJAN_GRPC_TCP_RELAY_SMOKE_PAYLOAD.len();
    let mut response_payload_bytes = None;
    let mut round_trip_observed = false;
    let mut server_received_payload = false;
    let mut metrics_recorded = false;
    let mut metrics_total_connections = 0;
    let mut metrics_success_count = 0;
    let mut metrics_inbound_count = 0;
    let mut metrics_outbound_route_count = 0;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let (trojan_port, trojan_thread) = match spawn_trojan_grpc_tcp_relay_smoke_server() {
        Ok(server) => server,
        Err(error) => {
            cases.push(trojan_grpc_tcp_relay_smoke_error_case(
                "start-trojan-grpc-tcp-server",
                "start-protocol-server",
                error,
            ));
            return finalize_trojan_grpc_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };

    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let config = trojan_grpc_tcp_relay_smoke_config(trojan_port);
    let relay_options = RelayOptions {
        first_byte_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
        idle_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
    };

    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some(TROJAN_GRPC_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
            relay_options,
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(trojan_grpc_tcp_relay_smoke_error_case(
                "start-trojan-grpc-tcp-relay-runtime",
                "start",
                error,
            ));
            let _ = join_tcp_relay_smoke_server(trojan_thread);
            return finalize_trojan_grpc_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    selected_outbound = started.selected_outbound.clone();
    cases.push(trojan_grpc_tcp_relay_smoke_start_case(&started));

    if let Some(listen_addr) = started.listen_addr {
        let exchange_result = run_trojan_grpc_tcp_relay_smoke_exchange(listen_addr);
        let server_result = join_tcp_relay_smoke_server(trojan_thread);
        if let Ok(exchange) = exchange_result.as_ref() {
            response_payload_bytes = Some(exchange.response_payload.len());
            round_trip_observed = exchange.response_payload == TROJAN_GRPC_TCP_RELAY_SMOKE_RESPONSE;
        }
        if let Ok(server) = server_result.as_ref() {
            server_received_payload = server.received_expected_payload;
        }
        cases.push(trojan_grpc_tcp_relay_smoke_exchange_case(
            exchange_result,
            server_result,
            round_trip_observed,
            server_received_payload,
        ));

        let status = wait_for_udp_relay_smoke_status(&core, |status| {
            trojan_grpc_tcp_relay_smoke_metrics_recorded(&status.connection_metrics)
        });
        metrics_total_connections = status.connection_metrics.total_connection_count;
        metrics_success_count = status.connection_metrics.success_count;
        metrics_inbound_count = udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5");
        metrics_outbound_route_count =
            trojan_grpc_tcp_relay_smoke_outbound_route_count(&status.connection_metrics);
        metrics_recorded = trojan_grpc_tcp_relay_smoke_metrics_recorded(&status.connection_metrics);
        cases.push(trojan_grpc_tcp_relay_smoke_metrics_case(
            &status,
            metrics_recorded,
        ));
    } else {
        cases.push(trojan_grpc_tcp_relay_smoke_error_case(
            "trojan-grpc-tcp-relay-round-trip",
            "socks5-connect",
            "managed mixed runtime did not expose a listen address".to_string(),
        ));
        let _ = join_tcp_relay_smoke_server(trojan_thread);
    }

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(trojan_grpc_tcp_relay_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(trojan_grpc_tcp_relay_smoke_stop_case(
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
            Some(error),
        )),
    }

    finalize_trojan_grpc_tcp_relay_smoke_report(
        cases,
        selected_outbound,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn trojan_grpc_tcp_relay_smoke_config(trojan_port: u16) -> String {
    format!(
        r#"
proxies:
  - name: {TROJAN_GRPC_TCP_RELAY_SMOKE_OUTBOUND}
    type: trojan
    server: 127.0.0.1
    port: {trojan_port}
    password: {TROJAN_GRPC_TCP_RELAY_SMOKE_PASSWORD}
    tls: false
    network: grpc
    grpc-opts:
      grpc-service-name: {TROJAN_GRPC_TCP_RELAY_SMOKE_SERVICE_NAME}
"#
    )
}

fn finalize_trojan_grpc_tcp_relay_smoke_report(
    cases: Vec<TcpRelaySmokeCaseReport>,
    selected_outbound: Option<String>,
    request_payload_bytes: usize,
    response_payload_bytes: Option<usize>,
    round_trip_observed: bool,
    server_received_payload: bool,
    metrics_recorded: bool,
    metrics_total_connections: u64,
    metrics_success_count: u64,
    metrics_inbound_count: u64,
    metrics_outbound_route_count: u64,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> TcpRelaySmokeReport {
    let failed = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect::<Vec<_>>();
    let passed = failed.is_empty()
        && selected_outbound.as_deref() == Some(TROJAN_GRPC_TCP_RELAY_SMOKE_OUTBOUND)
        && round_trip_observed
        && server_received_payload
        && metrics_recorded
        && clean_stop_observed;
    let target = trojan_grpc_tcp_relay_smoke_target();
    let detail = format!(
        "cases={} passed={} failed={} failed_cases={} selected={} transport=grpc service={} target={} request_bytes={} response_bytes={} round_trip_observed={} server_received_payload={} metrics_recorded={} metrics_total={} metrics_success={} metrics_inbound_socks5={} metrics_outbound_route={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
        cases.len(),
        passed,
        failed.len(),
        if failed.is_empty() {
            "-".to_string()
        } else {
            failed.join(",")
        },
        selected_outbound.as_deref().unwrap_or("-"),
        TROJAN_GRPC_TCP_RELAY_SMOKE_SERVICE_NAME,
        target,
        request_payload_bytes,
        response_payload_bytes
            .map(|bytes| bytes.to_string())
            .unwrap_or_else(|| "-".to_string()),
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining
            .map(|workers| workers.to_string())
            .unwrap_or_else(|| "-".to_string()),
        stop_timed_out
            .map(|timed_out| timed_out.to_string())
            .unwrap_or_else(|| "-".to_string())
    );
    TcpRelaySmokeReport {
        passed,
        detail,
        selected_outbound,
        target,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

