fn run_trojan_h2_tcp_relay_smoke_exchange(
    listen_addr: SocketAddr,
) -> Result<TcpRelaySmokeExchangeObservation, String> {
    let mut client = TcpStream::connect(listen_addr)
        .map_err(|error| format!("connect Trojan H2 TCP smoke listener {listen_addr}: {error}"))?;
    client
        .set_read_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Trojan H2 TCP smoke client read timeout: {error}"))?;
    client
        .set_write_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Trojan H2 TCP smoke client write timeout: {error}"))?;
    let target = OutboundTarget::new(
        TROJAN_H2_TCP_RELAY_SMOKE_TARGET_HOST,
        TROJAN_H2_TCP_RELAY_SMOKE_TARGET_PORT,
    );
    write_smoke_connect(&mut client, &target, SmokeInboundKind::Socks5)?;
    client
        .write_all(TROJAN_H2_TCP_RELAY_SMOKE_PAYLOAD)
        .map_err(|error| format!("write Trojan H2 TCP smoke payload: {error}"))?;
    let mut response = vec![0; TROJAN_H2_TCP_RELAY_SMOKE_RESPONSE.len()];
    client
        .read_exact(&mut response)
        .map_err(|error| format!("read Trojan H2 TCP smoke response: {error}"))?;
    client.shutdown(Shutdown::Both).ok();
    Ok(TcpRelaySmokeExchangeObservation {
        response_payload: response,
    })
}

fn spawn_trojan_h2_tcp_relay_smoke_server() -> Result<
    (
        u16,
        thread::JoinHandle<Result<TcpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind Trojan H2 TCP smoke server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set Trojan H2 TCP smoke accept mode: {error}"))?;
    let listen_port = listener
        .local_addr()
        .map_err(|error| format!("read Trojan H2 TCP smoke address: {error}"))?
        .port();
    let handle = thread::spawn(move || -> Result<TcpRelaySmokeServerObservation, String> {
        let deadline = Instant::now() + TCP_RELAY_SMOKE_TIMEOUT;
        let (stream, _) = loop {
            match listener.accept() {
                Ok(accepted) => break accepted,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err("Trojan H2 TCP smoke accept timed out".to_string());
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => return Err(format!("accept Trojan H2 TCP smoke server: {error}")),
            }
        };
        stream
            .set_nonblocking(true)
            .map_err(|error| format!("set Trojan H2 TCP smoke stream nonblocking: {error}"))?;
        let runtime = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .thread_name("keli-trojan-h2-smoke-server")
            .build()
            .map_err(|error| format!("build Trojan H2 TCP smoke runtime: {error}"))?;
        runtime.block_on(async move {
            tokio::time::timeout(
                TCP_RELAY_SMOKE_TIMEOUT,
                handle_trojan_h2_tcp_relay_smoke_stream(stream),
            )
            .await
            .map_err(|_| "Trojan H2 TCP smoke server timed out".to_string())?
        })
    });
    Ok((listen_port, handle))
}

async fn handle_trojan_h2_tcp_relay_smoke_stream(
    stream: TcpStream,
) -> Result<TcpRelaySmokeServerObservation, String> {
    let stream = tokio::net::TcpStream::from_std(stream)
        .map_err(|error| format!("convert Trojan H2 TCP smoke stream: {error}"))?;
    let mut h2 = h2::server::handshake(stream)
        .await
        .map_err(|error| format!("Trojan H2 TCP smoke h2 handshake: {error}"))?;
    let (result_tx, mut result_rx) =
        tokio::sync::mpsc::unbounded_channel::<Result<TcpRelaySmokeServerObservation, String>>();
    let mut accepted = false;
    let mut accepting = true;

    loop {
        tokio::select! {
            result = result_rx.recv() => {
                return result.unwrap_or_else(|| {
                    Err("Trojan H2 TCP smoke request handler ended without a result".to_string())
                });
            }
            request = h2.accept(), if accepting => {
                let Some(request) = request else {
                    accepting = false;
                    if !accepted {
                        return Err("Trojan H2 TCP smoke h2 stream was not opened".to_string());
                    }
                    continue;
                };
                let (request, respond) = request
                    .map_err(|error| format!("accept Trojan H2 TCP smoke h2 request: {error}"))?;
                if accepted {
                    return Err("Trojan H2 TCP smoke received an unexpected second h2 request".to_string());
                }
                accepted = true;
                let result_tx = result_tx.clone();
                tokio::spawn(async move {
                    let result = serve_trojan_h2_tcp_relay_smoke_request(request, respond).await;
                    let _ = result_tx.send(result);
                });
            }
        }

        if !accepting && accepted {
            return result_rx.recv().await.unwrap_or_else(|| {
                Err("Trojan H2 TCP smoke request handler ended after connection close".to_string())
            });
        }
    }
}

async fn serve_trojan_h2_tcp_relay_smoke_request(
    request: http::Request<h2::RecvStream>,
    mut respond: h2::server::SendResponse<Bytes>,
) -> Result<TcpRelaySmokeServerObservation, String> {
    validate_trojan_h2_tcp_relay_smoke_request(&request)?;
    let mut body = request.into_body();
    let response = http::Response::builder()
        .status(http::StatusCode::OK)
        .body(())
        .map_err(|error| format!("build Trojan H2 TCP smoke h2 response: {error}"))?;
    let mut send = respond
        .send_response(response, false)
        .map_err(|error| format!("send Trojan H2 TCP smoke h2 response: {error}"))?;

    let mut buffer = Vec::new();
    let expected_header = encode_trojan_tcp_request_header(
        TROJAN_H2_TCP_RELAY_SMOKE_PASSWORD,
        &Endpoint::new(
            TROJAN_H2_TCP_RELAY_SMOKE_TARGET_HOST,
            TROJAN_H2_TCP_RELAY_SMOKE_TARGET_PORT,
        ),
    )
    .map_err(|error| format!("encode expected Trojan H2 TCP smoke header: {error}"))?;
    let observed_header = read_h2_smoke_exact(
        &mut body,
        &mut buffer,
        expected_header.len(),
        "Trojan H2 TCP smoke header",
    )
    .await?;
    if observed_header != expected_header {
        return Err(format!(
            "unexpected Trojan H2 TCP smoke header: expected {:?}, got {:?}",
            expected_header, observed_header
        ));
    }

    let payload = read_h2_smoke_exact(
        &mut body,
        &mut buffer,
        TROJAN_H2_TCP_RELAY_SMOKE_PAYLOAD.len(),
        "Trojan H2 TCP smoke payload",
    )
    .await?;
    if payload != TROJAN_H2_TCP_RELAY_SMOKE_PAYLOAD {
        return Err(format!(
            "unexpected Trojan H2 TCP smoke payload: expected {:?}, got {:?}",
            TROJAN_H2_TCP_RELAY_SMOKE_PAYLOAD, payload
        ));
    }
    send.send_data(
        Bytes::copy_from_slice(TROJAN_H2_TCP_RELAY_SMOKE_RESPONSE),
        true,
    )
    .map_err(|error| format!("send Trojan H2 TCP smoke response data: {error}"))?;
    tokio::time::sleep(Duration::from_millis(50)).await;
    Ok(TcpRelaySmokeServerObservation {
        received_expected_payload: true,
    })
}

fn validate_trojan_h2_tcp_relay_smoke_request(
    request: &http::Request<h2::RecvStream>,
) -> Result<(), String> {
    if request.method() != http::Method::PUT {
        return Err(format!(
            "unexpected Trojan H2 TCP smoke method: expected PUT, got {}",
            request.method()
        ));
    }
    if request.uri().path() != TROJAN_H2_TCP_RELAY_SMOKE_PATH {
        return Err(format!(
            "unexpected Trojan H2 TCP smoke path: expected {}, got {}",
            TROJAN_H2_TCP_RELAY_SMOKE_PATH,
            request.uri().path()
        ));
    }
    let authority = request
        .uri()
        .authority()
        .map(|authority| authority.as_str())
        .unwrap_or_default();
    if authority != TROJAN_H2_TCP_RELAY_SMOKE_HOST {
        return Err(format!(
            "unexpected Trojan H2 TCP smoke authority: expected {}, got {authority}",
            TROJAN_H2_TCP_RELAY_SMOKE_HOST
        ));
    }
    let scheme = request.uri().scheme_str().unwrap_or_default();
    if scheme != "http" {
        return Err(format!(
            "unexpected Trojan H2 TCP smoke scheme: expected http, got {scheme}"
        ));
    }
    Ok(())
}

async fn read_h2_smoke_exact(
    body: &mut h2::RecvStream,
    buffer: &mut Vec<u8>,
    len: usize,
    label: &str,
) -> Result<Vec<u8>, String> {
    while buffer.len() < len {
        let Some(chunk) = body.data().await else {
            return Err(format!(
                "read {label}: h2 stream ended with {}/{} bytes buffered",
                buffer.len(),
                len
            ));
        };
        let chunk = chunk.map_err(|error| format!("read {label} h2 data: {error}"))?;
        let chunk_len = chunk.len();
        buffer.extend_from_slice(&chunk);
        body.flow_control()
            .release_capacity(chunk_len)
            .map_err(|error| format!("release {label} h2 capacity: {error}"))?;
    }
    Ok(buffer.drain(..len).collect())
}

fn trojan_h2_tcp_relay_smoke_metrics_recorded(metrics: &ConnectionMetricsSnapshot) -> bool {
    metrics.total_connection_count >= 1
        && metrics.success_count >= 1
        && udp_relay_smoke_inbound_count(metrics, "socks5") >= 1
        && trojan_h2_tcp_relay_smoke_outbound_route_count(metrics) >= 1
        && metrics.total_upload_bytes >= TROJAN_H2_TCP_RELAY_SMOKE_PAYLOAD.len() as u64
        && metrics.total_download_bytes >= TROJAN_H2_TCP_RELAY_SMOKE_RESPONSE.len() as u64
}

fn trojan_h2_tcp_relay_smoke_outbound_route_count(metrics: &ConnectionMetricsSnapshot) -> u64 {
    metrics
        .route_action_counts
        .iter()
        .find(|entry| {
            entry.route_action
                == RouteAction::Outbound(TROJAN_H2_TCP_RELAY_SMOKE_OUTBOUND.to_string())
        })
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn trojan_h2_tcp_relay_smoke_target() -> String {
    format!(
        "{}:{}",
        TROJAN_H2_TCP_RELAY_SMOKE_TARGET_HOST, TROJAN_H2_TCP_RELAY_SMOKE_TARGET_PORT
    )
}

#[cfg(test)]
mod trojan_h2_tcp_relay_smoke_tests {
    use super::*;

    #[test]
    fn default_trojan_h2_tcp_relay_smoke_proves_h2_trojan_round_trip() {
        let report = collect_default_trojan_h2_tcp_relay_smoke_report();

        assert!(report.passed, "{report:#?}");
        assert_eq!(
            report.selected_outbound.as_deref(),
            Some(TROJAN_H2_TCP_RELAY_SMOKE_OUTBOUND)
        );
        assert_eq!(report.target, trojan_h2_tcp_relay_smoke_target());
        assert_eq!(
            report.request_payload_bytes,
            TROJAN_H2_TCP_RELAY_SMOKE_PAYLOAD.len()
        );
        assert_eq!(
            report.response_payload_bytes,
            Some(TROJAN_H2_TCP_RELAY_SMOKE_RESPONSE.len())
        );
        assert!(report.round_trip_observed);
        assert!(report.server_received_payload);
        assert!(report.metrics_recorded);
        assert!(report.metrics_total_connections >= 1);
        assert!(report.metrics_success_count >= 1);
        assert!(report.metrics_inbound_count >= 1);
        assert!(report.metrics_outbound_route_count >= 1);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));

        let case_names = report
            .cases
            .iter()
            .map(|case| case.name)
            .collect::<Vec<_>>();
        for expected in [
            "start-trojan-h2-tcp-relay-runtime",
            "trojan-h2-tcp-protocol-round-trip",
            "record-trojan-h2-tcp-relay-metrics",
            "stop-trojan-h2-tcp-relay-runtime",
        ] {
            assert!(
                case_names.contains(&expected),
                "missing Trojan H2 TCP relay smoke case {expected}: {case_names:?}"
            );
        }
        let round_trip = report
            .cases
            .iter()
            .find(|case| case.name == "trojan-h2-tcp-protocol-round-trip")
            .expect("round trip case");
        assert_eq!(
            round_trip.observed_response.as_deref(),
            Some("keli-trojan-h2-pong")
        );
        assert_eq!(round_trip.round_trip_observed, Some(true));
        assert_eq!(round_trip.server_received_payload, Some(true));
    }
}

fn collect_default_trojan_quic_tcp_relay_smoke_report() -> TcpRelaySmokeReport {
    let mut cases = Vec::new();
    let mut selected_outbound = None;
    let request_payload_bytes = TROJAN_QUIC_TCP_RELAY_SMOKE_PAYLOAD.len();
    let mut response_payload_bytes = None;
    let mut round_trip_observed = false;
    let mut server_received_payload = false;
    let mut metrics_recorded = false;
    let mut metrics_total_connections = 0;
    let mut metrics_success_count = 0;
    let mut metrics_inbound_count = 0;
    let mut metrics_outbound_route_count = 0;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let (trojan_port, trojan_thread) = match spawn_trojan_quic_tcp_relay_smoke_server() {
        Ok(server) => server,
        Err(error) => {
            cases.push(trojan_quic_tcp_relay_smoke_error_case(
                "start-trojan-quic-tcp-server",
                "start-protocol-server",
                error,
            ));
            return finalize_trojan_quic_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };

    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let config = trojan_quic_tcp_relay_smoke_config(trojan_port);
    let relay_options = RelayOptions {
        first_byte_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
        idle_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
    };

    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some(TROJAN_QUIC_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
            relay_options,
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(trojan_quic_tcp_relay_smoke_error_case(
                "start-trojan-quic-tcp-relay-runtime",
                "start",
                error,
            ));
            let _ = join_tcp_relay_smoke_server(trojan_thread);
            return finalize_trojan_quic_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    selected_outbound = started.selected_outbound.clone();
    cases.push(trojan_quic_tcp_relay_smoke_start_case(&started));

    if let Some(listen_addr) = started.listen_addr {
        let exchange_result = run_trojan_quic_tcp_relay_smoke_exchange(listen_addr);
        let server_result = join_tcp_relay_smoke_server(trojan_thread);
        if let Ok(exchange) = exchange_result.as_ref() {
            response_payload_bytes = Some(exchange.response_payload.len());
            round_trip_observed = exchange.response_payload == TROJAN_QUIC_TCP_RELAY_SMOKE_RESPONSE;
        }
        if let Ok(server) = server_result.as_ref() {
            server_received_payload = server.received_expected_payload;
        }
        cases.push(trojan_quic_tcp_relay_smoke_exchange_case(
            exchange_result,
            server_result,
            round_trip_observed,
            server_received_payload,
        ));

        let status = wait_for_udp_relay_smoke_status(&core, |status| {
            trojan_quic_tcp_relay_smoke_metrics_recorded(&status.connection_metrics)
        });
        metrics_total_connections = status.connection_metrics.total_connection_count;
        metrics_success_count = status.connection_metrics.success_count;
        metrics_inbound_count = udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5");
        metrics_outbound_route_count =
            trojan_quic_tcp_relay_smoke_outbound_route_count(&status.connection_metrics);
        metrics_recorded = trojan_quic_tcp_relay_smoke_metrics_recorded(&status.connection_metrics);
        cases.push(trojan_quic_tcp_relay_smoke_metrics_case(
            &status,
            metrics_recorded,
        ));
    } else {
        cases.push(trojan_quic_tcp_relay_smoke_error_case(
            "trojan-quic-tcp-relay-round-trip",
            "socks5-connect",
            "managed mixed runtime did not expose a listen address".to_string(),
        ));
        let _ = join_tcp_relay_smoke_server(trojan_thread);
    }

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(trojan_quic_tcp_relay_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(trojan_quic_tcp_relay_smoke_stop_case(
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
            Some(error),
        )),
    }

    finalize_trojan_quic_tcp_relay_smoke_report(
        cases,
        selected_outbound,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn trojan_quic_tcp_relay_smoke_config(trojan_port: u16) -> String {
    format!(
        r#"
proxies:
  - name: {TROJAN_QUIC_TCP_RELAY_SMOKE_OUTBOUND}
    type: trojan
    server: 127.0.0.1
    port: {trojan_port}
    password: {TROJAN_QUIC_TCP_RELAY_SMOKE_PASSWORD}
    tls: true
    sni: {TROJAN_QUIC_TCP_RELAY_SMOKE_SNI}
    skip-cert-verify: true
    network: quic
"#
    )
}

fn finalize_trojan_quic_tcp_relay_smoke_report(
    cases: Vec<TcpRelaySmokeCaseReport>,
    selected_outbound: Option<String>,
    request_payload_bytes: usize,
    response_payload_bytes: Option<usize>,
    round_trip_observed: bool,
    server_received_payload: bool,
    metrics_recorded: bool,
    metrics_total_connections: u64,
    metrics_success_count: u64,
    metrics_inbound_count: u64,
    metrics_outbound_route_count: u64,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> TcpRelaySmokeReport {
    let failed = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect::<Vec<_>>();
    let passed = failed.is_empty()
        && selected_outbound.as_deref() == Some(TROJAN_QUIC_TCP_RELAY_SMOKE_OUTBOUND)
        && round_trip_observed
        && server_received_payload
        && metrics_recorded
        && clean_stop_observed;
    let target = trojan_quic_tcp_relay_smoke_target();
    let detail = format!(
        "cases={} passed={} failed={} failed_cases={} selected={} transport=quic sni={} target={} request_bytes={} response_bytes={} round_trip_observed={} server_received_payload={} metrics_recorded={} metrics_total={} metrics_success={} metrics_inbound_socks5={} metrics_outbound_route={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
        cases.len(),
        passed,
        failed.len(),
        if failed.is_empty() {
            "-".to_string()
        } else {
            failed.join(",")
        },
        selected_outbound.as_deref().unwrap_or("-"),
        TROJAN_QUIC_TCP_RELAY_SMOKE_SNI,
        target,
        request_payload_bytes,
        response_payload_bytes
            .map(|bytes| bytes.to_string())
            .unwrap_or_else(|| "-".to_string()),
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining
            .map(|workers| workers.to_string())
            .unwrap_or_else(|| "-".to_string()),
        stop_timed_out
            .map(|timed_out| timed_out.to_string())
            .unwrap_or_else(|| "-".to_string())
    );
    TcpRelaySmokeReport {
        passed,
        detail,
        selected_outbound,
        target,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

fn trojan_quic_tcp_relay_smoke_start_case(
    status: &ManagedMixedStatusSnapshot,
) -> TcpRelaySmokeCaseReport {
    let selected = status.selected_outbound.clone();
    let passed = selected.as_deref() == Some(TROJAN_QUIC_TCP_RELAY_SMOKE_OUTBOUND)
        && status.generation == 1
        && matches!(&status.status, RuntimeStatus::Running { .. });
    TcpRelaySmokeCaseReport {
        name: "start-trojan-quic-tcp-relay-runtime",
        action: "start",
        expected_selected_outbound: Some(TROJAN_QUIC_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: selected,
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        target: trojan_quic_tcp_relay_smoke_target(),
        expected_response: None,
        observed_response: None,
        request_payload_bytes: None,
        response_payload_bytes: None,
        runtime_running: Some(matches!(&status.status, RuntimeStatus::Running { .. })),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error: None,
    }
}

fn trojan_quic_tcp_relay_smoke_exchange_case(
    exchange_result: Result<TcpRelaySmokeExchangeObservation, String>,
    server_result: Result<TcpRelaySmokeServerObservation, String>,
    round_trip_observed: bool,
    server_received_payload: bool,
) -> TcpRelaySmokeCaseReport {
    let error = match (&exchange_result, &server_result) {
        (Ok(_), Ok(_)) => None,
        (Err(exchange), Ok(_)) => Some(exchange.clone()),
        (Ok(_), Err(server)) => Some(server.clone()),
        (Err(exchange), Err(server)) => Some(format!("{exchange}; {server}")),
    };
    let exchange = exchange_result.ok();
    let passed = error.is_none() && round_trip_observed && server_received_payload;
    TcpRelaySmokeCaseReport {
        name: "trojan-quic-tcp-protocol-round-trip",
        action: "socks5-connect",
        expected_selected_outbound: Some(TROJAN_QUIC_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: trojan_quic_tcp_relay_smoke_target(),
        expected_response: Some(
            String::from_utf8_lossy(TROJAN_QUIC_TCP_RELAY_SMOKE_RESPONSE).to_string(),
        ),
        observed_response: exchange
            .as_ref()
            .map(|exchange| String::from_utf8_lossy(&exchange.response_payload).to_string()),
        request_payload_bytes: Some(TROJAN_QUIC_TCP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: exchange
            .as_ref()
            .map(|exchange| exchange.response_payload.len()),
        runtime_running: None,
        round_trip_observed: Some(round_trip_observed),
        server_received_payload: Some(server_received_payload),
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error,
    }
}

