fn run_trojan_tls_udp_relay_smoke_exchange(
    listen_addr: SocketAddr,
) -> Result<UdpRelaySmokeExchangeObservation, String> {
    let mut client = TcpStream::connect(listen_addr)
        .map_err(|error| format!("connect Trojan TLS UDP smoke listener {listen_addr}: {error}"))?;
    client
        .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Trojan TLS UDP smoke control read timeout: {error}"))?;
    client
        .set_write_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Trojan TLS UDP smoke control write timeout: {error}"))?;
    client
        .write_all(&[0x05, 0x01, 0x00])
        .map_err(|error| format!("write Trojan TLS UDP smoke SOCKS hello: {error}"))?;
    let mut hello = [0; 2];
    client
        .read_exact(&mut hello)
        .map_err(|error| format!("read Trojan TLS UDP smoke SOCKS hello: {error}"))?;
    if hello != [0x05, 0x00] {
        return Err(format!(
            "unexpected Trojan TLS UDP smoke SOCKS hello response: {hello:?}"
        ));
    }

    client
        .write_all(&[0x05, 0x03, 0x00, 0x01, 127, 0, 0, 1, 0x00, 0x00])
        .map_err(|error| format!("write Trojan TLS UDP smoke associate request: {error}"))?;
    let mut reply = [0; 10];
    client
        .read_exact(&mut reply)
        .map_err(|error| format!("read Trojan TLS UDP smoke associate response: {error}"))?;
    if &reply[..4] != [0x05, 0x00, 0x00, 0x01] {
        return Err(format!(
            "unexpected Trojan TLS UDP smoke associate response: {reply:?}"
        ));
    }
    let relay_port = u16::from_be_bytes([reply[8], reply[9]]);
    if relay_port == 0 {
        return Err("Trojan TLS UDP smoke relay returned port 0".to_string());
    }

    let udp_client = UdpSocket::bind("127.0.0.1:0")
        .map_err(|error| format!("bind Trojan TLS UDP smoke client: {error}"))?;
    udp_client
        .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Trojan TLS UDP smoke client read timeout: {error}"))?;
    udp_client
        .set_write_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Trojan TLS UDP smoke client write timeout: {error}"))?;
    let request = encode_socks5_udp_datagram(
        &Socks5Address::Domain(TROJAN_TLS_UDP_RELAY_SMOKE_TARGET_HOST.to_string()),
        TROJAN_TLS_UDP_RELAY_SMOKE_TARGET_PORT,
        TROJAN_TLS_UDP_RELAY_SMOKE_PAYLOAD,
    )
    .map_err(|error| format!("encode Trojan TLS UDP smoke request: {error}"))?;
    udp_client
        .send_to(&request, ("127.0.0.1", relay_port))
        .map_err(|error| format!("send Trojan TLS UDP smoke request: {error}"))?;

    let mut response = [0; 1500];
    let (size, _) = udp_client
        .recv_from(&mut response)
        .map_err(|error| format!("read Trojan TLS UDP smoke response: {error}"))?;
    let response = parse_socks5_udp_datagram(&response[..size])
        .map_err(|error| format!("parse Trojan TLS UDP smoke response: {error}"))?;
    client.shutdown(Shutdown::Both).ok();
    Ok(UdpRelaySmokeExchangeObservation {
        relay_port,
        response_source: format!(
            "{}:{}",
            udp_relay_smoke_socks5_address_label(&response.address),
            response.port
        ),
        response_payload: response.payload,
    })
}

fn spawn_trojan_tls_udp_relay_smoke_server() -> Result<
    (
        u16,
        thread::JoinHandle<Result<UdpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    let server_config = trojan_tls_udp_relay_smoke_server_config()?;
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind Trojan TLS UDP smoke server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set Trojan TLS UDP smoke accept mode: {error}"))?;
    let listen_port = listener
        .local_addr()
        .map_err(|error| format!("read Trojan TLS UDP smoke address: {error}"))?
        .port();
    let handle = thread::spawn(move || -> Result<UdpRelaySmokeServerObservation, String> {
        let deadline = Instant::now() + UDP_RELAY_SMOKE_TIMEOUT;
        let (stream, _) = loop {
            match listener.accept() {
                Ok(accepted) => break accepted,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err("Trojan TLS UDP smoke accept timed out".to_string());
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => return Err(format!("accept Trojan TLS UDP smoke server: {error}")),
            }
        };
        stream
            .set_nonblocking(false)
            .map_err(|error| format!("set Trojan TLS UDP smoke stream blocking mode: {error}"))?;
        stream
            .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set Trojan TLS UDP smoke read timeout: {error}"))?;
        stream
            .set_write_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set Trojan TLS UDP smoke write timeout: {error}"))?;
        let connection = rustls::ServerConnection::new(server_config)
            .map_err(|error| format!("create Trojan TLS UDP smoke TLS connection: {error}"))?;
        let mut stream = rustls::StreamOwned::new(connection, stream);
        let target = Endpoint::new(
            TROJAN_TLS_UDP_RELAY_SMOKE_TARGET_HOST,
            TROJAN_TLS_UDP_RELAY_SMOKE_TARGET_PORT,
        );

        let expected_header =
            encode_trojan_udp_request_header(TROJAN_TLS_UDP_RELAY_SMOKE_PASSWORD, &target)
                .map_err(|error| format!("encode expected Trojan TLS UDP header: {error}"))?;
        let mut observed_header = vec![0; expected_header.len()];
        stream
            .read_exact(&mut observed_header)
            .map_err(|error| format!("read Trojan TLS UDP request header: {error}"))?;
        if observed_header != expected_header {
            return Err(format!(
                "unexpected Trojan TLS UDP header: expected {:?}, got {:?}",
                expected_header, observed_header
            ));
        }

        let expected_packet = encode_trojan_udp_packet(&target, TROJAN_TLS_UDP_RELAY_SMOKE_PAYLOAD)
            .map_err(|error| format!("encode expected Trojan TLS UDP packet: {error}"))?;
        let mut observed_packet = vec![0; expected_packet.len()];
        stream
            .read_exact(&mut observed_packet)
            .map_err(|error| format!("read Trojan TLS UDP packet: {error}"))?;
        if observed_packet != expected_packet {
            return Err(format!(
                "unexpected Trojan TLS UDP packet: expected {:?}, got {:?}",
                expected_packet, observed_packet
            ));
        }

        let response = encode_trojan_udp_packet(
            &Endpoint::new("127.0.0.1", TROJAN_TLS_UDP_RELAY_SMOKE_TARGET_PORT),
            TROJAN_TLS_UDP_RELAY_SMOKE_RESPONSE,
        )
        .map_err(|error| format!("encode Trojan TLS UDP response packet: {error}"))?;
        stream
            .write_all(&response)
            .map_err(|error| format!("write Trojan TLS UDP response packet: {error}"))?;
        stream
            .flush()
            .map_err(|error| format!("flush Trojan TLS UDP response: {error}"))?;
        Ok(UdpRelaySmokeServerObservation {
            received_expected_payload: true,
        })
    });
    Ok((listen_port, handle))
}

fn trojan_tls_udp_relay_smoke_server_config() -> Result<Arc<rustls::ServerConfig>, String> {
    let cert = generate_simple_self_signed(vec![TROJAN_TLS_UDP_RELAY_SMOKE_SNI.to_string()])
        .map_err(|error| format!("generate Trojan TLS UDP smoke cert: {error}"))?;
    let cert_der: CertificateDer<'static> = cert.cert.der().clone();
    let key_der = PrivateKeyDer::Pkcs8(cert.signing_key.serialize_der().into());
    rustls::ServerConfig::builder_with_provider(rustls::crypto::ring::default_provider().into())
        .with_protocol_versions(&[&rustls::version::TLS13, &rustls::version::TLS12])
        .map_err(|error| format!("configure Trojan TLS UDP smoke protocols: {error}"))?
        .with_no_client_auth()
        .with_single_cert(vec![cert_der], key_der)
        .map(Arc::new)
        .map_err(|error| format!("configure Trojan TLS UDP smoke certificate: {error}"))
}

fn trojan_tls_udp_relay_smoke_metrics_recorded(metrics: &ConnectionMetricsSnapshot) -> bool {
    metrics.total_connection_count >= 1
        && metrics.success_count >= 1
        && udp_relay_smoke_inbound_count(metrics, "socks5-udp") >= 1
        && trojan_tls_udp_relay_smoke_outbound_route_count(metrics) >= 1
        && metrics.total_upload_bytes >= TROJAN_TLS_UDP_RELAY_SMOKE_PAYLOAD.len() as u64
        && metrics.total_download_bytes >= TROJAN_TLS_UDP_RELAY_SMOKE_RESPONSE.len() as u64
}

fn trojan_tls_udp_relay_smoke_outbound_route_count(metrics: &ConnectionMetricsSnapshot) -> u64 {
    metrics
        .route_action_counts
        .iter()
        .find(|entry| {
            entry.route_action
                == RouteAction::Outbound(TROJAN_TLS_UDP_RELAY_SMOKE_OUTBOUND.to_string())
        })
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn trojan_tls_udp_relay_smoke_target() -> String {
    format!(
        "{}:{}",
        TROJAN_TLS_UDP_RELAY_SMOKE_TARGET_HOST, TROJAN_TLS_UDP_RELAY_SMOKE_TARGET_PORT
    )
}

#[cfg(test)]
mod trojan_tls_udp_relay_smoke_tests {
    use super::*;

    #[test]
    fn default_trojan_tls_udp_relay_smoke_proves_tls_trojan_udp_round_trip() {
        let report = collect_default_trojan_tls_udp_relay_smoke_report();

        assert!(report.passed, "{}", report.detail);
        assert_eq!(
            report.selected_outbound.as_deref(),
            Some(TROJAN_TLS_UDP_RELAY_SMOKE_OUTBOUND)
        );
        assert_eq!(report.target, trojan_tls_udp_relay_smoke_target());
        assert!(report.relay_port.is_some());
        assert_eq!(report.response_source.as_deref(), Some("127.0.0.1:53"));
        assert_eq!(
            report.request_payload_bytes,
            TROJAN_TLS_UDP_RELAY_SMOKE_PAYLOAD.len()
        );
        assert_eq!(
            report.response_payload_bytes,
            Some(TROJAN_TLS_UDP_RELAY_SMOKE_RESPONSE.len())
        );
        assert!(report.round_trip_observed);
        assert!(report.server_received_payload);
        assert!(report.metrics_recorded);
        assert!(report.metrics_total_connections >= 1);
        assert!(report.metrics_success_count >= 1);
        assert!(report.metrics_inbound_count >= 1);
        assert!(report.metrics_outbound_route_count >= 1);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));

        let case_names = report
            .cases
            .iter()
            .map(|case| case.name)
            .collect::<Vec<_>>();
        for expected in [
            "start-trojan-tls-udp-relay-runtime",
            "trojan-tls-udp-protocol-round-trip",
            "record-trojan-tls-udp-relay-metrics",
            "stop-trojan-tls-udp-relay-runtime",
        ] {
            assert!(
                case_names.contains(&expected),
                "missing Trojan TLS UDP relay smoke case {expected}: {case_names:?}"
            );
        }
        let round_trip = report
            .cases
            .iter()
            .find(|case| case.name == "trojan-tls-udp-protocol-round-trip")
            .expect("round trip case");
        assert_eq!(
            round_trip.observed_response.as_deref(),
            Some("keli-trojan-udp-pong")
        );
        assert_eq!(round_trip.round_trip_observed, Some(true));
        assert_eq!(round_trip.server_received_payload, Some(true));
    }
}

fn collect_default_anytls_tls_tcp_relay_smoke_report() -> TcpRelaySmokeReport {
    let mut cases = Vec::new();
    let mut selected_outbound = None;
    let request_payload_bytes = ANYTLS_TLS_TCP_RELAY_SMOKE_PAYLOAD.len();
    let mut response_payload_bytes = None;
    let mut round_trip_observed = false;
    let mut server_received_payload = false;
    let mut metrics_recorded = false;
    let mut metrics_total_connections = 0;
    let mut metrics_success_count = 0;
    let mut metrics_inbound_count = 0;
    let mut metrics_outbound_route_count = 0;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let (anytls_port, anytls_thread) = match spawn_anytls_tls_tcp_relay_smoke_server() {
        Ok(server) => server,
        Err(error) => {
            cases.push(anytls_tls_tcp_relay_smoke_error_case(
                "start-anytls-tls-tcp-server",
                "start-protocol-server",
                error,
            ));
            return finalize_anytls_tls_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };

    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let config = anytls_tls_tcp_relay_smoke_config(anytls_port);
    let relay_options = RelayOptions {
        first_byte_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
        idle_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
    };

    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some(ANYTLS_TLS_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
            relay_options,
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(anytls_tls_tcp_relay_smoke_error_case(
                "start-anytls-tls-tcp-relay-runtime",
                "start",
                error,
            ));
            let _ = join_tcp_relay_smoke_server(anytls_thread);
            return finalize_anytls_tls_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    selected_outbound = started.selected_outbound.clone();
    cases.push(anytls_tls_tcp_relay_smoke_start_case(&started));

    if let Some(listen_addr) = started.listen_addr {
        let exchange_result = run_anytls_tls_tcp_relay_smoke_exchange(listen_addr);
        let server_result = join_tcp_relay_smoke_server(anytls_thread);
        if let Ok(exchange) = exchange_result.as_ref() {
            response_payload_bytes = Some(exchange.response_payload.len());
            round_trip_observed = exchange.response_payload == ANYTLS_TLS_TCP_RELAY_SMOKE_RESPONSE;
        }
        if let Ok(server) = server_result.as_ref() {
            server_received_payload = server.received_expected_payload;
        }
        cases.push(anytls_tls_tcp_relay_smoke_exchange_case(
            exchange_result,
            server_result,
            round_trip_observed,
            server_received_payload,
        ));

        let status = wait_for_udp_relay_smoke_status(&core, |status| {
            anytls_tls_tcp_relay_smoke_metrics_recorded(&status.connection_metrics)
        });
        metrics_total_connections = status.connection_metrics.total_connection_count;
        metrics_success_count = status.connection_metrics.success_count;
        metrics_inbound_count = udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5");
        metrics_outbound_route_count =
            anytls_tls_tcp_relay_smoke_outbound_route_count(&status.connection_metrics);
        metrics_recorded = anytls_tls_tcp_relay_smoke_metrics_recorded(&status.connection_metrics);
        cases.push(anytls_tls_tcp_relay_smoke_metrics_case(
            &status,
            metrics_recorded,
        ));
    } else {
        cases.push(anytls_tls_tcp_relay_smoke_error_case(
            "anytls-tls-tcp-relay-round-trip",
            "socks5-connect",
            "managed mixed runtime did not expose a listen address".to_string(),
        ));
        let _ = join_tcp_relay_smoke_server(anytls_thread);
    }

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(anytls_tls_tcp_relay_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(anytls_tls_tcp_relay_smoke_stop_case(
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
            Some(error),
        )),
    }

    finalize_anytls_tls_tcp_relay_smoke_report(
        cases,
        selected_outbound,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn anytls_tls_tcp_relay_smoke_config(anytls_port: u16) -> String {
    format!(
        r#"
proxies:
  - name: {ANYTLS_TLS_TCP_RELAY_SMOKE_OUTBOUND}
    type: anytls
    server: 127.0.0.1
    port: {anytls_port}
    password: {ANYTLS_TLS_TCP_RELAY_SMOKE_PASSWORD}
    tls: true
    sni: {ANYTLS_TLS_TCP_RELAY_SMOKE_SNI}
    skip-cert-verify: true
    network: tcp
"#
    )
}

fn finalize_anytls_tls_tcp_relay_smoke_report(
    cases: Vec<TcpRelaySmokeCaseReport>,
    selected_outbound: Option<String>,
    request_payload_bytes: usize,
    response_payload_bytes: Option<usize>,
    round_trip_observed: bool,
    server_received_payload: bool,
    metrics_recorded: bool,
    metrics_total_connections: u64,
    metrics_success_count: u64,
    metrics_inbound_count: u64,
    metrics_outbound_route_count: u64,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> TcpRelaySmokeReport {
    let failed = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect::<Vec<_>>();
    let passed = failed.is_empty()
        && selected_outbound.as_deref() == Some(ANYTLS_TLS_TCP_RELAY_SMOKE_OUTBOUND)
        && round_trip_observed
        && server_received_payload
        && metrics_recorded
        && clean_stop_observed;
    let target = anytls_tls_tcp_relay_smoke_target();
    let detail = format!(
        "cases={} passed={} failed={} failed_cases={} selected={} target={} request_bytes={} response_bytes={} round_trip_observed={} server_received_payload={} metrics_recorded={} metrics_total={} metrics_success={} metrics_inbound_socks5={} metrics_outbound_route={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
        cases.len(),
        passed,
        failed.len(),
        if failed.is_empty() {
            "-".to_string()
        } else {
            failed.join(",")
        },
        selected_outbound.as_deref().unwrap_or("-"),
        target,
        request_payload_bytes,
        response_payload_bytes
            .map(|bytes| bytes.to_string())
            .unwrap_or_else(|| "-".to_string()),
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining
            .map(|workers| workers.to_string())
            .unwrap_or_else(|| "-".to_string()),
        stop_timed_out
            .map(|timed_out| timed_out.to_string())
            .unwrap_or_else(|| "-".to_string())
    );
    TcpRelaySmokeReport {
        passed,
        detail,
        selected_outbound,
        target,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

fn anytls_tls_tcp_relay_smoke_start_case(
    status: &ManagedMixedStatusSnapshot,
) -> TcpRelaySmokeCaseReport {
    let selected = status.selected_outbound.clone();
    let passed = selected.as_deref() == Some(ANYTLS_TLS_TCP_RELAY_SMOKE_OUTBOUND)
        && status.generation == 1
        && matches!(&status.status, RuntimeStatus::Running { .. });
    TcpRelaySmokeCaseReport {
        name: "start-anytls-tls-tcp-relay-runtime",
        action: "start",
        expected_selected_outbound: Some(ANYTLS_TLS_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: selected,
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        target: anytls_tls_tcp_relay_smoke_target(),
        expected_response: None,
        observed_response: None,
        request_payload_bytes: None,
        response_payload_bytes: None,
        runtime_running: Some(matches!(&status.status, RuntimeStatus::Running { .. })),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error: None,
    }
}

fn anytls_tls_tcp_relay_smoke_exchange_case(
    exchange_result: Result<TcpRelaySmokeExchangeObservation, String>,
    server_result: Result<TcpRelaySmokeServerObservation, String>,
    round_trip_observed: bool,
    server_received_payload: bool,
) -> TcpRelaySmokeCaseReport {
    let error = match (&exchange_result, &server_result) {
        (Ok(_), Ok(_)) => None,
        (Err(exchange), Ok(_)) => Some(exchange.clone()),
        (Ok(_), Err(server)) => Some(server.clone()),
        (Err(exchange), Err(server)) => Some(format!("{exchange}; {server}")),
    };
    let exchange = exchange_result.ok();
    let passed = error.is_none() && round_trip_observed && server_received_payload;
    TcpRelaySmokeCaseReport {
        name: "anytls-tls-tcp-protocol-round-trip",
        action: "socks5-connect",
        expected_selected_outbound: Some(ANYTLS_TLS_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: anytls_tls_tcp_relay_smoke_target(),
        expected_response: Some(
            String::from_utf8_lossy(ANYTLS_TLS_TCP_RELAY_SMOKE_RESPONSE).to_string(),
        ),
        observed_response: exchange
            .as_ref()
            .map(|exchange| String::from_utf8_lossy(&exchange.response_payload).to_string()),
        request_payload_bytes: Some(ANYTLS_TLS_TCP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: exchange
            .as_ref()
            .map(|exchange| exchange.response_payload.len()),
        runtime_running: None,
        round_trip_observed: Some(round_trip_observed),
        server_received_payload: Some(server_received_payload),
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error,
    }
}

