fn run_vless_httpupgrade_tcp_relay_smoke_exchange(
    listen_addr: SocketAddr,
) -> Result<TcpRelaySmokeExchangeObservation, String> {
    let mut client = TcpStream::connect(listen_addr).map_err(|error| {
        format!("connect VLESS HTTPUpgrade TCP smoke listener {listen_addr}: {error}")
    })?;
    client
        .set_read_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set VLESS HTTPUpgrade TCP smoke client read timeout: {error}"))?;
    client
        .set_write_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| {
            format!("set VLESS HTTPUpgrade TCP smoke client write timeout: {error}")
        })?;
    let target = OutboundTarget::new(
        VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_HOST,
        VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_PORT,
    );
    write_smoke_connect(&mut client, &target, SmokeInboundKind::Socks5)?;
    client
        .write_all(VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD)
        .map_err(|error| format!("write VLESS HTTPUpgrade TCP smoke payload: {error}"))?;
    let mut response = vec![0; VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE.len()];
    client
        .read_exact(&mut response)
        .map_err(|error| format!("read VLESS HTTPUpgrade TCP smoke response: {error}"))?;
    client.shutdown(Shutdown::Both).ok();
    Ok(TcpRelaySmokeExchangeObservation {
        response_payload: response,
    })
}

fn spawn_vless_httpupgrade_tcp_relay_smoke_server() -> Result<
    (
        u16,
        thread::JoinHandle<Result<TcpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind VLESS HTTPUpgrade TCP smoke server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set VLESS HTTPUpgrade TCP smoke accept mode: {error}"))?;
    let listen_port = listener
        .local_addr()
        .map_err(|error| format!("read VLESS HTTPUpgrade TCP smoke address: {error}"))?
        .port();
    let handle = thread::spawn(move || -> Result<TcpRelaySmokeServerObservation, String> {
        let deadline = Instant::now() + TCP_RELAY_SMOKE_TIMEOUT;
        let (mut stream, _) = loop {
            match listener.accept() {
                Ok(accepted) => break accepted,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err("VLESS HTTPUpgrade TCP smoke accept timed out".to_string());
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => {
                    return Err(format!(
                        "accept VLESS HTTPUpgrade TCP smoke server: {error}"
                    ))
                }
            }
        };
        stream.set_nonblocking(false).map_err(|error| {
            format!("set VLESS HTTPUpgrade TCP smoke stream blocking mode: {error}")
        })?;
        stream
            .set_read_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set VLESS HTTPUpgrade TCP smoke read timeout: {error}"))?;
        stream
            .set_write_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set VLESS HTTPUpgrade TCP smoke write timeout: {error}"))?;

        let request =
            read_websocket_smoke_http_request(&mut stream, "VLESS HTTPUpgrade TCP smoke")?;
        validate_vless_httpupgrade_tcp_relay_smoke_handshake(&request, &mut stream)?;

        let expected_header = encode_vless_tcp_request_header(
            VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_UUID,
            &Endpoint::new(
                VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_HOST,
                VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_PORT,
            ),
            None,
        )
        .map_err(|error| format!("encode expected VLESS HTTPUpgrade TCP smoke header: {error}"))?;
        let mut observed_header = vec![0; expected_header.len()];
        stream
            .read_exact(&mut observed_header)
            .map_err(|error| format!("read VLESS HTTPUpgrade TCP smoke request header: {error}"))?;
        if observed_header != expected_header {
            return Err(format!(
                "unexpected VLESS HTTPUpgrade TCP smoke header: expected {:?}, got {:?}",
                expected_header, observed_header
            ));
        }

        stream.write_all(&[0x00, 0x00]).map_err(|error| {
            format!("write VLESS HTTPUpgrade TCP smoke response header: {error}")
        })?;

        let mut payload = vec![0; VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD.len()];
        stream
            .read_exact(&mut payload)
            .map_err(|error| format!("read VLESS HTTPUpgrade TCP smoke payload: {error}"))?;
        if payload != VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD {
            return Err(format!(
                "unexpected VLESS HTTPUpgrade TCP smoke payload: expected {:?}, got {:?}",
                VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD, payload
            ));
        }

        stream
            .write_all(VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE)
            .map_err(|error| {
                format!("write VLESS HTTPUpgrade TCP smoke response payload: {error}")
            })?;
        stream
            .flush()
            .map_err(|error| format!("flush VLESS HTTPUpgrade TCP smoke response: {error}"))?;
        tcp_relay_smoke_wait_for_client_close(&mut stream);
        Ok(TcpRelaySmokeServerObservation {
            received_expected_payload: true,
        })
    });
    Ok((listen_port, handle))
}

fn validate_vless_httpupgrade_tcp_relay_smoke_handshake(
    request: &str,
    stream: &mut TcpStream,
) -> Result<(), String> {
    let request_line = request.lines().next().unwrap_or_default();
    let expected_request_line = format!("GET {} HTTP/1.1", VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_PATH);
    if request_line != expected_request_line {
        return Err(format!(
            "unexpected VLESS HTTPUpgrade TCP smoke request line: expected {expected_request_line}, got {request_line}"
        ));
    }
    let host = http_header_value(request, "Host")
        .ok_or_else(|| "VLESS HTTPUpgrade TCP smoke request missing Host header".to_string())?;
    if host != VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_HOST {
        return Err(format!(
            "unexpected VLESS HTTPUpgrade TCP smoke Host: expected {}, got {host}",
            VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_HOST
        ));
    }
    let upgrade = http_header_value(request, "Upgrade")
        .ok_or_else(|| "VLESS HTTPUpgrade TCP smoke request missing Upgrade header".to_string())?;
    if !upgrade.eq_ignore_ascii_case("websocket") {
        return Err(format!(
            "unexpected VLESS HTTPUpgrade TCP smoke Upgrade: expected websocket, got {upgrade}"
        ));
    }
    let connection = http_header_value(request, "Connection").ok_or_else(|| {
        "VLESS HTTPUpgrade TCP smoke request missing Connection header".to_string()
    })?;
    if !connection
        .split(',')
        .any(|item| item.trim().eq_ignore_ascii_case("upgrade"))
    {
        return Err(format!(
            "unexpected VLESS HTTPUpgrade TCP smoke Connection: expected Upgrade, got {connection}"
        ));
    }
    if http_header_value(request, "Sec-WebSocket-Key").is_some() {
        return Err("VLESS HTTPUpgrade TCP smoke unexpectedly sent Sec-WebSocket-Key".to_string());
    }
    if http_header_value(request, "Sec-WebSocket-Version").is_some() {
        return Err(
            "VLESS HTTPUpgrade TCP smoke unexpectedly sent Sec-WebSocket-Version".to_string(),
        );
    }
    stream
        .write_all(
            b"HTTP/1.1 101 Switching Protocols\r\nConnection: Upgrade\r\nUpgrade: websocket\r\n\r\n",
        )
        .map_err(|error| format!("write VLESS HTTPUpgrade TCP smoke handshake response: {error}"))
}

fn vless_httpupgrade_tcp_relay_smoke_metrics_recorded(metrics: &ConnectionMetricsSnapshot) -> bool {
    metrics.total_connection_count >= 1
        && metrics.success_count >= 1
        && udp_relay_smoke_inbound_count(metrics, "socks5") >= 1
        && vless_httpupgrade_tcp_relay_smoke_outbound_route_count(metrics) >= 1
        && metrics.total_upload_bytes >= VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD.len() as u64
        && metrics.total_download_bytes >= VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE.len() as u64
}

fn vless_httpupgrade_tcp_relay_smoke_outbound_route_count(
    metrics: &ConnectionMetricsSnapshot,
) -> u64 {
    metrics
        .route_action_counts
        .iter()
        .find(|entry| {
            entry.route_action
                == RouteAction::Outbound(VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND.to_string())
        })
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn vless_httpupgrade_tcp_relay_smoke_target() -> String {
    format!(
        "{}:{}",
        VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_HOST,
        VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_TARGET_PORT
    )
}

#[cfg(test)]
mod vless_httpupgrade_tcp_relay_smoke_tests {
    use super::*;

    #[test]
    fn default_vless_httpupgrade_tcp_relay_smoke_proves_upgraded_vless_round_trip() {
        let report = collect_default_vless_httpupgrade_tcp_relay_smoke_report();

        assert!(report.passed, "{report:#?}");
        assert_eq!(
            report.selected_outbound.as_deref(),
            Some(VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_OUTBOUND)
        );
        assert_eq!(report.target, vless_httpupgrade_tcp_relay_smoke_target());
        assert_eq!(
            report.request_payload_bytes,
            VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_PAYLOAD.len()
        );
        assert_eq!(
            report.response_payload_bytes,
            Some(VLESS_HTTPUPGRADE_TCP_RELAY_SMOKE_RESPONSE.len())
        );
        assert!(report.round_trip_observed);
        assert!(report.server_received_payload);
        assert!(report.metrics_recorded);
        assert!(report.metrics_total_connections >= 1);
        assert!(report.metrics_success_count >= 1);
        assert!(report.metrics_inbound_count >= 1);
        assert!(report.metrics_outbound_route_count >= 1);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));

        let case_names = report
            .cases
            .iter()
            .map(|case| case.name)
            .collect::<Vec<_>>();
        for expected in [
            "start-vless-httpupgrade-tcp-relay-runtime",
            "vless-httpupgrade-tcp-protocol-round-trip",
            "record-vless-httpupgrade-tcp-relay-metrics",
            "stop-vless-httpupgrade-tcp-relay-runtime",
        ] {
            assert!(
                case_names.contains(&expected),
                "missing VLESS HTTPUpgrade TCP relay smoke case {expected}: {case_names:?}"
            );
        }
        let round_trip = report
            .cases
            .iter()
            .find(|case| case.name == "vless-httpupgrade-tcp-protocol-round-trip")
            .expect("round trip case");
        assert_eq!(
            round_trip.observed_response.as_deref(),
            Some("keli-vless-hu-pong")
        );
        assert_eq!(round_trip.round_trip_observed, Some(true));
        assert_eq!(round_trip.server_received_payload, Some(true));
    }
}

fn collect_default_vless_httpupgrade_udp_relay_smoke_report() -> UdpRelaySmokeReport {
    let mut cases = Vec::new();
    let mut selected_outbound = None;
    let mut relay_port = None;
    let mut response_source = None;
    let request_payload_bytes = VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_PAYLOAD.len();
    let mut response_payload_bytes = None;
    let mut round_trip_observed = false;
    let mut server_received_payload = false;
    let mut metrics_recorded = false;
    let mut metrics_total_connections = 0;
    let mut metrics_success_count = 0;
    let mut metrics_inbound_count = 0;
    let mut metrics_outbound_route_count = 0;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let (vless_port, vless_thread) = match spawn_vless_httpupgrade_udp_relay_smoke_server() {
        Ok(server) => server,
        Err(error) => {
            cases.push(vless_httpupgrade_udp_relay_smoke_error_case(
                "start-vless-httpupgrade-udp-server",
                "start-protocol-server",
                error,
            ));
            return finalize_vless_httpupgrade_udp_relay_smoke_report(
                cases,
                selected_outbound,
                relay_port,
                response_source,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };

    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let config = vless_httpupgrade_udp_relay_smoke_config(vless_port);
    let relay_options = RelayOptions {
        first_byte_timeout: Some(UDP_RELAY_SMOKE_TIMEOUT),
        idle_timeout: Some(UDP_RELAY_SMOKE_TIMEOUT),
    };

    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some(VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_OUTBOUND.to_string()),
            relay_options,
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(vless_httpupgrade_udp_relay_smoke_error_case(
                "start-vless-httpupgrade-udp-relay-runtime",
                "start",
                error,
            ));
            let _ = join_udp_relay_smoke_server(vless_thread);
            return finalize_vless_httpupgrade_udp_relay_smoke_report(
                cases,
                selected_outbound,
                relay_port,
                response_source,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    selected_outbound = started.selected_outbound.clone();
    cases.push(vless_httpupgrade_udp_relay_smoke_start_case(&started));

    if let Some(listen_addr) = started.listen_addr {
        let exchange_result = run_vless_httpupgrade_udp_relay_smoke_exchange(listen_addr);
        let server_result = join_udp_relay_smoke_server(vless_thread);
        if let Ok(exchange) = exchange_result.as_ref() {
            relay_port = Some(exchange.relay_port);
            response_source = Some(exchange.response_source.clone());
            response_payload_bytes = Some(exchange.response_payload.len());
            round_trip_observed =
                exchange.response_payload == VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_RESPONSE;
        }
        if let Ok(server) = server_result.as_ref() {
            server_received_payload = server.received_expected_payload;
        }
        cases.push(vless_httpupgrade_udp_relay_smoke_exchange_case(
            exchange_result,
            server_result,
            round_trip_observed,
            server_received_payload,
        ));

        let status = wait_for_udp_relay_smoke_status(&core, |status| {
            vless_httpupgrade_udp_relay_smoke_metrics_recorded(&status.connection_metrics)
        });
        metrics_total_connections = status.connection_metrics.total_connection_count;
        metrics_success_count = status.connection_metrics.success_count;
        metrics_inbound_count =
            udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5-udp");
        metrics_outbound_route_count =
            vless_httpupgrade_udp_relay_smoke_outbound_route_count(&status.connection_metrics);
        metrics_recorded =
            vless_httpupgrade_udp_relay_smoke_metrics_recorded(&status.connection_metrics);
        cases.push(vless_httpupgrade_udp_relay_smoke_metrics_case(
            &status,
            metrics_recorded,
        ));
    } else {
        cases.push(vless_httpupgrade_udp_relay_smoke_error_case(
            "vless-httpupgrade-udp-protocol-round-trip",
            "socks5-udp-associate",
            "managed mixed runtime did not expose a listen address".to_string(),
        ));
        let _ = join_udp_relay_smoke_server(vless_thread);
    }

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(vless_httpupgrade_udp_relay_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(vless_httpupgrade_udp_relay_smoke_stop_case(
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
            Some(error),
        )),
    }

    finalize_vless_httpupgrade_udp_relay_smoke_report(
        cases,
        selected_outbound,
        relay_port,
        response_source,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn vless_httpupgrade_udp_relay_smoke_config(vless_port: u16) -> String {
    format!(
        r#"
proxies:
  - name: {VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_OUTBOUND}
    type: vless
    server: 127.0.0.1
    port: {vless_port}
    uuid: {VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_UUID}
    network: httpupgrade
    httpupgrade-opts:
      path: {VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_PATH}
      host: {VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_HOST}
"#
    )
}

fn finalize_vless_httpupgrade_udp_relay_smoke_report(
    cases: Vec<UdpRelaySmokeCaseReport>,
    selected_outbound: Option<String>,
    relay_port: Option<u16>,
    response_source: Option<String>,
    request_payload_bytes: usize,
    response_payload_bytes: Option<usize>,
    round_trip_observed: bool,
    server_received_payload: bool,
    metrics_recorded: bool,
    metrics_total_connections: u64,
    metrics_success_count: u64,
    metrics_inbound_count: u64,
    metrics_outbound_route_count: u64,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> UdpRelaySmokeReport {
    let failed = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect::<Vec<_>>();
    let passed = failed.is_empty()
        && selected_outbound.as_deref() == Some(VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_OUTBOUND)
        && round_trip_observed
        && server_received_payload
        && metrics_recorded
        && clean_stop_observed;
    let target = vless_httpupgrade_udp_relay_smoke_target();
    let detail = format!(
        "cases={} passed={} failed={} failed_cases={} selected={} transport=httpupgrade host={} path={} target={} relay_port={} response_source={} request_bytes={} response_bytes={} round_trip_observed={} server_received_payload={} metrics_recorded={} metrics_total={} metrics_success={} metrics_inbound_socks5_udp={} metrics_outbound_route={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
        cases.len(),
        passed,
        failed.len(),
        if failed.is_empty() {
            "-".to_string()
        } else {
            failed.join(",")
        },
        selected_outbound.as_deref().unwrap_or("-"),
        VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_HOST,
        VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_PATH,
        target,
        relay_port
            .map(|port| port.to_string())
            .unwrap_or_else(|| "-".to_string()),
        response_source.as_deref().unwrap_or("-"),
        request_payload_bytes,
        response_payload_bytes
            .map(|bytes| bytes.to_string())
            .unwrap_or_else(|| "-".to_string()),
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining
            .map(|workers| workers.to_string())
            .unwrap_or_else(|| "-".to_string()),
        stop_timed_out
            .map(|timed_out| timed_out.to_string())
            .unwrap_or_else(|| "-".to_string())
    );
    UdpRelaySmokeReport {
        passed,
        detail,
        selected_outbound,
        target,
        relay_port,
        response_source,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

fn vless_httpupgrade_udp_relay_smoke_start_case(
    status: &ManagedMixedStatusSnapshot,
) -> UdpRelaySmokeCaseReport {
    let selected = status.selected_outbound.clone();
    let passed = selected.as_deref() == Some(VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_OUTBOUND)
        && status.generation == 1
        && matches!(&status.status, RuntimeStatus::Running { .. });
    UdpRelaySmokeCaseReport {
        name: "start-vless-httpupgrade-udp-relay-runtime",
        action: "start",
        expected_selected_outbound: Some(VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: selected,
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        target: vless_httpupgrade_udp_relay_smoke_target(),
        relay_port: None,
        expected_response: None,
        observed_response: None,
        response_source: None,
        request_payload_bytes: None,
        response_payload_bytes: None,
        runtime_running: Some(matches!(&status.status, RuntimeStatus::Running { .. })),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error: None,
    }
}

fn vless_httpupgrade_udp_relay_smoke_exchange_case(
    exchange_result: Result<UdpRelaySmokeExchangeObservation, String>,
    server_result: Result<UdpRelaySmokeServerObservation, String>,
    round_trip_observed: bool,
    server_received_payload: bool,
) -> UdpRelaySmokeCaseReport {
    let error = match (&exchange_result, &server_result) {
        (Ok(_), Ok(_)) => None,
        (Err(exchange), Ok(_)) => Some(exchange.clone()),
        (Ok(_), Err(server)) => Some(server.clone()),
        (Err(exchange), Err(server)) => Some(format!("{exchange}; {server}")),
    };
    let exchange = exchange_result.ok();
    let passed = error.is_none() && round_trip_observed && server_received_payload;
    UdpRelaySmokeCaseReport {
        name: "vless-httpupgrade-udp-protocol-round-trip",
        action: "socks5-udp-associate",
        expected_selected_outbound: Some(VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: vless_httpupgrade_udp_relay_smoke_target(),
        relay_port: exchange.as_ref().map(|exchange| exchange.relay_port),
        expected_response: Some(
            String::from_utf8_lossy(VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_RESPONSE).to_string(),
        ),
        observed_response: exchange
            .as_ref()
            .map(|exchange| String::from_utf8_lossy(&exchange.response_payload).to_string()),
        response_source: exchange
            .as_ref()
            .map(|exchange| exchange.response_source.clone()),
        request_payload_bytes: Some(VLESS_HTTPUPGRADE_UDP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: exchange
            .as_ref()
            .map(|exchange| exchange.response_payload.len()),
        runtime_running: None,
        round_trip_observed: Some(round_trip_observed),
        server_received_payload: Some(server_received_payload),
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error,
    }
}

