fn run_vless_h2_tcp_relay_smoke_exchange(
    listen_addr: SocketAddr,
) -> Result<TcpRelaySmokeExchangeObservation, String> {
    let mut client = TcpStream::connect(listen_addr)
        .map_err(|error| format!("connect VLESS H2 TCP smoke listener {listen_addr}: {error}"))?;
    client
        .set_read_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set VLESS H2 TCP smoke client read timeout: {error}"))?;
    client
        .set_write_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set VLESS H2 TCP smoke client write timeout: {error}"))?;
    let target = OutboundTarget::new(
        VLESS_H2_TCP_RELAY_SMOKE_TARGET_HOST,
        VLESS_H2_TCP_RELAY_SMOKE_TARGET_PORT,
    );
    write_smoke_connect(&mut client, &target, SmokeInboundKind::Socks5)?;
    client
        .write_all(VLESS_H2_TCP_RELAY_SMOKE_PAYLOAD)
        .map_err(|error| format!("write VLESS H2 TCP smoke payload: {error}"))?;
    let mut response = vec![0; VLESS_H2_TCP_RELAY_SMOKE_RESPONSE.len()];
    client
        .read_exact(&mut response)
        .map_err(|error| format!("read VLESS H2 TCP smoke response: {error}"))?;
    client.shutdown(Shutdown::Both).ok();
    Ok(TcpRelaySmokeExchangeObservation {
        response_payload: response,
    })
}

fn spawn_vless_h2_tcp_relay_smoke_server() -> Result<
    (
        u16,
        thread::JoinHandle<Result<TcpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind VLESS H2 TCP smoke server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set VLESS H2 TCP smoke accept mode: {error}"))?;
    let listen_port = listener
        .local_addr()
        .map_err(|error| format!("read VLESS H2 TCP smoke address: {error}"))?
        .port();
    let handle = thread::spawn(move || -> Result<TcpRelaySmokeServerObservation, String> {
        let deadline = Instant::now() + TCP_RELAY_SMOKE_TIMEOUT;
        let (stream, _) = loop {
            match listener.accept() {
                Ok(accepted) => break accepted,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err("VLESS H2 TCP smoke accept timed out".to_string());
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => return Err(format!("accept VLESS H2 TCP smoke server: {error}")),
            }
        };
        stream
            .set_nonblocking(true)
            .map_err(|error| format!("set VLESS H2 TCP smoke stream nonblocking: {error}"))?;
        let runtime = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .thread_name("keli-vless-h2-smoke-server")
            .build()
            .map_err(|error| format!("build VLESS H2 TCP smoke runtime: {error}"))?;
        runtime.block_on(async move {
            tokio::time::timeout(
                TCP_RELAY_SMOKE_TIMEOUT,
                handle_vless_h2_tcp_relay_smoke_stream(stream),
            )
            .await
            .map_err(|_| "VLESS H2 TCP smoke server timed out".to_string())?
        })
    });
    Ok((listen_port, handle))
}

async fn handle_vless_h2_tcp_relay_smoke_stream(
    stream: TcpStream,
) -> Result<TcpRelaySmokeServerObservation, String> {
    let stream = tokio::net::TcpStream::from_std(stream)
        .map_err(|error| format!("convert VLESS H2 TCP smoke stream: {error}"))?;
    let mut h2 = h2::server::handshake(stream)
        .await
        .map_err(|error| format!("VLESS H2 TCP smoke h2 handshake: {error}"))?;
    let (result_tx, mut result_rx) =
        tokio::sync::mpsc::unbounded_channel::<Result<TcpRelaySmokeServerObservation, String>>();
    let mut accepted = false;
    let mut accepting = true;

    loop {
        tokio::select! {
            result = result_rx.recv() => {
                return result.unwrap_or_else(|| {
                    Err("VLESS H2 TCP smoke request handler ended without a result".to_string())
                });
            }
            request = h2.accept(), if accepting => {
                let Some(request) = request else {
                    accepting = false;
                    if !accepted {
                        return Err("VLESS H2 TCP smoke h2 stream was not opened".to_string());
                    }
                    continue;
                };
                let (request, respond) = request
                    .map_err(|error| format!("accept VLESS H2 TCP smoke h2 request: {error}"))?;
                if accepted {
                    return Err("VLESS H2 TCP smoke received an unexpected second h2 request".to_string());
                }
                accepted = true;
                let result_tx = result_tx.clone();
                tokio::spawn(async move {
                    let result = serve_vless_h2_tcp_relay_smoke_request(request, respond).await;
                    let _ = result_tx.send(result);
                });
            }
        }

        if !accepting && accepted {
            return result_rx.recv().await.unwrap_or_else(|| {
                Err("VLESS H2 TCP smoke request handler ended after connection close".to_string())
            });
        }
    }
}

async fn serve_vless_h2_tcp_relay_smoke_request(
    request: http::Request<h2::RecvStream>,
    mut respond: h2::server::SendResponse<Bytes>,
) -> Result<TcpRelaySmokeServerObservation, String> {
    validate_vless_h2_tcp_relay_smoke_request(&request)?;
    let mut body = request.into_body();
    let response = http::Response::builder()
        .status(http::StatusCode::OK)
        .body(())
        .map_err(|error| format!("build VLESS H2 TCP smoke h2 response: {error}"))?;
    let mut send = respond
        .send_response(response, false)
        .map_err(|error| format!("send VLESS H2 TCP smoke h2 response: {error}"))?;

    let mut buffer = Vec::new();
    let expected_header = encode_vless_tcp_request_header(
        VLESS_H2_TCP_RELAY_SMOKE_UUID,
        &Endpoint::new(
            VLESS_H2_TCP_RELAY_SMOKE_TARGET_HOST,
            VLESS_H2_TCP_RELAY_SMOKE_TARGET_PORT,
        ),
        None,
    )
    .map_err(|error| format!("encode expected VLESS H2 TCP smoke header: {error}"))?;
    let observed_header = read_h2_smoke_exact(
        &mut body,
        &mut buffer,
        expected_header.len(),
        "VLESS H2 TCP smoke header",
    )
    .await?;
    if observed_header != expected_header {
        return Err(format!(
            "unexpected VLESS H2 TCP smoke header: expected {:?}, got {:?}",
            expected_header, observed_header
        ));
    }
    send.send_data(Bytes::copy_from_slice(&[0x00, 0x00]), false)
        .map_err(|error| format!("send VLESS H2 TCP smoke response header: {error}"))?;

    let payload = read_h2_smoke_exact(
        &mut body,
        &mut buffer,
        VLESS_H2_TCP_RELAY_SMOKE_PAYLOAD.len(),
        "VLESS H2 TCP smoke payload",
    )
    .await?;
    if payload != VLESS_H2_TCP_RELAY_SMOKE_PAYLOAD {
        return Err(format!(
            "unexpected VLESS H2 TCP smoke payload: expected {:?}, got {:?}",
            VLESS_H2_TCP_RELAY_SMOKE_PAYLOAD, payload
        ));
    }
    send.send_data(
        Bytes::copy_from_slice(VLESS_H2_TCP_RELAY_SMOKE_RESPONSE),
        true,
    )
    .map_err(|error| format!("send VLESS H2 TCP smoke response data: {error}"))?;
    tokio::time::sleep(Duration::from_millis(50)).await;
    Ok(TcpRelaySmokeServerObservation {
        received_expected_payload: true,
    })
}

fn validate_vless_h2_tcp_relay_smoke_request(
    request: &http::Request<h2::RecvStream>,
) -> Result<(), String> {
    if request.method() != http::Method::PUT {
        return Err(format!(
            "unexpected VLESS H2 TCP smoke method: expected PUT, got {}",
            request.method()
        ));
    }
    if request.uri().path() != VLESS_H2_TCP_RELAY_SMOKE_PATH {
        return Err(format!(
            "unexpected VLESS H2 TCP smoke path: expected {}, got {}",
            VLESS_H2_TCP_RELAY_SMOKE_PATH,
            request.uri().path()
        ));
    }
    let authority = request
        .uri()
        .authority()
        .map(|authority| authority.as_str())
        .unwrap_or_default();
    if authority != VLESS_H2_TCP_RELAY_SMOKE_HOST {
        return Err(format!(
            "unexpected VLESS H2 TCP smoke authority: expected {}, got {authority}",
            VLESS_H2_TCP_RELAY_SMOKE_HOST
        ));
    }
    let scheme = request.uri().scheme_str().unwrap_or_default();
    if scheme != "http" {
        return Err(format!(
            "unexpected VLESS H2 TCP smoke scheme: expected http, got {scheme}"
        ));
    }
    Ok(())
}

fn vless_h2_tcp_relay_smoke_metrics_recorded(metrics: &ConnectionMetricsSnapshot) -> bool {
    metrics.total_connection_count >= 1
        && metrics.success_count >= 1
        && udp_relay_smoke_inbound_count(metrics, "socks5") >= 1
        && vless_h2_tcp_relay_smoke_outbound_route_count(metrics) >= 1
        && metrics.total_upload_bytes >= VLESS_H2_TCP_RELAY_SMOKE_PAYLOAD.len() as u64
        && metrics.total_download_bytes >= VLESS_H2_TCP_RELAY_SMOKE_RESPONSE.len() as u64
}

fn vless_h2_tcp_relay_smoke_outbound_route_count(metrics: &ConnectionMetricsSnapshot) -> u64 {
    metrics
        .route_action_counts
        .iter()
        .find(|entry| {
            entry.route_action
                == RouteAction::Outbound(VLESS_H2_TCP_RELAY_SMOKE_OUTBOUND.to_string())
        })
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn vless_h2_tcp_relay_smoke_target() -> String {
    format!(
        "{}:{}",
        VLESS_H2_TCP_RELAY_SMOKE_TARGET_HOST, VLESS_H2_TCP_RELAY_SMOKE_TARGET_PORT
    )
}

#[cfg(test)]
mod vless_h2_tcp_relay_smoke_tests {
    use super::*;

    #[test]
    fn default_vless_h2_tcp_relay_smoke_proves_h2_vless_round_trip() {
        let report = collect_default_vless_h2_tcp_relay_smoke_report();

        assert!(report.passed, "{report:#?}");
        assert_eq!(
            report.selected_outbound.as_deref(),
            Some(VLESS_H2_TCP_RELAY_SMOKE_OUTBOUND)
        );
        assert_eq!(report.target, vless_h2_tcp_relay_smoke_target());
        assert_eq!(
            report.request_payload_bytes,
            VLESS_H2_TCP_RELAY_SMOKE_PAYLOAD.len()
        );
        assert_eq!(
            report.response_payload_bytes,
            Some(VLESS_H2_TCP_RELAY_SMOKE_RESPONSE.len())
        );
        assert!(report.round_trip_observed);
        assert!(report.server_received_payload);
        assert!(report.metrics_recorded);
        assert!(report.metrics_total_connections >= 1);
        assert!(report.metrics_success_count >= 1);
        assert!(report.metrics_inbound_count >= 1);
        assert!(report.metrics_outbound_route_count >= 1);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));

        let case_names = report
            .cases
            .iter()
            .map(|case| case.name)
            .collect::<Vec<_>>();
        for expected in [
            "start-vless-h2-tcp-relay-runtime",
            "vless-h2-tcp-protocol-round-trip",
            "record-vless-h2-tcp-relay-metrics",
            "stop-vless-h2-tcp-relay-runtime",
        ] {
            assert!(
                case_names.contains(&expected),
                "missing VLESS H2 TCP relay smoke case {expected}: {case_names:?}"
            );
        }
        let round_trip = report
            .cases
            .iter()
            .find(|case| case.name == "vless-h2-tcp-protocol-round-trip")
            .expect("round trip case");
        assert_eq!(
            round_trip.observed_response.as_deref(),
            Some("keli-vless-h2-pong")
        );
        assert_eq!(round_trip.round_trip_observed, Some(true));
        assert_eq!(round_trip.server_received_payload, Some(true));
    }
}

fn collect_default_vless_h2_udp_relay_smoke_report() -> UdpRelaySmokeReport {
    let mut cases = Vec::new();
    let mut selected_outbound = None;
    let mut relay_port = None;
    let mut response_source = None;
    let request_payload_bytes = VLESS_H2_UDP_RELAY_SMOKE_PAYLOAD.len();
    let mut response_payload_bytes = None;
    let mut round_trip_observed = false;
    let mut server_received_payload = false;
    let mut metrics_recorded = false;
    let mut metrics_total_connections = 0;
    let mut metrics_success_count = 0;
    let mut metrics_inbound_count = 0;
    let mut metrics_outbound_route_count = 0;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let (vless_port, vless_thread) = match spawn_vless_h2_udp_relay_smoke_server() {
        Ok(server) => server,
        Err(error) => {
            cases.push(vless_h2_udp_relay_smoke_error_case(
                "start-vless-h2-udp-server",
                "start-protocol-server",
                error,
            ));
            return finalize_vless_h2_udp_relay_smoke_report(
                cases,
                selected_outbound,
                relay_port,
                response_source,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };

    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let config = vless_h2_udp_relay_smoke_config(vless_port);
    let relay_options = RelayOptions {
        first_byte_timeout: Some(UDP_RELAY_SMOKE_TIMEOUT),
        idle_timeout: Some(UDP_RELAY_SMOKE_TIMEOUT),
    };

    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some(VLESS_H2_UDP_RELAY_SMOKE_OUTBOUND.to_string()),
            relay_options,
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(vless_h2_udp_relay_smoke_error_case(
                "start-vless-h2-udp-relay-runtime",
                "start",
                error,
            ));
            let _ = join_udp_relay_smoke_server(vless_thread);
            return finalize_vless_h2_udp_relay_smoke_report(
                cases,
                selected_outbound,
                relay_port,
                response_source,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    selected_outbound = started.selected_outbound.clone();
    cases.push(vless_h2_udp_relay_smoke_start_case(&started));

    if let Some(listen_addr) = started.listen_addr {
        let exchange_result = run_vless_h2_udp_relay_smoke_exchange(listen_addr);
        let server_result = join_udp_relay_smoke_server(vless_thread);
        if let Ok(exchange) = exchange_result.as_ref() {
            relay_port = Some(exchange.relay_port);
            response_source = Some(exchange.response_source.clone());
            response_payload_bytes = Some(exchange.response_payload.len());
            round_trip_observed = exchange.response_payload == VLESS_H2_UDP_RELAY_SMOKE_RESPONSE;
        }
        if let Ok(server) = server_result.as_ref() {
            server_received_payload = server.received_expected_payload;
        }
        cases.push(vless_h2_udp_relay_smoke_exchange_case(
            exchange_result,
            server_result,
            round_trip_observed,
            server_received_payload,
        ));

        let status = wait_for_udp_relay_smoke_status(&core, |status| {
            vless_h2_udp_relay_smoke_metrics_recorded(&status.connection_metrics)
        });
        metrics_total_connections = status.connection_metrics.total_connection_count;
        metrics_success_count = status.connection_metrics.success_count;
        metrics_inbound_count =
            udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5-udp");
        metrics_outbound_route_count =
            vless_h2_udp_relay_smoke_outbound_route_count(&status.connection_metrics);
        metrics_recorded = vless_h2_udp_relay_smoke_metrics_recorded(&status.connection_metrics);
        cases.push(vless_h2_udp_relay_smoke_metrics_case(
            &status,
            metrics_recorded,
        ));
    } else {
        cases.push(vless_h2_udp_relay_smoke_error_case(
            "vless-h2-udp-protocol-round-trip",
            "socks5-udp-associate",
            "managed mixed runtime did not expose a listen address".to_string(),
        ));
        let _ = join_udp_relay_smoke_server(vless_thread);
    }

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(vless_h2_udp_relay_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(vless_h2_udp_relay_smoke_stop_case(
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
            Some(error),
        )),
    }

    finalize_vless_h2_udp_relay_smoke_report(
        cases,
        selected_outbound,
        relay_port,
        response_source,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn vless_h2_udp_relay_smoke_config(vless_port: u16) -> String {
    format!(
        r#"
proxies:
  - name: {VLESS_H2_UDP_RELAY_SMOKE_OUTBOUND}
    type: vless
    server: 127.0.0.1
    port: {vless_port}
    uuid: {VLESS_H2_UDP_RELAY_SMOKE_UUID}
    network: h2
    h2-opts:
      path: {VLESS_H2_UDP_RELAY_SMOKE_PATH}
      host:
        - {VLESS_H2_UDP_RELAY_SMOKE_HOST}
"#
    )
}

fn finalize_vless_h2_udp_relay_smoke_report(
    cases: Vec<UdpRelaySmokeCaseReport>,
    selected_outbound: Option<String>,
    relay_port: Option<u16>,
    response_source: Option<String>,
    request_payload_bytes: usize,
    response_payload_bytes: Option<usize>,
    round_trip_observed: bool,
    server_received_payload: bool,
    metrics_recorded: bool,
    metrics_total_connections: u64,
    metrics_success_count: u64,
    metrics_inbound_count: u64,
    metrics_outbound_route_count: u64,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> UdpRelaySmokeReport {
    let failed = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect::<Vec<_>>();
    let passed = failed.is_empty()
        && selected_outbound.as_deref() == Some(VLESS_H2_UDP_RELAY_SMOKE_OUTBOUND)
        && round_trip_observed
        && server_received_payload
        && metrics_recorded
        && clean_stop_observed;
    let target = vless_h2_udp_relay_smoke_target();
    let detail = format!(
        "cases={} passed={} failed={} failed_cases={} selected={} transport=h2 path={} host={} target={} relay_port={} response_source={} request_bytes={} response_bytes={} round_trip_observed={} server_received_payload={} metrics_recorded={} metrics_total={} metrics_success={} metrics_inbound_socks5_udp={} metrics_outbound_route={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
        cases.len(),
        passed,
        failed.len(),
        if failed.is_empty() {
            "-".to_string()
        } else {
            failed.join(",")
        },
        selected_outbound.as_deref().unwrap_or("-"),
        VLESS_H2_UDP_RELAY_SMOKE_PATH,
        VLESS_H2_UDP_RELAY_SMOKE_HOST,
        target,
        relay_port
            .map(|port| port.to_string())
            .unwrap_or_else(|| "-".to_string()),
        response_source.as_deref().unwrap_or("-"),
        request_payload_bytes,
        response_payload_bytes
            .map(|bytes| bytes.to_string())
            .unwrap_or_else(|| "-".to_string()),
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining
            .map(|workers| workers.to_string())
            .unwrap_or_else(|| "-".to_string()),
        stop_timed_out
            .map(|timed_out| timed_out.to_string())
            .unwrap_or_else(|| "-".to_string())
    );
    UdpRelaySmokeReport {
        passed,
        detail,
        selected_outbound,
        target,
        relay_port,
        response_source,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

