fn run_vmess_grpc_udp_relay_smoke_exchange(
    listen_addr: SocketAddr,
) -> Result<UdpRelaySmokeExchangeObservation, String> {
    let mut client = TcpStream::connect(listen_addr)
        .map_err(|error| format!("connect VMess gRPC UDP smoke listener {listen_addr}: {error}"))?;
    client
        .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set VMess gRPC UDP smoke control read timeout: {error}"))?;
    client
        .set_write_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set VMess gRPC UDP smoke control write timeout: {error}"))?;
    client
        .write_all(&[0x05, 0x01, 0x00])
        .map_err(|error| format!("write VMess gRPC UDP smoke SOCKS hello: {error}"))?;
    let mut hello = [0; 2];
    client
        .read_exact(&mut hello)
        .map_err(|error| format!("read VMess gRPC UDP smoke SOCKS hello: {error}"))?;
    if hello != [0x05, 0x00] {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke SOCKS hello response: {hello:?}"
        ));
    }

    client
        .write_all(&[0x05, 0x03, 0x00, 0x01, 127, 0, 0, 1, 0x00, 0x00])
        .map_err(|error| format!("write VMess gRPC UDP smoke associate request: {error}"))?;
    let mut reply = [0; 10];
    client
        .read_exact(&mut reply)
        .map_err(|error| format!("read VMess gRPC UDP smoke associate response: {error}"))?;
    if &reply[..4] != [0x05, 0x00, 0x00, 0x01] {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke associate response: {reply:?}"
        ));
    }
    let relay_port = u16::from_be_bytes([reply[8], reply[9]]);
    if relay_port == 0 {
        return Err("VMess gRPC UDP smoke relay returned port 0".to_string());
    }

    thread::sleep(Duration::from_millis(50));
    let udp_client = UdpSocket::bind("127.0.0.1:0")
        .map_err(|error| format!("bind VMess gRPC UDP smoke client: {error}"))?;
    udp_client
        .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set VMess gRPC UDP smoke client read timeout: {error}"))?;
    udp_client
        .set_write_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set VMess gRPC UDP smoke client write timeout: {error}"))?;
    let request = encode_socks5_udp_datagram(
        &Socks5Address::Ipv4(Ipv4Addr::LOCALHOST),
        VMESS_GRPC_UDP_RELAY_SMOKE_TARGET_PORT,
        VMESS_GRPC_UDP_RELAY_SMOKE_PAYLOAD,
    )
    .map_err(|error| format!("encode VMess gRPC UDP smoke request: {error}"))?;
    udp_client
        .send_to(&request, ("127.0.0.1", relay_port))
        .map_err(|error| format!("send VMess gRPC UDP smoke request: {error}"))?;

    let mut response = [0; 1500];
    let (size, _) = udp_client
        .recv_from(&mut response)
        .map_err(|error| format!("read VMess gRPC UDP smoke response: {error}"))?;
    let response = parse_socks5_udp_datagram(&response[..size])
        .map_err(|error| format!("parse VMess gRPC UDP smoke response: {error}"))?;
    client.shutdown(Shutdown::Both).ok();
    Ok(UdpRelaySmokeExchangeObservation {
        relay_port,
        response_source: format!(
            "{}:{}",
            udp_relay_smoke_socks5_address_label(&response.address),
            response.port
        ),
        response_payload: response.payload,
    })
}

fn spawn_vmess_grpc_udp_relay_smoke_server() -> Result<
    (
        u16,
        thread::JoinHandle<Result<UdpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind VMess gRPC UDP smoke server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set VMess gRPC UDP smoke accept mode: {error}"))?;
    let listen_port = listener
        .local_addr()
        .map_err(|error| format!("read VMess gRPC UDP smoke address: {error}"))?
        .port();
    let handle = thread::spawn(move || -> Result<UdpRelaySmokeServerObservation, String> {
        let deadline = Instant::now() + UDP_RELAY_SMOKE_TIMEOUT;
        let (stream, _) = loop {
            match listener.accept() {
                Ok(accepted) => break accepted,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err("VMess gRPC UDP smoke accept timed out".to_string());
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => return Err(format!("accept VMess gRPC UDP smoke server: {error}")),
            }
        };
        stream
            .set_nonblocking(true)
            .map_err(|error| format!("set VMess gRPC UDP smoke stream nonblocking: {error}"))?;
        let runtime = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .thread_name("keli-vmess-grpc-udp-smoke-server")
            .build()
            .map_err(|error| format!("build VMess gRPC UDP smoke runtime: {error}"))?;
        runtime.block_on(async move {
            tokio::time::timeout(
                UDP_RELAY_SMOKE_TIMEOUT,
                handle_vmess_grpc_udp_relay_smoke_stream(stream),
            )
            .await
            .map_err(|_| "VMess gRPC UDP smoke server timed out".to_string())?
        })
    });
    Ok((listen_port, handle))
}

async fn handle_vmess_grpc_udp_relay_smoke_stream(
    stream: TcpStream,
) -> Result<UdpRelaySmokeServerObservation, String> {
    let stream = tokio::net::TcpStream::from_std(stream)
        .map_err(|error| format!("convert VMess gRPC UDP smoke stream: {error}"))?;
    let mut h2 = h2::server::handshake(stream)
        .await
        .map_err(|error| format!("VMess gRPC UDP smoke h2 handshake: {error}"))?;
    let (result_tx, mut result_rx) =
        tokio::sync::mpsc::unbounded_channel::<Result<UdpRelaySmokeServerObservation, String>>();
    let mut accepted = false;
    let mut accepting = true;

    loop {
        tokio::select! {
            result = result_rx.recv() => {
                return result.unwrap_or_else(|| {
                    Err("VMess gRPC UDP smoke request handler ended without a result".to_string())
                });
            }
            request = h2.accept(), if accepting => {
                let Some(request) = request else {
                    accepting = false;
                    if !accepted {
                        return Err("VMess gRPC UDP smoke h2 stream was not opened".to_string());
                    }
                    continue;
                };
                let (request, respond) = request
                    .map_err(|error| format!("accept VMess gRPC UDP smoke h2 request: {error}"))?;
                if accepted {
                    return Err("VMess gRPC UDP smoke received an unexpected second h2 request".to_string());
                }
                accepted = true;
                let result_tx = result_tx.clone();
                tokio::spawn(async move {
                    let result =
                        serve_vmess_grpc_udp_relay_smoke_request(request, respond).await;
                    let _ = result_tx.send(result);
                });
            }
        }

        if !accepting && accepted {
            return result_rx.recv().await.unwrap_or_else(|| {
                Err("VMess gRPC UDP smoke request handler ended after connection close".to_string())
            });
        }
    }
}

async fn serve_vmess_grpc_udp_relay_smoke_request(
    request: http::Request<h2::RecvStream>,
    mut respond: h2::server::SendResponse<Bytes>,
) -> Result<UdpRelaySmokeServerObservation, String> {
    validate_vmess_grpc_udp_relay_smoke_request(&request)?;
    let mut body = request.into_body();
    let response = http::Response::builder()
        .status(http::StatusCode::OK)
        .header("content-type", "application/grpc")
        .body(())
        .map_err(|error| format!("build VMess gRPC UDP smoke h2 response: {error}"))?;
    let send = respond
        .send_response(response, false)
        .map_err(|error| format!("send VMess gRPC UDP smoke h2 response: {error}"))?;

    let (input_tx, input_rx) = std::sync::mpsc::channel::<Vec<u8>>();
    let (output_tx, mut output_rx) = tokio::sync::mpsc::unbounded_channel::<Vec<u8>>();
    let read_task = tokio::spawn(async move {
        read_grpc_smoke_hunks_to_channel(&mut body, input_tx, "VMess gRPC UDP smoke").await
    });
    let write_task = tokio::spawn(async move {
        let mut send = send;
        while let Some(payload) = output_rx.recv().await {
            send_grpc_smoke_hunk(&mut send, &payload, false).await?;
        }
        let mut trailers = http::HeaderMap::new();
        trailers.insert(
            "grpc-status",
            "0".parse()
                .map_err(|error| format!("build VMess gRPC UDP smoke trailer: {error}"))?,
        );
        if let Err(error) = send.send_trailers(trailers) {
            let error = error.to_string();
            if !error.contains("unexpected frame type") {
                return Err(format!("send VMess gRPC UDP smoke trailers: {error}"));
            }
        }
        tokio::time::sleep(Duration::from_millis(50)).await;
        Ok::<(), String>(())
    });

    let handler_result = tokio::task::spawn_blocking(move || {
        let mut stream = GrpcSmokeIoStream::new(input_rx, output_tx);
        handle_vmess_grpc_udp_relay_smoke_io(&mut stream)
    })
    .await
    .map_err(|error| format!("join VMess gRPC UDP smoke handler: {error}"))?;
    read_task.abort();
    write_task
        .await
        .map_err(|error| format!("join VMess gRPC UDP smoke writer: {error}"))??;
    handler_result
}

fn handle_vmess_grpc_udp_relay_smoke_io(
    stream: &mut GrpcSmokeIoStream,
) -> Result<UdpRelaySmokeServerObservation, String> {
    let request = read_vmess_tcp_relay_smoke_request(stream, VMESS_GRPC_UDP_RELAY_SMOKE_UUID)?;
    if request.target_host != VMESS_GRPC_UDP_RELAY_SMOKE_TARGET_HOST
        || request.target_port != VMESS_GRPC_UDP_RELAY_SMOKE_TARGET_PORT
    {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke target: expected {}:{}, got {}:{}",
            VMESS_GRPC_UDP_RELAY_SMOKE_TARGET_HOST,
            VMESS_GRPC_UDP_RELAY_SMOKE_TARGET_PORT,
            request.target_host,
            request.target_port
        ));
    }
    if request.command != VMESS_COMMAND_UDP {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke command: expected {VMESS_COMMAND_UDP}, got {}",
            request.command
        ));
    }
    if request.option != (VMESS_OPTION_CHUNK_STREAM | VMESS_OPTION_CHUNK_MASKING) {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke option: expected {}, got {}",
            VMESS_OPTION_CHUNK_STREAM | VMESS_OPTION_CHUNK_MASKING,
            request.option
        ));
    }
    if request.security != VMESS_SECURITY_AES_128_GCM {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke security: expected {VMESS_SECURITY_AES_128_GCM}, got {}",
            request.security
        ));
    }
    write_vmess_tcp_relay_smoke_response_header(stream, &request)?;
    stream
        .flush()
        .map_err(|error| format!("flush VMess gRPC UDP smoke response header: {error}"))?;

    let payload = read_vmess_tcp_relay_smoke_aes128_gcm_chunk(stream, &request)?;
    if payload != VMESS_GRPC_UDP_RELAY_SMOKE_PAYLOAD {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke payload: expected {:?}, got {:?}",
            VMESS_GRPC_UDP_RELAY_SMOKE_PAYLOAD, payload
        ));
    }
    write_vmess_tcp_relay_smoke_aes128_gcm_response_chunk(
        stream,
        &request,
        VMESS_GRPC_UDP_RELAY_SMOKE_RESPONSE,
    )?;
    stream
        .flush()
        .map_err(|error| format!("flush VMess gRPC UDP smoke response: {error}"))?;
    Ok(UdpRelaySmokeServerObservation {
        received_expected_payload: true,
    })
}

fn validate_vmess_grpc_udp_relay_smoke_request(
    request: &http::Request<h2::RecvStream>,
) -> Result<(), String> {
    if request.method() != http::Method::POST {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke method: expected POST, got {}",
            request.method()
        ));
    }
    let expected_path = format!("/{VMESS_GRPC_UDP_RELAY_SMOKE_SERVICE_NAME}/Tun");
    if request.uri().path() != expected_path {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke path: expected {expected_path}, got {}",
            request.uri().path()
        ));
    }
    let authority = request
        .uri()
        .authority()
        .map(|authority| authority.as_str())
        .unwrap_or_default();
    if authority != "127.0.0.1" {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke authority: expected 127.0.0.1, got {authority}"
        ));
    }
    let content_type = request
        .headers()
        .get("content-type")
        .and_then(|value| value.to_str().ok())
        .unwrap_or_default();
    if content_type != "application/grpc" {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke content-type: expected application/grpc, got {content_type}"
        ));
    }
    let te = request
        .headers()
        .get("te")
        .and_then(|value| value.to_str().ok())
        .unwrap_or_default();
    if te != "trailers" {
        return Err(format!(
            "unexpected VMess gRPC UDP smoke te header: expected trailers, got {te}"
        ));
    }
    Ok(())
}

fn vmess_grpc_udp_relay_smoke_metrics_recorded(metrics: &ConnectionMetricsSnapshot) -> bool {
    metrics.total_connection_count >= 1
        && metrics.success_count >= 1
        && udp_relay_smoke_inbound_count(metrics, "socks5-udp") >= 1
        && vmess_grpc_udp_relay_smoke_outbound_route_count(metrics) >= 1
        && metrics.total_upload_bytes >= VMESS_GRPC_UDP_RELAY_SMOKE_PAYLOAD.len() as u64
        && metrics.total_download_bytes >= VMESS_GRPC_UDP_RELAY_SMOKE_RESPONSE.len() as u64
}

fn vmess_grpc_udp_relay_smoke_outbound_route_count(metrics: &ConnectionMetricsSnapshot) -> u64 {
    metrics
        .route_action_counts
        .iter()
        .find(|entry| {
            entry.route_action
                == RouteAction::Outbound(VMESS_GRPC_UDP_RELAY_SMOKE_OUTBOUND.to_string())
        })
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn vmess_grpc_udp_relay_smoke_target() -> String {
    format!(
        "{}:{}",
        VMESS_GRPC_UDP_RELAY_SMOKE_TARGET_HOST, VMESS_GRPC_UDP_RELAY_SMOKE_TARGET_PORT
    )
}

#[cfg(test)]
mod vmess_grpc_udp_relay_smoke_tests {
    use super::*;

    #[test]
    fn default_vmess_grpc_udp_relay_smoke_proves_grpc_vmess_udp_round_trip() {
        let report = collect_default_vmess_grpc_udp_relay_smoke_report();

        assert!(report.passed, "{report:#?}");
        assert_eq!(
            report.selected_outbound.as_deref(),
            Some(VMESS_GRPC_UDP_RELAY_SMOKE_OUTBOUND)
        );
        assert_eq!(report.target, vmess_grpc_udp_relay_smoke_target());
        assert!(report.relay_port.is_some());
        assert_eq!(report.response_source.as_deref(), Some("127.0.0.1:53"));
        assert_eq!(
            report.request_payload_bytes,
            VMESS_GRPC_UDP_RELAY_SMOKE_PAYLOAD.len()
        );
        assert_eq!(
            report.response_payload_bytes,
            Some(VMESS_GRPC_UDP_RELAY_SMOKE_RESPONSE.len())
        );
        assert!(report.round_trip_observed);
        assert!(report.server_received_payload);
        assert!(report.metrics_recorded);
        assert!(report.metrics_total_connections >= 1);
        assert!(report.metrics_success_count >= 1);
        assert!(report.metrics_inbound_count >= 1);
        assert!(report.metrics_outbound_route_count >= 1);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));

        let case_names = report
            .cases
            .iter()
            .map(|case| case.name)
            .collect::<Vec<_>>();
        for expected in [
            "start-vmess-grpc-udp-relay-runtime",
            "vmess-grpc-udp-protocol-round-trip",
            "record-vmess-grpc-udp-relay-metrics",
            "stop-vmess-grpc-udp-relay-runtime",
        ] {
            assert!(
                case_names.contains(&expected),
                "missing VMess gRPC UDP relay smoke case {expected}: {case_names:?}"
            );
        }
        let round_trip = report
            .cases
            .iter()
            .find(|case| case.name == "vmess-grpc-udp-protocol-round-trip")
            .expect("round trip case");
        assert_eq!(
            round_trip.observed_response.as_deref(),
            Some("keli-vmess-grpc-udp-pong")
        );
        assert_eq!(round_trip.round_trip_observed, Some(true));
        assert_eq!(round_trip.server_received_payload, Some(true));
    }
}

fn collect_default_vmess_h2_tcp_relay_smoke_report() -> TcpRelaySmokeReport {
    let mut cases = Vec::new();
    let mut selected_outbound = None;
    let request_payload_bytes = VMESS_H2_TCP_RELAY_SMOKE_PAYLOAD.len();
    let mut response_payload_bytes = None;
    let mut round_trip_observed = false;
    let mut server_received_payload = false;
    let mut metrics_recorded = false;
    let mut metrics_total_connections = 0;
    let mut metrics_success_count = 0;
    let mut metrics_inbound_count = 0;
    let mut metrics_outbound_route_count = 0;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let (vmess_port, vmess_thread) = match spawn_vmess_h2_tcp_relay_smoke_server() {
        Ok(server) => server,
        Err(error) => {
            cases.push(vmess_h2_tcp_relay_smoke_error_case(
                "start-vmess-h2-tcp-server",
                "start-protocol-server",
                error,
            ));
            return finalize_vmess_h2_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };

    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let config = vmess_h2_tcp_relay_smoke_config(vmess_port);
    let relay_options = RelayOptions {
        first_byte_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
        idle_timeout: Some(TCP_RELAY_SMOKE_TIMEOUT),
    };

    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some(VMESS_H2_TCP_RELAY_SMOKE_OUTBOUND.to_string()),
            relay_options,
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(vmess_h2_tcp_relay_smoke_error_case(
                "start-vmess-h2-tcp-relay-runtime",
                "start",
                error,
            ));
            let _ = join_tcp_relay_smoke_server(vmess_thread);
            return finalize_vmess_h2_tcp_relay_smoke_report(
                cases,
                selected_outbound,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    selected_outbound = started.selected_outbound.clone();
    cases.push(vmess_h2_tcp_relay_smoke_start_case(&started));

    if let Some(listen_addr) = started.listen_addr {
        let exchange_result = run_vmess_h2_tcp_relay_smoke_exchange(listen_addr);
        let server_result = join_tcp_relay_smoke_server(vmess_thread);
        if let Ok(exchange) = exchange_result.as_ref() {
            response_payload_bytes = Some(exchange.response_payload.len());
            round_trip_observed = exchange.response_payload == VMESS_H2_TCP_RELAY_SMOKE_RESPONSE;
        }
        if let Ok(server) = server_result.as_ref() {
            server_received_payload = server.received_expected_payload;
        }
        cases.push(vmess_h2_tcp_relay_smoke_exchange_case(
            exchange_result,
            server_result,
            round_trip_observed,
            server_received_payload,
        ));

        let status = wait_for_udp_relay_smoke_status(&core, |status| {
            vmess_h2_tcp_relay_smoke_metrics_recorded(&status.connection_metrics)
        });
        metrics_total_connections = status.connection_metrics.total_connection_count;
        metrics_success_count = status.connection_metrics.success_count;
        metrics_inbound_count = udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5");
        metrics_outbound_route_count =
            vmess_h2_tcp_relay_smoke_outbound_route_count(&status.connection_metrics);
        metrics_recorded = vmess_h2_tcp_relay_smoke_metrics_recorded(&status.connection_metrics);
        cases.push(vmess_h2_tcp_relay_smoke_metrics_case(
            &status,
            metrics_recorded,
        ));
    } else {
        cases.push(vmess_h2_tcp_relay_smoke_error_case(
            "vmess-h2-tcp-relay-round-trip",
            "socks5-connect",
            "managed mixed runtime did not expose a listen address".to_string(),
        ));
        let _ = join_tcp_relay_smoke_server(vmess_thread);
    }

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(vmess_h2_tcp_relay_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(vmess_h2_tcp_relay_smoke_stop_case(
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
            Some(error),
        )),
    }

    finalize_vmess_h2_tcp_relay_smoke_report(
        cases,
        selected_outbound,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn vmess_h2_tcp_relay_smoke_config(vmess_port: u16) -> String {
    format!(
        r#"
proxies:
  - name: {VMESS_H2_TCP_RELAY_SMOKE_OUTBOUND}
    type: vmess
    server: 127.0.0.1
    port: {vmess_port}
    uuid: {VMESS_H2_TCP_RELAY_SMOKE_UUID}
    cipher: aes-128-gcm
    network: h2
    h2-opts:
      path: {VMESS_H2_TCP_RELAY_SMOKE_PATH}
      host:
        - {VMESS_H2_TCP_RELAY_SMOKE_HOST}
"#
    )
}

fn finalize_vmess_h2_tcp_relay_smoke_report(
    cases: Vec<TcpRelaySmokeCaseReport>,
    selected_outbound: Option<String>,
    request_payload_bytes: usize,
    response_payload_bytes: Option<usize>,
    round_trip_observed: bool,
    server_received_payload: bool,
    metrics_recorded: bool,
    metrics_total_connections: u64,
    metrics_success_count: u64,
    metrics_inbound_count: u64,
    metrics_outbound_route_count: u64,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> TcpRelaySmokeReport {
    let failed = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect::<Vec<_>>();
    let passed = failed.is_empty()
        && selected_outbound.as_deref() == Some(VMESS_H2_TCP_RELAY_SMOKE_OUTBOUND)
        && round_trip_observed
        && server_received_payload
        && metrics_recorded
        && clean_stop_observed;
    let target = vmess_h2_tcp_relay_smoke_target();
    let detail = format!(
        "cases={} passed={} failed={} failed_cases={} selected={} transport=h2 path={} host={} cipher=aes-128-gcm target={} request_bytes={} response_bytes={} round_trip_observed={} server_received_payload={} metrics_recorded={} metrics_total={} metrics_success={} metrics_inbound_socks5={} metrics_outbound_route={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
        cases.len(),
        passed,
        failed.len(),
        if failed.is_empty() {
            "-".to_string()
        } else {
            failed.join(",")
        },
        selected_outbound.as_deref().unwrap_or("-"),
        VMESS_H2_TCP_RELAY_SMOKE_PATH,
        VMESS_H2_TCP_RELAY_SMOKE_HOST,
        target,
        request_payload_bytes,
        response_payload_bytes
            .map(|bytes| bytes.to_string())
            .unwrap_or_else(|| "-".to_string()),
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining
            .map(|workers| workers.to_string())
            .unwrap_or_else(|| "-".to_string()),
        stop_timed_out
            .map(|timed_out| timed_out.to_string())
            .unwrap_or_else(|| "-".to_string())
    );
    TcpRelaySmokeReport {
        passed,
        detail,
        selected_outbound,
        target,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

