fn run_vmess_quic_tcp_relay_smoke_exchange(
    listen_addr: SocketAddr,
) -> Result<TcpRelaySmokeExchangeObservation, String> {
    let mut client = TcpStream::connect(listen_addr)
        .map_err(|error| format!("connect VMess QUIC TCP smoke listener {listen_addr}: {error}"))?;
    client
        .set_read_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set VMess QUIC TCP smoke client read timeout: {error}"))?;
    client
        .set_write_timeout(Some(TCP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set VMess QUIC TCP smoke client write timeout: {error}"))?;
    let target = OutboundTarget::new(
        VMESS_QUIC_TCP_RELAY_SMOKE_TARGET_HOST,
        VMESS_QUIC_TCP_RELAY_SMOKE_TARGET_PORT,
    );
    write_smoke_connect(&mut client, &target, SmokeInboundKind::Socks5)?;
    client
        .write_all(VMESS_QUIC_TCP_RELAY_SMOKE_PAYLOAD)
        .map_err(|error| format!("write VMess QUIC TCP smoke payload: {error}"))?;
    let mut response = vec![0; VMESS_QUIC_TCP_RELAY_SMOKE_RESPONSE.len()];
    client
        .read_exact(&mut response)
        .map_err(|error| format!("read VMess QUIC TCP smoke response: {error}"))?;
    client.shutdown(Shutdown::Both).ok();
    Ok(TcpRelaySmokeExchangeObservation {
        response_payload: response,
    })
}

fn spawn_vmess_quic_tcp_relay_smoke_server() -> Result<
    (
        u16,
        thread::JoinHandle<Result<TcpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    let server_config = vmess_quic_tcp_relay_smoke_server_config()?;
    let (port_tx, port_rx) = std::sync::mpsc::channel();
    let handle = thread::spawn(move || -> Result<TcpRelaySmokeServerObservation, String> {
        let runtime = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .map_err(|error| format!("build VMess QUIC TCP smoke runtime: {error}"))?;
        runtime.block_on(async move {
            let endpoint = match quinn::Endpoint::server(
                server_config,
                SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), 0),
            ) {
                Ok(endpoint) => endpoint,
                Err(error) => {
                    let message = format!("bind VMess QUIC TCP smoke server: {error}");
                    let _ = port_tx.send(Err(message.clone()));
                    return Err(message);
                }
            };
            let listen_port = match endpoint.local_addr() {
                Ok(address) => address.port(),
                Err(error) => {
                    let message = format!("read VMess QUIC TCP smoke address: {error}");
                    let _ = port_tx.send(Err(message.clone()));
                    return Err(message);
                }
            };
            port_tx
                .send(Ok(listen_port))
                .map_err(|error| format!("publish VMess QUIC TCP smoke address: {error}"))?;
            let incoming = tokio::time::timeout(TCP_RELAY_SMOKE_TIMEOUT, endpoint.accept())
                .await
                .map_err(|_| "VMess QUIC TCP smoke accept timed out".to_string())?
                .ok_or_else(|| "VMess QUIC TCP smoke endpoint closed before accept".to_string())?;
            let connection = tokio::time::timeout(TCP_RELAY_SMOKE_TIMEOUT, incoming)
                .await
                .map_err(|_| "VMess QUIC TCP smoke handshake timed out".to_string())?
                .map_err(|error| format!("accept VMess QUIC TCP connection: {error}"))?;
            let (mut send, mut recv) =
                tokio::time::timeout(TCP_RELAY_SMOKE_TIMEOUT, connection.accept_bi())
                    .await
                    .map_err(|_| "VMess QUIC TCP stream accept timed out".to_string())?
                    .map_err(|error| format!("accept VMess QUIC TCP stream: {error}"))?;
            let request =
                read_vmess_quic_tcp_relay_smoke_request(&mut recv, VMESS_QUIC_TCP_RELAY_SMOKE_UUID)
                    .await?;
            if request.target_host != VMESS_QUIC_TCP_RELAY_SMOKE_TARGET_HOST
                || request.target_port != VMESS_QUIC_TCP_RELAY_SMOKE_TARGET_PORT
            {
                return Err(format!(
                    "unexpected VMess QUIC TCP smoke target: expected {}:{}, got {}:{}",
                    VMESS_QUIC_TCP_RELAY_SMOKE_TARGET_HOST,
                    VMESS_QUIC_TCP_RELAY_SMOKE_TARGET_PORT,
                    request.target_host,
                    request.target_port
                ));
            }
            if request.command != VMESS_COMMAND_TCP {
                return Err(format!(
                    "unexpected VMess QUIC TCP smoke command: expected {VMESS_COMMAND_TCP}, got {}",
                    request.command
                ));
            }
            if request.security != VMESS_SECURITY_AES_128_GCM {
                return Err(format!(
                    "unexpected VMess QUIC TCP smoke security: expected {VMESS_SECURITY_AES_128_GCM}, got {}",
                    request.security
                ));
            }
            write_vmess_quic_tcp_relay_smoke_response_header(&mut send, &request).await?;
            let payload =
                read_vmess_quic_tcp_relay_smoke_aes128_gcm_chunk(&mut recv, &request).await?;
            if payload != VMESS_QUIC_TCP_RELAY_SMOKE_PAYLOAD {
                return Err(format!(
                    "unexpected VMess QUIC TCP smoke payload: expected {:?}, got {:?}",
                    VMESS_QUIC_TCP_RELAY_SMOKE_PAYLOAD, payload
                ));
            }
            write_vmess_quic_tcp_relay_smoke_aes128_gcm_response_chunk(
                &mut send,
                &request,
                VMESS_QUIC_TCP_RELAY_SMOKE_RESPONSE,
            )
            .await?;
            send.finish()
                .map_err(|error| format!("finish VMess QUIC TCP response stream: {error}"))?;
            tokio::time::sleep(Duration::from_millis(50)).await;
            Ok(TcpRelaySmokeServerObservation {
                received_expected_payload: true,
            })
        })
    });
    let listen_port = match port_rx.recv_timeout(TCP_RELAY_SMOKE_TIMEOUT) {
        Ok(Ok(port)) => port,
        Ok(Err(error)) => {
            let _ = join_tcp_relay_smoke_server(handle);
            return Err(error);
        }
        Err(error) => {
            let _ = join_tcp_relay_smoke_server(handle);
            return Err(format!("receive VMess QUIC TCP smoke address: {error}"));
        }
    };
    Ok((listen_port, handle))
}

async fn read_vmess_quic_tcp_relay_smoke_request(
    recv: &mut quinn::RecvStream,
    uuid: &str,
) -> Result<VmessTcpRelaySmokeRequest, String> {
    let uuid = parse_vmess_tcp_relay_smoke_uuid(uuid)?;
    let cmd_key = vmess_tcp_relay_smoke_cmd_key(&uuid);
    let mut auth_id = [0; 16];
    let mut encrypted_len = [0; 18];
    let mut nonce = [0; 8];
    tokio::time::timeout(TCP_RELAY_SMOKE_TIMEOUT, recv.read_exact(&mut auth_id))
        .await
        .map_err(|_| "VMess QUIC TCP auth id read timed out".to_string())?
        .map_err(|error| format!("read VMess QUIC TCP smoke auth id: {error}"))?;
    if !vmess_tcp_relay_smoke_auth_id_is_valid(&cmd_key, &auth_id) {
        return Err("VMess QUIC TCP smoke auth id failed validation".to_string());
    }
    tokio::time::timeout(TCP_RELAY_SMOKE_TIMEOUT, recv.read_exact(&mut encrypted_len))
        .await
        .map_err(|_| "VMess QUIC TCP header length read timed out".to_string())?
        .map_err(|error| format!("read VMess QUIC TCP smoke header length: {error}"))?;
    tokio::time::timeout(TCP_RELAY_SMOKE_TIMEOUT, recv.read_exact(&mut nonce))
        .await
        .map_err(|_| "VMess QUIC TCP nonce read timed out".to_string())?
        .map_err(|error| format!("read VMess QUIC TCP smoke nonce: {error}"))?;

    let len_key =
        vmess_tcp_relay_smoke_kdf16(&cmd_key, &[VMESS_HEADER_LENGTH_KEY, &auth_id, &nonce]);
    let len_nonce = first_12_vmess_tcp_relay_smoke(&vmess_tcp_relay_smoke_kdf(
        &cmd_key,
        &[VMESS_HEADER_LENGTH_NONCE, &auth_id, &nonce],
    ));
    let len_plain =
        vmess_tcp_relay_smoke_aes_gcm_open(&len_key, &len_nonce, &encrypted_len, &auth_id)?;
    if len_plain.len() != 2 {
        return Err(format!(
            "unexpected VMess QUIC TCP smoke header length payload bytes: {}",
            len_plain.len()
        ));
    }
    let header_len = u16::from_be_bytes([len_plain[0], len_plain[1]]) as usize;
    let mut encrypted_header = vec![0; header_len + 16];
    tokio::time::timeout(
        TCP_RELAY_SMOKE_TIMEOUT,
        recv.read_exact(&mut encrypted_header),
    )
    .await
    .map_err(|_| "VMess QUIC TCP request header read timed out".to_string())?
    .map_err(|error| format!("read VMess QUIC TCP smoke request header: {error}"))?;
    let payload_key =
        vmess_tcp_relay_smoke_kdf16(&cmd_key, &[VMESS_HEADER_PAYLOAD_KEY, &auth_id, &nonce]);
    let payload_nonce = first_12_vmess_tcp_relay_smoke(&vmess_tcp_relay_smoke_kdf(
        &cmd_key,
        &[VMESS_HEADER_PAYLOAD_NONCE, &auth_id, &nonce],
    ));
    let header = vmess_tcp_relay_smoke_aes_gcm_open(
        &payload_key,
        &payload_nonce,
        &encrypted_header,
        &auth_id,
    )?;
    if header.len() < 41 {
        return Err(format!(
            "VMess QUIC TCP smoke header too short: {} bytes",
            header.len()
        ));
    }
    if header[0] != 0x01 {
        return Err(format!(
            "unexpected VMess QUIC TCP smoke version: expected 1, got {}",
            header[0]
        ));
    }
    let request_body_iv = header[1..17]
        .try_into()
        .map_err(|_| "VMess QUIC TCP smoke request iv length mismatch".to_string())?;
    let request_body_key = header[17..33]
        .try_into()
        .map_err(|_| "VMess QUIC TCP smoke request key length mismatch".to_string())?;
    let response_header = header[33];
    let option = header[34];
    let security = header[35] & 0x0f;
    let command = header[37];
    let target_port = u16::from_be_bytes([header[38], header[39]]);
    let target_host = match header[40] {
        VMESS_ATYP_IPV4 => {
            if header.len() < 45 {
                return Err(format!(
                    "VMess QUIC TCP smoke IPv4 target is truncated: header_bytes={}",
                    header.len()
                ));
            }
            Ipv4Addr::new(header[41], header[42], header[43], header[44]).to_string()
        }
        VMESS_ATYP_DOMAIN => {
            if header.len() < 42 {
                return Err("VMess QUIC TCP smoke domain header is truncated".to_string());
            }
            let domain_len = header[41] as usize;
            if header.len() < 42 + domain_len {
                return Err(format!(
                    "VMess QUIC TCP smoke domain is truncated: len={} header_bytes={}",
                    domain_len,
                    header.len()
                ));
            }
            String::from_utf8(header[42..42 + domain_len].to_vec())
                .map_err(|error| format!("decode VMess QUIC TCP smoke target domain: {error}"))?
        }
        value => {
            return Err(format!(
                "unexpected VMess QUIC TCP smoke target address type: {value}"
            ));
        }
    };

    Ok(VmessTcpRelaySmokeRequest {
        target_host,
        target_port,
        command,
        option,
        security,
        request_body_key,
        request_body_iv,
        response_header,
    })
}

async fn write_vmess_quic_tcp_relay_smoke_response_header(
    send: &mut quinn::SendStream,
    request: &VmessTcpRelaySmokeRequest,
) -> Result<(), String> {
    let mut response = Vec::new();
    write_vmess_tcp_relay_smoke_response_header(&mut response, request)?;
    tokio::time::timeout(TCP_RELAY_SMOKE_TIMEOUT, send.write_all(&response))
        .await
        .map_err(|_| "VMess QUIC TCP response header write timed out".to_string())?
        .map_err(|error| format!("write VMess QUIC TCP response header: {error}"))
}

async fn read_vmess_quic_tcp_relay_smoke_aes128_gcm_chunk(
    recv: &mut quinn::RecvStream,
    request: &VmessTcpRelaySmokeRequest,
) -> Result<Vec<u8>, String> {
    let mut masked_len = [0; 2];
    tokio::time::timeout(TCP_RELAY_SMOKE_TIMEOUT, recv.read_exact(&mut masked_len))
        .await
        .map_err(|_| "VMess QUIC TCP chunk length read timed out".to_string())?
        .map_err(|error| format!("read VMess QUIC TCP masked chunk length: {error}"))?;
    let encrypted_len =
        u16::from_be_bytes(masked_len) ^ vmess_tcp_relay_smoke_chunk_mask(&request.request_body_iv);
    let mut encrypted_payload = vec![0; usize::from(encrypted_len)];
    tokio::time::timeout(
        TCP_RELAY_SMOKE_TIMEOUT,
        recv.read_exact(&mut encrypted_payload),
    )
    .await
    .map_err(|_| "VMess QUIC TCP encrypted chunk read timed out".to_string())?
    .map_err(|error| format!("read VMess QUIC TCP encrypted chunk: {error}"))?;
    let nonce = vmess_tcp_relay_smoke_body_nonce(&request.request_body_iv, 0);
    vmess_tcp_relay_smoke_aes_gcm_open(&request.request_body_key, &nonce, &encrypted_payload, &[])
}

async fn write_vmess_quic_tcp_relay_smoke_aes128_gcm_response_chunk(
    send: &mut quinn::SendStream,
    request: &VmessTcpRelaySmokeRequest,
    payload: &[u8],
) -> Result<(), String> {
    let mut response = Vec::new();
    write_vmess_tcp_relay_smoke_aes128_gcm_response_chunk(&mut response, request, payload)?;
    tokio::time::timeout(TCP_RELAY_SMOKE_TIMEOUT, send.write_all(&response))
        .await
        .map_err(|_| "VMess QUIC TCP response chunk write timed out".to_string())?
        .map_err(|error| format!("write VMess QUIC TCP response chunk: {error}"))
}

fn vmess_quic_tcp_relay_smoke_server_config() -> Result<quinn::ServerConfig, String> {
    let cert = generate_simple_self_signed(vec![VMESS_QUIC_TCP_RELAY_SMOKE_SNI.to_string()])
        .map_err(|error| format!("generate VMess QUIC TCP smoke cert: {error}"))?;
    let cert_der: CertificateDer<'static> = cert.cert.der().clone();
    let key_der = PrivateKeyDer::Pkcs8(cert.signing_key.serialize_der().into());
    let tls = rustls::ServerConfig::builder_with_provider(
        rustls::crypto::ring::default_provider().into(),
    )
    .with_protocol_versions(&[&rustls::version::TLS13])
    .map_err(|error| format!("configure VMess QUIC TCP smoke TLS versions: {error}"))?
    .with_no_client_auth()
    .with_single_cert(vec![cert_der], key_der)
    .map_err(|error| format!("configure VMess QUIC TCP smoke certificate: {error}"))?;
    quinn::crypto::rustls::QuicServerConfig::try_from(tls)
        .map(|config| quinn::ServerConfig::with_crypto(Arc::new(config)))
        .map_err(|error| format!("configure VMess QUIC TCP smoke server: {error}"))
}

fn vmess_quic_tcp_relay_smoke_metrics_recorded(metrics: &ConnectionMetricsSnapshot) -> bool {
    metrics.total_connection_count >= 1
        && metrics.success_count >= 1
        && udp_relay_smoke_inbound_count(metrics, "socks5") >= 1
        && vmess_quic_tcp_relay_smoke_outbound_route_count(metrics) >= 1
        && metrics.total_upload_bytes >= VMESS_QUIC_TCP_RELAY_SMOKE_PAYLOAD.len() as u64
        && metrics.total_download_bytes >= VMESS_QUIC_TCP_RELAY_SMOKE_RESPONSE.len() as u64
}

fn vmess_quic_tcp_relay_smoke_outbound_route_count(metrics: &ConnectionMetricsSnapshot) -> u64 {
    metrics
        .route_action_counts
        .iter()
        .find(|entry| {
            entry.route_action
                == RouteAction::Outbound(VMESS_QUIC_TCP_RELAY_SMOKE_OUTBOUND.to_string())
        })
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn vmess_quic_tcp_relay_smoke_target() -> String {
    format!(
        "{}:{}",
        VMESS_QUIC_TCP_RELAY_SMOKE_TARGET_HOST, VMESS_QUIC_TCP_RELAY_SMOKE_TARGET_PORT
    )
}

#[cfg(test)]
mod vmess_quic_tcp_relay_smoke_tests {
    use super::*;

    #[test]
    fn default_vmess_quic_tcp_relay_smoke_proves_quic_vmess_round_trip() {
        let report = collect_default_vmess_quic_tcp_relay_smoke_report();

        assert!(report.passed, "{report:#?}");
        assert_eq!(
            report.selected_outbound.as_deref(),
            Some(VMESS_QUIC_TCP_RELAY_SMOKE_OUTBOUND)
        );
        assert_eq!(report.target, vmess_quic_tcp_relay_smoke_target());
        assert_eq!(
            report.request_payload_bytes,
            VMESS_QUIC_TCP_RELAY_SMOKE_PAYLOAD.len()
        );
        assert_eq!(
            report.response_payload_bytes,
            Some(VMESS_QUIC_TCP_RELAY_SMOKE_RESPONSE.len())
        );
        assert!(report.round_trip_observed);
        assert!(report.server_received_payload);
        assert!(report.metrics_recorded);
        assert!(report.metrics_total_connections >= 1);
        assert!(report.metrics_success_count >= 1);
        assert!(report.metrics_inbound_count >= 1);
        assert!(report.metrics_outbound_route_count >= 1);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));

        let case_names = report
            .cases
            .iter()
            .map(|case| case.name)
            .collect::<Vec<_>>();
        for expected in [
            "start-vmess-quic-tcp-relay-runtime",
            "vmess-quic-tcp-protocol-round-trip",
            "record-vmess-quic-tcp-relay-metrics",
            "stop-vmess-quic-tcp-relay-runtime",
        ] {
            assert!(
                case_names.contains(&expected),
                "missing VMess QUIC TCP relay smoke case {expected}: {case_names:?}"
            );
        }
        let round_trip = report
            .cases
            .iter()
            .find(|case| case.name == "vmess-quic-tcp-protocol-round-trip")
            .expect("round trip case");
        assert_eq!(
            round_trip.observed_response.as_deref(),
            Some("keli-vmess-quic-pong")
        );
        assert_eq!(round_trip.round_trip_observed, Some(true));
        assert_eq!(round_trip.server_received_payload, Some(true));
    }
}

fn collect_default_vmess_quic_udp_relay_smoke_report() -> UdpRelaySmokeReport {
    let mut cases = Vec::new();
    let mut selected_outbound = None;
    let mut relay_port = None;
    let mut response_source = None;
    let request_payload_bytes = VMESS_QUIC_UDP_RELAY_SMOKE_PAYLOAD.len();
    let mut response_payload_bytes = None;
    let mut round_trip_observed = false;
    let mut server_received_payload = false;
    let mut metrics_recorded = false;
    let mut metrics_total_connections = 0;
    let mut metrics_success_count = 0;
    let mut metrics_inbound_count = 0;
    let mut metrics_outbound_route_count = 0;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let (vmess_port, vmess_thread) = match spawn_vmess_quic_udp_relay_smoke_server() {
        Ok(server) => server,
        Err(error) => {
            cases.push(vmess_quic_udp_relay_smoke_error_case(
                "start-vmess-quic-udp-server",
                "start-protocol-server",
                error,
            ));
            return finalize_vmess_quic_udp_relay_smoke_report(
                cases,
                selected_outbound,
                relay_port,
                response_source,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };

    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let config = vmess_quic_udp_relay_smoke_config(vmess_port);
    let relay_options = RelayOptions {
        first_byte_timeout: Some(UDP_RELAY_SMOKE_TIMEOUT),
        idle_timeout: Some(UDP_RELAY_SMOKE_TIMEOUT),
    };

    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some(VMESS_QUIC_UDP_RELAY_SMOKE_OUTBOUND.to_string()),
            relay_options,
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(vmess_quic_udp_relay_smoke_error_case(
                "start-vmess-quic-udp-relay-runtime",
                "start",
                error,
            ));
            let _ = join_udp_relay_smoke_server(vmess_thread);
            return finalize_vmess_quic_udp_relay_smoke_report(
                cases,
                selected_outbound,
                relay_port,
                response_source,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    selected_outbound = started.selected_outbound.clone();
    cases.push(vmess_quic_udp_relay_smoke_start_case(&started));

    if let Some(listen_addr) = started.listen_addr {
        let exchange_result = run_vmess_quic_udp_relay_smoke_exchange(listen_addr);
        let server_result = join_udp_relay_smoke_server(vmess_thread);
        if let Ok(exchange) = exchange_result.as_ref() {
            relay_port = Some(exchange.relay_port);
            response_source = Some(exchange.response_source.clone());
            response_payload_bytes = Some(exchange.response_payload.len());
            round_trip_observed = exchange.response_payload == VMESS_QUIC_UDP_RELAY_SMOKE_RESPONSE;
        }
        if let Ok(server) = server_result.as_ref() {
            server_received_payload = server.received_expected_payload;
        }
        cases.push(vmess_quic_udp_relay_smoke_exchange_case(
            exchange_result,
            server_result,
            round_trip_observed,
            server_received_payload,
        ));

        let status = wait_for_udp_relay_smoke_status(&core, |status| {
            vmess_quic_udp_relay_smoke_metrics_recorded(&status.connection_metrics)
        });
        metrics_total_connections = status.connection_metrics.total_connection_count;
        metrics_success_count = status.connection_metrics.success_count;
        metrics_inbound_count =
            udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5-udp");
        metrics_outbound_route_count =
            vmess_quic_udp_relay_smoke_outbound_route_count(&status.connection_metrics);
        metrics_recorded = vmess_quic_udp_relay_smoke_metrics_recorded(&status.connection_metrics);
        cases.push(vmess_quic_udp_relay_smoke_metrics_case(
            &status,
            metrics_recorded,
        ));
    } else {
        cases.push(vmess_quic_udp_relay_smoke_error_case(
            "vmess-quic-udp-protocol-round-trip",
            "socks5-udp-associate",
            "managed mixed runtime did not expose a listen address".to_string(),
        ));
        let _ = join_udp_relay_smoke_server(vmess_thread);
    }

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(vmess_quic_udp_relay_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(vmess_quic_udp_relay_smoke_stop_case(
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
            Some(error),
        )),
    }

    finalize_vmess_quic_udp_relay_smoke_report(
        cases,
        selected_outbound,
        relay_port,
        response_source,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn vmess_quic_udp_relay_smoke_config(vmess_port: u16) -> String {
    format!(
        r#"
proxies:
  - name: {VMESS_QUIC_UDP_RELAY_SMOKE_OUTBOUND}
    type: vmess
    server: 127.0.0.1
    port: {vmess_port}
    uuid: {VMESS_QUIC_UDP_RELAY_SMOKE_UUID}
    cipher: aes-128-gcm
    tls: true
    sni: {VMESS_QUIC_UDP_RELAY_SMOKE_SNI}
    skip-cert-verify: true
    network: quic
"#
    )
}

fn finalize_vmess_quic_udp_relay_smoke_report(
    cases: Vec<UdpRelaySmokeCaseReport>,
    selected_outbound: Option<String>,
    relay_port: Option<u16>,
    response_source: Option<String>,
    request_payload_bytes: usize,
    response_payload_bytes: Option<usize>,
    round_trip_observed: bool,
    server_received_payload: bool,
    metrics_recorded: bool,
    metrics_total_connections: u64,
    metrics_success_count: u64,
    metrics_inbound_count: u64,
    metrics_outbound_route_count: u64,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> UdpRelaySmokeReport {
    let failed = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect::<Vec<_>>();
    let passed = failed.is_empty()
        && selected_outbound.as_deref() == Some(VMESS_QUIC_UDP_RELAY_SMOKE_OUTBOUND)
        && round_trip_observed
        && server_received_payload
        && metrics_recorded
        && clean_stop_observed;
    let target = vmess_quic_udp_relay_smoke_target();
    let detail = format!(
        "cases={} passed={} failed={} failed_cases={} selected={} transport=quic sni={} cipher=aes-128-gcm target={} relay_port={} response_source={} request_bytes={} response_bytes={} round_trip_observed={} server_received_payload={} metrics_recorded={} metrics_total={} metrics_success={} metrics_inbound_socks5_udp={} metrics_outbound_route={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
        cases.len(),
        passed,
        failed.len(),
        if failed.is_empty() {
            "-".to_string()
        } else {
            failed.join(",")
        },
        selected_outbound.as_deref().unwrap_or("-"),
        VMESS_QUIC_UDP_RELAY_SMOKE_SNI,
        target,
        relay_port
            .map(|port| port.to_string())
            .unwrap_or_else(|| "-".to_string()),
        response_source.as_deref().unwrap_or("-"),
        request_payload_bytes,
        response_payload_bytes
            .map(|bytes| bytes.to_string())
            .unwrap_or_else(|| "-".to_string()),
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining
            .map(|workers| workers.to_string())
            .unwrap_or_else(|| "-".to_string()),
        stop_timed_out
            .map(|timed_out| timed_out.to_string())
            .unwrap_or_else(|| "-".to_string())
    );
    UdpRelaySmokeReport {
        passed,
        detail,
        selected_outbound,
        target,
        relay_port,
        response_source,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

fn vmess_quic_udp_relay_smoke_start_case(
    status: &ManagedMixedStatusSnapshot,
) -> UdpRelaySmokeCaseReport {
    let selected = status.selected_outbound.clone();
    let passed = selected.as_deref() == Some(VMESS_QUIC_UDP_RELAY_SMOKE_OUTBOUND)
        && status.generation == 1
        && matches!(&status.status, RuntimeStatus::Running { .. });
    UdpRelaySmokeCaseReport {
        name: "start-vmess-quic-udp-relay-runtime",
        action: "start",
        expected_selected_outbound: Some(VMESS_QUIC_UDP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: selected,
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        target: vmess_quic_udp_relay_smoke_target(),
        relay_port: None,
        expected_response: None,
        observed_response: None,
        response_source: None,
        request_payload_bytes: None,
        response_payload_bytes: None,
        runtime_running: Some(matches!(&status.status, RuntimeStatus::Running { .. })),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error: None,
    }
}

fn vmess_quic_udp_relay_smoke_exchange_case(
    exchange_result: Result<UdpRelaySmokeExchangeObservation, String>,
    server_result: Result<UdpRelaySmokeServerObservation, String>,
    round_trip_observed: bool,
    server_received_payload: bool,
) -> UdpRelaySmokeCaseReport {
    let error = match (&exchange_result, &server_result) {
        (Ok(_), Ok(_)) => None,
        (Err(error), Ok(_)) => Some(error.clone()),
        (Ok(_), Err(error)) => Some(error.clone()),
        (Err(exchange_error), Err(server_error)) => {
            Some(format!("{exchange_error}; server={server_error}"))
        }
    };
    let (relay_port, observed_response, response_source, response_payload_bytes) =
        match exchange_result.as_ref() {
            Ok(exchange) => (
                Some(exchange.relay_port),
                Some(String::from_utf8_lossy(&exchange.response_payload).to_string()),
                Some(exchange.response_source.clone()),
                Some(exchange.response_payload.len()),
            ),
            Err(_) => (None, None, None, None),
        };
    let passed =
        error.is_none() && round_trip_observed && server_received_payload && relay_port.is_some();
    UdpRelaySmokeCaseReport {
        name: "vmess-quic-udp-protocol-round-trip",
        action: "socks5-udp-associate",
        expected_selected_outbound: Some(VMESS_QUIC_UDP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: vmess_quic_udp_relay_smoke_target(),
        relay_port,
        expected_response: Some(
            String::from_utf8_lossy(VMESS_QUIC_UDP_RELAY_SMOKE_RESPONSE).to_string(),
        ),
        observed_response,
        response_source,
        request_payload_bytes: Some(VMESS_QUIC_UDP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes,
        runtime_running: None,
        round_trip_observed: Some(round_trip_observed),
        server_received_payload: Some(server_received_payload),
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error,
    }
}

fn vmess_quic_udp_relay_smoke_metrics_case(
    status: &ManagedMixedStatusSnapshot,
    metrics_recorded: bool,
) -> UdpRelaySmokeCaseReport {
    let inbound_count = udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5-udp");
    let outbound_route_count =
        vmess_quic_udp_relay_smoke_outbound_route_count(&status.connection_metrics);
    UdpRelaySmokeCaseReport {
        name: "record-vmess-quic-udp-relay-metrics",
        action: "metrics",
        expected_selected_outbound: Some(VMESS_QUIC_UDP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: status.selected_outbound.clone(),
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        target: vmess_quic_udp_relay_smoke_target(),
        relay_port: None,
        expected_response: None,
        observed_response: None,
        response_source: None,
        request_payload_bytes: Some(VMESS_QUIC_UDP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: Some(VMESS_QUIC_UDP_RELAY_SMOKE_RESPONSE.len()),
        runtime_running: Some(matches!(&status.status, RuntimeStatus::Running { .. })),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: Some(metrics_recorded),
        metrics_total_connections: Some(status.connection_metrics.total_connection_count),
        metrics_success_count: Some(status.connection_metrics.success_count),
        metrics_inbound_count: Some(inbound_count),
        metrics_outbound_route_count: Some(outbound_route_count),
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed: metrics_recorded,
        error: if metrics_recorded {
            None
        } else {
            Some(format!(
                "metrics did not record VMess QUIC UDP relay: total={} success={} inbound_socks5_udp={} outbound_route={} upload_bytes={} download_bytes={}",
                status.connection_metrics.total_connection_count,
                status.connection_metrics.success_count,
                inbound_count,
                outbound_route_count,
                status.connection_metrics.total_upload_bytes,
                status.connection_metrics.total_download_bytes
            ))
        },
    }
}

