fn run_mieru_tcp_udp_relay_smoke_exchange(
    listen_addr: SocketAddr,
) -> Result<UdpRelaySmokeExchangeObservation, String> {
    let mut client = TcpStream::connect(listen_addr)
        .map_err(|error| format!("connect Mieru TCP UDP smoke listener {listen_addr}: {error}"))?;
    client
        .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Mieru TCP UDP smoke control read timeout: {error}"))?;
    client
        .set_write_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Mieru TCP UDP smoke control write timeout: {error}"))?;
    client
        .write_all(&[0x05, 0x01, 0x00])
        .map_err(|error| format!("write Mieru TCP UDP smoke SOCKS hello: {error}"))?;
    let mut hello = [0; 2];
    client
        .read_exact(&mut hello)
        .map_err(|error| format!("read Mieru TCP UDP smoke SOCKS hello: {error}"))?;
    if hello != [0x05, 0x00] {
        return Err(format!(
            "unexpected Mieru TCP UDP smoke SOCKS hello response: {hello:?}"
        ));
    }

    client
        .write_all(&[0x05, 0x03, 0x00, 0x01, 127, 0, 0, 1, 0x00, 0x00])
        .map_err(|error| format!("write Mieru TCP UDP smoke associate request: {error}"))?;
    let mut reply = [0; 10];
    client
        .read_exact(&mut reply)
        .map_err(|error| format!("read Mieru TCP UDP smoke associate response: {error}"))?;
    if &reply[..4] != [0x05, 0x00, 0x00, 0x01] {
        return Err(format!(
            "unexpected Mieru TCP UDP smoke associate response: {reply:?}"
        ));
    }
    let relay_port = u16::from_be_bytes([reply[8], reply[9]]);
    if relay_port == 0 {
        return Err("Mieru TCP UDP smoke relay returned port 0".to_string());
    }

    let udp_client = UdpSocket::bind("127.0.0.1:0")
        .map_err(|error| format!("bind Mieru TCP UDP smoke client: {error}"))?;
    udp_client
        .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Mieru TCP UDP smoke client read timeout: {error}"))?;
    udp_client
        .set_write_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set Mieru TCP UDP smoke client write timeout: {error}"))?;
    let request = encode_socks5_udp_datagram(
        &Socks5Address::Ipv4(Ipv4Addr::LOCALHOST),
        MIERU_TCP_UDP_RELAY_SMOKE_TARGET_PORT,
        MIERU_TCP_UDP_RELAY_SMOKE_PAYLOAD,
    )
    .map_err(|error| format!("encode Mieru TCP UDP smoke request: {error}"))?;
    udp_client
        .send_to(&request, ("127.0.0.1", relay_port))
        .map_err(|error| format!("send Mieru TCP UDP smoke request: {error}"))?;

    let mut response = [0; 1500];
    let (size, _) = udp_client
        .recv_from(&mut response)
        .map_err(|error| format!("read Mieru TCP UDP smoke response: {error}"))?;
    let response = parse_socks5_udp_datagram(&response[..size])
        .map_err(|error| format!("parse Mieru TCP UDP smoke response: {error}"))?;
    client.shutdown(Shutdown::Both).ok();
    Ok(UdpRelaySmokeExchangeObservation {
        relay_port,
        response_source: format!(
            "{}:{}",
            udp_relay_smoke_socks5_address_label(&response.address),
            response.port
        ),
        response_payload: response.payload,
    })
}

fn spawn_mieru_tcp_udp_relay_smoke_server() -> Result<
    (
        u16,
        thread::JoinHandle<Result<UdpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind Mieru TCP UDP smoke server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set Mieru TCP UDP smoke accept mode: {error}"))?;
    let listen_port = listener
        .local_addr()
        .map_err(|error| format!("read Mieru TCP UDP smoke address: {error}"))?
        .port();
    let handle = thread::spawn(move || -> Result<UdpRelaySmokeServerObservation, String> {
        let deadline = Instant::now() + UDP_RELAY_SMOKE_TIMEOUT;
        let (mut stream, _) = loop {
            match listener.accept() {
                Ok(accepted) => break accepted,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err("Mieru TCP UDP smoke accept timed out".to_string());
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => return Err(format!("accept Mieru TCP UDP smoke server: {error}")),
            }
        };
        stream
            .set_nonblocking(false)
            .map_err(|error| format!("set Mieru TCP UDP smoke stream blocking mode: {error}"))?;
        stream
            .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set Mieru TCP UDP smoke read timeout: {error}"))?;
        stream
            .set_write_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| format!("set Mieru TCP UDP smoke write timeout: {error}"))?;

        let key = derive_mieru_tcp_relay_smoke_key(
            MIERU_TCP_RELAY_SMOKE_USERNAME,
            MIERU_TCP_RELAY_SMOKE_PASSWORD,
        );
        let mut read_nonce = None;
        let open = read_mieru_tcp_relay_smoke_segment(&mut stream, &key, &mut read_nonce)
            .map_err(|error| format!("read Mieru TCP UDP smoke open session request: {error}"))?;
        if open.protocol_type != MIERU_TCP_RELAY_SMOKE_OPEN_SESSION_REQUEST {
            return Err(format!(
                "unexpected Mieru TCP UDP smoke open protocol: expected {}, got {}",
                MIERU_TCP_RELAY_SMOKE_OPEN_SESSION_REQUEST, open.protocol_type
            ));
        }
        let expected_open = mieru_tcp_udp_relay_smoke_socks_udp_associate_request();
        if open.payload != expected_open {
            return Err(format!(
                "unexpected Mieru TCP UDP smoke open payload: expected {:?}, got {:?}",
                expected_open, open.payload
            ));
        }

        let mut writer = MieruTcpRelaySmokeWriter::new(
            stream
                .try_clone()
                .map_err(|error| format!("clone Mieru TCP UDP smoke stream: {error}"))?,
            key,
            open.session_id,
        );
        writer.write_segment(MIERU_TCP_RELAY_SMOKE_OPEN_SESSION_RESPONSE, b"")?;
        writer.write_segment(
            MIERU_TCP_RELAY_SMOKE_DATA_SERVER_TO_CLIENT,
            &MIERU_TCP_RELAY_SMOKE_SOCKS_CONNECT_SUCCESS,
        )?;

        let data = read_mieru_tcp_relay_smoke_segment(&mut stream, &key, &mut read_nonce)
            .map_err(|error| format!("read Mieru TCP UDP smoke data segment: {error}"))?;
        if data.session_id != open.session_id {
            return Err(format!(
                "unexpected Mieru TCP UDP smoke data session id: expected {}, got {}",
                open.session_id, data.session_id
            ));
        }
        if data.protocol_type != MIERU_TCP_RELAY_SMOKE_DATA_CLIENT_TO_SERVER {
            return Err(format!(
                "unexpected Mieru TCP UDP smoke data protocol: expected {}, got {}",
                MIERU_TCP_RELAY_SMOKE_DATA_CLIENT_TO_SERVER, data.protocol_type
            ));
        }
        let packet = decode_mieru_udp_relay_smoke_frame(&data.payload)?;
        let datagram = parse_socks5_udp_datagram(&packet)
            .map_err(|error| format!("parse Mieru TCP UDP smoke packet: {error}"))?;
        if datagram.address != Socks5Address::Ipv4(Ipv4Addr::LOCALHOST) {
            return Err(format!(
                "unexpected Mieru TCP UDP smoke target address: {:?}",
                datagram.address
            ));
        }
        if datagram.port != MIERU_TCP_UDP_RELAY_SMOKE_TARGET_PORT {
            return Err(format!(
                "unexpected Mieru TCP UDP smoke target port: expected {}, got {}",
                MIERU_TCP_UDP_RELAY_SMOKE_TARGET_PORT, datagram.port
            ));
        }
        if datagram.payload != MIERU_TCP_UDP_RELAY_SMOKE_PAYLOAD {
            return Err(format!(
                "unexpected Mieru TCP UDP smoke payload: expected {:?}, got {:?}",
                MIERU_TCP_UDP_RELAY_SMOKE_PAYLOAD, datagram.payload
            ));
        }

        let response = encode_socks5_udp_datagram(
            &Socks5Address::Ipv4(Ipv4Addr::LOCALHOST),
            MIERU_TCP_UDP_RELAY_SMOKE_TARGET_PORT,
            MIERU_TCP_UDP_RELAY_SMOKE_RESPONSE,
        )
        .map_err(|error| format!("encode Mieru TCP UDP smoke response: {error}"))?;
        writer.write_segment(
            MIERU_TCP_RELAY_SMOKE_DATA_SERVER_TO_CLIENT,
            &encode_mieru_udp_relay_smoke_frame(&response)?,
        )?;
        Ok(UdpRelaySmokeServerObservation {
            received_expected_payload: true,
        })
    });
    Ok((listen_port, handle))
}

fn mieru_tcp_udp_relay_smoke_metrics_recorded(metrics: &ConnectionMetricsSnapshot) -> bool {
    metrics.total_connection_count >= 1
        && metrics.success_count >= 1
        && udp_relay_smoke_inbound_count(metrics, "socks5-udp") >= 1
        && mieru_tcp_udp_relay_smoke_outbound_route_count(metrics) >= 1
        && metrics.total_upload_bytes >= MIERU_TCP_UDP_RELAY_SMOKE_PAYLOAD.len() as u64
        && metrics.total_download_bytes >= MIERU_TCP_UDP_RELAY_SMOKE_RESPONSE.len() as u64
}

fn mieru_tcp_udp_relay_smoke_outbound_route_count(metrics: &ConnectionMetricsSnapshot) -> u64 {
    metrics
        .route_action_counts
        .iter()
        .find(|entry| {
            entry.route_action
                == RouteAction::Outbound(MIERU_TCP_UDP_RELAY_SMOKE_OUTBOUND.to_string())
        })
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn mieru_tcp_udp_relay_smoke_target() -> String {
    format!("{MIERU_TCP_UDP_RELAY_SMOKE_TARGET_HOST}:{MIERU_TCP_UDP_RELAY_SMOKE_TARGET_PORT}")
}

fn mieru_tcp_udp_relay_smoke_socks_udp_associate_request() -> Vec<u8> {
    vec![0x05, 0x03, 0x00, 0x01, 0, 0, 0, 0, 0, 0]
}

fn encode_mieru_udp_relay_smoke_frame(packet: &[u8]) -> Result<Vec<u8>, String> {
    let packet_len = u16::try_from(packet.len()).map_err(|_| {
        format!(
            "Mieru TCP UDP smoke packet too large for frame: {}",
            packet.len()
        )
    })?;
    let mut output = Vec::with_capacity(packet.len() + 4);
    output.push(MIERU_UDP_RELAY_SMOKE_MARKER_START);
    output.extend_from_slice(&packet_len.to_be_bytes());
    output.extend_from_slice(packet);
    output.push(MIERU_UDP_RELAY_SMOKE_MARKER_END);
    Ok(output)
}

fn decode_mieru_udp_relay_smoke_frame(input: &[u8]) -> Result<Vec<u8>, String> {
    if input.len() < 4 {
        return Err(format!(
            "Mieru TCP UDP smoke frame too short: {} bytes",
            input.len()
        ));
    }
    if input[0] != MIERU_UDP_RELAY_SMOKE_MARKER_START {
        return Err(format!(
            "unexpected Mieru TCP UDP smoke frame start marker: {}",
            input[0]
        ));
    }
    let len = u16::from_be_bytes([input[1], input[2]]) as usize;
    if input.len() != len + 4 {
        return Err(format!(
            "invalid Mieru TCP UDP smoke frame length: expected {}, got {}",
            len + 4,
            input.len()
        ));
    }
    if input[input.len() - 1] != MIERU_UDP_RELAY_SMOKE_MARKER_END {
        return Err(format!(
            "unexpected Mieru TCP UDP smoke frame end marker: {}",
            input[input.len() - 1]
        ));
    }
    Ok(input[3..3 + len].to_vec())
}

#[cfg(test)]
mod mieru_tcp_udp_relay_smoke_tests {
    use super::*;

    #[test]
    fn default_mieru_tcp_udp_relay_smoke_proves_mieru_udp_round_trip() {
        let report = collect_default_mieru_tcp_udp_relay_smoke_report();

        assert!(report.passed, "{report:#?}");
        assert_eq!(
            report.selected_outbound.as_deref(),
            Some(MIERU_TCP_UDP_RELAY_SMOKE_OUTBOUND)
        );
        assert_eq!(report.target, mieru_tcp_udp_relay_smoke_target());
        assert!(report.relay_port.is_some());
        assert_eq!(report.response_source.as_deref(), Some("127.0.0.1:53"));
        assert_eq!(
            report.request_payload_bytes,
            MIERU_TCP_UDP_RELAY_SMOKE_PAYLOAD.len()
        );
        assert_eq!(
            report.response_payload_bytes,
            Some(MIERU_TCP_UDP_RELAY_SMOKE_RESPONSE.len())
        );
        assert!(report.round_trip_observed);
        assert!(report.server_received_payload);
        assert!(report.metrics_recorded);
        assert!(report.metrics_total_connections >= 1);
        assert!(report.metrics_success_count >= 1);
        assert!(report.metrics_inbound_count >= 1);
        assert!(report.metrics_outbound_route_count >= 1);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));

        let case_names = report
            .cases
            .iter()
            .map(|case| case.name)
            .collect::<Vec<_>>();
        for expected in [
            "start-mieru-tcp-udp-relay-runtime",
            "mieru-tcp-udp-protocol-round-trip",
            "record-mieru-tcp-udp-relay-metrics",
            "stop-mieru-tcp-udp-relay-runtime",
        ] {
            assert!(
                case_names.contains(&expected),
                "missing Mieru TCP UDP relay smoke case {expected}: {case_names:?}"
            );
        }
        let round_trip = report
            .cases
            .iter()
            .find(|case| case.name == "mieru-tcp-udp-protocol-round-trip")
            .expect("round trip case");
        assert_eq!(
            round_trip.observed_response.as_deref(),
            Some("keli-mieru-udp-pong")
        );
        assert_eq!(round_trip.response_source.as_deref(), Some("127.0.0.1:53"));
        assert_eq!(round_trip.round_trip_observed, Some(true));
        assert_eq!(round_trip.server_received_payload, Some(true));
    }
}

fn collect_default_udp_relay_smoke_report() -> UdpRelaySmokeReport {
    let mut cases = Vec::new();
    let mut selected_outbound = None;
    let mut relay_port = None;
    let mut response_source = None;
    let request_payload_bytes = UDP_RELAY_SMOKE_PAYLOAD.len();
    let mut response_payload_bytes = None;
    let mut round_trip_observed = false;
    let mut server_received_payload = false;
    let mut metrics_recorded = false;
    let mut metrics_total_connections = 0;
    let mut metrics_success_count = 0;
    let mut metrics_inbound_count = 0;
    let mut metrics_outbound_route_count = 0;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let (ss_port, ss_thread) = match spawn_udp_relay_smoke_shadowsocks_server() {
        Ok(server) => server,
        Err(error) => {
            cases.push(udp_relay_smoke_error_case(
                "start-shadowsocks-udp-echo",
                "start-echo-server",
                error,
            ));
            return finalize_udp_relay_smoke_report(
                cases,
                selected_outbound,
                relay_port,
                response_source,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };

    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let config = udp_relay_smoke_config(ss_port);
    let relay_options = RelayOptions {
        first_byte_timeout: Some(UDP_RELAY_SMOKE_TIMEOUT),
        idle_timeout: Some(UDP_RELAY_SMOKE_TIMEOUT),
    };

    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some(UDP_RELAY_SMOKE_OUTBOUND.to_string()),
            relay_options,
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(udp_relay_smoke_error_case(
                "start-udp-relay-runtime",
                "start",
                error,
            ));
            let _ = join_udp_relay_smoke_server(ss_thread);
            return finalize_udp_relay_smoke_report(
                cases,
                selected_outbound,
                relay_port,
                response_source,
                request_payload_bytes,
                response_payload_bytes,
                round_trip_observed,
                server_received_payload,
                metrics_recorded,
                metrics_total_connections,
                metrics_success_count,
                metrics_inbound_count,
                metrics_outbound_route_count,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    selected_outbound = started.selected_outbound.clone();
    cases.push(udp_relay_smoke_start_case(&started));

    if let Some(listen_addr) = started.listen_addr {
        let exchange_result = run_udp_relay_smoke_socks5_exchange(listen_addr);
        let server_result = join_udp_relay_smoke_server(ss_thread);
        if let Ok(exchange) = exchange_result.as_ref() {
            relay_port = Some(exchange.relay_port);
            response_source = Some(exchange.response_source.clone());
            response_payload_bytes = Some(exchange.response_payload.len());
            round_trip_observed = exchange.response_payload == UDP_RELAY_SMOKE_RESPONSE;
        }
        if let Ok(server) = server_result.as_ref() {
            server_received_payload = server.received_expected_payload;
        }
        cases.push(udp_relay_smoke_exchange_case(
            exchange_result,
            server_result,
            round_trip_observed,
            server_received_payload,
        ));

        let status = wait_for_udp_relay_smoke_status(&core, |status| {
            udp_relay_smoke_metrics_recorded(&status.connection_metrics)
        });
        metrics_total_connections = status.connection_metrics.total_connection_count;
        metrics_success_count = status.connection_metrics.success_count;
        metrics_inbound_count =
            udp_relay_smoke_inbound_count(&status.connection_metrics, "socks5-udp");
        metrics_outbound_route_count =
            udp_relay_smoke_outbound_route_count(&status.connection_metrics);
        metrics_recorded = udp_relay_smoke_metrics_recorded(&status.connection_metrics);
        cases.push(udp_relay_smoke_metrics_case(&status, metrics_recorded));
    } else {
        cases.push(udp_relay_smoke_error_case(
            "udp-relay-round-trip",
            "socks5-udp-associate",
            "managed mixed runtime did not expose a listen address".to_string(),
        ));
        let _ = join_udp_relay_smoke_server(ss_thread);
    }

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(udp_relay_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(udp_relay_smoke_stop_case(
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
            Some(error),
        )),
    }

    finalize_udp_relay_smoke_report(
        cases,
        selected_outbound,
        relay_port,
        response_source,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct UdpRelaySmokeExchangeObservation {
    relay_port: u16,
    response_source: String,
    response_payload: Vec<u8>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct UdpRelaySmokeServerObservation {
    received_expected_payload: bool,
}

fn udp_relay_smoke_config(ss_port: u16) -> String {
    format!(
        r#"
proxies:
  - name: {UDP_RELAY_SMOKE_OUTBOUND}
    type: ss
    server: 127.0.0.1
    port: {ss_port}
    cipher: aes-256-gcm
    password: secret
"#
    )
}

fn finalize_udp_relay_smoke_report(
    cases: Vec<UdpRelaySmokeCaseReport>,
    selected_outbound: Option<String>,
    relay_port: Option<u16>,
    response_source: Option<String>,
    request_payload_bytes: usize,
    response_payload_bytes: Option<usize>,
    round_trip_observed: bool,
    server_received_payload: bool,
    metrics_recorded: bool,
    metrics_total_connections: u64,
    metrics_success_count: u64,
    metrics_inbound_count: u64,
    metrics_outbound_route_count: u64,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> UdpRelaySmokeReport {
    let failed = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect::<Vec<_>>();
    let passed = failed.is_empty()
        && selected_outbound.as_deref() == Some(UDP_RELAY_SMOKE_OUTBOUND)
        && round_trip_observed
        && server_received_payload
        && metrics_recorded
        && clean_stop_observed;
    let target = udp_relay_smoke_target();
    let detail = format!(
        "cases={} passed={} failed={} failed_cases={} selected={} target={} relay_port={} response_source={} request_bytes={} response_bytes={} round_trip_observed={} server_received_payload={} metrics_recorded={} metrics_total={} metrics_success={} metrics_inbound_socks5_udp={} metrics_outbound_route={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
        cases.len(),
        passed,
        failed.len(),
        if failed.is_empty() {
            "-".to_string()
        } else {
            failed.join(",")
        },
        selected_outbound.as_deref().unwrap_or("-"),
        target,
        relay_port
            .map(|port| port.to_string())
            .unwrap_or_else(|| "-".to_string()),
        response_source.as_deref().unwrap_or("-"),
        request_payload_bytes,
        response_payload_bytes
            .map(|bytes| bytes.to_string())
            .unwrap_or_else(|| "-".to_string()),
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining
            .map(|workers| workers.to_string())
            .unwrap_or_else(|| "-".to_string()),
        stop_timed_out
            .map(|timed_out| timed_out.to_string())
            .unwrap_or_else(|| "-".to_string())
    );
    UdpRelaySmokeReport {
        passed,
        detail,
        selected_outbound,
        target,
        relay_port,
        response_source,
        request_payload_bytes,
        response_payload_bytes,
        round_trip_observed,
        server_received_payload,
        metrics_recorded,
        metrics_total_connections,
        metrics_success_count,
        metrics_inbound_count,
        metrics_outbound_route_count,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

fn udp_relay_smoke_start_case(status: &ManagedMixedStatusSnapshot) -> UdpRelaySmokeCaseReport {
    let selected = status.selected_outbound.clone();
    let passed = selected.as_deref() == Some(UDP_RELAY_SMOKE_OUTBOUND)
        && status.generation == 1
        && matches!(&status.status, RuntimeStatus::Running { .. });
    UdpRelaySmokeCaseReport {
        name: "start-udp-relay-runtime",
        action: "start",
        expected_selected_outbound: Some(UDP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: selected,
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        target: udp_relay_smoke_target(),
        relay_port: None,
        expected_response: None,
        observed_response: None,
        response_source: None,
        request_payload_bytes: None,
        response_payload_bytes: None,
        runtime_running: Some(matches!(&status.status, RuntimeStatus::Running { .. })),
        round_trip_observed: None,
        server_received_payload: None,
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error: None,
    }
}

fn udp_relay_smoke_exchange_case(
    exchange_result: Result<UdpRelaySmokeExchangeObservation, String>,
    server_result: Result<UdpRelaySmokeServerObservation, String>,
    round_trip_observed: bool,
    server_received_payload: bool,
) -> UdpRelaySmokeCaseReport {
    let error = match (&exchange_result, &server_result) {
        (Ok(_), Ok(_)) => None,
        (Err(exchange), Ok(_)) => Some(exchange.clone()),
        (Ok(_), Err(server)) => Some(server.clone()),
        (Err(exchange), Err(server)) => Some(format!("{exchange}; {server}")),
    };
    let exchange = exchange_result.ok();
    let passed = error.is_none() && round_trip_observed && server_received_payload;
    UdpRelaySmokeCaseReport {
        name: "socks5-udp-shadowsocks-round-trip",
        action: "socks5-udp-associate",
        expected_selected_outbound: Some(UDP_RELAY_SMOKE_OUTBOUND.to_string()),
        observed_selected_outbound: None,
        expected_generation: None,
        observed_generation: None,
        target: udp_relay_smoke_target(),
        relay_port: exchange.as_ref().map(|exchange| exchange.relay_port),
        expected_response: Some(String::from_utf8_lossy(UDP_RELAY_SMOKE_RESPONSE).to_string()),
        observed_response: exchange
            .as_ref()
            .map(|exchange| String::from_utf8_lossy(&exchange.response_payload).to_string()),
        response_source: exchange
            .as_ref()
            .map(|exchange| exchange.response_source.clone()),
        request_payload_bytes: Some(UDP_RELAY_SMOKE_PAYLOAD.len()),
        response_payload_bytes: exchange
            .as_ref()
            .map(|exchange| exchange.response_payload.len()),
        runtime_running: None,
        round_trip_observed: Some(round_trip_observed),
        server_received_payload: Some(server_received_payload),
        metrics_recorded: None,
        metrics_total_connections: None,
        metrics_success_count: None,
        metrics_inbound_count: None,
        metrics_outbound_route_count: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error,
    }
}

