fn run_socks5_udp_outbound_relay_smoke_exchange(
    listen_addr: SocketAddr,
) -> Result<UdpRelaySmokeExchangeObservation, String> {
    let mut client = TcpStream::connect(listen_addr).map_err(|error| {
        format!("connect SOCKS5 UDP outbound smoke listener {listen_addr}: {error}")
    })?;
    client
        .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set SOCKS5 UDP outbound smoke control read timeout: {error}"))?;
    client
        .set_write_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set SOCKS5 UDP outbound smoke control write timeout: {error}"))?;
    client
        .write_all(&[0x05, 0x01, 0x00])
        .map_err(|error| format!("write SOCKS5 UDP outbound smoke SOCKS hello: {error}"))?;
    let mut hello = [0; 2];
    client
        .read_exact(&mut hello)
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke SOCKS hello: {error}"))?;
    if hello != [0x05, 0x00] {
        return Err(format!(
            "unexpected SOCKS5 UDP outbound smoke SOCKS hello response: {hello:?}"
        ));
    }

    client
        .write_all(&[0x05, 0x03, 0x00, 0x01, 127, 0, 0, 1, 0x00, 0x00])
        .map_err(|error| format!("write SOCKS5 UDP outbound smoke associate request: {error}"))?;
    let mut reply = [0; 10];
    client
        .read_exact(&mut reply)
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke associate response: {error}"))?;
    if &reply[..4] != [0x05, 0x00, 0x00, 0x01] {
        return Err(format!(
            "unexpected SOCKS5 UDP outbound smoke associate response: {reply:?}"
        ));
    }
    let relay_port = u16::from_be_bytes([reply[8], reply[9]]);
    if relay_port == 0 {
        return Err("SOCKS5 UDP outbound smoke relay returned port 0".to_string());
    }

    let udp_client = UdpSocket::bind("127.0.0.1:0")
        .map_err(|error| format!("bind SOCKS5 UDP outbound smoke client: {error}"))?;
    udp_client
        .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set SOCKS5 UDP outbound smoke client read timeout: {error}"))?;
    udp_client
        .set_write_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set SOCKS5 UDP outbound smoke client write timeout: {error}"))?;
    let request = encode_socks5_udp_datagram(
        &Socks5Address::Domain(SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_TARGET_HOST.to_string()),
        SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_TARGET_PORT,
        SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_PAYLOAD,
    )
    .map_err(|error| format!("encode SOCKS5 UDP outbound smoke request: {error}"))?;
    udp_client
        .send_to(&request, ("127.0.0.1", relay_port))
        .map_err(|error| format!("send SOCKS5 UDP outbound smoke request: {error}"))?;

    let mut response = [0; 1500];
    let (size, _) = udp_client
        .recv_from(&mut response)
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke response: {error}"))?;
    let response = parse_socks5_udp_datagram(&response[..size])
        .map_err(|error| format!("parse SOCKS5 UDP outbound smoke response: {error}"))?;
    client.shutdown(Shutdown::Both).ok();
    Ok(UdpRelaySmokeExchangeObservation {
        relay_port,
        response_source: format!(
            "{}:{}",
            udp_relay_smoke_socks5_address_label(&response.address),
            response.port
        ),
        response_payload: response.payload,
    })
}

fn spawn_socks5_udp_outbound_relay_smoke_server() -> Result<
    (
        u16,
        thread::JoinHandle<Result<UdpRelaySmokeServerObservation, String>>,
    ),
    String,
> {
    let relay = UdpSocket::bind("127.0.0.1:0")
        .map_err(|error| format!("bind SOCKS5 UDP outbound smoke UDP relay: {error}"))?;
    relay
        .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
        .map_err(|error| format!("set SOCKS5 UDP outbound smoke UDP relay timeout: {error}"))?;
    let relay_port = relay
        .local_addr()
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke relay address: {error}"))?
        .port();
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind SOCKS5 UDP outbound smoke control server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set SOCKS5 UDP outbound smoke accept mode: {error}"))?;
    let control_port = listener
        .local_addr()
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke control address: {error}"))?
        .port();
    let handle = thread::spawn(move || -> Result<UdpRelaySmokeServerObservation, String> {
        let deadline = Instant::now() + UDP_RELAY_SMOKE_TIMEOUT;
        let (mut control, _) = loop {
            match listener.accept() {
                Ok(accepted) => break accepted,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err(
                            "SOCKS5 UDP outbound smoke control accept timed out".to_string()
                        );
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => {
                    return Err(format!(
                        "accept SOCKS5 UDP outbound smoke control server: {error}"
                    ))
                }
            }
        };
        control
            .set_nonblocking(false)
            .map_err(|error| format!("set SOCKS5 UDP outbound smoke control mode: {error}"))?;
        control
            .set_read_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| {
                format!("set SOCKS5 UDP outbound smoke control read timeout: {error}")
            })?;
        control
            .set_write_timeout(Some(UDP_RELAY_SMOKE_TIMEOUT))
            .map_err(|error| {
                format!("set SOCKS5 UDP outbound smoke control write timeout: {error}")
            })?;

        read_socks5_udp_outbound_relay_smoke_handshake(&mut control)?;
        read_socks5_udp_outbound_relay_smoke_associate(&mut control)?;
        let mut response = vec![0x05, 0x00, 0x00, 0x01, 127, 0, 0, 1];
        response.extend_from_slice(&relay_port.to_be_bytes());
        control
            .write_all(&response)
            .map_err(|error| format!("write SOCKS5 UDP outbound smoke associate reply: {error}"))?;

        let mut packet = [0; 1500];
        let (size, from) = relay
            .recv_from(&mut packet)
            .map_err(|error| format!("read SOCKS5 UDP outbound smoke relay packet: {error}"))?;
        let datagram = parse_socks5_udp_datagram(&packet[..size])
            .map_err(|error| format!("parse SOCKS5 UDP outbound smoke relay packet: {error}"))?;
        if datagram.address
            != Socks5Address::Domain(SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_TARGET_HOST.to_string())
            || datagram.port != SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_TARGET_PORT
        {
            return Err(format!(
                "unexpected SOCKS5 UDP outbound smoke target: {}:{}",
                udp_relay_smoke_socks5_address_label(&datagram.address),
                datagram.port
            ));
        }
        if datagram.payload != SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_PAYLOAD {
            return Err(format!(
                "unexpected SOCKS5 UDP outbound smoke payload: expected {:?}, got {:?}",
                SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_PAYLOAD, datagram.payload
            ));
        }
        let response = encode_socks5_udp_datagram(
            &Socks5Address::Ipv4(Ipv4Addr::LOCALHOST),
            SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_TARGET_PORT,
            SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_RESPONSE,
        )
        .map_err(|error| format!("encode SOCKS5 UDP outbound smoke relay response: {error}"))?;
        relay
            .send_to(&response, from)
            .map_err(|error| format!("write SOCKS5 UDP outbound smoke relay response: {error}"))?;
        tcp_relay_smoke_wait_for_client_close(&mut control);
        Ok(UdpRelaySmokeServerObservation {
            received_expected_payload: true,
        })
    });
    Ok((control_port, handle))
}

fn read_socks5_udp_outbound_relay_smoke_handshake(stream: &mut TcpStream) -> Result<(), String> {
    let mut greeting = [0; 2];
    stream
        .read_exact(&mut greeting)
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke greeting: {error}"))?;
    if greeting[0] != 0x05 {
        return Err(format!(
            "unexpected SOCKS5 UDP outbound smoke greeting version: {}",
            greeting[0]
        ));
    }
    let mut methods = vec![0; greeting[1] as usize];
    stream
        .read_exact(&mut methods)
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke methods: {error}"))?;
    if !methods.contains(&0x02) {
        return Err(format!(
            "SOCKS5 UDP outbound smoke client did not offer username/password auth: {methods:?}"
        ));
    }
    stream
        .write_all(&[0x05, 0x02])
        .map_err(|error| format!("write SOCKS5 UDP outbound smoke auth method: {error}"))?;

    let mut auth_header = [0; 2];
    stream
        .read_exact(&mut auth_header)
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke auth header: {error}"))?;
    if auth_header[0] != 0x01 {
        return Err(format!(
            "unexpected SOCKS5 UDP outbound smoke auth version: {}",
            auth_header[0]
        ));
    }
    let mut username = vec![0; auth_header[1] as usize];
    stream
        .read_exact(&mut username)
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke username: {error}"))?;
    let mut password_len = [0; 1];
    stream
        .read_exact(&mut password_len)
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke password length: {error}"))?;
    let mut password = vec![0; password_len[0] as usize];
    stream
        .read_exact(&mut password)
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke password: {error}"))?;
    let credentials_ok = username == SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_USERNAME.as_bytes()
        && password == SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_PASSWORD.as_bytes();
    stream
        .write_all(&[0x01, if credentials_ok { 0x00 } else { 0x01 }])
        .map_err(|error| format!("write SOCKS5 UDP outbound smoke auth response: {error}"))?;
    if credentials_ok {
        Ok(())
    } else {
        Err(format!(
            "unexpected SOCKS5 UDP outbound smoke credentials: username={:?} password={:?}",
            String::from_utf8_lossy(&username),
            String::from_utf8_lossy(&password)
        ))
    }
}

fn read_socks5_udp_outbound_relay_smoke_associate(stream: &mut TcpStream) -> Result<(), String> {
    let mut request = [0; 10];
    stream
        .read_exact(&mut request)
        .map_err(|error| format!("read SOCKS5 UDP outbound smoke associate request: {error}"))?;
    let expected = [0x05, 0x03, 0x00, 0x01, 0, 0, 0, 0, 0, 0];
    if request == expected {
        Ok(())
    } else {
        Err(format!(
            "unexpected SOCKS5 UDP outbound smoke associate request: {request:?}"
        ))
    }
}

fn socks5_udp_outbound_relay_smoke_metrics_recorded(metrics: &ConnectionMetricsSnapshot) -> bool {
    metrics.total_connection_count >= 1
        && metrics.success_count >= 1
        && udp_relay_smoke_inbound_count(metrics, "socks5-udp") >= 1
        && socks5_udp_outbound_relay_smoke_outbound_route_count(metrics) >= 1
        && metrics.total_upload_bytes >= SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_PAYLOAD.len() as u64
        && metrics.total_download_bytes >= SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_RESPONSE.len() as u64
}

fn socks5_udp_outbound_relay_smoke_outbound_route_count(
    metrics: &ConnectionMetricsSnapshot,
) -> u64 {
    metrics
        .route_action_counts
        .iter()
        .find(|entry| {
            entry.route_action
                == RouteAction::Outbound(SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_OUTBOUND.to_string())
        })
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn socks5_udp_outbound_relay_smoke_target() -> String {
    format!(
        "{}:{}",
        SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_TARGET_HOST, SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_TARGET_PORT
    )
}

#[cfg(test)]
mod socks5_udp_outbound_relay_smoke_tests {
    use super::*;

    #[test]
    fn default_socks5_udp_outbound_relay_smoke_proves_socks5_proxy_udp_round_trip() {
        let report = collect_default_socks5_udp_outbound_relay_smoke_report();

        assert!(report.passed, "{}", report.detail);
        assert_eq!(
            report.selected_outbound.as_deref(),
            Some(SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_OUTBOUND)
        );
        assert_eq!(report.target, socks5_udp_outbound_relay_smoke_target());
        assert!(report.relay_port.is_some());
        assert_eq!(report.response_source.as_deref(), Some("127.0.0.1:53"));
        assert_eq!(
            report.request_payload_bytes,
            SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_PAYLOAD.len()
        );
        assert_eq!(
            report.response_payload_bytes,
            Some(SOCKS5_UDP_OUTBOUND_RELAY_SMOKE_RESPONSE.len())
        );
        assert!(report.round_trip_observed);
        assert!(report.server_received_payload);
        assert!(report.metrics_recorded);
        assert!(report.metrics_total_connections >= 1);
        assert!(report.metrics_success_count >= 1);
        assert!(report.metrics_inbound_count >= 1);
        assert!(report.metrics_outbound_route_count >= 1);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));

        let case_names = report
            .cases
            .iter()
            .map(|case| case.name)
            .collect::<Vec<_>>();
        for expected in [
            "start-socks5-udp-outbound-relay-runtime",
            "socks5-udp-outbound-protocol-round-trip",
            "record-socks5-udp-outbound-relay-metrics",
            "stop-socks5-udp-outbound-relay-runtime",
        ] {
            assert!(
                case_names.contains(&expected),
                "missing SOCKS5 UDP outbound relay smoke case {expected}: {case_names:?}"
            );
        }
        let round_trip = report
            .cases
            .iter()
            .find(|case| case.name == "socks5-udp-outbound-protocol-round-trip")
            .expect("round trip case");
        assert_eq!(
            round_trip.observed_response.as_deref(),
            Some("keli-socks5-udp-outbound-pong")
        );
        assert_eq!(round_trip.round_trip_observed, Some(true));
        assert_eq!(round_trip.server_received_payload, Some(true));
    }
}

fn collect_default_subscription_reload_smoke_report() -> SubscriptionReloadSmokeReport {
    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let mut cases = Vec::new();
    let mut initial_generation = None;
    let mut final_generation = None;
    let mut final_selected_outbound = None;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let started = match core.start_from_subscription_config_text(
        &subscription_reload_smoke_config(&["SS-OLD", "SS-STAY"]),
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some("SS-STAY".to_string()),
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(subscription_reload_smoke_error_case(
                "start-subscription-runtime",
                "start",
                Some("SS-STAY"),
                Some(1),
                None,
                error,
            ));
            return finalize_subscription_reload_smoke_report(
                cases,
                initial_generation,
                final_generation,
                final_selected_outbound,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    initial_generation = Some(started.generation);
    cases.push(subscription_reload_smoke_start_case(&started));

    let preserve_result = (|| -> Result<ManagedSubscriptionUpdateOutcome, String> {
        core.record_node_health(ManagedNodeHealthStatus::healthy(
            "SS-OLD",
            Some(80),
            true,
            true,
        ))?;
        core.record_node_health(ManagedNodeHealthStatus::healthy(
            "SS-STAY",
            Some(42),
            true,
            true,
        ))?;
        core.reload_from_subscription_config_text_with_update_plan(
            &subscription_reload_smoke_config(&["SS-STAY", "SS-NEW"]),
        )
    })();
    match preserve_result {
        Ok(outcome) => cases.push(subscription_reload_smoke_update_case(
            "preserve-selected-outbound",
            "planned-reload",
            &outcome,
            "selected-outbound-preserved",
            "SS-STAY",
            2,
            true,
            false,
            &["SS-NEW"],
            &["SS-OLD"],
            &["SS-STAY"],
            Some("SS-OLD"),
        )),
        Err(error) => cases.push(subscription_reload_smoke_error_case(
            "preserve-selected-outbound",
            "planned-reload",
            Some("SS-STAY"),
            Some(2),
            Some("selected-outbound-preserved"),
            error,
        )),
    }

    let fallback_result = core.reload_from_subscription_config_text_with_update_plan(
        &subscription_reload_smoke_config(&["SS-FALLBACK", "SS-ALT"]),
    );
    match fallback_result {
        Ok(outcome) => {
            final_selected_outbound = outcome.status.selected_outbound.clone();
            cases.push(subscription_reload_smoke_update_case(
                "fallback-to-new-default",
                "planned-reload",
                &outcome,
                "selected-outbound-missing-use-default",
                "SS-FALLBACK",
                3,
                false,
                true,
                &["SS-FALLBACK", "SS-ALT"],
                &["SS-STAY", "SS-NEW"],
                &[],
                Some("SS-STAY"),
            ));
        }
        Err(error) => cases.push(subscription_reload_smoke_error_case(
            "fallback-to-new-default",
            "planned-reload",
            Some("SS-FALLBACK"),
            Some(3),
            Some("selected-outbound-missing-use-default"),
            error,
        )),
    }

    match core.stop() {
        Ok(stopped) => {
            final_generation = Some(stopped.generation());
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(subscription_reload_smoke_stop_case(
                clean_stop_observed,
                final_generation,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(subscription_reload_smoke_stop_case(
            false,
            None,
            None,
            None,
            Some(error),
        )),
    }

    finalize_subscription_reload_smoke_report(
        cases,
        initial_generation,
        final_generation,
        final_selected_outbound,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

#[derive(Debug)]
struct SubscriptionReloadSmokeSystemProxyController;

impl SystemProxyController for SubscriptionReloadSmokeSystemProxyController {
    fn snapshot(&self) -> Result<SystemProxySnapshot, keli_platform::SystemProxyError> {
        Ok(SystemProxySnapshot::default())
    }

    fn apply(
        &self,
        _config: &SystemProxyConfig,
    ) -> Result<SystemProxySnapshot, keli_platform::SystemProxyError> {
        Ok(SystemProxySnapshot::default())
    }

    fn restore(
        &self,
        _snapshot: &SystemProxySnapshot,
    ) -> Result<(), keli_platform::SystemProxyError> {
        Ok(())
    }
}

fn subscription_reload_smoke_config(tags: &[&str]) -> String {
    let mut config = String::from("proxies:\n");
    for tag in tags {
        config.push_str(&format!(
            r#"  - name: {tag}
    type: ss
    server: ss.example.com
    port: 8388
    cipher: aes-256-gcm
    password: secret
"#
        ));
    }
    config
}

fn finalize_subscription_reload_smoke_report(
    cases: Vec<SubscriptionReloadSmokeCaseReport>,
    initial_generation: Option<u64>,
    final_generation: Option<u64>,
    final_selected_outbound: Option<String>,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> SubscriptionReloadSmokeReport {
    let passed_count = cases.iter().filter(|case| case.passed).count();
    let failed: Vec<&str> = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect();
    let passed = failed.is_empty();
    SubscriptionReloadSmokeReport {
        passed,
        detail: format!(
            "cases={} passed={} failed={} failed_cases={} initial_generation={} final_generation={} final_selected={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
            cases.len(),
            passed_count,
            failed.len(),
            if failed.is_empty() {
                "-".to_string()
            } else {
                failed.join(",")
            },
            optional_u64_label(initial_generation),
            optional_u64_label(final_generation),
            final_selected_outbound.as_deref().unwrap_or("-"),
            clean_stop_observed,
            optional_usize_label(stop_workers_remaining),
            optional_bool_label(stop_timed_out)
        ),
        initial_generation,
        final_generation,
        final_selected_outbound,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

fn subscription_reload_smoke_start_case(
    status: &ManagedMixedStatusSnapshot,
) -> SubscriptionReloadSmokeCaseReport {
    let selected = status.selected_outbound.clone();
    let selected_health_present = status
        .subscription
        .as_ref()
        .and_then(|subscription| subscription.health_for("SS-STAY"))
        .is_some();
    let selected_health_state = status
        .subscription
        .as_ref()
        .and_then(|subscription| subscription.health_for("SS-STAY"))
        .map(|health| health.state.label().to_string());
    let passed = matches!(
        &status.status,
        RuntimeStatus::Running {
            selected_outbound,
            generation,
            ..
        } if selected_outbound == "SS-STAY" && *generation == 1
    ) && status.generation == 1
        && selected.as_deref() == Some("SS-STAY")
        && status
            .subscription
            .as_ref()
            .is_some_and(|subscription| subscription.usable && subscription.supported_count() == 2)
        && selected_health_present;

    SubscriptionReloadSmokeCaseReport {
        name: "start-subscription-runtime",
        action: "start",
        expected_selected_outbound: Some("SS-STAY".to_string()),
        observed_selected_outbound: selected,
        expected_generation: Some(1),
        observed_generation: Some(status.generation),
        expected_reason: None,
        observed_reason: None,
        applied: None,
        selected_outbound_preserved: None,
        selected_outbound_changed: None,
        added_tags: Vec::new(),
        removed_tags: Vec::new(),
        retained_tags: Vec::new(),
        stale_health_pruned: None,
        selected_health_present: Some(selected_health_present),
        selected_health_state,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error: None,
    }
}

fn subscription_reload_smoke_update_case(
    name: &'static str,
    action: &'static str,
    outcome: &ManagedSubscriptionUpdateOutcome,
    expected_reason: &'static str,
    expected_selected_outbound: &'static str,
    expected_generation: u64,
    expected_preserved: bool,
    expected_changed: bool,
    expected_added: &[&str],
    expected_removed: &[&str],
    expected_retained: &[&str],
    stale_health_tag: Option<&str>,
) -> SubscriptionReloadSmokeCaseReport {
    let selected_health = outcome
        .status
        .subscription
        .as_ref()
        .and_then(|subscription| subscription.health_for(expected_selected_outbound));
    let selected_health_present = selected_health.is_some();
    let selected_health_state = selected_health.map(|health| health.state.label().to_string());
    let stale_health_pruned = stale_health_tag.map(|tag| {
        outcome
            .status
            .subscription
            .as_ref()
            .is_some_and(|subscription| subscription.health_for(tag).is_none())
    });
    let added_matches = tags_match(&outcome.report.added_tags, expected_added);
    let removed_matches = tags_match(&outcome.report.removed_tags, expected_removed);
    let retained_matches = tags_match(&outcome.report.retained_tags, expected_retained);
    let passed = outcome.applied
        && outcome.error.is_none()
        && outcome.report.reason.label() == expected_reason
        && outcome.report.planned_selected_outbound.as_deref() == Some(expected_selected_outbound)
        && outcome.status.selected_outbound.as_deref() == Some(expected_selected_outbound)
        && outcome.status.generation == expected_generation
        && outcome.report.selected_outbound_preserved == expected_preserved
        && outcome.report.selected_outbound_changed == expected_changed
        && added_matches
        && removed_matches
        && retained_matches
        && stale_health_pruned.unwrap_or(true)
        && selected_health_present;

    SubscriptionReloadSmokeCaseReport {
        name,
        action,
        expected_selected_outbound: Some(expected_selected_outbound.to_string()),
        observed_selected_outbound: outcome.status.selected_outbound.clone(),
        expected_generation: Some(expected_generation),
        observed_generation: Some(outcome.status.generation),
        expected_reason: Some(expected_reason),
        observed_reason: Some(outcome.report.reason.label().to_string()),
        applied: Some(outcome.applied),
        selected_outbound_preserved: Some(outcome.report.selected_outbound_preserved),
        selected_outbound_changed: Some(outcome.report.selected_outbound_changed),
        added_tags: outcome.report.added_tags.clone(),
        removed_tags: outcome.report.removed_tags.clone(),
        retained_tags: outcome.report.retained_tags.clone(),
        stale_health_pruned,
        selected_health_present: Some(selected_health_present),
        selected_health_state,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error: outcome.error.clone(),
    }
}

fn subscription_reload_smoke_stop_case(
    clean_stop_observed: bool,
    final_generation: Option<u64>,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
    error: Option<String>,
) -> SubscriptionReloadSmokeCaseReport {
    SubscriptionReloadSmokeCaseReport {
        name: "stop-subscription-runtime",
        action: "stop",
        expected_selected_outbound: None,
        observed_selected_outbound: None,
        expected_generation: Some(3),
        observed_generation: final_generation,
        expected_reason: None,
        observed_reason: None,
        applied: None,
        selected_outbound_preserved: None,
        selected_outbound_changed: None,
        added_tags: Vec::new(),
        removed_tags: Vec::new(),
        retained_tags: Vec::new(),
        stale_health_pruned: None,
        selected_health_present: None,
        selected_health_state: None,
        clean_stop_observed: Some(clean_stop_observed),
        stop_workers_remaining,
        stop_timed_out,
        passed: clean_stop_observed && final_generation == Some(3) && error.is_none(),
        error,
    }
}

fn subscription_reload_smoke_error_case(
    name: &'static str,
    action: &'static str,
    expected_selected_outbound: Option<&'static str>,
    expected_generation: Option<u64>,
    expected_reason: Option<&'static str>,
    error: String,
) -> SubscriptionReloadSmokeCaseReport {
    SubscriptionReloadSmokeCaseReport {
        name,
        action,
        expected_selected_outbound: expected_selected_outbound.map(str::to_string),
        observed_selected_outbound: None,
        expected_generation,
        observed_generation: None,
        expected_reason,
        observed_reason: None,
        applied: None,
        selected_outbound_preserved: None,
        selected_outbound_changed: None,
        added_tags: Vec::new(),
        removed_tags: Vec::new(),
        retained_tags: Vec::new(),
        stale_health_pruned: None,
        selected_health_present: None,
        selected_health_state: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed: false,
        error: Some(error),
    }
}

fn tags_match(actual: &[String], expected: &[&str]) -> bool {
    actual.len() == expected.len()
        && expected
            .iter()
            .all(|expected| actual.iter().any(|actual| actual == expected))
}

fn optional_u64_label(value: Option<u64>) -> String {
    value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "-".to_string())
}

fn optional_usize_label(value: Option<usize>) -> String {
    value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "-".to_string())
}

fn optional_bool_label(value: Option<bool>) -> &'static str {
    match value {
        Some(true) => "true",
        Some(false) => "false",
        None => "-",
    }
}

fn collect_default_resource_limit_smoke_report() -> ResourceLimitSmokeReport {
    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let mut cases = Vec::new();
    let mut busy_worker_count = None;
    let mut rejected_connection_count = 0;
    let mut connection_limit_error_count = 0;
    let mut worker_limit_enforced = false;
    let mut metrics_recorded = false;
    let mut workers_drained = false;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let started = match core.start_from_subscription_config_text(
        &subscription_reload_smoke_config(&["SS-READY"]),
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some("SS-READY".to_string()),
            system_proxy: false,
            max_connection_workers: 1,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(resource_limit_smoke_error_case(
                "start-resource-limit-runtime",
                "start",
                error,
            ));
            return finalize_resource_limit_smoke_report(
                cases,
                busy_worker_count,
                rejected_connection_count,
                connection_limit_error_count,
                worker_limit_enforced,
                metrics_recorded,
                workers_drained,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    cases.push(resource_limit_smoke_status_case(
        "start-resource-limit-runtime",
        "start",
        &started,
        Some(1),
        Some(0),
        Some(0),
        None,
        None,
        None,
        None,
    ));

    let Some(listen_addr) = started.listen_addr else {
        cases.push(resource_limit_smoke_error_case(
            "occupy-worker-slot",
            "connect",
            "managed listener address missing".to_string(),
        ));
        let _ = core.stop();
        return finalize_resource_limit_smoke_report(
            cases,
            busy_worker_count,
            rejected_connection_count,
            connection_limit_error_count,
            worker_limit_enforced,
            metrics_recorded,
            workers_drained,
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
        );
    };

    let mut stalled_client = match open_resource_limit_smoke_socks5_handshake(listen_addr) {
        Ok(client) => Some(client),
        Err(error) => {
            cases.push(resource_limit_smoke_error_case(
                "occupy-worker-slot",
                "connect",
                error,
            ));
            None
        }
    };

    if stalled_client.is_some() {
        let busy = wait_for_resource_limit_smoke_status(&core, |status| {
            status.active_connection_workers == 1 && status.active_client_connections == 1
        });
        busy_worker_count = Some(busy.active_connection_workers);
        cases.push(resource_limit_smoke_status_case(
            "occupy-worker-slot",
            "connect",
            &busy,
            Some(1),
            Some(1),
            Some(0),
            None,
            None,
            None,
            None,
        ));

        let rejection_error = attempt_resource_limit_smoke_rejected_socks5_hello(listen_addr).err();
        let rejected = wait_for_resource_limit_smoke_status(&core, |status| {
            status.connection_metrics.connection_limit_rejection_count >= 1
        });
        rejected_connection_count = rejected.connection_metrics.connection_limit_rejection_count;
        connection_limit_error_count =
            resource_limit_error_kind_count(&rejected.connection_metrics);
        let observed_error_kind = resource_limit_observed_error_kind(&rejected.connection_metrics);
        worker_limit_enforced = rejection_error.is_none()
            && rejected.max_connection_workers == 1
            && rejected.active_connection_workers == 1
            && rejected.available_connection_worker_slots == 0
            && rejected_connection_count >= 1;
        metrics_recorded = rejected.connection_metrics.total_connection_count >= 1
            && rejected.connection_metrics.failure_count >= 1
            && rejected_connection_count >= 1
            && connection_limit_error_count >= 1
            && observed_error_kind.as_deref() == Some("connection_limit_reached");
        let mut rejection_case = resource_limit_smoke_status_case(
            "reject-over-worker-limit",
            "connect-rejected",
            &rejected,
            Some(1),
            Some(1),
            Some(1),
            Some("connection_limit_reached"),
            Some(worker_limit_enforced),
            Some(metrics_recorded),
            None,
        );
        rejection_case.error = rejection_error;
        rejection_case.passed = rejection_case.passed && rejection_case.error.is_none();
        cases.push(rejection_case);
    }

    drop(stalled_client.take());
    let drained = wait_for_resource_limit_smoke_status(&core, |status| {
        status.active_connection_workers == 0 && status.active_client_connections == 0
    });
    workers_drained = drained.active_connection_workers == 0
        && drained.active_client_connections == 0
        && drained.available_connection_worker_slots == drained.max_connection_workers;
    cases.push(resource_limit_smoke_status_case(
        "drain-worker-slot",
        "drop-client",
        &drained,
        Some(1),
        Some(0),
        Some(rejected_connection_count),
        Some("connection_limit_reached"),
        None,
        None,
        Some(workers_drained),
    ));

    match core.stop() {
        Ok(stopped) => {
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(resource_limit_smoke_stop_case(
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(resource_limit_smoke_stop_case(
            false,
            None,
            None,
            Some(error),
        )),
    }

    finalize_resource_limit_smoke_report(
        cases,
        busy_worker_count,
        rejected_connection_count,
        connection_limit_error_count,
        worker_limit_enforced,
        metrics_recorded,
        workers_drained,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn finalize_resource_limit_smoke_report(
    cases: Vec<ResourceLimitSmokeCaseReport>,
    busy_worker_count: Option<usize>,
    rejected_connection_count: u64,
    connection_limit_error_count: u64,
    worker_limit_enforced: bool,
    metrics_recorded: bool,
    workers_drained: bool,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> ResourceLimitSmokeReport {
    let passed_count = cases.iter().filter(|case| case.passed).count();
    let failed: Vec<&str> = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect();
    let passed = failed.is_empty()
        && worker_limit_enforced
        && metrics_recorded
        && workers_drained
        && clean_stop_observed;
    ResourceLimitSmokeReport {
        passed,
        detail: format!(
            "cases={} passed={} failed={} failed_cases={} max_workers=1 busy_workers={} rejected_connections={} connection_limit_errors={} worker_limit_enforced={} metrics_recorded={} workers_drained={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
            cases.len(),
            passed_count,
            failed.len(),
            if failed.is_empty() {
                "-".to_string()
            } else {
                failed.join(",")
            },
            optional_usize_label(busy_worker_count),
            rejected_connection_count,
            connection_limit_error_count,
            worker_limit_enforced,
            metrics_recorded,
            workers_drained,
            clean_stop_observed,
            optional_usize_label(stop_workers_remaining),
            optional_bool_label(stop_timed_out)
        ),
        max_connection_workers: 1,
        busy_worker_count,
        rejected_connection_count,
        connection_limit_error_count,
        worker_limit_enforced,
        metrics_recorded,
        workers_drained,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

fn resource_limit_smoke_status_case(
    name: &'static str,
    action: &'static str,
    status: &ManagedMixedStatusSnapshot,
    expected_max_connection_workers: Option<usize>,
    expected_active_connection_workers: Option<usize>,
    expected_rejection_count: Option<u64>,
    expected_error_kind: Option<&'static str>,
    worker_limit_enforced: Option<bool>,
    metrics_recorded: Option<bool>,
    workers_drained: Option<bool>,
) -> ResourceLimitSmokeCaseReport {
    let runtime_running = matches!(&status.status, RuntimeStatus::Running { .. });
    let observed_rejection_count = Some(status.connection_metrics.connection_limit_rejection_count);
    let observed_error_kind = resource_limit_observed_error_kind(&status.connection_metrics);
    let passed = runtime_running
        && expected_max_connection_workers
            .is_none_or(|expected| status.max_connection_workers == expected)
        && expected_active_connection_workers
            .is_none_or(|expected| status.active_connection_workers == expected)
        && expected_rejection_count.is_none_or(|expected| {
            status.connection_metrics.connection_limit_rejection_count >= expected
        })
        && expected_error_kind
            .is_none_or(|expected| observed_error_kind.as_deref() == Some(expected))
        && worker_limit_enforced.unwrap_or(true)
        && metrics_recorded.unwrap_or(true)
        && workers_drained.unwrap_or(true);

    ResourceLimitSmokeCaseReport {
        name,
        action,
        expected_max_connection_workers,
        observed_max_connection_workers: Some(status.max_connection_workers),
        expected_active_connection_workers,
        observed_active_connection_workers: Some(status.active_connection_workers),
        expected_rejection_count,
        observed_rejection_count,
        expected_error_kind,
        observed_error_kind,
        runtime_running: Some(runtime_running),
        worker_limit_enforced,
        metrics_recorded,
        workers_drained,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
        error: None,
    }
}

fn resource_limit_smoke_stop_case(
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
    error: Option<String>,
) -> ResourceLimitSmokeCaseReport {
    ResourceLimitSmokeCaseReport {
        name: "stop-resource-limit-runtime",
        action: "stop",
        expected_max_connection_workers: Some(1),
        observed_max_connection_workers: Some(1),
        expected_active_connection_workers: Some(0),
        observed_active_connection_workers: Some(0),
        expected_rejection_count: None,
        observed_rejection_count: None,
        expected_error_kind: None,
        observed_error_kind: None,
        runtime_running: Some(false),
        worker_limit_enforced: None,
        metrics_recorded: None,
        workers_drained: None,
        clean_stop_observed: Some(clean_stop_observed),
        stop_workers_remaining,
        stop_timed_out,
        passed: clean_stop_observed && error.is_none(),
        error,
    }
}

fn resource_limit_smoke_error_case(
    name: &'static str,
    action: &'static str,
    error: String,
) -> ResourceLimitSmokeCaseReport {
    ResourceLimitSmokeCaseReport {
        name,
        action,
        expected_max_connection_workers: Some(1),
        observed_max_connection_workers: None,
        expected_active_connection_workers: None,
        observed_active_connection_workers: None,
        expected_rejection_count: None,
        observed_rejection_count: None,
        expected_error_kind: None,
        observed_error_kind: None,
        runtime_running: None,
        worker_limit_enforced: None,
        metrics_recorded: None,
        workers_drained: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed: false,
        error: Some(error),
    }
}

fn wait_for_resource_limit_smoke_status<C, F>(
    core: &ManagedMixedController<'_, C>,
    mut predicate: F,
) -> ManagedMixedStatusSnapshot
where
    C: SystemProxyController + ?Sized,
    F: FnMut(&ManagedMixedStatusSnapshot) -> bool,
{
    for _ in 0..80 {
        let status = core.status();
        if predicate(&status) {
            return status;
        }
        thread::sleep(Duration::from_millis(25));
    }
    core.status()
}

fn open_resource_limit_smoke_socks5_handshake(
    listen_addr: SocketAddr,
) -> Result<TcpStream, String> {
    let mut client =
        TcpStream::connect(listen_addr).map_err(|error| format!("connect listener: {error}"))?;
    client
        .set_read_timeout(Some(Duration::from_secs(2)))
        .map_err(|error| format!("set read timeout: {error}"))?;
    client
        .set_write_timeout(Some(Duration::from_secs(2)))
        .map_err(|error| format!("set write timeout: {error}"))?;
    client
        .write_all(&[0x05, 0x01, 0x00])
        .map_err(|error| format!("write SOCKS5 hello: {error}"))?;
    let mut hello = [0; 2];
    client
        .read_exact(&mut hello)
        .map_err(|error| format!("read SOCKS5 hello response: {error}"))?;
    if hello != [0x05, 0x00] {
        return Err(format!("unexpected SOCKS5 hello response: {hello:?}"));
    }
    Ok(client)
}

fn attempt_resource_limit_smoke_rejected_socks5_hello(
    listen_addr: SocketAddr,
) -> Result<(), String> {
    let mut client =
        TcpStream::connect(listen_addr).map_err(|error| format!("connect listener: {error}"))?;
    client
        .set_read_timeout(Some(Duration::from_secs(2)))
        .map_err(|error| format!("set read timeout: {error}"))?;
    client
        .set_write_timeout(Some(Duration::from_secs(2)))
        .map_err(|error| format!("set write timeout: {error}"))?;
    if client.write_all(&[0x05, 0x01, 0x00]).is_err() {
        return Ok(());
    }
    let mut hello = [0; 2];
    match client.read_exact(&mut hello) {
        Ok(()) => Err(format!("over-limit SOCKS5 hello was accepted: {hello:?}")),
        Err(_) => Ok(()),
    }
}

fn resource_limit_error_kind_count(metrics: &ConnectionMetricsSnapshot) -> u64 {
    metrics
        .error_kind_counts
        .iter()
        .find(|entry| entry.error_kind == ConnectionErrorKind::ConnectionLimitReached)
        .map(|entry| entry.count)
        .unwrap_or(0)
}

fn resource_limit_observed_error_kind(metrics: &ConnectionMetricsSnapshot) -> Option<String> {
    metrics
        .recent_connections
        .iter()
        .rev()
        .find_map(|report| report.error_kind.map(|kind| kind.as_str().to_string()))
}

#[cfg(test)]
mod resource_limit_smoke_tests {
    use super::*;

    #[test]
    fn default_resource_limit_smoke_enforces_worker_limit_and_records_metrics() {
        let report = collect_default_resource_limit_smoke_report();

        assert!(report.passed, "{}", report.detail);
        assert_eq!(report.max_connection_workers, 1);
        assert_eq!(report.busy_worker_count, Some(1));
        assert_eq!(report.rejected_connection_count, 1);
        assert_eq!(report.connection_limit_error_count, 1);
        assert!(report.worker_limit_enforced);
        assert!(report.metrics_recorded);
        assert!(report.workers_drained);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));
        assert_eq!(report.cases.len(), 5);

        for case_name in [
            "start-resource-limit-runtime",
            "occupy-worker-slot",
            "reject-over-worker-limit",
            "drain-worker-slot",
            "stop-resource-limit-runtime",
        ] {
            let case = report
                .cases
                .iter()
                .find(|case| case.name == case_name)
                .unwrap_or_else(|| panic!("missing resource limit smoke case {case_name}"));
            assert!(case.passed, "{case:?}");
        }

        let reject = report
            .cases
            .iter()
            .find(|case| case.name == "reject-over-worker-limit")
            .expect("reject case");
        assert_eq!(
            reject.observed_error_kind.as_deref(),
            Some("connection_limit_reached")
        );
        assert_eq!(reject.worker_limit_enforced, Some(true));
        assert_eq!(reject.metrics_recorded, Some(true));
        assert_eq!(reject.observed_rejection_count, Some(1));

        let drain = report
            .cases
            .iter()
            .find(|case| case.name == "drain-worker-slot")
            .expect("drain case");
        assert_eq!(drain.workers_drained, Some(true));
        assert_eq!(drain.observed_active_connection_workers, Some(0));
    }
}

fn collect_default_panel_subscription_smoke_report() -> PanelSubscriptionSmokeReport {
    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let mut cases = Vec::new();
    let mut reload_blocked = false;
    let mut probe_blocked = false;
    let mut apply_blocked = false;
    let mut runtime_preserved_while_restricted = false;
    let mut clear_allowed_runtime = false;
    let mut final_selected_outbound = None;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;
    let config = subscription_reload_smoke_config(&["SS-READY"]);
    let restricted_panel = panel_subscription_smoke_restricted_panel_state();

    let restricted_status = core.record_panel_state(restricted_panel.clone());
    cases.push(panel_subscription_smoke_status_case(
        "record-restricted-panel-before-start",
        "record-panel-state",
        &restricted_status,
        PanelSubscriptionSmokeCaseExpectations {
            expected_error_kind: None,
            error_detail: None,
            expected_selected_outbound: None,
            expected_generation: Some(0),
            expected_runtime_running: Some(false),
            expected_panel_state_present: Some(true),
            expected_restrict_traffic: Some(true),
            start_blocked: None,
            reload_blocked: None,
            probe_blocked: None,
            apply_blocked: None,
            runtime_preserved: None,
            clear_allowed_runtime: None,
        },
    ));

    let start_error = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some("SS-READY".to_string()),
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(_) => None,
        Err(error) => Some(error),
    };
    let start_blocked = start_error
        .as_deref()
        .and_then(panel_subscription_smoke_error_kind_from_detail)
        .as_deref()
        == Some("panel-traffic-restricted");
    let blocked_start_status = core.status();
    cases.push(panel_subscription_smoke_status_case(
        "block-start-while-restricted",
        "start-rejected",
        &blocked_start_status,
        PanelSubscriptionSmokeCaseExpectations {
            expected_error_kind: Some("panel-traffic-restricted"),
            error_detail: start_error,
            expected_selected_outbound: None,
            expected_generation: Some(0),
            expected_runtime_running: Some(false),
            expected_panel_state_present: Some(true),
            expected_restrict_traffic: Some(true),
            start_blocked: Some(start_blocked),
            reload_blocked: None,
            probe_blocked: None,
            apply_blocked: None,
            runtime_preserved: None,
            clear_allowed_runtime: None,
        },
    ));
    if core.is_running() {
        let _ = core.stop();
    }

    core.clear_panel_state();
    let started = match core.start_from_subscription_config_text(
        &config,
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some("SS-READY".to_string()),
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => {
            cases.push(panel_subscription_smoke_status_case(
                "clear-and-start-runtime",
                "clear-panel-state-start",
                &status,
                PanelSubscriptionSmokeCaseExpectations {
                    expected_error_kind: None,
                    error_detail: None,
                    expected_selected_outbound: Some("SS-READY"),
                    expected_generation: Some(1),
                    expected_runtime_running: Some(true),
                    expected_panel_state_present: Some(false),
                    expected_restrict_traffic: None,
                    start_blocked: None,
                    reload_blocked: None,
                    probe_blocked: None,
                    apply_blocked: None,
                    runtime_preserved: None,
                    clear_allowed_runtime: Some(true),
                },
            ));
            Some(status)
        }
        Err(error) => {
            cases.push(panel_subscription_smoke_error_case(
                "clear-and-start-runtime",
                "clear-panel-state-start",
                Some("SS-READY"),
                Some(1),
                error,
            ));
            None
        }
    };

    if started.is_none() {
        return finalize_panel_subscription_smoke_report(
            cases,
            start_blocked,
            reload_blocked,
            probe_blocked,
            apply_blocked,
            runtime_preserved_while_restricted,
            clear_allowed_runtime,
            final_selected_outbound,
            clean_stop_observed,
            stop_workers_remaining,
            stop_timed_out,
        );
    }

    let restricted_running = core.record_panel_state(restricted_panel);
    cases.push(panel_subscription_smoke_status_case(
        "record-restricted-panel-during-runtime",
        "record-panel-state",
        &restricted_running,
        PanelSubscriptionSmokeCaseExpectations {
            expected_error_kind: None,
            error_detail: None,
            expected_selected_outbound: Some("SS-READY"),
            expected_generation: Some(1),
            expected_runtime_running: Some(true),
            expected_panel_state_present: Some(true),
            expected_restrict_traffic: Some(true),
            start_blocked: None,
            reload_blocked: None,
            probe_blocked: None,
            apply_blocked: None,
            runtime_preserved: None,
            clear_allowed_runtime: None,
        },
    ));

    let reload_error = core
        .reload_from_subscription_config_text(&config, Some("SS-READY".to_string()))
        .err();
    reload_blocked = reload_error
        .as_deref()
        .and_then(panel_subscription_smoke_error_kind_from_detail)
        .as_deref()
        == Some("panel-traffic-restricted");
    let reload_status = core.status();
    runtime_preserved_while_restricted = panel_subscription_smoke_runtime_preserved(&reload_status);
    cases.push(panel_subscription_smoke_status_case(
        "block-reload-while-restricted",
        "reload-rejected",
        &reload_status,
        PanelSubscriptionSmokeCaseExpectations {
            expected_error_kind: Some("panel-traffic-restricted"),
            error_detail: reload_error,
            expected_selected_outbound: Some("SS-READY"),
            expected_generation: Some(1),
            expected_runtime_running: Some(true),
            expected_panel_state_present: Some(true),
            expected_restrict_traffic: Some(true),
            start_blocked: None,
            reload_blocked: Some(reload_blocked),
            probe_blocked: None,
            apply_blocked: None,
            runtime_preserved: Some(runtime_preserved_while_restricted),
            clear_allowed_runtime: None,
        },
    ));

    let probe_error = core
        .probe_node_health(ManagedNodeProbeOptions {
            outbound_tag: "SS-READY".to_string(),
            target: "127.0.0.1:1".to_string(),
            payload: Vec::new(),
            expect: Vec::new(),
            inbound: SmokeInboundKind::Socks5,
            first_byte_timeout: Duration::from_millis(20),
            udp_available: None,
            udp_probe: None,
        })
        .err();
    probe_blocked = probe_error
        .as_deref()
        .and_then(panel_subscription_smoke_error_kind_from_detail)
        .as_deref()
        == Some("panel-traffic-restricted");
    let probe_status = core.status();
    cases.push(panel_subscription_smoke_status_case(
        "block-node-probe-while-restricted",
        "probe-rejected",
        &probe_status,
        PanelSubscriptionSmokeCaseExpectations {
            expected_error_kind: Some("panel-traffic-restricted"),
            error_detail: probe_error,
            expected_selected_outbound: Some("SS-READY"),
            expected_generation: Some(1),
            expected_runtime_running: Some(true),
            expected_panel_state_present: Some(true),
            expected_restrict_traffic: Some(true),
            start_blocked: None,
            reload_blocked: None,
            probe_blocked: Some(probe_blocked),
            apply_blocked: None,
            runtime_preserved: Some(panel_subscription_smoke_runtime_preserved(&probe_status)),
            clear_allowed_runtime: None,
        },
    ));

    let apply_error = core.apply_recommended_outbound().err();
    apply_blocked = apply_error
        .as_deref()
        .and_then(panel_subscription_smoke_error_kind_from_detail)
        .as_deref()
        == Some("panel-traffic-restricted");
    let apply_status = core.status();
    cases.push(panel_subscription_smoke_status_case(
        "block-recommended-switch-while-restricted",
        "recommended-switch-rejected",
        &apply_status,
        PanelSubscriptionSmokeCaseExpectations {
            expected_error_kind: Some("panel-traffic-restricted"),
            error_detail: apply_error,
            expected_selected_outbound: Some("SS-READY"),
            expected_generation: Some(1),
            expected_runtime_running: Some(true),
            expected_panel_state_present: Some(true),
            expected_restrict_traffic: Some(true),
            start_blocked: None,
            reload_blocked: None,
            probe_blocked: None,
            apply_blocked: Some(apply_blocked),
            runtime_preserved: Some(panel_subscription_smoke_runtime_preserved(&apply_status)),
            clear_allowed_runtime: None,
        },
    ));

    core.clear_panel_state();
    match core.reload_from_subscription_config_text(&config, Some("SS-READY".to_string())) {
        Ok(status) => {
            final_selected_outbound = status.selected_outbound.clone();
            clear_allowed_runtime = panel_subscription_smoke_runtime_reloaded_after_clear(&status);
            cases.push(panel_subscription_smoke_status_case(
                "clear-restriction-allows-reload",
                "clear-panel-state-reload",
                &status,
                PanelSubscriptionSmokeCaseExpectations {
                    expected_error_kind: None,
                    error_detail: None,
                    expected_selected_outbound: Some("SS-READY"),
                    expected_generation: Some(2),
                    expected_runtime_running: Some(true),
                    expected_panel_state_present: Some(false),
                    expected_restrict_traffic: None,
                    start_blocked: None,
                    reload_blocked: None,
                    probe_blocked: None,
                    apply_blocked: None,
                    runtime_preserved: None,
                    clear_allowed_runtime: Some(clear_allowed_runtime),
                },
            ));
        }
        Err(error) => cases.push(panel_subscription_smoke_error_case(
            "clear-restriction-allows-reload",
            "clear-panel-state-reload",
            Some("SS-READY"),
            Some(2),
            error,
        )),
    }

    match core.stop() {
        Ok(stopped) => {
            let final_generation = Some(stopped.generation());
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(panel_subscription_smoke_stop_case(
                clean_stop_observed,
                final_generation,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(panel_subscription_smoke_stop_case(
            false,
            None,
            None,
            None,
            Some(error),
        )),
    }

    finalize_panel_subscription_smoke_report(
        cases,
        start_blocked,
        reload_blocked,
        probe_blocked,
        apply_blocked,
        runtime_preserved_while_restricted,
        clear_allowed_runtime,
        final_selected_outbound,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn panel_subscription_smoke_restricted_panel_state() -> PanelState {
    PanelState::new(
        PanelUserState {
            account_state: PanelAccountState::Limited,
            used_bytes: Some(1024),
            total_bytes: Some(1024),
            expires_at: None,
        },
        PanelRiskControlState::Restricted,
    )
    .with_support_note("panel smoke restricted traffic")
}

fn finalize_panel_subscription_smoke_report(
    cases: Vec<PanelSubscriptionSmokeCaseReport>,
    start_blocked: bool,
    reload_blocked: bool,
    probe_blocked: bool,
    apply_blocked: bool,
    runtime_preserved_while_restricted: bool,
    clear_allowed_runtime: bool,
    final_selected_outbound: Option<String>,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> PanelSubscriptionSmokeReport {
    let passed_count = cases.iter().filter(|case| case.passed).count();
    let failed: Vec<&str> = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect();
    let passed = failed.is_empty()
        && start_blocked
        && reload_blocked
        && probe_blocked
        && apply_blocked
        && runtime_preserved_while_restricted
        && clear_allowed_runtime
        && clean_stop_observed;
    PanelSubscriptionSmokeReport {
        passed,
        detail: format!(
            "cases={} passed={} failed={} failed_cases={} restricted_account=limited restricted_risk=restricted start_blocked={} reload_blocked={} probe_blocked={} apply_blocked={} runtime_preserved={} clear_allowed_runtime={} final_selected={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
            cases.len(),
            passed_count,
            failed.len(),
            if failed.is_empty() {
                "-".to_string()
            } else {
                failed.join(",")
            },
            start_blocked,
            reload_blocked,
            probe_blocked,
            apply_blocked,
            runtime_preserved_while_restricted,
            clear_allowed_runtime,
            final_selected_outbound.as_deref().unwrap_or("-"),
            clean_stop_observed,
            optional_usize_label(stop_workers_remaining),
            optional_bool_label(stop_timed_out)
        ),
        restricted_account_state: "limited",
        restricted_risk_control: "restricted",
        start_blocked,
        reload_blocked,
        probe_blocked,
        apply_blocked,
        runtime_preserved_while_restricted,
        clear_allowed_runtime,
        final_selected_outbound,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

#[derive(Debug)]
struct PanelSubscriptionSmokeCaseExpectations {
    expected_error_kind: Option<&'static str>,
    error_detail: Option<String>,
    expected_selected_outbound: Option<&'static str>,
    expected_generation: Option<u64>,
    expected_runtime_running: Option<bool>,
    expected_panel_state_present: Option<bool>,
    expected_restrict_traffic: Option<bool>,
    start_blocked: Option<bool>,
    reload_blocked: Option<bool>,
    probe_blocked: Option<bool>,
    apply_blocked: Option<bool>,
    runtime_preserved: Option<bool>,
    clear_allowed_runtime: Option<bool>,
}

fn panel_subscription_smoke_status_case(
    name: &'static str,
    action: &'static str,
    status: &ManagedMixedStatusSnapshot,
    expected: PanelSubscriptionSmokeCaseExpectations,
) -> PanelSubscriptionSmokeCaseReport {
    let runtime_running = matches!(&status.status, RuntimeStatus::Running { .. });
    let observed_error_kind = expected
        .error_detail
        .as_deref()
        .and_then(panel_subscription_smoke_error_kind_from_detail)
        .or_else(|| {
            expected.expected_error_kind.and_then(|_| {
                status
                    .last_error
                    .as_ref()
                    .map(client_error_kind_label)
                    .map(str::to_string)
            })
        });
    let panel_state_present = status.panel_state.is_some();
    let restrict_traffic = status
        .panel_state
        .as_ref()
        .map(PanelState::should_restrict_traffic);
    let error_matches = expected
        .expected_error_kind
        .map(|expected| observed_error_kind.as_deref() == Some(expected))
        .unwrap_or_else(|| observed_error_kind.is_none());
    let selected_matches = expected
        .expected_selected_outbound
        .map(|expected| status.selected_outbound.as_deref() == Some(expected))
        .unwrap_or(true);
    let generation_matches = expected
        .expected_generation
        .map(|expected| status.generation == expected)
        .unwrap_or(true);
    let runtime_matches = expected
        .expected_runtime_running
        .map(|expected| runtime_running == expected)
        .unwrap_or(true);
    let panel_state_matches = expected
        .expected_panel_state_present
        .map(|expected| panel_state_present == expected)
        .unwrap_or(true);
    let restrict_matches = expected
        .expected_restrict_traffic
        .map(|expected| restrict_traffic == Some(expected))
        .unwrap_or(true);
    let passed = error_matches
        && selected_matches
        && generation_matches
        && runtime_matches
        && panel_state_matches
        && restrict_matches
        && expected.start_blocked.unwrap_or(true)
        && expected.reload_blocked.unwrap_or(true)
        && expected.probe_blocked.unwrap_or(true)
        && expected.apply_blocked.unwrap_or(true)
        && expected.runtime_preserved.unwrap_or(true)
        && expected.clear_allowed_runtime.unwrap_or(true);

    PanelSubscriptionSmokeCaseReport {
        name,
        action,
        expected_error_kind: expected.expected_error_kind,
        observed_error_kind,
        error_detail: expected.error_detail,
        expected_selected_outbound: expected.expected_selected_outbound.map(str::to_string),
        observed_selected_outbound: status.selected_outbound.clone(),
        expected_generation: expected.expected_generation,
        observed_generation: Some(status.generation),
        runtime_running: Some(runtime_running),
        panel_state_present: Some(panel_state_present),
        restrict_traffic,
        start_blocked: expected.start_blocked,
        reload_blocked: expected.reload_blocked,
        probe_blocked: expected.probe_blocked,
        apply_blocked: expected.apply_blocked,
        runtime_preserved: expected.runtime_preserved,
        clear_allowed_runtime: expected.clear_allowed_runtime,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
    }
}

fn panel_subscription_smoke_stop_case(
    clean_stop_observed: bool,
    final_generation: Option<u64>,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
    error: Option<String>,
) -> PanelSubscriptionSmokeCaseReport {
    PanelSubscriptionSmokeCaseReport {
        name: "stop-runtime-after-panel-smoke",
        action: "stop",
        expected_error_kind: None,
        observed_error_kind: None,
        error_detail: error,
        expected_selected_outbound: None,
        observed_selected_outbound: None,
        expected_generation: Some(2),
        observed_generation: final_generation,
        runtime_running: Some(false),
        panel_state_present: Some(false),
        restrict_traffic: None,
        start_blocked: None,
        reload_blocked: None,
        probe_blocked: None,
        apply_blocked: None,
        runtime_preserved: None,
        clear_allowed_runtime: None,
        clean_stop_observed: Some(clean_stop_observed),
        stop_workers_remaining,
        stop_timed_out,
        passed: clean_stop_observed && final_generation == Some(2),
    }
}

fn panel_subscription_smoke_error_case(
    name: &'static str,
    action: &'static str,
    expected_selected_outbound: Option<&'static str>,
    expected_generation: Option<u64>,
    error: String,
) -> PanelSubscriptionSmokeCaseReport {
    PanelSubscriptionSmokeCaseReport {
        name,
        action,
        expected_error_kind: None,
        observed_error_kind: panel_subscription_smoke_error_kind_from_detail(&error),
        error_detail: Some(error),
        expected_selected_outbound: expected_selected_outbound.map(str::to_string),
        observed_selected_outbound: None,
        expected_generation,
        observed_generation: None,
        runtime_running: None,
        panel_state_present: None,
        restrict_traffic: None,
        start_blocked: None,
        reload_blocked: None,
        probe_blocked: None,
        apply_blocked: None,
        runtime_preserved: None,
        clear_allowed_runtime: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed: false,
    }
}

fn panel_subscription_smoke_error_kind_from_detail(error: &str) -> Option<String> {
    if error.contains("PanelTrafficRestricted") {
        Some("panel-traffic-restricted".to_string())
    } else {
        None
    }
}

fn panel_subscription_smoke_runtime_preserved(status: &ManagedMixedStatusSnapshot) -> bool {
    status.selected_outbound.as_deref() == Some("SS-READY")
        && status.generation == 1
        && matches!(
            status.status,
            RuntimeStatus::Running {
                ref selected_outbound,
                generation,
                ..
            } if selected_outbound == "SS-READY" && generation == 1
        )
}

fn panel_subscription_smoke_runtime_reloaded_after_clear(
    status: &ManagedMixedStatusSnapshot,
) -> bool {
    status.panel_state.is_none()
        && status.selected_outbound.as_deref() == Some("SS-READY")
        && status.generation == 2
        && matches!(
            status.status,
            RuntimeStatus::Running {
                ref selected_outbound,
                generation,
                ..
            } if selected_outbound == "SS-READY" && generation == 2
        )
}

#[cfg(test)]
mod panel_subscription_smoke_tests {
    use super::*;

    #[test]
    fn default_panel_subscription_smoke_blocks_restricted_panel_and_recovers() {
        let report = collect_default_panel_subscription_smoke_report();

        assert!(report.passed, "{}", report.detail);
        assert_eq!(report.restricted_account_state, "limited");
        assert_eq!(report.restricted_risk_control, "restricted");
        assert!(report.start_blocked);
        assert!(report.reload_blocked);
        assert!(report.probe_blocked);
        assert!(report.apply_blocked);
        assert!(report.runtime_preserved_while_restricted);
        assert!(report.clear_allowed_runtime);
        assert_eq!(report.final_selected_outbound.as_deref(), Some("SS-READY"));
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));
        assert_eq!(report.cases.len(), 9);

        for case_name in [
            "record-restricted-panel-before-start",
            "block-start-while-restricted",
            "clear-and-start-runtime",
            "record-restricted-panel-during-runtime",
            "block-reload-while-restricted",
            "block-node-probe-while-restricted",
            "block-recommended-switch-while-restricted",
            "clear-restriction-allows-reload",
            "stop-runtime-after-panel-smoke",
        ] {
            let case = report
                .cases
                .iter()
                .find(|case| case.name == case_name)
                .unwrap_or_else(|| panic!("missing panel smoke case {case_name}"));
            assert!(case.passed, "{case:?}");
        }

        let reload = report
            .cases
            .iter()
            .find(|case| case.name == "block-reload-while-restricted")
            .expect("reload block case");
        assert_eq!(
            reload.observed_error_kind.as_deref(),
            Some("panel-traffic-restricted")
        );
        assert_eq!(reload.runtime_preserved, Some(true));
        assert_eq!(reload.restrict_traffic, Some(true));

        let clear = report
            .cases
            .iter()
            .find(|case| case.name == "clear-restriction-allows-reload")
            .expect("clear reload case");
        assert_eq!(clear.clear_allowed_runtime, Some(true));
        assert_eq!(clear.panel_state_present, Some(false));
        assert_eq!(clear.observed_generation, Some(2));
    }
}

#[cfg(test)]
mod subscription_reload_smoke_tests {
    use super::*;

    #[test]
    fn default_subscription_reload_smoke_preserves_fallbacks_prunes_and_stops_cleanly() {
        let report = collect_default_subscription_reload_smoke_report();

        assert!(report.passed, "{}", report.detail);
        assert_eq!(report.initial_generation, Some(1));
        assert_eq!(report.final_generation, Some(3));
        assert_eq!(
            report.final_selected_outbound.as_deref(),
            Some("SS-FALLBACK")
        );
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));
        assert_eq!(report.cases.len(), 4);

        for case_name in [
            "start-subscription-runtime",
            "preserve-selected-outbound",
            "fallback-to-new-default",
            "stop-subscription-runtime",
        ] {
            let case = report
                .cases
                .iter()
                .find(|case| case.name == case_name)
                .unwrap_or_else(|| panic!("missing subscription reload smoke case {case_name}"));
            assert!(case.passed, "{case:?}");
        }

        let preserve = report
            .cases
            .iter()
            .find(|case| case.name == "preserve-selected-outbound")
            .expect("preserve case");
        assert_eq!(
            preserve.observed_reason.as_deref(),
            Some("selected-outbound-preserved")
        );
        assert_eq!(
            preserve.observed_selected_outbound.as_deref(),
            Some("SS-STAY")
        );
        assert_eq!(preserve.stale_health_pruned, Some(true));
        assert_eq!(preserve.selected_health_state.as_deref(), Some("healthy"));

        let fallback = report
            .cases
            .iter()
            .find(|case| case.name == "fallback-to-new-default")
            .expect("fallback case");
        assert_eq!(
            fallback.observed_reason.as_deref(),
            Some("selected-outbound-missing-use-default")
        );
        assert_eq!(
            fallback.observed_selected_outbound.as_deref(),
            Some("SS-FALLBACK")
        );
        assert_eq!(fallback.stale_health_pruned, Some(true));
        assert_eq!(fallback.selected_health_state.as_deref(), Some("unknown"));
    }
}

fn collect_default_runtime_recovery_smoke_report() -> RuntimeRecoverySmokeReport {
    let controller = SubscriptionReloadSmokeSystemProxyController;
    let mut core = ManagedMixedController::new(&controller);
    let mut cases = Vec::new();
    let mut initial_generation = None;
    let mut final_generation = None;
    let mut final_selected_outbound = None;
    let mut clean_stop_observed = false;
    let mut stop_workers_remaining = None;
    let mut stop_timed_out = None;

    let started = match core.start_from_subscription_config_text(
        &subscription_reload_smoke_config(&["SS-READY"]),
        ManagedMixedOptions {
            listen: "127.0.0.1:0".to_string(),
            outbound_tag: Some("SS-READY".to_string()),
            system_proxy: false,
            max_connection_workers: 2,
            ..ManagedMixedOptions::default()
        },
    ) {
        Ok(status) => status,
        Err(error) => {
            cases.push(runtime_recovery_smoke_error_case(
                "start-runtime",
                "start",
                None,
                Some("SS-READY"),
                Some(1),
                error,
            ));
            return finalize_runtime_recovery_smoke_report(
                cases,
                initial_generation,
                final_generation,
                final_selected_outbound,
                false,
                clean_stop_observed,
                stop_workers_remaining,
                stop_timed_out,
            );
        }
    };
    initial_generation = Some(started.generation);
    cases.push(runtime_recovery_smoke_status_case(
        "start-runtime",
        "start",
        &started,
        None,
        None,
        Some("SS-READY"),
        Some(1),
        None,
    ));

    let unknown_error = core
        .reload_from_subscription_config_text(
            &subscription_reload_smoke_config(&["SS-READY"]),
            Some("MISSING".to_string()),
        )
        .expect_err("unknown outbound reload should be rejected");
    let unknown_status = core.status();
    cases.push(runtime_recovery_smoke_status_case(
        "reject-unknown-outbound-reload",
        "reload-rejected",
        &unknown_status,
        Some("outbound-not-found"),
        Some(unknown_error),
        Some("SS-READY"),
        Some(1),
        None,
    ));

    let unusable = r#"
proxies:
  - name: WG-SKIPPED
    type: wireguard
    server: wg.example.com
    port: 51820
    password: ignored
"#;
    match core.reload_from_subscription_config_text_with_update_plan(unusable) {
        Ok(outcome) => {
            cases.push(runtime_recovery_smoke_status_case(
                "reject-unusable-subscription-update",
                "planned-reload-rejected",
                &outcome.status,
                Some("no-supported-outbounds"),
                outcome.error.clone(),
                Some("SS-READY"),
                Some(1),
                Some(outcome.applied),
            ));
        }
        Err(error) => {
            let status = core.status();
            cases.push(runtime_recovery_smoke_status_case(
                "reject-unusable-subscription-update",
                "planned-reload-rejected",
                &status,
                Some("no-supported-outbounds"),
                Some(error),
                Some("SS-READY"),
                Some(1),
                None,
            ));
        }
    }

    let preserved_after_failures = cases.iter().filter(|case| !case.passed).count() == 0
        && core.status().selected_outbound.as_deref() == Some("SS-READY")
        && core.status().generation == 1
        && matches!(
            core.status().status,
            RuntimeStatus::Running {
                ref selected_outbound,
                generation,
                ..
            } if selected_outbound == "SS-READY" && generation == 1
        );

    match core.stop() {
        Ok(stopped) => {
            final_generation = Some(stopped.generation());
            final_selected_outbound = Some("SS-READY".to_string());
            let stop_drain = stopped.events().iter().rev().find_map(|event| {
                if let Some(RuntimeDiagnostic::ManagedMixedStopDrain(diagnostic)) =
                    event.diagnostic.as_ref()
                {
                    Some(diagnostic)
                } else {
                    None
                }
            });
            stop_workers_remaining = stop_drain.map(|diagnostic| diagnostic.workers_remaining);
            stop_timed_out = stop_drain.map(|diagnostic| diagnostic.timed_out);
            clean_stop_observed = matches!(stopped.status(), RuntimeStatus::Stopped)
                && stop_workers_remaining == Some(0)
                && stop_timed_out == Some(false);
            cases.push(runtime_recovery_smoke_stop_case(
                clean_stop_observed,
                final_generation,
                stop_workers_remaining,
                stop_timed_out,
                None,
            ));
        }
        Err(error) => cases.push(runtime_recovery_smoke_stop_case(
            false,
            None,
            None,
            None,
            Some(error),
        )),
    }

    finalize_runtime_recovery_smoke_report(
        cases,
        initial_generation,
        final_generation,
        final_selected_outbound,
        preserved_after_failures,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
    )
}

fn finalize_runtime_recovery_smoke_report(
    cases: Vec<RuntimeRecoverySmokeCaseReport>,
    initial_generation: Option<u64>,
    final_generation: Option<u64>,
    final_selected_outbound: Option<String>,
    preserved_after_failures: bool,
    clean_stop_observed: bool,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
) -> RuntimeRecoverySmokeReport {
    let passed_count = cases.iter().filter(|case| case.passed).count();
    let failed: Vec<&str> = cases
        .iter()
        .filter(|case| !case.passed)
        .map(|case| case.name)
        .collect();
    let passed = failed.is_empty() && preserved_after_failures && clean_stop_observed;
    RuntimeRecoverySmokeReport {
        passed,
        detail: format!(
            "cases={} passed={} failed={} failed_cases={} initial_generation={} final_generation={} final_selected={} preserved_after_failures={} clean_stop_observed={} stop_workers_remaining={} stop_timed_out={}",
            cases.len(),
            passed_count,
            failed.len(),
            if failed.is_empty() {
                "-".to_string()
            } else {
                failed.join(",")
            },
            optional_u64_label(initial_generation),
            optional_u64_label(final_generation),
            final_selected_outbound.as_deref().unwrap_or("-"),
            preserved_after_failures,
            clean_stop_observed,
            optional_usize_label(stop_workers_remaining),
            optional_bool_label(stop_timed_out)
        ),
        initial_generation,
        final_generation,
        final_selected_outbound,
        preserved_after_failures,
        clean_stop_observed,
        stop_workers_remaining,
        stop_timed_out,
        cases,
    }
}

fn runtime_recovery_smoke_status_case(
    name: &'static str,
    action: &'static str,
    status: &ManagedMixedStatusSnapshot,
    expected_error_kind: Option<&'static str>,
    error_detail: Option<String>,
    expected_selected_outbound: Option<&'static str>,
    expected_generation: Option<u64>,
    applied: Option<bool>,
) -> RuntimeRecoverySmokeCaseReport {
    let observed_error_kind = status
        .last_error
        .as_ref()
        .map(client_error_kind_label)
        .map(str::to_string);
    let runtime_still_running = matches!(
        &status.status,
        RuntimeStatus::Running {
            selected_outbound,
            generation,
            ..
        } if expected_selected_outbound
            .is_none_or(|expected| selected_outbound == expected)
            && expected_generation.is_none_or(|expected| *generation == expected)
    );
    let active_subscription_usable = status.subscription.as_ref().map(|subscription| {
        subscription.usable
            && expected_selected_outbound
                .is_none_or(|expected| subscription.selected_outbound == expected)
    });
    let error_matches = expected_error_kind
        .map(|expected| observed_error_kind.as_deref() == Some(expected))
        .unwrap_or_else(|| observed_error_kind.is_none());
    let selected_matches = expected_selected_outbound
        .map(|expected| status.selected_outbound.as_deref() == Some(expected))
        .unwrap_or(true);
    let generation_matches = expected_generation
        .map(|expected| status.generation == expected)
        .unwrap_or(true);
    let applied_matches = applied != Some(true);
    let passed = runtime_still_running
        && active_subscription_usable.unwrap_or(false)
        && error_matches
        && selected_matches
        && generation_matches
        && applied_matches;

    RuntimeRecoverySmokeCaseReport {
        name,
        action,
        expected_error_kind,
        observed_error_kind,
        error_detail,
        expected_selected_outbound: expected_selected_outbound.map(str::to_string),
        observed_selected_outbound: status.selected_outbound.clone(),
        expected_generation,
        observed_generation: Some(status.generation),
        runtime_still_running: Some(runtime_still_running),
        active_subscription_usable,
        applied,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed,
    }
}

fn runtime_recovery_smoke_stop_case(
    clean_stop_observed: bool,
    final_generation: Option<u64>,
    stop_workers_remaining: Option<usize>,
    stop_timed_out: Option<bool>,
    error: Option<String>,
) -> RuntimeRecoverySmokeCaseReport {
    RuntimeRecoverySmokeCaseReport {
        name: "stop-runtime-after-recovery",
        action: "stop",
        expected_error_kind: None,
        observed_error_kind: None,
        error_detail: error,
        expected_selected_outbound: None,
        observed_selected_outbound: None,
        expected_generation: Some(1),
        observed_generation: final_generation,
        runtime_still_running: None,
        active_subscription_usable: None,
        applied: None,
        clean_stop_observed: Some(clean_stop_observed),
        stop_workers_remaining,
        stop_timed_out,
        passed: clean_stop_observed && final_generation == Some(1),
    }
}

fn runtime_recovery_smoke_error_case(
    name: &'static str,
    action: &'static str,
    expected_error_kind: Option<&'static str>,
    expected_selected_outbound: Option<&'static str>,
    expected_generation: Option<u64>,
    error: String,
) -> RuntimeRecoverySmokeCaseReport {
    RuntimeRecoverySmokeCaseReport {
        name,
        action,
        expected_error_kind,
        observed_error_kind: None,
        error_detail: Some(error),
        expected_selected_outbound: expected_selected_outbound.map(str::to_string),
        observed_selected_outbound: None,
        expected_generation,
        observed_generation: None,
        runtime_still_running: None,
        active_subscription_usable: None,
        applied: None,
        clean_stop_observed: None,
        stop_workers_remaining: None,
        stop_timed_out: None,
        passed: false,
    }
}

fn client_error_kind_label(error: &ClientErrorKind) -> &'static str {
    match error {
        ClientErrorKind::CoreNotStarted => "core-not-started",
        ClientErrorKind::DnsTimeout => "dns-timeout",
        ClientErrorKind::TcpConnectTimeout => "tcp-connect-timeout",
        ClientErrorKind::TlsHandshakeFailed => "tls-handshake-failed",
        ClientErrorKind::WebSocketUpgradeFailed => "websocket-upgrade-failed",
        ClientErrorKind::ProxyAuthFailed => "proxy-auth-failed",
        ClientErrorKind::RelayStalled => "relay-stalled",
        ClientErrorKind::TunPermissionMissing => "tun-permission-missing",
        ClientErrorKind::SystemProxyLoop => "system-proxy-loop",
        ClientErrorKind::RouteNoOutbound => "route-no-outbound",
        ClientErrorKind::NoSupportedOutbounds => "no-supported-outbounds",
        ClientErrorKind::OutboundNotFound(_) => "outbound-not-found",
        ClientErrorKind::PanelTrafficRestricted { .. } => "panel-traffic-restricted",
        ClientErrorKind::ConfigInvalid(_) => "config-invalid",
    }
}

#[cfg(test)]
mod runtime_recovery_smoke_tests {
    use super::*;

    #[test]
    fn default_runtime_recovery_smoke_rejects_bad_reloads_without_dropping_runtime() {
        let report = collect_default_runtime_recovery_smoke_report();

        assert!(report.passed, "{}", report.detail);
        assert_eq!(report.initial_generation, Some(1));
        assert_eq!(report.final_generation, Some(1));
        assert_eq!(report.final_selected_outbound.as_deref(), Some("SS-READY"));
        assert!(report.preserved_after_failures);
        assert!(report.clean_stop_observed);
        assert_eq!(report.stop_workers_remaining, Some(0));
        assert_eq!(report.stop_timed_out, Some(false));
        assert_eq!(report.cases.len(), 4);

        for case_name in [
            "start-runtime",
            "reject-unknown-outbound-reload",
            "reject-unusable-subscription-update",
            "stop-runtime-after-recovery",
        ] {
            let case = report
                .cases
                .iter()
                .find(|case| case.name == case_name)
                .unwrap_or_else(|| panic!("missing runtime recovery smoke case {case_name}"));
            assert!(case.passed, "{case:?}");
        }

        let unknown = report
            .cases
            .iter()
            .find(|case| case.name == "reject-unknown-outbound-reload")
            .expect("unknown outbound recovery case");
        assert_eq!(
            unknown.observed_error_kind.as_deref(),
            Some("outbound-not-found")
        );
        assert_eq!(
            unknown.observed_selected_outbound.as_deref(),
            Some("SS-READY")
        );
        assert_eq!(unknown.observed_generation, Some(1));
        assert_eq!(unknown.runtime_still_running, Some(true));

        let unusable = report
            .cases
            .iter()
            .find(|case| case.name == "reject-unusable-subscription-update")
            .expect("unusable subscription recovery case");
        assert_eq!(
            unusable.observed_error_kind.as_deref(),
            Some("no-supported-outbounds")
        );
        assert_eq!(unusable.applied, Some(false));
        assert_eq!(
            unusable.observed_selected_outbound.as_deref(),
            Some("SS-READY")
        );
        assert_eq!(unusable.runtime_still_running, Some(true));
    }
}

fn readiness_system_proxy_smoke_gate(
    smoke_report: &mut Option<SystemProxySmokeReport>,
) -> ReadinessGateReport {
    let report = collect_default_system_proxy_smoke_report();
    let status = if report.passed {
        ReadinessGateStatus::Passed
    } else {
        ReadinessGateStatus::Failed
    };
    let detail = report.detail.clone();
    *smoke_report = Some(report);
    ReadinessGateReport {
        name: "system-proxy-smoke",
        category: "platform",
        status,
        detail,
    }
}

fn collect_default_system_proxy_smoke_report() -> SystemProxySmokeReport {
    let controller = NativeSystemProxyController::new();
    collect_system_proxy_smoke_report(&controller, default_system_proxy_smoke_config())
}

fn default_system_proxy_smoke_config() -> SystemProxyConfig {
    SystemProxyConfig::mixed_inbound(SYSTEM_PROXY_SMOKE_LISTEN, SYSTEM_PROXY_SMOKE_PORT)
        .expect("default system proxy smoke config is valid")
        .with_bypass(SYSTEM_PROXY_SMOKE_BYPASS)
}

fn collect_system_proxy_smoke_report<C>(
    controller: &C,
    config: SystemProxyConfig,
) -> SystemProxySmokeReport
where
    C: SystemProxyController + ?Sized,
{
    let mut report = SystemProxySmokeReport {
        passed: false,
        detail: String::new(),
        config,
        original_snapshot: None,
        apply_returned_snapshot: None,
        applied_snapshot: None,
        restored_snapshot: None,
        apply_returned_original_match: false,
        applied_matches_config: false,
        restore_attempted: false,
        restore_succeeded: false,
        restored_original_snapshot_match: false,
        snapshot_error: None,
        apply_error: None,
        applied_snapshot_error: None,
        restore_error: None,
        restored_snapshot_error: None,
    };

    let original_snapshot = match controller.snapshot() {
        Ok(snapshot) => {
            report.original_snapshot = Some(snapshot.clone());
            snapshot
        }
        Err(error) => {
            report.snapshot_error = Some(error.to_string());
            report.detail = system_proxy_smoke_detail(&report);
            return report;
        }
    };

    match controller.apply(&report.config) {
        Ok(snapshot) => {
            report.apply_returned_original_match = snapshot == original_snapshot;
            report.apply_returned_snapshot = Some(snapshot);
        }
        Err(error) => {
            report.apply_error = Some(error.to_string());
        }
    }

    if report.apply_error.is_none() {
        match controller.snapshot() {
            Ok(snapshot) => {
                report.applied_matches_config =
                    system_proxy_snapshot_matches_config(&snapshot, &report.config);
                report.applied_snapshot = Some(snapshot);
            }
            Err(error) => {
                report.applied_snapshot_error = Some(error.to_string());
            }
        }
    }

    report.restore_attempted = true;
    match controller.restore(&original_snapshot) {
        Ok(()) => {
            report.restore_succeeded = true;
        }
        Err(error) => {
            report.restore_error = Some(error.to_string());
        }
    }

    match controller.snapshot() {
        Ok(snapshot) => {
            report.restored_original_snapshot_match = snapshot == original_snapshot;
            report.restored_snapshot = Some(snapshot);
        }
        Err(error) => {
            report.restored_snapshot_error = Some(error.to_string());
        }
    }

    report.passed = report.snapshot_error.is_none()
        && report.apply_error.is_none()
        && report.applied_snapshot_error.is_none()
        && report.apply_returned_original_match
        && report.applied_matches_config
        && report.restore_attempted
        && report.restore_succeeded
        && report.restore_error.is_none()
        && report.restored_snapshot_error.is_none()
        && report.restored_original_snapshot_match;
    report.detail = system_proxy_smoke_detail(&report);
    report
}

fn system_proxy_snapshot_matches_config(
    snapshot: &SystemProxySnapshot,
    config: &SystemProxyConfig,
) -> bool {
    snapshot.enabled()
        && snapshot.proxy_server.as_deref() == Some(config.server.as_str())
        && snapshot.proxy_override.as_deref() == config.bypass_value().as_deref()
}

fn system_proxy_smoke_detail(report: &SystemProxySmokeReport) -> String {
    format!(
        "server={} bypass={} applied_matches_config={} apply_returned_original_match={} restore_attempted={} restore_succeeded={} restored_original_snapshot_match={} snapshot_error={} apply_error={} applied_snapshot_error={} restore_error={} restored_snapshot_error={}",
        report.config.server,
        report.config.bypass.join(";"),
        report.applied_matches_config,
        report.apply_returned_original_match,
        report.restore_attempted,
        report.restore_succeeded,
        report.restored_original_snapshot_match,
        report.snapshot_error.as_deref().unwrap_or("-"),
        report.apply_error.as_deref().unwrap_or("-"),
        report.applied_snapshot_error.as_deref().unwrap_or("-"),
        report.restore_error.as_deref().unwrap_or("-"),
        report.restored_snapshot_error.as_deref().unwrap_or("-")
    )
}

#[cfg(test)]
mod system_proxy_smoke_tests {
    use super::*;
    use std::cell::RefCell;

    #[derive(Debug)]
    struct FakeSystemProxyController {
        current: RefCell<SystemProxySnapshot>,
        applied: RefCell<Vec<SystemProxyConfig>>,
        restored: RefCell<Vec<SystemProxySnapshot>>,
    }

    impl FakeSystemProxyController {
        fn new(snapshot: SystemProxySnapshot) -> Self {
            Self {
                current: RefCell::new(snapshot),
                applied: RefCell::new(Vec::new()),
                restored: RefCell::new(Vec::new()),
            }
        }
    }

    impl SystemProxyController for FakeSystemProxyController {
        fn snapshot(&self) -> Result<SystemProxySnapshot, keli_platform::SystemProxyError> {
            Ok(self.current.borrow().clone())
        }

        fn apply(
            &self,
            config: &SystemProxyConfig,
        ) -> Result<SystemProxySnapshot, keli_platform::SystemProxyError> {
            let previous = self.current.borrow().clone();
            self.applied.borrow_mut().push(config.clone());
            *self.current.borrow_mut() = SystemProxySnapshot {
                proxy_enable: Some(1),
                proxy_server: Some(config.server.clone()),
                proxy_override: config.bypass_value(),
            };
            Ok(previous)
        }

        fn restore(
            &self,
            snapshot: &SystemProxySnapshot,
        ) -> Result<(), keli_platform::SystemProxyError> {
            self.restored.borrow_mut().push(snapshot.clone());
            *self.current.borrow_mut() = snapshot.clone();
            Ok(())
        }
    }

    #[test]
    fn system_proxy_smoke_applies_verifies_and_restores_snapshot() {
        let original = SystemProxySnapshot {
            proxy_enable: Some(0),
            proxy_server: Some("old.proxy:8080".to_string()),
            proxy_override: Some("<local>".to_string()),
        };
        let controller = FakeSystemProxyController::new(original.clone());
        let config = SystemProxyConfig::mixed_inbound("127.0.0.1", 7890)
            .expect("valid smoke config")
            .with_bypass(["localhost", "<local>"]);

        let report = collect_system_proxy_smoke_report(&controller, config.clone());

        assert!(report.passed, "{}", report.detail);
        assert_eq!(report.config, config);
        assert_eq!(report.original_snapshot, Some(original.clone()));
        assert_eq!(report.apply_returned_snapshot, Some(original.clone()));
        assert!(report.apply_returned_original_match);
        assert!(report.applied_matches_config);
        assert!(report.restore_attempted);
        assert!(report.restore_succeeded);
        assert!(report.restored_original_snapshot_match);
        assert_eq!(report.restored_snapshot, Some(original.clone()));
        assert_eq!(controller.current.borrow().clone(), original.clone());
        assert_eq!(controller.applied.borrow().len(), 1);
        assert_eq!(controller.restored.borrow().as_slice(), &[original]);
    }
}

