fn collect_default_tun_tcp_session_smoke_report() -> TunTcpSessionSmokeReport {
    match run_default_tun_tcp_session_smoke() {
        Ok(evidence) => tun_tcp_session_smoke_report_from_evidence(evidence),
        Err(error) => tun_tcp_session_smoke_failed_report(error),
    }
}

#[derive(Debug)]
struct TunTcpSessionSmokeRunEvidence {
    report: ManagedTunPacketLoopReport,
    target: SocketAddr,
    starts_observed: usize,
    opens_observed: usize,
    stops_observed: usize,
    tun_writes: Vec<Vec<u8>>,
    server_received_payload: bool,
}

fn run_default_tun_tcp_session_smoke() -> Result<TunTcpSessionSmokeRunEvidence, String> {
    let config = default_tun_device_config();
    let stopped_snapshot = tun_tcp_session_smoke_stopped_snapshot();
    let (tcp_port, tcp_server) = spawn_tun_tcp_session_smoke_server(
        TUN_TCP_SESSION_SMOKE_REQUEST,
        TUN_TCP_SESSION_SMOKE_RESPONSE,
    )?;
    let target = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), tcp_port);
    let tun_writes = Arc::new(Mutex::new(Vec::new()));
    let packet_io = TunTcpSessionSmokeFakePacketIo {
        reads: VecDeque::from(tun_tcp_session_smoke_packets(
            Ipv4Addr::LOCALHOST,
            tcp_port,
            DEFAULT_TUN_TCP_SERVER_INITIAL_SEQUENCE_NUMBER,
            TUN_TCP_SESSION_SMOKE_REQUEST,
            TUN_TCP_SESSION_SMOKE_RESPONSE.len(),
        )),
        read_delays: VecDeque::new(),
        writes: Vec::new(),
        shared_writes: Arc::clone(&tun_writes),
    };
    let controller = TunTcpSessionSmokeFakeController::new(
        stopped_snapshot.clone(),
        TunDeviceSnapshot::running(&config),
        stopped_snapshot,
        packet_io,
    );
    let runtime = default_tun_tcp_session_smoke_runtime();

    let loop_result = run_managed_tun_packet_loop_with_runtime(
        &controller,
        config,
        &runtime,
        DEFAULT_TUN_DNS_TTL_SECONDS,
        TUN_TCP_SESSION_SMOKE_MAX_PACKETS,
    );
    let server_received_payload = tcp_server
        .join()
        .map_err(|_| "TUN TCP session smoke server panicked".to_string())??;
    let report = loop_result?;
    let tun_writes = tun_writes
        .lock()
        .map_err(|_| "TUN TCP session smoke writes lock poisoned".to_string())?
        .clone();

    Ok(TunTcpSessionSmokeRunEvidence {
        report,
        target,
        starts_observed: controller.starts_observed()?,
        opens_observed: controller.opens_observed()?,
        stops_observed: controller.stops_observed(),
        tun_writes,
        server_received_payload,
    })
}

fn default_tun_tcp_session_smoke_runtime() -> MixedProxyRuntime {
    let mut outbounds = OutboundRegistry::new();
    outbounds.add_direct(TUN_TCP_SESSION_SMOKE_OUTBOUND);
    MixedProxyRuntime {
        routes: RouteEngine::new(RouteAction::Outbound(
            TUN_TCP_SESSION_SMOKE_OUTBOUND.to_string(),
        )),
        relay_options: RelayOptions {
            first_byte_timeout: Some(Duration::from_secs(2)),
            idle_timeout: Some(Duration::from_secs(2)),
        },
        outbounds,
        dns_options: MixedDnsOptions::default(),
        tun_tcp_max_active_sessions: DEFAULT_TUN_TCP_MAX_ACTIVE_SESSIONS,
        connection_metrics: ConnectionMetrics::default(),
        max_connection_workers: DEFAULT_MANAGED_MIXED_MAX_CONNECTION_WORKERS,
        connection_worker_gauge: ConnectionWorkerGauge::default(),
        active_connection_registry: ActiveConnectionRegistry::default(),
    }
}

fn tun_tcp_session_smoke_report_from_evidence(
    evidence: TunTcpSessionSmokeRunEvidence,
) -> TunTcpSessionSmokeReport {
    let summary = &evidence.report.summary;
    let observed_response = tun_tcp_session_smoke_observed_response(&evidence.tun_writes);
    let observed_response_text = observed_response
        .as_ref()
        .map(|payload| String::from_utf8_lossy(payload).into_owned());
    let response_payload_observed = tun_tcp_session_smoke_response_payload_observed(
        &evidence.tun_writes,
        evidence.target.port(),
    );
    let clean_stop_observed =
        evidence.stops_observed == 1 && !evidence.report.stop_snapshot.running;
    let residual_state_clean = summary.tcp_sessions_open == 0
        && summary.tcp_server_close_markers_open == 0
        && summary.tcp_post_close_markers_open == 0;
    let mut report = TunTcpSessionSmokeReport {
        passed: false,
        detail: String::new(),
        selected_outbound: TUN_TCP_SESSION_SMOKE_OUTBOUND.to_string(),
        target: evidence.target.to_string(),
        request_payload_bytes: TUN_TCP_SESSION_SMOKE_REQUEST.len(),
        response_payload_bytes: TUN_TCP_SESSION_SMOKE_RESPONSE.len(),
        response_payload_observed,
        server_received_payload: evidence.server_received_payload,
        starts_observed: evidence.starts_observed,
        opens_observed: evidence.opens_observed,
        stops_observed: evidence.stops_observed,
        tun_writes_observed: evidence.tun_writes.len(),
        processed_packets: summary.processed_packets(),
        tcp_session_events: summary.tcp_session_events,
        tcp_session_packets_written: summary.tcp_session_packets_written,
        tcp_sessions_peak: summary.tcp_sessions_peak,
        tcp_sessions_open: summary.tcp_sessions_open,
        tcp_server_close_markers_open: summary.tcp_server_close_markers_open,
        tcp_post_close_markers_open: summary.tcp_post_close_markers_open,
        tcp_session_errors: summary.tcp_session_errors,
        tcp_session_limit_rejections: summary.tcp_session_limit_rejections,
        tcp_max_active_sessions: summary.tcp_max_active_sessions,
        clean_stop_observed,
        residual_state_clean,
        cases: Vec::new(),
    };
    report.passed = tun_tcp_session_smoke_passed(&report);
    report.detail = tun_tcp_session_smoke_detail(&report);
    report.cases = tun_tcp_session_smoke_cases(&report, observed_response_text, None);
    report
}

fn tun_tcp_session_smoke_failed_report(error: String) -> TunTcpSessionSmokeReport {
    let mut report = TunTcpSessionSmokeReport {
        passed: false,
        detail: format!("TUN TCP session smoke failed: {error}"),
        selected_outbound: TUN_TCP_SESSION_SMOKE_OUTBOUND.to_string(),
        target: "127.0.0.1:0".to_string(),
        request_payload_bytes: TUN_TCP_SESSION_SMOKE_REQUEST.len(),
        response_payload_bytes: TUN_TCP_SESSION_SMOKE_RESPONSE.len(),
        response_payload_observed: false,
        server_received_payload: false,
        starts_observed: 0,
        opens_observed: 0,
        stops_observed: 0,
        tun_writes_observed: 0,
        processed_packets: 0,
        tcp_session_events: 0,
        tcp_session_packets_written: 0,
        tcp_sessions_peak: 0,
        tcp_sessions_open: 0,
        tcp_server_close_markers_open: 0,
        tcp_post_close_markers_open: 0,
        tcp_session_errors: 0,
        tcp_session_limit_rejections: 0,
        tcp_max_active_sessions: DEFAULT_TUN_TCP_MAX_ACTIVE_SESSIONS,
        clean_stop_observed: false,
        residual_state_clean: false,
        cases: Vec::new(),
    };
    report.cases = tun_tcp_session_smoke_cases(&report, None, Some(error));
    report
}

fn tun_tcp_session_smoke_passed(report: &TunTcpSessionSmokeReport) -> bool {
    report.starts_observed == 1
        && report.opens_observed == 1
        && report.stops_observed == 1
        && report.tun_writes_observed == 3
        && report.processed_packets == TUN_TCP_SESSION_SMOKE_MAX_PACKETS
        && report.tcp_session_events == TUN_TCP_SESSION_SMOKE_MAX_PACKETS
        && report.tcp_session_packets_written == 3
        && report.tcp_sessions_peak == 1
        && report.tcp_sessions_open == 0
        && report.tcp_server_close_markers_open == 0
        && report.tcp_post_close_markers_open == 0
        && report.tcp_session_errors == 0
        && report.tcp_session_limit_rejections == 0
        && report.tcp_max_active_sessions == DEFAULT_TUN_TCP_MAX_ACTIVE_SESSIONS
        && report.response_payload_observed
        && report.server_received_payload
        && report.clean_stop_observed
        && report.residual_state_clean
}

fn tun_tcp_session_smoke_detail(report: &TunTcpSessionSmokeReport) -> String {
    format!(
        "outbound={} target={} request_bytes={} response_bytes={} response_observed={} server_received={} starts={} opens={} stops={} tun_writes={} processed={} tcp_events={} tcp_writes={} tcp_sessions_peak={} tcp_sessions_open={} tcp_errors={} residual_state_clean={}",
        report.selected_outbound,
        report.target,
        report.request_payload_bytes,
        report.response_payload_bytes,
        report.response_payload_observed,
        report.server_received_payload,
        report.starts_observed,
        report.opens_observed,
        report.stops_observed,
        report.tun_writes_observed,
        report.processed_packets,
        report.tcp_session_events,
        report.tcp_session_packets_written,
        report.tcp_sessions_peak,
        report.tcp_sessions_open,
        report.tcp_session_errors,
        report.residual_state_clean
    )
}

fn tun_tcp_session_smoke_cases(
    report: &TunTcpSessionSmokeReport,
    observed_response: Option<String>,
    error: Option<String>,
) -> Vec<TunTcpSessionSmokeCaseReport> {
    let expected_response = String::from_utf8_lossy(TUN_TCP_SESSION_SMOKE_RESPONSE).into_owned();
    let case_error = |passed: bool| {
        if passed {
            None
        } else {
            error.clone().or_else(|| Some(report.detail.clone()))
        }
    };
    let case = |name, action, passed| TunTcpSessionSmokeCaseReport {
        name,
        action,
        target: report.target.clone(),
        expected_response: expected_response.clone(),
        observed_response: observed_response.clone(),
        request_payload_bytes: report.request_payload_bytes,
        response_payload_bytes: report.response_payload_bytes,
        processed_packets: report.processed_packets,
        tcp_session_events: report.tcp_session_events,
        tcp_session_packets_written: report.tcp_session_packets_written,
        tcp_sessions_peak: report.tcp_sessions_peak,
        tcp_sessions_open: report.tcp_sessions_open,
        tcp_session_errors: report.tcp_session_errors,
        tun_writes_observed: report.tun_writes_observed,
        passed,
        error: case_error(passed),
    };
    vec![
        case(
            "start-tun-tcp-session-relay",
            "start managed TUN packet loop and open packet IO",
            report.starts_observed == 1 && report.opens_observed == 1,
        ),
        case(
            "relay-tun-tcp-client-payload",
            "relay client payload from TUN TCP session to selected outbound",
            report.server_received_payload
                && report.processed_packets >= 3
                && report.tcp_session_events >= 3,
        ),
        case(
            "write-tun-tcp-server-payload",
            "write server payload packet back to TUN client",
            report.response_payload_observed
                && report.tun_writes_observed == 3
                && report.tcp_session_packets_written == 3,
        ),
        case(
            "stop-tun-tcp-session-relay-cleanly",
            "stop runtime and leave no residual TCP session state",
            report.clean_stop_observed
                && report.residual_state_clean
                && report.tcp_session_errors == 0
                && report.tcp_session_limit_rejections == 0,
        ),
    ]
}

fn collect_default_tun_tcp_session_server_retransmit_smoke_report(
) -> TunTcpSessionServerRetransmitSmokeReport {
    match run_default_tun_tcp_session_server_retransmit_smoke() {
        Ok(evidence) => tun_tcp_session_server_retransmit_smoke_report_from_evidence(evidence),
        Err(error) => tun_tcp_session_server_retransmit_smoke_failed_report(error),
    }
}

#[derive(Debug)]
struct TunTcpSessionServerRetransmitSmokeEvidence {
    retransmit: TunTcpSessionServerRetransmitCaseEvidence,
    ack_clear: TunTcpSessionServerRetransmitCaseEvidence,
}

#[derive(Debug)]
struct TunTcpSessionServerRetransmitCaseEvidence {
    report: ManagedTunPacketLoopReport,
    target: SocketAddr,
    tun_writes: Vec<Vec<u8>>,
    server_initial_payload_received: bool,
    server_follow_up_payload_received: bool,
}

#[derive(Debug, Clone, Copy)]
enum TunTcpSessionServerRetransmitCaseKind {
    Retransmit,
    AckClear,
}

#[derive(Debug)]
struct TunTcpSessionServerRetransmitServerObservation {
    initial_payload_received: bool,
    follow_up_payload_received: bool,
}

fn run_default_tun_tcp_session_server_retransmit_smoke(
) -> Result<TunTcpSessionServerRetransmitSmokeEvidence, String> {
    let retransmit = run_tun_tcp_session_server_retransmit_smoke_case(
        TunTcpSessionServerRetransmitCaseKind::Retransmit,
    )?;
    let ack_clear = run_tun_tcp_session_server_retransmit_smoke_case(
        TunTcpSessionServerRetransmitCaseKind::AckClear,
    )?;
    Ok(TunTcpSessionServerRetransmitSmokeEvidence {
        retransmit,
        ack_clear,
    })
}

fn run_tun_tcp_session_server_retransmit_smoke_case(
    kind: TunTcpSessionServerRetransmitCaseKind,
) -> Result<TunTcpSessionServerRetransmitCaseEvidence, String> {
    let config = default_tun_device_config();
    let stopped_snapshot = tun_tcp_session_smoke_stopped_snapshot();
    let follow_up = match kind {
        TunTcpSessionServerRetransmitCaseKind::Retransmit => None,
        TunTcpSessionServerRetransmitCaseKind::AckClear => {
            Some(TUN_TCP_SESSION_SERVER_RETRANSMIT_SMOKE_FOLLOW_UP)
        }
    };
    let (tcp_port, tcp_server) = spawn_tun_tcp_session_server_retransmit_smoke_server(follow_up)?;
    let target = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), tcp_port);
    let max_packets = tun_tcp_session_server_retransmit_smoke_max_packets(kind);
    let tun_writes = Arc::new(Mutex::new(Vec::new()));
    let packet_io = TunTcpSessionSmokeFakePacketIo {
        reads: VecDeque::from(tun_tcp_session_server_retransmit_smoke_packets(
            Ipv4Addr::LOCALHOST,
            tcp_port,
            kind,
        )),
        read_delays: VecDeque::new(),
        writes: Vec::new(),
        shared_writes: Arc::clone(&tun_writes),
    };
    let controller = TunTcpSessionSmokeFakeController::new(
        stopped_snapshot.clone(),
        TunDeviceSnapshot::running(&config),
        stopped_snapshot,
        packet_io,
    );
    let runtime = default_tun_tcp_session_server_retransmit_smoke_runtime();

    let loop_result = run_managed_tun_packet_loop_with_runtime(
        &controller,
        config,
        &runtime,
        DEFAULT_TUN_DNS_TTL_SECONDS,
        max_packets,
    );
    let server_observation = tcp_server
        .join()
        .map_err(|_| "TUN TCP server retransmit smoke server panicked".to_string())??;
    let report = loop_result?;
    let tun_writes = tun_writes
        .lock()
        .map_err(|_| "TUN TCP server retransmit smoke writes lock poisoned".to_string())?
        .clone();

    Ok(TunTcpSessionServerRetransmitCaseEvidence {
        report,
        target,
        tun_writes,
        server_initial_payload_received: server_observation.initial_payload_received,
        server_follow_up_payload_received: server_observation.follow_up_payload_received,
    })
}

fn default_tun_tcp_session_server_retransmit_smoke_runtime() -> MixedProxyRuntime {
    let mut outbounds = OutboundRegistry::new();
    outbounds.add_direct(TUN_TCP_SESSION_SERVER_RETRANSMIT_SMOKE_OUTBOUND);
    MixedProxyRuntime {
        routes: RouteEngine::new(RouteAction::Outbound(
            TUN_TCP_SESSION_SERVER_RETRANSMIT_SMOKE_OUTBOUND.to_string(),
        )),
        relay_options: RelayOptions {
            first_byte_timeout: Some(Duration::from_secs(2)),
            idle_timeout: Some(Duration::from_secs(2)),
        },
        outbounds,
        dns_options: MixedDnsOptions::default(),
        tun_tcp_max_active_sessions: DEFAULT_TUN_TCP_MAX_ACTIVE_SESSIONS,
        connection_metrics: ConnectionMetrics::default(),
        max_connection_workers: DEFAULT_MANAGED_MIXED_MAX_CONNECTION_WORKERS,
        connection_worker_gauge: ConnectionWorkerGauge::default(),
        active_connection_registry: ActiveConnectionRegistry::default(),
    }
}

fn tun_tcp_session_server_retransmit_smoke_report_from_evidence(
    evidence: TunTcpSessionServerRetransmitSmokeEvidence,
) -> TunTcpSessionServerRetransmitSmokeReport {
    let retransmit_summary = &evidence.retransmit.report.summary;
    let ack_clear_summary = &evidence.ack_clear.report.summary;
    let retransmit_payload_count = tun_tcp_session_server_retransmit_response_payload_count(
        &evidence.retransmit.tun_writes,
        evidence.retransmit.target.port(),
    );
    let ack_clear_payload_count = tun_tcp_session_server_retransmit_response_payload_count(
        &evidence.ack_clear.tun_writes,
        evidence.ack_clear.target.port(),
    );
    let ack_clear_packet_observed = tun_tcp_session_server_retransmit_ack_clear_packet_observed(
        &evidence.ack_clear.tun_writes,
        evidence.ack_clear.target.port(),
    );
    let mut report = TunTcpSessionServerRetransmitSmokeReport {
        passed: false,
        detail: String::new(),
        selected_outbound: TUN_TCP_SESSION_SERVER_RETRANSMIT_SMOKE_OUTBOUND.to_string(),
        target: evidence.retransmit.target.to_string(),
        request_payload_bytes: TUN_TCP_SESSION_SMOKE_REQUEST.len(),
        follow_up_payload_bytes: TUN_TCP_SESSION_SERVER_RETRANSMIT_SMOKE_FOLLOW_UP.len(),
        response_payload_bytes: TUN_TCP_SESSION_SMOKE_RESPONSE.len(),
        retransmit_response_payload_observed: retransmit_payload_count >= 1,
        ack_clear_response_payload_observed: ack_clear_payload_count == 1,
        retransmitted_payload_observed: retransmit_payload_count >= 2,
        no_retransmit_after_ack_clear: ack_clear_payload_count == 1,
        ack_clear_packet_observed,
        retransmit_server_received_payload: evidence.retransmit.server_initial_payload_received,
        ack_clear_server_received_initial_payload: evidence
            .ack_clear
            .server_initial_payload_received,
        ack_clear_server_received_follow_up_payload: evidence
            .ack_clear
            .server_follow_up_payload_received,
        retransmit_processed_packets: retransmit_summary.processed_packets(),
        retransmit_tcp_session_events: retransmit_summary.tcp_session_events,
        retransmit_tcp_session_packets_written: retransmit_summary.tcp_session_packets_written,
        retransmit_tun_writes_observed: evidence.retransmit.tun_writes.len(),
        ack_clear_processed_packets: ack_clear_summary.processed_packets(),
        ack_clear_tcp_session_events: ack_clear_summary.tcp_session_events,
        ack_clear_tcp_session_packets_written: ack_clear_summary.tcp_session_packets_written,
        ack_clear_tun_writes_observed: evidence.ack_clear.tun_writes.len(),
        tcp_session_errors: retransmit_summary.tcp_session_errors
            + ack_clear_summary.tcp_session_errors,
        cases: Vec::new(),
    };
    report.passed = tun_tcp_session_server_retransmit_smoke_passed(&report);
    report.detail = tun_tcp_session_server_retransmit_smoke_detail(&report);
    report.cases = tun_tcp_session_server_retransmit_smoke_cases(
        &report,
        retransmit_payload_count,
        ack_clear_payload_count,
        None,
    );
    report
}

fn tun_tcp_session_server_retransmit_smoke_failed_report(
    error: String,
) -> TunTcpSessionServerRetransmitSmokeReport {
    let mut report = TunTcpSessionServerRetransmitSmokeReport {
        passed: false,
        detail: format!("TUN TCP server retransmit smoke failed: {error}"),
        selected_outbound: TUN_TCP_SESSION_SERVER_RETRANSMIT_SMOKE_OUTBOUND.to_string(),
        target: "127.0.0.1:0".to_string(),
        request_payload_bytes: TUN_TCP_SESSION_SMOKE_REQUEST.len(),
        follow_up_payload_bytes: TUN_TCP_SESSION_SERVER_RETRANSMIT_SMOKE_FOLLOW_UP.len(),
        response_payload_bytes: TUN_TCP_SESSION_SMOKE_RESPONSE.len(),
        retransmit_response_payload_observed: false,
        ack_clear_response_payload_observed: false,
        retransmitted_payload_observed: false,
        no_retransmit_after_ack_clear: false,
        ack_clear_packet_observed: false,
        retransmit_server_received_payload: false,
        ack_clear_server_received_initial_payload: false,
        ack_clear_server_received_follow_up_payload: false,
        retransmit_processed_packets: 0,
        retransmit_tcp_session_events: 0,
        retransmit_tcp_session_packets_written: 0,
        retransmit_tun_writes_observed: 0,
        ack_clear_processed_packets: 0,
        ack_clear_tcp_session_events: 0,
        ack_clear_tcp_session_packets_written: 0,
        ack_clear_tun_writes_observed: 0,
        tcp_session_errors: 0,
        cases: Vec::new(),
    };
    report.cases = tun_tcp_session_server_retransmit_smoke_cases(&report, 0, 0, Some(error));
    report
}

fn tun_tcp_session_server_retransmit_smoke_passed(
    report: &TunTcpSessionServerRetransmitSmokeReport,
) -> bool {
    report.retransmit_response_payload_observed
        && report.retransmitted_payload_observed
        && report.ack_clear_response_payload_observed
        && report.no_retransmit_after_ack_clear
        && report.ack_clear_packet_observed
        && report.retransmit_server_received_payload
        && report.ack_clear_server_received_initial_payload
        && report.ack_clear_server_received_follow_up_payload
        && report.retransmit_processed_packets
            == tun_tcp_session_server_retransmit_smoke_max_packets(
                TunTcpSessionServerRetransmitCaseKind::Retransmit,
            )
        && report.ack_clear_processed_packets
            == tun_tcp_session_server_retransmit_smoke_max_packets(
                TunTcpSessionServerRetransmitCaseKind::AckClear,
            )
        && report.retransmit_tcp_session_events == report.retransmit_processed_packets
        && report.ack_clear_tcp_session_events == report.ack_clear_processed_packets
        && report.retransmit_tcp_session_packets_written == 4
        && report.ack_clear_tcp_session_packets_written >= 4
        && report.retransmit_tun_writes_observed == 4
        && report.ack_clear_tun_writes_observed >= 4
        && report.tcp_session_errors == 0
}

fn tun_tcp_session_server_retransmit_smoke_detail(
    report: &TunTcpSessionServerRetransmitSmokeReport,
) -> String {
    format!(
        "outbound={} target={} request_bytes={} follow_up_bytes={} response_bytes={} retransmit_response_observed={} retransmitted_payload_observed={} ack_clear_response_observed={} ack_clear_packet_observed={} no_retransmit_after_ack_clear={} retransmit_server_received={} ack_clear_server_received_initial={} ack_clear_server_received_follow_up={} retransmit_processed={} retransmit_tcp_writes={} retransmit_tun_writes={} ack_clear_processed={} ack_clear_tcp_writes={} ack_clear_tun_writes={} tcp_errors={}",
        report.selected_outbound,
        report.target,
        report.request_payload_bytes,
        report.follow_up_payload_bytes,
        report.response_payload_bytes,
        report.retransmit_response_payload_observed,
        report.retransmitted_payload_observed,
        report.ack_clear_response_payload_observed,
        report.ack_clear_packet_observed,
        report.no_retransmit_after_ack_clear,
        report.retransmit_server_received_payload,
        report.ack_clear_server_received_initial_payload,
        report.ack_clear_server_received_follow_up_payload,
        report.retransmit_processed_packets,
        report.retransmit_tcp_session_packets_written,
        report.retransmit_tun_writes_observed,
        report.ack_clear_processed_packets,
        report.ack_clear_tcp_session_packets_written,
        report.ack_clear_tun_writes_observed,
        report.tcp_session_errors
    )
}

fn tun_tcp_session_server_retransmit_smoke_cases(
    report: &TunTcpSessionServerRetransmitSmokeReport,
    retransmit_payload_count: usize,
    ack_clear_payload_count: usize,
    error: Option<String>,
) -> Vec<TunTcpSessionServerRetransmitSmokeCaseReport> {
    let expected_response = String::from_utf8_lossy(TUN_TCP_SESSION_SMOKE_RESPONSE).into_owned();
    let case_error = |passed: bool| {
        if passed {
            None
        } else {
            error.clone().or_else(|| Some(report.detail.clone()))
        }
    };
    let retransmit_payload_passed =
        report.retransmit_response_payload_observed && report.retransmit_server_received_payload;
    let retransmit_passed = report.retransmitted_payload_observed
        && report.retransmit_tcp_session_packets_written == 4
        && report.retransmit_tun_writes_observed == 4;
    let ack_clear_passed = report.ack_clear_packet_observed
        && report.ack_clear_server_received_initial_payload
        && report.ack_clear_server_received_follow_up_payload;
    let no_replay_passed = report.no_retransmit_after_ack_clear
        && report.ack_clear_tcp_session_packets_written >= 4
        && report.ack_clear_tun_writes_observed >= 4
        && report.tcp_session_errors == 0;
    vec![
        TunTcpSessionServerRetransmitSmokeCaseReport {
            name: "write-server-payload-before-retransmit",
            action: "write server payload to TUN before duplicate ACK",
            target: report.target.clone(),
            expected_response: expected_response.clone(),
            expected_response_payload_count: 1,
            observed_response_payload_count: retransmit_payload_count,
            expected_retransmitted_payload_count: 0,
            observed_retransmitted_payload_count: retransmit_payload_count.saturating_sub(1),
            expected_ack_clear_packet: false,
            observed_ack_clear_packet: false,
            expected_no_retransmit_after_ack_clear: false,
            observed_no_retransmit_after_ack_clear: false,
            processed_packets: report.retransmit_processed_packets,
            tcp_session_events: report.retransmit_tcp_session_events,
            tcp_session_packets_written: report.retransmit_tcp_session_packets_written,
            tun_writes_observed: report.retransmit_tun_writes_observed,
            passed: retransmit_payload_passed,
            error: case_error(retransmit_payload_passed),
        },
        TunTcpSessionServerRetransmitSmokeCaseReport {
            name: "retransmit-server-payload-on-stale-ack",
            action: "retransmit the last server payload on duplicate stale ACK",
            target: report.target.clone(),
            expected_response: expected_response.clone(),
            expected_response_payload_count: 2,
            observed_response_payload_count: retransmit_payload_count,
            expected_retransmitted_payload_count: 1,
            observed_retransmitted_payload_count: retransmit_payload_count.saturating_sub(1),
            expected_ack_clear_packet: false,
            observed_ack_clear_packet: false,
            expected_no_retransmit_after_ack_clear: false,
            observed_no_retransmit_after_ack_clear: false,
            processed_packets: report.retransmit_processed_packets,
            tcp_session_events: report.retransmit_tcp_session_events,
            tcp_session_packets_written: report.retransmit_tcp_session_packets_written,
            tun_writes_observed: report.retransmit_tun_writes_observed,
            passed: retransmit_passed,
            error: case_error(retransmit_passed),
        },
        TunTcpSessionServerRetransmitSmokeCaseReport {
            name: "clear-server-payload-retransmit-slot-on-latest-ack",
            action: "accept latest server ACK with follow-up client payload",
            target: report.target.clone(),
            expected_response: expected_response.clone(),
            expected_response_payload_count: 1,
            observed_response_payload_count: ack_clear_payload_count,
            expected_retransmitted_payload_count: 0,
            observed_retransmitted_payload_count: ack_clear_payload_count.saturating_sub(1),
            expected_ack_clear_packet: true,
            observed_ack_clear_packet: report.ack_clear_packet_observed,
            expected_no_retransmit_after_ack_clear: false,
            observed_no_retransmit_after_ack_clear: false,
            processed_packets: report.ack_clear_processed_packets,
            tcp_session_events: report.ack_clear_tcp_session_events,
            tcp_session_packets_written: report.ack_clear_tcp_session_packets_written,
            tun_writes_observed: report.ack_clear_tun_writes_observed,
            passed: ack_clear_passed,
            error: case_error(ack_clear_passed),
        },
        TunTcpSessionServerRetransmitSmokeCaseReport {
            name: "do-not-replay-server-payload-after-ack-clear",
            action: "ignore later stale ACK after the latest ACK cleared retransmit state",
            target: report.target.clone(),
            expected_response,
            expected_response_payload_count: 1,
            observed_response_payload_count: ack_clear_payload_count,
            expected_retransmitted_payload_count: 0,
            observed_retransmitted_payload_count: ack_clear_payload_count.saturating_sub(1),
            expected_ack_clear_packet: true,
            observed_ack_clear_packet: report.ack_clear_packet_observed,
            expected_no_retransmit_after_ack_clear: true,
            observed_no_retransmit_after_ack_clear: report.no_retransmit_after_ack_clear,
            processed_packets: report.ack_clear_processed_packets,
            tcp_session_events: report.ack_clear_tcp_session_events,
            tcp_session_packets_written: report.ack_clear_tcp_session_packets_written,
            tun_writes_observed: report.ack_clear_tun_writes_observed,
            passed: no_replay_passed,
            error: case_error(no_replay_passed),
        },
    ]
}

fn tun_tcp_session_server_retransmit_smoke_max_packets(
    kind: TunTcpSessionServerRetransmitCaseKind,
) -> usize {
    match kind {
        TunTcpSessionServerRetransmitCaseKind::Retransmit => 4,
        TunTcpSessionServerRetransmitCaseKind::AckClear => 5,
    }
}

fn tun_tcp_session_server_retransmit_smoke_packets(
    destination: Ipv4Addr,
    destination_port: u16,
    kind: TunTcpSessionServerRetransmitCaseKind,
) -> Vec<Vec<u8>> {
    let client_initial_sequence_number = 10;
    let client_payload_sequence_number = client_initial_sequence_number + 1;
    let first_client_payload_end =
        client_payload_sequence_number + TUN_TCP_SESSION_SMOKE_REQUEST.len() as u32;
    let follow_up_payload_end =
        first_client_payload_end + TUN_TCP_SESSION_SERVER_RETRANSMIT_SMOKE_FOLLOW_UP.len() as u32;
    let server_acknowledgment_number = DEFAULT_TUN_TCP_SERVER_INITIAL_SEQUENCE_NUMBER + 1;
    let latest_server_ack =
        server_acknowledgment_number + TUN_TCP_SESSION_SMOKE_RESPONSE.len() as u32;
    let mut packets = vec![
        tun_tcp_session_smoke_ipv4_packet(
            TUN_TCP_SESSION_SMOKE_CLIENT_IP,
            destination,
            6,
            &tun_tcp_session_smoke_tcp_segment(
                TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                destination_port,
                client_initial_sequence_number,
                0,
                0x0002,
                DEFAULT_TUN_TCP_WINDOW_SIZE,
                b"",
            ),
        ),
        tun_tcp_session_smoke_ipv4_packet(
            TUN_TCP_SESSION_SMOKE_CLIENT_IP,
            destination,
            6,
            &tun_tcp_session_smoke_tcp_segment(
                TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                destination_port,
                client_payload_sequence_number,
                server_acknowledgment_number,
                0x0010,
                DEFAULT_TUN_TCP_WINDOW_SIZE,
                b"",
            ),
        ),
        tun_tcp_session_smoke_ipv4_packet(
            TUN_TCP_SESSION_SMOKE_CLIENT_IP,
            destination,
            6,
            &tun_tcp_session_smoke_tcp_segment(
                TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                destination_port,
                client_payload_sequence_number,
                server_acknowledgment_number,
                0x0018,
                DEFAULT_TUN_TCP_WINDOW_SIZE,
                TUN_TCP_SESSION_SMOKE_REQUEST,
            ),
        ),
    ];
    match kind {
        TunTcpSessionServerRetransmitCaseKind::Retransmit => {
            packets.push(tun_tcp_session_smoke_ipv4_packet(
                TUN_TCP_SESSION_SMOKE_CLIENT_IP,
                destination,
                6,
                &tun_tcp_session_smoke_tcp_segment(
                    TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                    destination_port,
                    first_client_payload_end,
                    server_acknowledgment_number,
                    0x0010,
                    DEFAULT_TUN_TCP_WINDOW_SIZE,
                    b"",
                ),
            ));
        }
        TunTcpSessionServerRetransmitCaseKind::AckClear => {
            packets.push(tun_tcp_session_smoke_ipv4_packet(
                TUN_TCP_SESSION_SMOKE_CLIENT_IP,
                destination,
                6,
                &tun_tcp_session_smoke_tcp_segment(
                    TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                    destination_port,
                    first_client_payload_end,
                    latest_server_ack,
                    0x0018,
                    DEFAULT_TUN_TCP_WINDOW_SIZE,
                    TUN_TCP_SESSION_SERVER_RETRANSMIT_SMOKE_FOLLOW_UP,
                ),
            ));
            packets.push(tun_tcp_session_smoke_ipv4_packet(
                TUN_TCP_SESSION_SMOKE_CLIENT_IP,
                destination,
                6,
                &tun_tcp_session_smoke_tcp_segment(
                    TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                    destination_port,
                    follow_up_payload_end,
                    server_acknowledgment_number,
                    0x0010,
                    DEFAULT_TUN_TCP_WINDOW_SIZE,
                    b"",
                ),
            ));
        }
    }
    packets
}

fn spawn_tun_tcp_session_server_retransmit_smoke_server(
    expected_follow_up: Option<&'static [u8]>,
) -> Result<
    (
        u16,
        thread::JoinHandle<Result<TunTcpSessionServerRetransmitServerObservation, String>>,
    ),
    String,
> {
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind TUN TCP server retransmit smoke server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set TUN TCP server retransmit smoke nonblocking: {error}"))?;
    let port = listener
        .local_addr()
        .map_err(|error| format!("read TUN TCP server retransmit smoke address: {error}"))?
        .port();
    let server = thread::spawn(move || {
        let deadline = Instant::now() + Duration::from_secs(5);
        let mut stream = loop {
            match listener.accept() {
                Ok((stream, _)) => break stream,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err(
                            "timed out accepting TUN TCP server retransmit smoke connection"
                                .to_string(),
                        );
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => {
                    return Err(format!(
                        "accept TUN TCP server retransmit smoke connection: {error}"
                    ));
                }
            }
        };
        stream
            .set_nonblocking(false)
            .map_err(|error| format!("set TUN TCP server retransmit stream blocking: {error}"))?;
        stream
            .set_read_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set TUN TCP server retransmit read timeout: {error}"))?;
        stream
            .set_write_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set TUN TCP server retransmit write timeout: {error}"))?;
        let mut request = vec![0; TUN_TCP_SESSION_SMOKE_REQUEST.len()];
        stream
            .read_exact(&mut request)
            .map_err(|error| format!("read TUN TCP server retransmit request: {error}"))?;
        if request != TUN_TCP_SESSION_SMOKE_REQUEST {
            return Err(format!(
                "unexpected TUN TCP server retransmit request: expected {} bytes got {} bytes",
                TUN_TCP_SESSION_SMOKE_REQUEST.len(),
                request.len()
            ));
        }
        stream
            .write_all(TUN_TCP_SESSION_SMOKE_RESPONSE)
            .map_err(|error| format!("write TUN TCP server retransmit response: {error}"))?;
        stream
            .flush()
            .map_err(|error| format!("flush TUN TCP server retransmit response: {error}"))?;
        let mut follow_up_received = false;
        if let Some(expected_follow_up) = expected_follow_up {
            let mut follow_up = vec![0; expected_follow_up.len()];
            stream
                .read_exact(&mut follow_up)
                .map_err(|error| format!("read TUN TCP server retransmit follow-up: {error}"))?;
            if follow_up != expected_follow_up {
                return Err(format!(
                    "unexpected TUN TCP server retransmit follow-up: expected {} bytes got {} bytes",
                    expected_follow_up.len(),
                    follow_up.len()
                ));
            }
            follow_up_received = true;
        }
        thread::sleep(Duration::from_millis(50));
        Ok(TunTcpSessionServerRetransmitServerObservation {
            initial_payload_received: true,
            follow_up_payload_received: follow_up_received,
        })
    });
    Ok((port, server))
}

fn tun_tcp_session_server_retransmit_response_payload_count(
    writes: &[Vec<u8>],
    server_port: u16,
) -> usize {
    writes
        .iter()
        .filter(|packet| {
            let Ok(segment) = parse_tun_tcp_segment(packet) else {
                return false;
            };
            segment.flow.source_port == Some(server_port)
                && segment.flow.destination_port == Some(TUN_TCP_SESSION_SMOKE_CLIENT_PORT)
                && segment.sequence_number == DEFAULT_TUN_TCP_SERVER_INITIAL_SEQUENCE_NUMBER + 1
                && segment.payload == TUN_TCP_SESSION_SMOKE_RESPONSE
                && segment.flags.psh()
                && segment.flags.ack()
                && !segment.flags.rst()
        })
        .count()
}

fn tun_tcp_session_server_retransmit_ack_clear_packet_observed(
    writes: &[Vec<u8>],
    server_port: u16,
) -> bool {
    let expected_sequence = DEFAULT_TUN_TCP_SERVER_INITIAL_SEQUENCE_NUMBER
        + 1
        + TUN_TCP_SESSION_SMOKE_RESPONSE.len() as u32;
    let expected_acknowledgment = 10
        + 1
        + TUN_TCP_SESSION_SMOKE_REQUEST.len() as u32
        + TUN_TCP_SESSION_SERVER_RETRANSMIT_SMOKE_FOLLOW_UP.len() as u32;
    writes.iter().any(|packet| {
        let Ok(segment) = parse_tun_tcp_segment(packet) else {
            return false;
        };
        segment.flow.source_port == Some(server_port)
            && segment.flow.destination_port == Some(TUN_TCP_SESSION_SMOKE_CLIENT_PORT)
            && segment.sequence_number == expected_sequence
            && segment.acknowledgment_number == expected_acknowledgment
            && segment.payload.is_empty()
            && segment.flags.ack()
            && !segment.flags.psh()
            && !segment.flags.rst()
    })
}

fn collect_default_tun_tcp_session_server_fin_retransmit_smoke_report(
) -> TunTcpSessionServerFinRetransmitSmokeReport {
    match run_default_tun_tcp_session_server_fin_retransmit_smoke() {
        Ok(evidence) => tun_tcp_session_server_fin_retransmit_smoke_report_from_evidence(evidence),
        Err(error) => tun_tcp_session_server_fin_retransmit_smoke_failed_report(error),
    }
}

#[derive(Debug)]
struct TunTcpSessionServerFinRetransmitSmokeRunEvidence {
    report: ManagedTunPacketLoopReport,
    target: SocketAddr,
    starts_observed: usize,
    opens_observed: usize,
    stops_observed: usize,
    tun_writes: Vec<Vec<u8>>,
    server_received_payload: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct TunTcpSessionServerFinObservation {
    sequence_number: u32,
    acknowledgment_number: u32,
    fin_flag: bool,
    ack_flag: bool,
    rst_flag: bool,
    payload_empty: bool,
}

fn run_default_tun_tcp_session_server_fin_retransmit_smoke(
) -> Result<TunTcpSessionServerFinRetransmitSmokeRunEvidence, String> {
    let config = default_tun_device_config();
    let stopped_snapshot = tun_tcp_session_smoke_stopped_snapshot();
    let (tcp_port, tcp_server) = spawn_tun_tcp_session_server_fin_retransmit_smoke_server()?;
    let target = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), tcp_port);
    let tun_writes = Arc::new(Mutex::new(Vec::new()));
    let packet_io = TunTcpSessionSmokeFakePacketIo {
        reads: VecDeque::from(tun_tcp_session_server_fin_retransmit_smoke_packets(
            Ipv4Addr::LOCALHOST,
            tcp_port,
        )),
        read_delays: VecDeque::from(vec![
            Duration::from_millis(0),
            Duration::from_millis(0),
            Duration::from_millis(0),
            Duration::from_millis(500),
            Duration::from_millis(200),
        ]),
        writes: Vec::new(),
        shared_writes: Arc::clone(&tun_writes),
    };
    let controller = TunTcpSessionSmokeFakeController::new(
        stopped_snapshot.clone(),
        TunDeviceSnapshot::running(&config),
        stopped_snapshot,
        packet_io,
    );
    let runtime = default_tun_tcp_session_server_fin_retransmit_smoke_runtime();

    let loop_result = run_managed_tun_packet_loop_with_runtime(
        &controller,
        config,
        &runtime,
        DEFAULT_TUN_DNS_TTL_SECONDS,
        TUN_TCP_SESSION_SERVER_FIN_RETRANSMIT_SMOKE_MAX_PACKETS,
    );
    let server_received_payload = tcp_server
        .join()
        .map_err(|_| "TUN TCP server FIN retransmit smoke server panicked".to_string())??;
    let report = loop_result?;
    let tun_writes = tun_writes
        .lock()
        .map_err(|_| "TUN TCP server FIN retransmit smoke writes lock poisoned".to_string())?
        .clone();

    Ok(TunTcpSessionServerFinRetransmitSmokeRunEvidence {
        report,
        target,
        starts_observed: controller.starts_observed()?,
        opens_observed: controller.opens_observed()?,
        stops_observed: controller.stops_observed(),
        tun_writes,
        server_received_payload,
    })
}

fn default_tun_tcp_session_server_fin_retransmit_smoke_runtime() -> MixedProxyRuntime {
    let mut outbounds = OutboundRegistry::new();
    outbounds.add_direct(TUN_TCP_SESSION_SERVER_FIN_RETRANSMIT_SMOKE_OUTBOUND);
    MixedProxyRuntime {
        routes: RouteEngine::new(RouteAction::Outbound(
            TUN_TCP_SESSION_SERVER_FIN_RETRANSMIT_SMOKE_OUTBOUND.to_string(),
        )),
        relay_options: RelayOptions {
            first_byte_timeout: Some(Duration::from_secs(2)),
            idle_timeout: Some(Duration::from_secs(2)),
        },
        outbounds,
        dns_options: MixedDnsOptions::default(),
        tun_tcp_max_active_sessions: DEFAULT_TUN_TCP_MAX_ACTIVE_SESSIONS,
        connection_metrics: ConnectionMetrics::default(),
        max_connection_workers: DEFAULT_MANAGED_MIXED_MAX_CONNECTION_WORKERS,
        connection_worker_gauge: ConnectionWorkerGauge::default(),
        active_connection_registry: ActiveConnectionRegistry::default(),
    }
}

fn tun_tcp_session_server_fin_retransmit_smoke_report_from_evidence(
    evidence: TunTcpSessionServerFinRetransmitSmokeRunEvidence,
) -> TunTcpSessionServerFinRetransmitSmokeReport {
    let summary = &evidence.report.summary;
    let first_fin = tun_tcp_session_server_fin_retransmit_observation(
        &evidence.tun_writes,
        2,
        evidence.target.port(),
    );
    let retransmitted_fin = tun_tcp_session_server_fin_retransmit_observation(
        &evidence.tun_writes,
        3,
        evidence.target.port(),
    );
    let expected_sequence = tun_tcp_session_server_fin_retransmit_expected_sequence_number();
    let expected_acknowledgment =
        tun_tcp_session_server_fin_retransmit_expected_acknowledgment_number();
    let server_fin_observed = first_fin.as_ref().is_some_and(|fin| {
        fin.sequence_number == expected_sequence
            && fin.acknowledgment_number == expected_acknowledgment
            && fin.fin_flag
            && fin.ack_flag
            && !fin.rst_flag
            && fin.payload_empty
    });
    let server_fin_retransmitted = retransmitted_fin.as_ref().is_some_and(|fin| {
        fin.sequence_number == expected_sequence
            && fin.acknowledgment_number == expected_acknowledgment
            && fin.fin_flag
            && fin.ack_flag
            && !fin.rst_flag
            && fin.payload_empty
    });
    let no_reset_observed = evidence.tun_writes.iter().all(|packet| {
        parse_tun_tcp_segment(packet)
            .map(|segment| !segment.flags.rst())
            .unwrap_or(false)
    });
    let final_ack_absorbed = evidence.tun_writes.len() == 4
        && summary.processed_packets() == TUN_TCP_SESSION_SERVER_FIN_RETRANSMIT_SMOKE_MAX_PACKETS
        && summary.tcp_session_packets_written == 4;
    let clean_stop_observed =
        evidence.stops_observed == 1 && !evidence.report.stop_snapshot.running;
    let post_close_marker_retained = summary.tcp_post_close_markers_open == 1;
    let residual_state_clean = summary.tcp_sessions_open == 0
        && summary.tcp_server_close_markers_open == 0
        && post_close_marker_retained;
    let mut report = TunTcpSessionServerFinRetransmitSmokeReport {
        passed: false,
        detail: String::new(),
        selected_outbound: TUN_TCP_SESSION_SERVER_FIN_RETRANSMIT_SMOKE_OUTBOUND.to_string(),
        target: evidence.target.to_string(),
        request_payload_bytes: TUN_TCP_SESSION_SMOKE_REQUEST.len(),
        server_received_payload: evidence.server_received_payload,
        server_fin_observed,
        server_fin_retransmitted,
        final_ack_absorbed,
        no_reset_observed,
        first_fin_sequence_number: first_fin.as_ref().map(|fin| fin.sequence_number),
        first_fin_acknowledgment_number: first_fin.as_ref().map(|fin| fin.acknowledgment_number),
        retransmitted_fin_sequence_number: retransmitted_fin
            .as_ref()
            .map(|fin| fin.sequence_number),
        retransmitted_fin_acknowledgment_number: retransmitted_fin
            .as_ref()
            .map(|fin| fin.acknowledgment_number),
        starts_observed: evidence.starts_observed,
        opens_observed: evidence.opens_observed,
        stops_observed: evidence.stops_observed,
        processed_packets: summary.processed_packets(),
        tcp_session_events: summary.tcp_session_events,
        tcp_session_packets_written: summary.tcp_session_packets_written,
        tun_writes_observed: evidence.tun_writes.len(),
        tcp_sessions_open: summary.tcp_sessions_open,
        tcp_server_close_markers_open: summary.tcp_server_close_markers_open,
        tcp_post_close_markers_open: summary.tcp_post_close_markers_open,
        tcp_session_errors: summary.tcp_session_errors,
        post_close_marker_retained,
        clean_stop_observed,
        residual_state_clean,
        cases: Vec::new(),
    };
    report.passed = tun_tcp_session_server_fin_retransmit_smoke_passed(&report);
    report.detail = tun_tcp_session_server_fin_retransmit_smoke_detail(&report);
    report.cases = tun_tcp_session_server_fin_retransmit_smoke_cases(
        &report,
        first_fin,
        retransmitted_fin,
        None,
    );
    report
}

fn tun_tcp_session_server_fin_retransmit_smoke_failed_report(
    error: String,
) -> TunTcpSessionServerFinRetransmitSmokeReport {
    let mut report = TunTcpSessionServerFinRetransmitSmokeReport {
        passed: false,
        detail: format!("TUN TCP server FIN retransmit smoke failed: {error}"),
        selected_outbound: TUN_TCP_SESSION_SERVER_FIN_RETRANSMIT_SMOKE_OUTBOUND.to_string(),
        target: "127.0.0.1:0".to_string(),
        request_payload_bytes: TUN_TCP_SESSION_SMOKE_REQUEST.len(),
        server_received_payload: false,
        server_fin_observed: false,
        server_fin_retransmitted: false,
        final_ack_absorbed: false,
        no_reset_observed: false,
        first_fin_sequence_number: None,
        first_fin_acknowledgment_number: None,
        retransmitted_fin_sequence_number: None,
        retransmitted_fin_acknowledgment_number: None,
        starts_observed: 0,
        opens_observed: 0,
        stops_observed: 0,
        processed_packets: 0,
        tcp_session_events: 0,
        tcp_session_packets_written: 0,
        tun_writes_observed: 0,
        tcp_sessions_open: 0,
        tcp_server_close_markers_open: 0,
        tcp_post_close_markers_open: 0,
        tcp_session_errors: 0,
        post_close_marker_retained: false,
        clean_stop_observed: false,
        residual_state_clean: false,
        cases: Vec::new(),
    };
    report.cases =
        tun_tcp_session_server_fin_retransmit_smoke_cases(&report, None, None, Some(error));
    report
}

fn tun_tcp_session_server_fin_retransmit_smoke_passed(
    report: &TunTcpSessionServerFinRetransmitSmokeReport,
) -> bool {
    report.starts_observed == 1
        && report.opens_observed == 1
        && report.stops_observed == 1
        && report.server_received_payload
        && report.server_fin_observed
        && report.server_fin_retransmitted
        && report.final_ack_absorbed
        && report.no_reset_observed
        && report.processed_packets == TUN_TCP_SESSION_SERVER_FIN_RETRANSMIT_SMOKE_MAX_PACKETS
        && report.tcp_session_events == TUN_TCP_SESSION_SERVER_FIN_RETRANSMIT_SMOKE_MAX_PACKETS
        && report.tcp_session_packets_written == 4
        && report.tun_writes_observed == 4
        && report.tcp_sessions_open == 0
        && report.tcp_server_close_markers_open == 0
        && report.tcp_post_close_markers_open == 1
        && report.tcp_session_errors == 0
        && report.post_close_marker_retained
        && report.clean_stop_observed
        && report.residual_state_clean
}

fn tun_tcp_session_server_fin_retransmit_smoke_detail(
    report: &TunTcpSessionServerFinRetransmitSmokeReport,
) -> String {
    format!(
        "outbound={} target={} request_bytes={} server_received={} server_fin_observed={} first_fin_seq={:?} first_fin_ack={:?} server_fin_retransmitted={} retransmitted_fin_seq={:?} retransmitted_fin_ack={:?} final_ack_absorbed={} no_reset_observed={} starts={} opens={} stops={} processed={} tcp_events={} tcp_writes={} tun_writes={} tcp_sessions_open={} close_markers={} post_close_markers={} post_close_marker_retained={} tcp_errors={} residual_state_clean={}",
        report.selected_outbound,
        report.target,
        report.request_payload_bytes,
        report.server_received_payload,
        report.server_fin_observed,
        report.first_fin_sequence_number,
        report.first_fin_acknowledgment_number,
        report.server_fin_retransmitted,
        report.retransmitted_fin_sequence_number,
        report.retransmitted_fin_acknowledgment_number,
        report.final_ack_absorbed,
        report.no_reset_observed,
        report.starts_observed,
        report.opens_observed,
        report.stops_observed,
        report.processed_packets,
        report.tcp_session_events,
        report.tcp_session_packets_written,
        report.tun_writes_observed,
        report.tcp_sessions_open,
        report.tcp_server_close_markers_open,
        report.tcp_post_close_markers_open,
        report.post_close_marker_retained,
        report.tcp_session_errors,
        report.residual_state_clean
    )
}

fn tun_tcp_session_server_fin_retransmit_smoke_cases(
    report: &TunTcpSessionServerFinRetransmitSmokeReport,
    first_fin: Option<TunTcpSessionServerFinObservation>,
    retransmitted_fin: Option<TunTcpSessionServerFinObservation>,
    error: Option<String>,
) -> Vec<TunTcpSessionServerFinRetransmitSmokeCaseReport> {
    let expected_sequence = tun_tcp_session_server_fin_retransmit_expected_sequence_number();
    let expected_acknowledgment =
        tun_tcp_session_server_fin_retransmit_expected_acknowledgment_number();
    let case_error = |passed: bool| {
        if passed {
            None
        } else {
            error.clone().or_else(|| Some(report.detail.clone()))
        }
    };
    let first_fin_passed = report.server_fin_observed;
    let retransmitted_fin_passed = report.server_fin_retransmitted;
    let final_ack_passed = report.final_ack_absorbed && report.no_reset_observed;
    vec![
        TunTcpSessionServerFinRetransmitSmokeCaseReport {
            name: "write-server-fin-after-eof",
            action: "server-eof-fin-ack",
            target: report.target.clone(),
            expected_fin_written: true,
            observed_fin_written: first_fin.is_some(),
            expected_sequence_number: Some(expected_sequence),
            observed_sequence_number: first_fin.as_ref().map(|fin| fin.sequence_number),
            expected_acknowledgment_number: Some(expected_acknowledgment),
            observed_acknowledgment_number: first_fin.as_ref().map(|fin| fin.acknowledgment_number),
            expected_reset_written: false,
            observed_reset_written: first_fin.as_ref().map(|fin| fin.rst_flag).unwrap_or(false),
            processed_packets: report.processed_packets,
            tcp_session_events: report.tcp_session_events,
            tcp_session_packets_written: report.tcp_session_packets_written,
            tun_writes_observed: report.tun_writes_observed,
            passed: first_fin_passed,
            error: case_error(first_fin_passed),
        },
        TunTcpSessionServerFinRetransmitSmokeCaseReport {
            name: "retransmit-server-fin-on-duplicate-ack",
            action: "server-fin-retransmit",
            target: report.target.clone(),
            expected_fin_written: true,
            observed_fin_written: retransmitted_fin.is_some(),
            expected_sequence_number: Some(expected_sequence),
            observed_sequence_number: retransmitted_fin.as_ref().map(|fin| fin.sequence_number),
            expected_acknowledgment_number: Some(expected_acknowledgment),
            observed_acknowledgment_number: retransmitted_fin
                .as_ref()
                .map(|fin| fin.acknowledgment_number),
            expected_reset_written: false,
            observed_reset_written: retransmitted_fin
                .as_ref()
                .map(|fin| fin.rst_flag)
                .unwrap_or(false),
            processed_packets: report.processed_packets,
            tcp_session_events: report.tcp_session_events,
            tcp_session_packets_written: report.tcp_session_packets_written,
            tun_writes_observed: report.tun_writes_observed,
            passed: retransmitted_fin_passed,
            error: case_error(retransmitted_fin_passed),
        },
        TunTcpSessionServerFinRetransmitSmokeCaseReport {
            name: "absorb-server-fin-final-ack-without-reset",
            action: "server-fin-final-ack",
            target: report.target.clone(),
            expected_fin_written: false,
            observed_fin_written: report.tun_writes_observed > 4,
            expected_sequence_number: None,
            observed_sequence_number: None,
            expected_acknowledgment_number: None,
            observed_acknowledgment_number: None,
            expected_reset_written: false,
            observed_reset_written: !report.no_reset_observed,
            processed_packets: report.processed_packets,
            tcp_session_events: report.tcp_session_events,
            tcp_session_packets_written: report.tcp_session_packets_written,
            tun_writes_observed: report.tun_writes_observed,
            passed: final_ack_passed,
            error: case_error(final_ack_passed),
        },
    ]
}

fn tun_tcp_session_server_fin_retransmit_observation(
    writes: &[Vec<u8>],
    index: usize,
    server_port: u16,
) -> Option<TunTcpSessionServerFinObservation> {
    let segment = parse_tun_tcp_segment(writes.get(index)?).ok()?;
    if segment.flow.source_port != Some(server_port)
        || segment.flow.destination_port != Some(TUN_TCP_SESSION_SMOKE_CLIENT_PORT)
    {
        return None;
    }
    Some(TunTcpSessionServerFinObservation {
        sequence_number: segment.sequence_number,
        acknowledgment_number: segment.acknowledgment_number,
        fin_flag: segment.flags.fin(),
        ack_flag: segment.flags.ack(),
        rst_flag: segment.flags.rst(),
        payload_empty: segment.payload.is_empty(),
    })
}

fn tun_tcp_session_server_fin_retransmit_smoke_packets(
    destination: Ipv4Addr,
    destination_port: u16,
) -> Vec<Vec<u8>> {
    let client_initial_sequence_number = 10;
    let client_payload_sequence_number = client_initial_sequence_number + 1;
    let client_payload_end =
        client_payload_sequence_number + TUN_TCP_SESSION_SMOKE_REQUEST.len() as u32;
    let server_acknowledgment_number = DEFAULT_TUN_TCP_SERVER_INITIAL_SEQUENCE_NUMBER + 1;
    let final_server_acknowledgment_number = server_acknowledgment_number + 1;
    vec![
        tun_tcp_session_smoke_ipv4_packet(
            TUN_TCP_SESSION_SMOKE_CLIENT_IP,
            destination,
            6,
            &tun_tcp_session_smoke_tcp_segment(
                TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                destination_port,
                client_initial_sequence_number,
                0,
                0x0002,
                DEFAULT_TUN_TCP_WINDOW_SIZE,
                b"",
            ),
        ),
        tun_tcp_session_smoke_ipv4_packet(
            TUN_TCP_SESSION_SMOKE_CLIENT_IP,
            destination,
            6,
            &tun_tcp_session_smoke_tcp_segment(
                TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                destination_port,
                client_payload_sequence_number,
                server_acknowledgment_number,
                0x0010,
                DEFAULT_TUN_TCP_WINDOW_SIZE,
                b"",
            ),
        ),
        tun_tcp_session_smoke_ipv4_packet(
            TUN_TCP_SESSION_SMOKE_CLIENT_IP,
            destination,
            6,
            &tun_tcp_session_smoke_tcp_segment(
                TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                destination_port,
                client_payload_sequence_number,
                server_acknowledgment_number,
                0x0018,
                DEFAULT_TUN_TCP_WINDOW_SIZE,
                TUN_TCP_SESSION_SMOKE_REQUEST,
            ),
        ),
        tun_tcp_session_smoke_ipv4_packet(
            TUN_TCP_SESSION_SMOKE_CLIENT_IP,
            destination,
            6,
            &tun_tcp_session_smoke_tcp_segment(
                TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                destination_port,
                client_payload_end,
                server_acknowledgment_number,
                0x0010,
                DEFAULT_TUN_TCP_WINDOW_SIZE,
                b"",
            ),
        ),
        tun_tcp_session_smoke_ipv4_packet(
            TUN_TCP_SESSION_SMOKE_CLIENT_IP,
            destination,
            6,
            &tun_tcp_session_smoke_tcp_segment(
                TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                destination_port,
                client_payload_end,
                final_server_acknowledgment_number,
                0x0010,
                DEFAULT_TUN_TCP_WINDOW_SIZE,
                b"",
            ),
        ),
    ]
}

fn spawn_tun_tcp_session_server_fin_retransmit_smoke_server(
) -> Result<(u16, thread::JoinHandle<Result<bool, String>>), String> {
    let listener = TcpListener::bind("127.0.0.1:0")
        .map_err(|error| format!("bind TUN TCP server FIN retransmit smoke server: {error}"))?;
    listener
        .set_nonblocking(true)
        .map_err(|error| format!("set TUN TCP server FIN retransmit smoke nonblocking: {error}"))?;
    let port = listener
        .local_addr()
        .map_err(|error| format!("read TUN TCP server FIN retransmit smoke address: {error}"))?
        .port();
    let server = thread::spawn(move || {
        let deadline = Instant::now() + Duration::from_secs(5);
        let mut stream = loop {
            match listener.accept() {
                Ok((stream, _)) => break stream,
                Err(error) if error.kind() == io::ErrorKind::WouldBlock => {
                    if Instant::now() >= deadline {
                        return Err(
                            "timed out accepting TUN TCP server FIN retransmit smoke connection"
                                .to_string(),
                        );
                    }
                    thread::sleep(Duration::from_millis(10));
                }
                Err(error) => {
                    return Err(format!(
                        "accept TUN TCP server FIN retransmit smoke connection: {error}"
                    ));
                }
            }
        };
        stream.set_nonblocking(false).map_err(|error| {
            format!("set TUN TCP server FIN retransmit stream blocking: {error}")
        })?;
        stream
            .set_read_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set TUN TCP server FIN retransmit read timeout: {error}"))?;
        stream
            .set_write_timeout(Some(Duration::from_secs(2)))
            .map_err(|error| format!("set TUN TCP server FIN retransmit write timeout: {error}"))?;
        let mut request = vec![0; TUN_TCP_SESSION_SMOKE_REQUEST.len()];
        stream
            .read_exact(&mut request)
            .map_err(|error| format!("read TUN TCP server FIN retransmit request: {error}"))?;
        if request != TUN_TCP_SESSION_SMOKE_REQUEST {
            return Err(format!(
                "unexpected TUN TCP server FIN retransmit request: expected {} bytes got {} bytes",
                TUN_TCP_SESSION_SMOKE_REQUEST.len(),
                request.len()
            ));
        }
        stream.shutdown(Shutdown::Write).map_err(|error| {
            format!("shutdown TUN TCP server FIN retransmit write side: {error}")
        })?;
        thread::sleep(Duration::from_millis(50));
        Ok(true)
    });
    Ok((port, server))
}

fn tun_tcp_session_server_fin_retransmit_expected_sequence_number() -> u32 {
    DEFAULT_TUN_TCP_SERVER_INITIAL_SEQUENCE_NUMBER + 1
}

fn tun_tcp_session_server_fin_retransmit_expected_acknowledgment_number() -> u32 {
    10 + 1 + TUN_TCP_SESSION_SMOKE_REQUEST.len() as u32
}

fn collect_default_tun_tcp_session_post_close_guard_smoke_report(
) -> TunTcpSessionPostCloseGuardSmokeReport {
    match run_default_tun_tcp_session_post_close_guard_smoke() {
        Ok(evidence) => tun_tcp_session_post_close_guard_smoke_report_from_evidence(evidence),
        Err(error) => tun_tcp_session_post_close_guard_smoke_failed_report(error),
    }
}

#[derive(Debug)]
struct TunTcpSessionPostCloseGuardSmokeRunEvidence {
    report: ManagedTunPacketLoopReport,
    target: SocketAddr,
    starts_observed: usize,
    opens_observed: usize,
    stops_observed: usize,
    tun_writes: Vec<Vec<u8>>,
    server_received_payload: bool,
}

fn run_default_tun_tcp_session_post_close_guard_smoke(
) -> Result<TunTcpSessionPostCloseGuardSmokeRunEvidence, String> {
    let config = default_tun_device_config();
    let stopped_snapshot = tun_tcp_session_smoke_stopped_snapshot();
    let (tcp_port, tcp_server) = spawn_tun_tcp_session_server_fin_retransmit_smoke_server()?;
    let target = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), tcp_port);
    let tun_writes = Arc::new(Mutex::new(Vec::new()));
    let packet_io = TunTcpSessionSmokeFakePacketIo {
        reads: VecDeque::from(tun_tcp_session_post_close_guard_smoke_packets(
            Ipv4Addr::LOCALHOST,
            tcp_port,
        )),
        read_delays: VecDeque::from(vec![
            Duration::from_millis(0),
            Duration::from_millis(0),
            Duration::from_millis(0),
            Duration::from_millis(500),
            Duration::from_millis(200),
            Duration::from_millis(200),
            Duration::from_millis(200),
        ]),
        writes: Vec::new(),
        shared_writes: Arc::clone(&tun_writes),
    };
    let controller = TunTcpSessionSmokeFakeController::new(
        stopped_snapshot.clone(),
        TunDeviceSnapshot::running(&config),
        stopped_snapshot,
        packet_io,
    );
    let runtime = default_tun_tcp_session_post_close_guard_smoke_runtime();

    let loop_result = run_managed_tun_packet_loop_with_runtime(
        &controller,
        config,
        &runtime,
        DEFAULT_TUN_DNS_TTL_SECONDS,
        TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_MAX_PACKETS,
    );
    let server_received_payload = tcp_server
        .join()
        .map_err(|_| "TUN TCP post-close guard smoke server panicked".to_string())??;
    let report = loop_result?;
    let tun_writes = tun_writes
        .lock()
        .map_err(|_| "TUN TCP post-close guard smoke writes lock poisoned".to_string())?
        .clone();

    Ok(TunTcpSessionPostCloseGuardSmokeRunEvidence {
        report,
        target,
        starts_observed: controller.starts_observed()?,
        opens_observed: controller.opens_observed()?,
        stops_observed: controller.stops_observed(),
        tun_writes,
        server_received_payload,
    })
}

fn default_tun_tcp_session_post_close_guard_smoke_runtime() -> MixedProxyRuntime {
    let mut outbounds = OutboundRegistry::new();
    outbounds.add_direct(TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_OUTBOUND);
    MixedProxyRuntime {
        routes: RouteEngine::new(RouteAction::Outbound(
            TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_OUTBOUND.to_string(),
        )),
        relay_options: RelayOptions {
            first_byte_timeout: Some(Duration::from_secs(2)),
            idle_timeout: Some(Duration::from_secs(2)),
        },
        outbounds,
        dns_options: MixedDnsOptions::default(),
        tun_tcp_max_active_sessions: DEFAULT_TUN_TCP_MAX_ACTIVE_SESSIONS,
        connection_metrics: ConnectionMetrics::default(),
        max_connection_workers: DEFAULT_MANAGED_MIXED_MAX_CONNECTION_WORKERS,
        connection_worker_gauge: ConnectionWorkerGauge::default(),
        active_connection_registry: ActiveConnectionRegistry::default(),
    }
}

fn tun_tcp_session_post_close_guard_smoke_report_from_evidence(
    evidence: TunTcpSessionPostCloseGuardSmokeRunEvidence,
) -> TunTcpSessionPostCloseGuardSmokeReport {
    let summary = &evidence.report.summary;
    let server_fin = tun_tcp_session_server_fin_retransmit_observation(
        &evidence.tun_writes,
        2,
        evidence.target.port(),
    );
    let late_client_fin_ack = tun_tcp_session_server_fin_retransmit_observation(
        &evidence.tun_writes,
        4,
        evidence.target.port(),
    );
    let expected_fin_sequence = tun_tcp_session_server_fin_retransmit_expected_sequence_number();
    let expected_fin_acknowledgment =
        tun_tcp_session_server_fin_retransmit_expected_acknowledgment_number();
    let expected_late_fin_ack_sequence =
        tun_tcp_session_post_close_guard_expected_sequence_number();
    let expected_late_fin_ack_acknowledgment =
        tun_tcp_session_post_close_guard_expected_acknowledgment_number();
    let server_fin_observed = server_fin.as_ref().is_some_and(|fin| {
        fin.sequence_number == expected_fin_sequence
            && fin.acknowledgment_number == expected_fin_acknowledgment
            && fin.fin_flag
            && fin.ack_flag
            && !fin.rst_flag
            && fin.payload_empty
    });
    let late_client_fin_acknowledged = late_client_fin_ack.as_ref().is_some_and(|ack| {
        ack.sequence_number == expected_late_fin_ack_sequence
            && ack.acknowledgment_number == expected_late_fin_ack_acknowledgment
            && !ack.fin_flag
            && ack.ack_flag
            && !ack.rst_flag
            && ack.payload_empty
    });
    let no_reset_observed = evidence.tun_writes.iter().all(|packet| {
        parse_tun_tcp_segment(packet)
            .map(|segment| !segment.flags.rst())
            .unwrap_or(false)
    });
    let final_ack_absorbed = summary.tcp_server_close_markers_open == 0
        && summary.tcp_post_close_markers_peak >= 1
        && no_reset_observed;
    let duplicate_final_ack_absorbed = evidence.tun_writes.len() == 5
        && summary.tcp_session_packets_written == 5
        && late_client_fin_acknowledged;
    let clean_stop_observed =
        evidence.stops_observed == 1 && !evidence.report.stop_snapshot.running;
    let post_close_marker_retained = summary.tcp_post_close_markers_open == 1;
    let residual_state_clean = summary.tcp_sessions_open == 0
        && summary.tcp_server_close_markers_open == 0
        && post_close_marker_retained;
    let mut report = TunTcpSessionPostCloseGuardSmokeReport {
        passed: false,
        detail: String::new(),
        selected_outbound: TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_OUTBOUND.to_string(),
        target: evidence.target.to_string(),
        request_payload_bytes: TUN_TCP_SESSION_SMOKE_REQUEST.len(),
        late_client_fin_payload_bytes: TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_LATE_FIN_PAYLOAD
            .len(),
        server_received_payload: evidence.server_received_payload,
        server_fin_observed,
        final_ack_absorbed,
        duplicate_final_ack_absorbed,
        late_client_fin_payload_acknowledged: late_client_fin_acknowledged,
        late_client_fin_acknowledged,
        no_reset_observed,
        late_client_fin_ack_sequence_number: late_client_fin_ack
            .as_ref()
            .map(|ack| ack.sequence_number),
        late_client_fin_ack_acknowledgment_number: late_client_fin_ack
            .as_ref()
            .map(|ack| ack.acknowledgment_number),
        starts_observed: evidence.starts_observed,
        opens_observed: evidence.opens_observed,
        stops_observed: evidence.stops_observed,
        processed_packets: summary.processed_packets(),
        tcp_session_events: summary.tcp_session_events,
        tcp_session_packets_written: summary.tcp_session_packets_written,
        tun_writes_observed: evidence.tun_writes.len(),
        tcp_sessions_open: summary.tcp_sessions_open,
        tcp_server_close_markers_open: summary.tcp_server_close_markers_open,
        tcp_post_close_markers_open: summary.tcp_post_close_markers_open,
        tcp_session_errors: summary.tcp_session_errors,
        post_close_marker_retained,
        clean_stop_observed,
        residual_state_clean,
        cases: Vec::new(),
    };
    report.passed = tun_tcp_session_post_close_guard_smoke_passed(&report);
    report.detail = tun_tcp_session_post_close_guard_smoke_detail(&report);
    report.cases = tun_tcp_session_post_close_guard_smoke_cases(&report, late_client_fin_ack, None);
    report
}

fn tun_tcp_session_post_close_guard_smoke_failed_report(
    error: String,
) -> TunTcpSessionPostCloseGuardSmokeReport {
    let mut report = TunTcpSessionPostCloseGuardSmokeReport {
        passed: false,
        detail: format!("TUN TCP post-close guard smoke failed: {error}"),
        selected_outbound: TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_OUTBOUND.to_string(),
        target: "127.0.0.1:0".to_string(),
        request_payload_bytes: TUN_TCP_SESSION_SMOKE_REQUEST.len(),
        late_client_fin_payload_bytes: TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_LATE_FIN_PAYLOAD
            .len(),
        server_received_payload: false,
        server_fin_observed: false,
        final_ack_absorbed: false,
        duplicate_final_ack_absorbed: false,
        late_client_fin_payload_acknowledged: false,
        late_client_fin_acknowledged: false,
        no_reset_observed: false,
        late_client_fin_ack_sequence_number: None,
        late_client_fin_ack_acknowledgment_number: None,
        starts_observed: 0,
        opens_observed: 0,
        stops_observed: 0,
        processed_packets: 0,
        tcp_session_events: 0,
        tcp_session_packets_written: 0,
        tun_writes_observed: 0,
        tcp_sessions_open: 0,
        tcp_server_close_markers_open: 0,
        tcp_post_close_markers_open: 0,
        tcp_session_errors: 0,
        post_close_marker_retained: false,
        clean_stop_observed: false,
        residual_state_clean: false,
        cases: Vec::new(),
    };
    report.cases = tun_tcp_session_post_close_guard_smoke_cases(&report, None, Some(error));
    report
}

fn tun_tcp_session_post_close_guard_smoke_passed(
    report: &TunTcpSessionPostCloseGuardSmokeReport,
) -> bool {
    report.starts_observed == 1
        && report.opens_observed == 1
        && report.stops_observed == 1
        && report.server_received_payload
        && report.server_fin_observed
        && report.final_ack_absorbed
        && report.duplicate_final_ack_absorbed
        && report.late_client_fin_payload_bytes
            == TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_LATE_FIN_PAYLOAD.len()
        && report.late_client_fin_payload_acknowledged
        && report.late_client_fin_acknowledged
        && report.no_reset_observed
        && report.processed_packets == TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_MAX_PACKETS
        && report.tcp_session_events == TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_MAX_PACKETS
        && report.tcp_session_packets_written == 5
        && report.tun_writes_observed == 5
        && report.tcp_sessions_open == 0
        && report.tcp_server_close_markers_open == 0
        && report.tcp_post_close_markers_open == 1
        && report.tcp_session_errors == 0
        && report.post_close_marker_retained
        && report.clean_stop_observed
        && report.residual_state_clean
}

fn tun_tcp_session_post_close_guard_smoke_detail(
    report: &TunTcpSessionPostCloseGuardSmokeReport,
) -> String {
    format!(
        "outbound={} target={} request_bytes={} late_fin_payload_bytes={} server_received={} server_fin_observed={} final_ack_absorbed={} duplicate_final_ack_absorbed={} late_client_fin_payload_acknowledged={} late_client_fin_acknowledged={} late_fin_ack_seq={:?} late_fin_ack_ack={:?} no_reset_observed={} starts={} opens={} stops={} processed={} tcp_events={} tcp_writes={} tun_writes={} tcp_sessions_open={} close_markers={} post_close_markers={} post_close_marker_retained={} tcp_errors={} residual_state_clean={}",
        report.selected_outbound,
        report.target,
        report.request_payload_bytes,
        report.late_client_fin_payload_bytes,
        report.server_received_payload,
        report.server_fin_observed,
        report.final_ack_absorbed,
        report.duplicate_final_ack_absorbed,
        report.late_client_fin_payload_acknowledged,
        report.late_client_fin_acknowledged,
        report.late_client_fin_ack_sequence_number,
        report.late_client_fin_ack_acknowledgment_number,
        report.no_reset_observed,
        report.starts_observed,
        report.opens_observed,
        report.stops_observed,
        report.processed_packets,
        report.tcp_session_events,
        report.tcp_session_packets_written,
        report.tun_writes_observed,
        report.tcp_sessions_open,
        report.tcp_server_close_markers_open,
        report.tcp_post_close_markers_open,
        report.post_close_marker_retained,
        report.tcp_session_errors,
        report.residual_state_clean
    )
}

fn tun_tcp_session_post_close_guard_smoke_cases(
    report: &TunTcpSessionPostCloseGuardSmokeReport,
    late_client_fin_ack: Option<TunTcpSessionServerFinObservation>,
    error: Option<String>,
) -> Vec<TunTcpSessionPostCloseGuardSmokeCaseReport> {
    let expected_sequence = tun_tcp_session_post_close_guard_expected_sequence_number();
    let expected_acknowledgment = tun_tcp_session_post_close_guard_expected_acknowledgment_number();
    let case_error = |passed: bool| {
        if passed {
            None
        } else {
            error.clone().or_else(|| Some(report.detail.clone()))
        }
    };
    let final_ack_passed = report.server_fin_observed
        && report.final_ack_absorbed
        && report.post_close_marker_retained;
    let duplicate_ack_passed = report.duplicate_final_ack_absorbed && report.no_reset_observed;
    let late_fin_passed = report.late_client_fin_payload_acknowledged
        && report.late_client_fin_acknowledged
        && report.no_reset_observed;
    let residual_passed =
        report.clean_stop_observed && report.residual_state_clean && report.tcp_session_errors == 0;
    vec![
        TunTcpSessionPostCloseGuardSmokeCaseReport {
            name: "create-post-close-marker-after-server-fin-final-ack",
            action: "server-fin-final-ack-post-close-marker",
            target: report.target.clone(),
            expected_packet_written: false,
            observed_packet_written: false,
            expected_sequence_number: None,
            observed_sequence_number: None,
            expected_acknowledgment_number: None,
            observed_acknowledgment_number: None,
            expected_reset_written: false,
            observed_reset_written: !report.no_reset_observed,
            processed_packets: report.processed_packets,
            tcp_session_events: report.tcp_session_events,
            tcp_session_packets_written: report.tcp_session_packets_written,
            tun_writes_observed: report.tun_writes_observed,
            passed: final_ack_passed,
            error: case_error(final_ack_passed),
        },
        TunTcpSessionPostCloseGuardSmokeCaseReport {
            name: "absorb-post-close-duplicate-final-ack-without-reset",
            action: "post-close-duplicate-final-ack",
            target: report.target.clone(),
            expected_packet_written: false,
            observed_packet_written: report.tun_writes_observed > 5,
            expected_sequence_number: None,
            observed_sequence_number: None,
            expected_acknowledgment_number: None,
            observed_acknowledgment_number: None,
            expected_reset_written: false,
            observed_reset_written: !report.no_reset_observed,
            processed_packets: report.processed_packets,
            tcp_session_events: report.tcp_session_events,
            tcp_session_packets_written: report.tcp_session_packets_written,
            tun_writes_observed: report.tun_writes_observed,
            passed: duplicate_ack_passed,
            error: case_error(duplicate_ack_passed),
        },
        TunTcpSessionPostCloseGuardSmokeCaseReport {
            name: "acknowledge-late-post-close-client-fin-payload-without-reset",
            action: "post-close-late-client-fin-payload-ack",
            target: report.target.clone(),
            expected_packet_written: true,
            observed_packet_written: late_client_fin_ack.is_some(),
            expected_sequence_number: Some(expected_sequence),
            observed_sequence_number: late_client_fin_ack.as_ref().map(|ack| ack.sequence_number),
            expected_acknowledgment_number: Some(expected_acknowledgment),
            observed_acknowledgment_number: late_client_fin_ack
                .as_ref()
                .map(|ack| ack.acknowledgment_number),
            expected_reset_written: false,
            observed_reset_written: late_client_fin_ack
                .as_ref()
                .map(|ack| ack.rst_flag)
                .unwrap_or(false),
            processed_packets: report.processed_packets,
            tcp_session_events: report.tcp_session_events,
            tcp_session_packets_written: report.tcp_session_packets_written,
            tun_writes_observed: report.tun_writes_observed,
            passed: late_fin_passed,
            error: case_error(late_fin_passed),
        },
        TunTcpSessionPostCloseGuardSmokeCaseReport {
            name: "retain-bounded-post-close-marker-cleanly",
            action: "post-close-marker-residual-state",
            target: report.target.clone(),
            expected_packet_written: false,
            observed_packet_written: false,
            expected_sequence_number: None,
            observed_sequence_number: None,
            expected_acknowledgment_number: None,
            observed_acknowledgment_number: None,
            expected_reset_written: false,
            observed_reset_written: !report.no_reset_observed,
            processed_packets: report.processed_packets,
            tcp_session_events: report.tcp_session_events,
            tcp_session_packets_written: report.tcp_session_packets_written,
            tun_writes_observed: report.tun_writes_observed,
            passed: residual_passed,
            error: case_error(residual_passed),
        },
    ]
}

fn tun_tcp_session_post_close_guard_smoke_packets(
    destination: Ipv4Addr,
    destination_port: u16,
) -> Vec<Vec<u8>> {
    let client_initial_sequence_number = 10;
    let client_payload_sequence_number = client_initial_sequence_number + 1;
    let client_payload_end =
        client_payload_sequence_number + TUN_TCP_SESSION_SMOKE_REQUEST.len() as u32;
    let final_server_acknowledgment_number = DEFAULT_TUN_TCP_SERVER_INITIAL_SEQUENCE_NUMBER + 1 + 1;
    let mut packets =
        tun_tcp_session_server_fin_retransmit_smoke_packets(destination, destination_port);
    packets.push(tun_tcp_session_smoke_ipv4_packet(
        TUN_TCP_SESSION_SMOKE_CLIENT_IP,
        destination,
        6,
        &tun_tcp_session_smoke_tcp_segment(
            TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
            destination_port,
            client_payload_end,
            final_server_acknowledgment_number,
            0x0010,
            DEFAULT_TUN_TCP_WINDOW_SIZE,
            b"",
        ),
    ));
    packets.push(tun_tcp_session_smoke_ipv4_packet(
        TUN_TCP_SESSION_SMOKE_CLIENT_IP,
        destination,
        6,
        &tun_tcp_session_smoke_tcp_segment(
            TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
            destination_port,
            client_payload_end,
            final_server_acknowledgment_number,
            0x0011,
            DEFAULT_TUN_TCP_WINDOW_SIZE,
            TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_LATE_FIN_PAYLOAD,
        ),
    ));
    packets
}

fn tun_tcp_session_post_close_guard_expected_sequence_number() -> u32 {
    DEFAULT_TUN_TCP_SERVER_INITIAL_SEQUENCE_NUMBER + 2
}

fn tun_tcp_session_post_close_guard_expected_acknowledgment_number() -> u32 {
    10 + 1
        + TUN_TCP_SESSION_SMOKE_REQUEST.len() as u32
        + TUN_TCP_SESSION_POST_CLOSE_GUARD_SMOKE_LATE_FIN_PAYLOAD.len() as u32
        + 1
}

fn collect_default_tun_tcp_unknown_session_reset_smoke_report(
) -> TunTcpUnknownSessionResetSmokeReport {
    match run_default_tun_tcp_unknown_session_reset_smoke() {
        Ok(evidence) => tun_tcp_unknown_session_reset_smoke_report_from_evidence(evidence),
        Err(error) => tun_tcp_unknown_session_reset_smoke_failed_report(error),
    }
}

#[derive(Debug)]
struct TunTcpUnknownSessionResetSmokeRunEvidence {
    report: ManagedTunPacketLoopReport,
    target: SocketAddr,
    starts_observed: usize,
    opens_observed: usize,
    stops_observed: usize,
    tun_writes: Vec<Vec<u8>>,
}

#[derive(Debug, Clone, Copy)]
struct TunTcpUnknownSessionResetObservation {
    sequence_number: u32,
    acknowledgment_number: u32,
    rst: bool,
    ack: bool,
}

fn run_default_tun_tcp_unknown_session_reset_smoke(
) -> Result<TunTcpUnknownSessionResetSmokeRunEvidence, String> {
    let config = default_tun_device_config();
    let stopped_snapshot = tun_tcp_session_smoke_stopped_snapshot();
    let target = SocketAddr::new(
        IpAddr::V4(TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_TARGET),
        TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_DESTINATION_PORT,
    );
    let tun_writes = Arc::new(Mutex::new(Vec::new()));
    let packet_io = TunTcpSessionSmokeFakePacketIo {
        reads: VecDeque::from(tun_tcp_unknown_session_reset_smoke_packets()),
        read_delays: VecDeque::new(),
        writes: Vec::new(),
        shared_writes: Arc::clone(&tun_writes),
    };
    let controller = TunTcpSessionSmokeFakeController::new(
        stopped_snapshot.clone(),
        TunDeviceSnapshot::running(&config),
        stopped_snapshot,
        packet_io,
    );
    let runtime = default_tun_tcp_unknown_session_reset_smoke_runtime();

    let report = run_managed_tun_packet_loop_with_runtime(
        &controller,
        config,
        &runtime,
        DEFAULT_TUN_DNS_TTL_SECONDS,
        TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_MAX_PACKETS,
    )?;
    let tun_writes = tun_writes
        .lock()
        .map_err(|_| "TUN TCP unknown-session reset smoke writes lock poisoned".to_string())?
        .clone();

    Ok(TunTcpUnknownSessionResetSmokeRunEvidence {
        report,
        target,
        starts_observed: controller.starts_observed()?,
        opens_observed: controller.opens_observed()?,
        stops_observed: controller.stops_observed(),
        tun_writes,
    })
}

fn default_tun_tcp_unknown_session_reset_smoke_runtime() -> MixedProxyRuntime {
    let mut outbounds = OutboundRegistry::new();
    outbounds.add_direct(TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_OUTBOUND);
    MixedProxyRuntime {
        routes: RouteEngine::new(RouteAction::Outbound(
            TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_OUTBOUND.to_string(),
        )),
        relay_options: RelayOptions {
            first_byte_timeout: Some(Duration::from_secs(1)),
            idle_timeout: Some(Duration::from_secs(1)),
        },
        outbounds,
        dns_options: MixedDnsOptions::default(),
        tun_tcp_max_active_sessions: DEFAULT_TUN_TCP_MAX_ACTIVE_SESSIONS,
        connection_metrics: ConnectionMetrics::default(),
        max_connection_workers: DEFAULT_MANAGED_MIXED_MAX_CONNECTION_WORKERS,
        connection_worker_gauge: ConnectionWorkerGauge::default(),
        active_connection_registry: ActiveConnectionRegistry::default(),
    }
}

fn tun_tcp_unknown_session_reset_smoke_report_from_evidence(
    evidence: TunTcpUnknownSessionResetSmokeRunEvidence,
) -> TunTcpUnknownSessionResetSmokeReport {
    let summary = &evidence.report.summary;
    let data_reset = tun_tcp_unknown_session_reset_observation(
        &evidence.tun_writes,
        0,
        tun_tcp_unknown_session_reset_expected_sequence_number(),
        tun_tcp_unknown_session_reset_expected_data_acknowledgment_number(),
    );
    let fin_reset = tun_tcp_unknown_session_reset_observation(
        &evidence.tun_writes,
        1,
        tun_tcp_unknown_session_reset_expected_sequence_number(),
        tun_tcp_unknown_session_reset_expected_fin_acknowledgment_number(),
    );
    let clean_stop_observed =
        evidence.stops_observed == 1 && !evidence.report.stop_snapshot.running;
    let residual_state_clean = summary.tcp_sessions_open == 0
        && summary.tcp_server_close_markers_open == 0
        && summary.tcp_post_close_markers_open == 0;
    let stray_rst_absorbed = evidence.tun_writes.len() == 2;
    let reset_loop_avoided = stray_rst_absorbed && summary.tcp_session_packets_written == 2;
    let mut report = TunTcpUnknownSessionResetSmokeReport {
        passed: false,
        detail: String::new(),
        selected_outbound: TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_OUTBOUND.to_string(),
        target: evidence.target.to_string(),
        request_payload_bytes: TUN_TCP_SESSION_SMOKE_REQUEST.len(),
        data_reset_observed: data_reset.is_some(),
        fin_reset_observed: fin_reset.is_some(),
        stray_rst_absorbed,
        reset_loop_avoided,
        data_reset_sequence_number: data_reset.map(|reset| reset.sequence_number),
        data_reset_acknowledgment_number: data_reset.map(|reset| reset.acknowledgment_number),
        fin_reset_sequence_number: fin_reset.map(|reset| reset.sequence_number),
        fin_reset_acknowledgment_number: fin_reset.map(|reset| reset.acknowledgment_number),
        starts_observed: evidence.starts_observed,
        opens_observed: evidence.opens_observed,
        stops_observed: evidence.stops_observed,
        processed_packets: summary.processed_packets(),
        tcp_session_events: summary.tcp_session_events,
        tcp_session_packets_written: summary.tcp_session_packets_written,
        tun_writes_observed: evidence.tun_writes.len(),
        tcp_sessions_open: summary.tcp_sessions_open,
        tcp_session_errors: summary.tcp_session_errors,
        clean_stop_observed,
        residual_state_clean,
        cases: Vec::new(),
    };
    report.passed = tun_tcp_unknown_session_reset_smoke_passed(&report);
    report.detail = tun_tcp_unknown_session_reset_smoke_detail(&report);
    report.cases = tun_tcp_unknown_session_reset_smoke_cases(&report, data_reset, fin_reset, None);
    report
}

fn tun_tcp_unknown_session_reset_smoke_failed_report(
    error: String,
) -> TunTcpUnknownSessionResetSmokeReport {
    let mut report = TunTcpUnknownSessionResetSmokeReport {
        passed: false,
        detail: format!("TUN TCP unknown-session reset smoke failed: {error}"),
        selected_outbound: TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_OUTBOUND.to_string(),
        target: SocketAddr::new(
            IpAddr::V4(TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_TARGET),
            TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_DESTINATION_PORT,
        )
        .to_string(),
        request_payload_bytes: TUN_TCP_SESSION_SMOKE_REQUEST.len(),
        data_reset_observed: false,
        fin_reset_observed: false,
        stray_rst_absorbed: false,
        reset_loop_avoided: false,
        data_reset_sequence_number: None,
        data_reset_acknowledgment_number: None,
        fin_reset_sequence_number: None,
        fin_reset_acknowledgment_number: None,
        starts_observed: 0,
        opens_observed: 0,
        stops_observed: 0,
        processed_packets: 0,
        tcp_session_events: 0,
        tcp_session_packets_written: 0,
        tun_writes_observed: 0,
        tcp_sessions_open: 0,
        tcp_session_errors: 0,
        clean_stop_observed: false,
        residual_state_clean: false,
        cases: Vec::new(),
    };
    report.cases = tun_tcp_unknown_session_reset_smoke_cases(&report, None, None, Some(error));
    report
}

fn tun_tcp_unknown_session_reset_smoke_passed(
    report: &TunTcpUnknownSessionResetSmokeReport,
) -> bool {
    report.starts_observed == 1
        && report.opens_observed == 1
        && report.stops_observed == 1
        && report.data_reset_observed
        && report.fin_reset_observed
        && report.stray_rst_absorbed
        && report.reset_loop_avoided
        && report.data_reset_sequence_number
            == Some(tun_tcp_unknown_session_reset_expected_sequence_number())
        && report.data_reset_acknowledgment_number
            == Some(tun_tcp_unknown_session_reset_expected_data_acknowledgment_number())
        && report.fin_reset_sequence_number
            == Some(tun_tcp_unknown_session_reset_expected_sequence_number())
        && report.fin_reset_acknowledgment_number
            == Some(tun_tcp_unknown_session_reset_expected_fin_acknowledgment_number())
        && report.processed_packets == TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_MAX_PACKETS
        && report.tcp_session_events == TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_MAX_PACKETS
        && report.tcp_session_packets_written == 2
        && report.tun_writes_observed == 2
        && report.tcp_sessions_open == 0
        && report.tcp_session_errors == 0
        && report.clean_stop_observed
        && report.residual_state_clean
}

fn tun_tcp_unknown_session_reset_smoke_detail(
    report: &TunTcpUnknownSessionResetSmokeReport,
) -> String {
    format!(
        "outbound={} target={} request_bytes={} data_reset_observed={} data_reset_seq={:?} data_reset_ack={:?} fin_reset_observed={} fin_reset_seq={:?} fin_reset_ack={:?} stray_rst_absorbed={} reset_loop_avoided={} starts={} opens={} stops={} processed={} tcp_events={} tcp_writes={} tun_writes={} tcp_sessions_open={} tcp_errors={} residual_state_clean={}",
        report.selected_outbound,
        report.target,
        report.request_payload_bytes,
        report.data_reset_observed,
        report.data_reset_sequence_number,
        report.data_reset_acknowledgment_number,
        report.fin_reset_observed,
        report.fin_reset_sequence_number,
        report.fin_reset_acknowledgment_number,
        report.stray_rst_absorbed,
        report.reset_loop_avoided,
        report.starts_observed,
        report.opens_observed,
        report.stops_observed,
        report.processed_packets,
        report.tcp_session_events,
        report.tcp_session_packets_written,
        report.tun_writes_observed,
        report.tcp_sessions_open,
        report.tcp_session_errors,
        report.residual_state_clean
    )
}

fn tun_tcp_unknown_session_reset_smoke_cases(
    report: &TunTcpUnknownSessionResetSmokeReport,
    data_reset: Option<TunTcpUnknownSessionResetObservation>,
    fin_reset: Option<TunTcpUnknownSessionResetObservation>,
    error: Option<String>,
) -> Vec<TunTcpUnknownSessionResetSmokeCaseReport> {
    let case_error = |passed: bool| {
        if passed {
            None
        } else {
            error.clone().or_else(|| Some(report.detail.clone()))
        }
    };
    let reset_case = |name,
                      action,
                      reset: Option<TunTcpUnknownSessionResetObservation>,
                      expected_acknowledgment_number|
     -> TunTcpUnknownSessionResetSmokeCaseReport {
        let observed_reset_written = reset.is_some();
        let observed_sequence_number = reset.map(|reset| reset.sequence_number);
        let observed_acknowledgment_number = reset.map(|reset| reset.acknowledgment_number);
        let observed_rst_flag = reset.map(|reset| reset.rst);
        let observed_ack_flag = reset.map(|reset| reset.ack);
        let passed = observed_reset_written
            && observed_sequence_number
                == Some(tun_tcp_unknown_session_reset_expected_sequence_number())
            && observed_acknowledgment_number == Some(expected_acknowledgment_number)
            && observed_rst_flag == Some(true)
            && observed_ack_flag == Some(true);
        TunTcpUnknownSessionResetSmokeCaseReport {
            name,
            action,
            target: report.target.clone(),
            expected_reset_written: true,
            observed_reset_written,
            expected_sequence_number: Some(tun_tcp_unknown_session_reset_expected_sequence_number()),
            observed_sequence_number,
            expected_acknowledgment_number: Some(expected_acknowledgment_number),
            observed_acknowledgment_number,
            observed_rst_flag,
            observed_ack_flag,
            processed_packets: report.processed_packets,
            tcp_session_events: report.tcp_session_events,
            tcp_session_packets_written: report.tcp_session_packets_written,
            tun_writes_observed: report.tun_writes_observed,
            passed,
            error: case_error(passed),
        }
    };
    let stray_rst_passed = report.stray_rst_absorbed && report.reset_loop_avoided;
    vec![
        reset_case(
            "reset-unknown-tun-tcp-data",
            "write RST+ACK for an unknown TUN TCP data segment",
            data_reset,
            tun_tcp_unknown_session_reset_expected_data_acknowledgment_number(),
        ),
        reset_case(
            "reset-unknown-tun-tcp-fin",
            "write RST+ACK for an unknown TUN TCP FIN segment",
            fin_reset,
            tun_tcp_unknown_session_reset_expected_fin_acknowledgment_number(),
        ),
        TunTcpUnknownSessionResetSmokeCaseReport {
            name: "absorb-unknown-tun-tcp-rst-without-reset-loop",
            action: "absorb an unknown TUN TCP RST without writing another reset",
            target: report.target.clone(),
            expected_reset_written: false,
            observed_reset_written: !report.stray_rst_absorbed,
            expected_sequence_number: None,
            observed_sequence_number: None,
            expected_acknowledgment_number: None,
            observed_acknowledgment_number: None,
            observed_rst_flag: None,
            observed_ack_flag: None,
            processed_packets: report.processed_packets,
            tcp_session_events: report.tcp_session_events,
            tcp_session_packets_written: report.tcp_session_packets_written,
            tun_writes_observed: report.tun_writes_observed,
            passed: stray_rst_passed,
            error: case_error(stray_rst_passed),
        },
    ]
}

fn tun_tcp_unknown_session_reset_observation(
    writes: &[Vec<u8>],
    index: usize,
    expected_sequence_number: u32,
    expected_acknowledgment_number: u32,
) -> Option<TunTcpUnknownSessionResetObservation> {
    let packet = writes.get(index)?;
    let segment = parse_tun_tcp_segment(packet).ok()?;
    let observation = TunTcpUnknownSessionResetObservation {
        sequence_number: segment.sequence_number,
        acknowledgment_number: segment.acknowledgment_number,
        rst: segment.flags.rst(),
        ack: segment.flags.ack(),
    };
    if segment.flow.source_port == Some(TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_DESTINATION_PORT)
        && segment.flow.destination_port == Some(TUN_TCP_SESSION_SMOKE_CLIENT_PORT)
        && segment.payload.is_empty()
        && observation.sequence_number == expected_sequence_number
        && observation.acknowledgment_number == expected_acknowledgment_number
        && observation.rst
        && observation.ack
    {
        Some(observation)
    } else {
        None
    }
}

fn tun_tcp_unknown_session_reset_smoke_packets() -> Vec<Vec<u8>> {
    vec![
        tun_tcp_session_smoke_ipv4_packet(
            TUN_TCP_SESSION_SMOKE_CLIENT_IP,
            TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_TARGET,
            6,
            &tun_tcp_session_smoke_tcp_segment(
                TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_DESTINATION_PORT,
                11,
                tun_tcp_unknown_session_reset_expected_sequence_number(),
                0x0018,
                DEFAULT_TUN_TCP_WINDOW_SIZE,
                TUN_TCP_SESSION_SMOKE_REQUEST,
            ),
        ),
        tun_tcp_session_smoke_ipv4_packet(
            TUN_TCP_SESSION_SMOKE_CLIENT_IP,
            TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_TARGET,
            6,
            &tun_tcp_session_smoke_tcp_segment(
                TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_DESTINATION_PORT,
                tun_tcp_unknown_session_reset_expected_data_acknowledgment_number(),
                tun_tcp_unknown_session_reset_expected_sequence_number(),
                0x0011,
                DEFAULT_TUN_TCP_WINDOW_SIZE,
                b"",
            ),
        ),
        tun_tcp_session_smoke_ipv4_packet(
            TUN_TCP_SESSION_SMOKE_CLIENT_IP,
            TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_TARGET,
            6,
            &tun_tcp_session_smoke_tcp_segment(
                TUN_TCP_SESSION_SMOKE_CLIENT_PORT,
                TUN_TCP_UNKNOWN_SESSION_RESET_SMOKE_DESTINATION_PORT,
                tun_tcp_unknown_session_reset_expected_data_acknowledgment_number(),
                tun_tcp_unknown_session_reset_expected_sequence_number(),
                0x0014,
                DEFAULT_TUN_TCP_WINDOW_SIZE,
                b"",
            ),
        ),
    ]
}

fn tun_tcp_unknown_session_reset_expected_sequence_number() -> u32 {
    1001
}

fn tun_tcp_unknown_session_reset_expected_data_acknowledgment_number() -> u32 {
    11 + TUN_TCP_SESSION_SMOKE_REQUEST.len() as u32
}

fn tun_tcp_unknown_session_reset_expected_fin_acknowledgment_number() -> u32 {
    tun_tcp_unknown_session_reset_expected_data_acknowledgment_number() + 1
}

fn collect_default_tun_tcp_session_limit_smoke_report() -> TunTcpSessionLimitSmokeReport {
    match run_default_tun_tcp_session_limit_smoke() {
        Ok(evidence) => tun_tcp_session_limit_smoke_report_from_evidence(evidence),
        Err(error) => tun_tcp_session_limit_smoke_failed_report(error),
    }
}

#[derive(Debug)]
struct TunTcpSessionLimitSmokeRunEvidence {
    report: ManagedTunPacketLoopReport,
    target: SocketAddr,
    first_client: SocketAddr,
    second_client: SocketAddr,
    starts_observed: usize,
    opens_observed: usize,
    stops_observed: usize,
    tun_writes: Vec<Vec<u8>>,
}

fn run_default_tun_tcp_session_limit_smoke() -> Result<TunTcpSessionLimitSmokeRunEvidence, String> {
    let config = default_tun_device_config();
    let stopped_snapshot = tun_tcp_session_smoke_stopped_snapshot();
    let target = tun_tcp_session_limit_smoke_target();
    let first_client = tun_tcp_session_limit_smoke_first_client();
    let second_client = tun_tcp_session_limit_smoke_second_client();
    let tun_writes = Arc::new(Mutex::new(Vec::new()));
    let packet_io = TunTcpSessionSmokeFakePacketIo {
        reads: VecDeque::from(tun_tcp_session_limit_smoke_packets()),
        read_delays: VecDeque::new(),
        writes: Vec::new(),
        shared_writes: Arc::clone(&tun_writes),
    };
    let controller = TunTcpSessionSmokeFakeController::new(
        stopped_snapshot.clone(),
        TunDeviceSnapshot::running(&config),
        stopped_snapshot,
        packet_io,
    );
    let runtime = default_tun_tcp_session_limit_smoke_runtime();

    let report = run_managed_tun_packet_loop_with_runtime(
        &controller,
        config,
        &runtime,
        DEFAULT_TUN_DNS_TTL_SECONDS,
        TUN_TCP_SESSION_LIMIT_SMOKE_MAX_PACKETS,
    )?;
    let tun_writes = tun_writes
        .lock()
        .map_err(|_| "TUN TCP session limit smoke writes lock poisoned".to_string())?
        .clone();

    Ok(TunTcpSessionLimitSmokeRunEvidence {
        report,
        target,
        first_client,
        second_client,
        starts_observed: controller.starts_observed()?,
        opens_observed: controller.opens_observed()?,
        stops_observed: controller.stops_observed(),
        tun_writes,
    })
}

fn default_tun_tcp_session_limit_smoke_runtime() -> MixedProxyRuntime {
    let mut outbounds = OutboundRegistry::new();
    outbounds.add_direct(TUN_TCP_SESSION_LIMIT_SMOKE_OUTBOUND);
    MixedProxyRuntime {
        routes: RouteEngine::new(RouteAction::Outbound(
            TUN_TCP_SESSION_LIMIT_SMOKE_OUTBOUND.to_string(),
        )),
        relay_options: RelayOptions {
            first_byte_timeout: Some(Duration::from_secs(1)),
            idle_timeout: Some(Duration::from_secs(1)),
        },
        outbounds,
        dns_options: MixedDnsOptions::default(),
        tun_tcp_max_active_sessions: TUN_TCP_SESSION_LIMIT_SMOKE_MAX_ACTIVE_SESSIONS,
        connection_metrics: ConnectionMetrics::default(),
        max_connection_workers: DEFAULT_MANAGED_MIXED_MAX_CONNECTION_WORKERS,
        connection_worker_gauge: ConnectionWorkerGauge::default(),
        active_connection_registry: ActiveConnectionRegistry::default(),
    }
}

fn tun_tcp_session_limit_smoke_report_from_evidence(
    evidence: TunTcpSessionLimitSmokeRunEvidence,
) -> TunTcpSessionLimitSmokeReport {
    let summary = &evidence.report.summary;
    let last_error_kind = summary
        .last_tcp_session_error
        .as_ref()
        .map(|error| format!("{error:?}"));
    let limit_rejection_observed = summary.tcp_session_limit_rejections == 1
        && last_error_kind
            .as_deref()
            .map(|error| error.contains("TcpSessionLimitExceeded"))
            .unwrap_or(false);
    let session_error_observed =
        summary.tcp_session_errors == 1 && summary.last_tcp_session_error.is_some();
    let clean_stop_observed =
        evidence.stops_observed == 1 && !evidence.report.stop_snapshot.running;
    let active_session_retained = summary.tcp_sessions_open == 1;
    let bounded_state_observed = summary.tcp_max_active_sessions
        == TUN_TCP_SESSION_LIMIT_SMOKE_MAX_ACTIVE_SESSIONS
        && summary.tcp_sessions_peak == TUN_TCP_SESSION_LIMIT_SMOKE_MAX_ACTIVE_SESSIONS
        && active_session_retained;
    let mut report = TunTcpSessionLimitSmokeReport {
        passed: false,
        detail: String::new(),
        selected_outbound: TUN_TCP_SESSION_LIMIT_SMOKE_OUTBOUND.to_string(),
        target: evidence.target.to_string(),
        first_client: evidence.first_client.to_string(),
        second_client: evidence.second_client.to_string(),
        max_active_sessions: TUN_TCP_SESSION_LIMIT_SMOKE_MAX_ACTIVE_SESSIONS,
        limit_rejection_observed,
        session_error_observed,
        last_error_kind,
        starts_observed: evidence.starts_observed,
        opens_observed: evidence.opens_observed,
        stops_observed: evidence.stops_observed,
        tun_writes_observed: evidence.tun_writes.len(),
        processed_packets: summary.processed_packets(),
        tcp_session_events: summary.tcp_session_events,
        tcp_session_packets_written: summary.tcp_session_packets_written,
        tcp_sessions_peak: summary.tcp_sessions_peak,
        tcp_sessions_open: summary.tcp_sessions_open,
        tcp_session_errors: summary.tcp_session_errors,
        tcp_session_limit_rejections: summary.tcp_session_limit_rejections,
        tcp_max_active_sessions: summary.tcp_max_active_sessions,
        clean_stop_observed,
        active_session_retained,
        bounded_state_observed,
        cases: Vec::new(),
    };
    report.passed = tun_tcp_session_limit_smoke_passed(&report);
    report.detail = tun_tcp_session_limit_smoke_detail(&report);
    report.cases = tun_tcp_session_limit_smoke_cases(&report, None);
    report
}

fn tun_tcp_session_limit_smoke_failed_report(error: String) -> TunTcpSessionLimitSmokeReport {
    let mut report = TunTcpSessionLimitSmokeReport {
        passed: false,
        detail: format!("TUN TCP session limit smoke failed: {error}"),
        selected_outbound: TUN_TCP_SESSION_LIMIT_SMOKE_OUTBOUND.to_string(),
        target: tun_tcp_session_limit_smoke_target().to_string(),
        first_client: tun_tcp_session_limit_smoke_first_client().to_string(),
        second_client: tun_tcp_session_limit_smoke_second_client().to_string(),
        max_active_sessions: TUN_TCP_SESSION_LIMIT_SMOKE_MAX_ACTIVE_SESSIONS,
        limit_rejection_observed: false,
        session_error_observed: false,
        last_error_kind: Some(error.clone()),
        starts_observed: 0,
        opens_observed: 0,
        stops_observed: 0,
        tun_writes_observed: 0,
        processed_packets: 0,
        tcp_session_events: 0,
        tcp_session_packets_written: 0,
        tcp_sessions_peak: 0,
        tcp_sessions_open: 0,
        tcp_session_errors: 0,
        tcp_session_limit_rejections: 0,
        tcp_max_active_sessions: TUN_TCP_SESSION_LIMIT_SMOKE_MAX_ACTIVE_SESSIONS,
        clean_stop_observed: false,
        active_session_retained: false,
        bounded_state_observed: false,
        cases: Vec::new(),
    };
    report.cases = tun_tcp_session_limit_smoke_cases(&report, Some(error));
    report
}

fn tun_tcp_session_limit_smoke_passed(report: &TunTcpSessionLimitSmokeReport) -> bool {
    report.starts_observed == 1
        && report.opens_observed == 1
        && report.stops_observed == 1
        && report.tun_writes_observed == 1
        && report.processed_packets == TUN_TCP_SESSION_LIMIT_SMOKE_MAX_PACKETS
        && report.tcp_session_events == 1
        && report.tcp_session_packets_written == 1
        && report.tcp_sessions_peak == TUN_TCP_SESSION_LIMIT_SMOKE_MAX_ACTIVE_SESSIONS
        && report.tcp_sessions_open == TUN_TCP_SESSION_LIMIT_SMOKE_MAX_ACTIVE_SESSIONS
        && report.tcp_session_errors == 1
        && report.tcp_session_limit_rejections == 1
        && report.tcp_max_active_sessions == TUN_TCP_SESSION_LIMIT_SMOKE_MAX_ACTIVE_SESSIONS
        && report.limit_rejection_observed
        && report.session_error_observed
        && report.clean_stop_observed
        && report.active_session_retained
        && report.bounded_state_observed
}

fn tun_tcp_session_limit_smoke_detail(report: &TunTcpSessionLimitSmokeReport) -> String {
    format!(
        "outbound={} target={} first_client={} second_client={} max_active_sessions={} limit_rejection_observed={} session_error_observed={} starts={} opens={} stops={} tun_writes={} processed={} tcp_events={} tcp_writes={} tcp_sessions_peak={} tcp_sessions_open={} tcp_errors={} tcp_limit_rejections={} clean_stop_observed={} bounded_state_observed={} last_error={}",
        report.selected_outbound,
        report.target,
        report.first_client,
        report.second_client,
        report.max_active_sessions,
        report.limit_rejection_observed,
        report.session_error_observed,
        report.starts_observed,
        report.opens_observed,
        report.stops_observed,
        report.tun_writes_observed,
        report.processed_packets,
        report.tcp_session_events,
        report.tcp_session_packets_written,
        report.tcp_sessions_peak,
        report.tcp_sessions_open,
        report.tcp_session_errors,
        report.tcp_session_limit_rejections,
        report.clean_stop_observed,
        report.bounded_state_observed,
        report.last_error_kind.as_deref().unwrap_or("-")
    )
}

fn tun_tcp_session_limit_smoke_cases(
    report: &TunTcpSessionLimitSmokeReport,
    error: Option<String>,
) -> Vec<TunTcpSessionLimitSmokeCaseReport> {
    let case_error = |passed: bool| {
        if passed {
            None
        } else {
            error.clone().or_else(|| Some(report.detail.clone()))
        }
    };
    let case = |name, action, expected_error_kind, passed| TunTcpSessionLimitSmokeCaseReport {
        name,
        action,
        target: report.target.clone(),
        first_client: report.first_client.clone(),
        second_client: report.second_client.clone(),
        max_active_sessions: report.max_active_sessions,
        expected_error_kind,
        observed_error_kind: report.last_error_kind.clone(),
        processed_packets: report.processed_packets,
        tcp_session_events: report.tcp_session_events,
        tcp_session_packets_written: report.tcp_session_packets_written,
        tcp_sessions_peak: report.tcp_sessions_peak,
        tcp_sessions_open: report.tcp_sessions_open,
        tcp_session_errors: report.tcp_session_errors,
        tcp_session_limit_rejections: report.tcp_session_limit_rejections,
        tun_writes_observed: report.tun_writes_observed,
        passed,
        error: case_error(passed),
    };
    vec![
        case(
            "start-tun-tcp-session-limit-smoke",
            "start managed TUN packet loop and open packet IO for limit evidence",
            None,
            report.starts_observed == 1 && report.opens_observed == 1,
        ),
        case(
            "retain-first-tun-tcp-session",
            "accept the first SYN and retain one active TCP session",
            None,
            report.tcp_session_events == 1
                && report.tcp_session_packets_written == 1
                && report.tcp_sessions_peak == TUN_TCP_SESSION_LIMIT_SMOKE_MAX_ACTIVE_SESSIONS
                && report.active_session_retained,
        ),
        case(
            "reject-second-tun-tcp-session-over-limit",
            "reject the second SYN once the active session limit is reached",
            Some("TcpSessionLimitExceeded"),
            report.limit_rejection_observed
                && report.session_error_observed
                && report.tcp_session_limit_rejections == 1,
        ),
        case(
            "stop-tun-tcp-session-limit-smoke-cleanly",
            "stop runtime after recording bounded active-session state",
            None,
            report.clean_stop_observed
                && report.bounded_state_observed
                && report.processed_packets == TUN_TCP_SESSION_LIMIT_SMOKE_MAX_PACKETS,
        ),
    ]
}

