fn readiness_tun_runtime_smoke_gate(
    smoke_report: &mut Option<TunRuntimeSmokeReport>,
    min_duration: Duration,
) -> ReadinessGateReport {
    let report = collect_default_tun_runtime_smoke_report(min_duration);
    let status = if report.passed {
        ReadinessGateStatus::Passed
    } else {
        ReadinessGateStatus::Failed
    };
    let detail = report.detail.clone();
    *smoke_report = Some(report);
    ReadinessGateReport {
        name: "tun-runtime-smoke",
        category: "platform",
        status,
        detail,
    }
}

fn collect_default_tun_runtime_smoke_report(min_duration: Duration) -> TunRuntimeSmokeReport {
    match run_default_tun_runtime_smoke(min_duration) {
        Ok((report, evidence, route_cleanup, elapsed)) => {
            let interface_snapshot = evidence.interface_snapshot;
            let traffic_stimulus = evidence.traffic_stimulus;
            let dns_stimulus = evidence.dns_stimulus;
            let route_takeover = evidence.route_takeover;
            let route_cleanup_observed = tun_runtime_smoke_route_cleanup_observed(&route_cleanup);
            let route_cleanup_expected_prefixes_absent =
                tun_runtime_smoke_route_cleanup_expected_prefixes_absent(&route_cleanup);
            let duration_target_met = elapsed >= min_duration;
            let loop_activity_observed =
                report.summary.idle_events > 0 || report.summary.processed_packets() > 0;
            let traffic_stimulus_required = DEFAULT_TUN_RUNTIME_SMOKE_TRAFFIC_REQUIRED;
            let traffic_packets_observed = report.summary.processed_packets() > 0;
            let traffic_stimulus_drop_observed =
                tun_runtime_smoke_traffic_stimulus_drop_observed(&report);
            let traffic_stimulus_transport_attempted =
                traffic_stimulus.sent_packets > 0 || traffic_stimulus.ping_attempted;
            let traffic_stimulus_observed = traffic_stimulus_transport_attempted
                && traffic_packets_observed
                && traffic_stimulus_drop_observed;
            let traffic_drop_observed = report.summary.dropped_packets > 0;
            let dns_stimulus_required = TUN_RUNTIME_SMOKE_DNS_REQUIRED;
            let dns_hijack_route_observed = tun_runtime_smoke_dns_hijack_route_observed(&report);
            let dns_stimulus_observed =
                tun_runtime_smoke_dns_stimulus_observed(&report, &dns_stimulus);
            let clean_stop_observed = tun_runtime_smoke_clean_stop_observed(&report);
            let residual_state_clean = tun_runtime_smoke_residual_state_clean(&report);
            let passed = tun_runtime_smoke_report_passed(
                &report,
                &traffic_stimulus,
                &dns_stimulus,
                duration_target_met,
                loop_activity_observed,
                traffic_stimulus_required,
                traffic_stimulus_observed,
                traffic_packets_observed,
                dns_stimulus_required,
                dns_stimulus_observed,
                dns_hijack_route_observed,
                &route_takeover,
                route_cleanup_expected_prefixes_absent,
                clean_stop_observed,
                residual_state_clean,
            );
            let detail = tun_runtime_smoke_detail(
                &report,
                &traffic_stimulus,
                min_duration,
                elapsed,
                duration_target_met,
                loop_activity_observed,
                traffic_stimulus_required,
                traffic_stimulus_observed,
                traffic_packets_observed,
                traffic_stimulus_drop_observed,
                traffic_drop_observed,
                dns_stimulus_required,
                dns_stimulus_observed,
                dns_hijack_route_observed,
                &interface_snapshot,
                &dns_stimulus,
                &route_takeover,
                &route_cleanup,
                route_cleanup_observed,
                route_cleanup_expected_prefixes_absent,
                clean_stop_observed,
                residual_state_clean,
            );
            TunRuntimeSmokeReport {
                passed,
                detail,
                min_duration,
                elapsed,
                duration_target_met,
                loop_activity_observed,
                traffic_stimulus_required,
                traffic_stimulus_observed,
                traffic_packets_observed,
                traffic_drop_observed,
                traffic_stimulus_drop_observed,
                dns_stimulus_required,
                dns_stimulus_observed,
                dns_hijack_route_observed,
                interface_snapshot,
                traffic_stimulus,
                dns_stimulus,
                route_takeover,
                route_cleanup,
                route_cleanup_observed,
                route_cleanup_expected_prefixes_absent,
                clean_stop_observed,
                residual_state_clean,
                report: Some(report),
            }
        }
        Err(error) => TunRuntimeSmokeReport {
            passed: false,
            detail: format!("tun runtime smoke failed: {error}"),
            min_duration,
            elapsed: Duration::from_millis(0),
            duration_target_met: false,
            loop_activity_observed: false,
            traffic_stimulus_required: DEFAULT_TUN_RUNTIME_SMOKE_TRAFFIC_REQUIRED,
            traffic_stimulus_observed: false,
            traffic_packets_observed: false,
            traffic_drop_observed: false,
            traffic_stimulus_drop_observed: false,
            dns_stimulus_required: TUN_RUNTIME_SMOKE_DNS_REQUIRED,
            dns_stimulus_observed: false,
            dns_hijack_route_observed: false,
            interface_snapshot: tun_runtime_smoke_interface_snapshot_not_attempted(),
            traffic_stimulus: tun_runtime_smoke_traffic_stimulus_not_attempted(),
            dns_stimulus: tun_runtime_smoke_dns_stimulus_not_attempted(),
            route_takeover: tun_runtime_smoke_route_takeover_not_collected(),
            route_cleanup: tun_runtime_smoke_route_cleanup_not_collected(),
            route_cleanup_observed: false,
            route_cleanup_expected_prefixes_absent: false,
            clean_stop_observed: false,
            residual_state_clean: false,
            report: None,
        },
    }
}

fn run_default_tun_runtime_smoke(
    min_duration: Duration,
) -> Result<
    (
        ManagedTunPacketLoopReport,
        TunRuntimeSmokeRunEvidence,
        TunRouteTakeoverSnapshot,
        Duration,
    ),
    String,
> {
    let controller = NativeTunDeviceController::new();
    let runtime = default_tun_runtime_smoke_runtime();
    let started_at = Instant::now();
    let (evidence, report) = run_with_optional_tun_runtime_background_report(
        &controller,
        Some(default_tun_device_config()),
        &runtime,
        DEFAULT_TUN_DNS_TTL_SECONDS,
        DEFAULT_TUN_PACKET_LOOP_MAX_PACKETS,
        || Ok(collect_tun_runtime_smoke_evidence(min_duration)),
    )?;
    let elapsed = started_at.elapsed();
    let report =
        report.ok_or_else(|| "managed TUN runtime smoke did not produce a report".to_string())?;
    let route_cleanup = snapshot_tun_route_takeover(&default_tun_device_config());
    Ok((report, evidence, route_cleanup, elapsed))
}

fn collect_tun_runtime_smoke_evidence(min_duration: Duration) -> TunRuntimeSmokeRunEvidence {
    let started_at = Instant::now();
    thread::sleep(TUN_RUNTIME_SMOKE_TRAFFIC_STIMULUS_WARMUP);
    let route_takeover = snapshot_tun_route_takeover(&default_tun_device_config());
    let interface_snapshot = collect_tun_runtime_smoke_interface_snapshot();
    let dns_stimulus = send_tun_runtime_smoke_dns_stimulus();
    let traffic_stimulus = send_tun_runtime_smoke_traffic_stimulus();
    hold_tun_runtime_smoke_until(started_at, min_duration);
    TunRuntimeSmokeRunEvidence {
        interface_snapshot,
        traffic_stimulus,
        dns_stimulus,
        route_takeover,
    }
}

fn default_tun_runtime_smoke_runtime() -> MixedProxyRuntime {
    let mut routes = RouteEngine::new(RouteAction::Block);
    routes.add_rule(RouteRule {
        name: TUN_RUNTIME_SMOKE_TRAFFIC_RULE.to_string(),
        matcher: RouteMatcher::IpExact(TUN_RUNTIME_SMOKE_TRAFFIC_TARGET.ip()),
        action: RouteAction::Block,
    });
    routes.add_rule(RouteRule {
        name: TUN_RUNTIME_SMOKE_TRAFFIC_RULE.to_string(),
        matcher: RouteMatcher::PortExact(TUN_RUNTIME_SMOKE_TRAFFIC_TARGET.port()),
        action: RouteAction::Block,
    });
    MixedProxyRuntime::with_routes(routes)
}

fn hold_tun_runtime_smoke_until(started_at: Instant, min_duration: Duration) {
    while started_at.elapsed() < min_duration {
        let remaining = min_duration.saturating_sub(started_at.elapsed());
        thread::sleep(remaining.min(MANAGED_TUN_IDLE_POLL_INTERVAL));
    }
}

fn collect_tun_runtime_smoke_interface_snapshot() -> TunRuntimeSmokeInterfaceSnapshot {
    let mut snapshot = TunRuntimeSmokeInterfaceSnapshot {
        attempted: true,
        addresses_command: tun_runtime_smoke_interface_addresses_command(),
        addresses_exit_success: None,
        addresses_exit_code: None,
        addresses_stdout: None,
        addresses_stderr: None,
        addresses_error: None,
        interfaces_command: tun_runtime_smoke_interfaces_command(),
        interfaces_exit_success: None,
        interfaces_exit_code: None,
        interfaces_stdout: None,
        interfaces_stderr: None,
        interfaces_error: None,
    };
    match Command::new("netsh")
        .args([
            "interface",
            "ipv4",
            "show",
            "addresses",
            format!("name={DEFAULT_TUN_INTERFACE_NAME}").as_str(),
        ])
        .output()
    {
        Ok(output) => {
            snapshot.addresses_exit_success = Some(output.status.success());
            snapshot.addresses_exit_code = output.status.code();
            snapshot.addresses_stdout = Some(tun_runtime_smoke_command_output(&output.stdout));
            snapshot.addresses_stderr = Some(tun_runtime_smoke_command_output(&output.stderr));
        }
        Err(error) => {
            snapshot.addresses_error = Some(format!("run interface addresses snapshot: {error}"));
        }
    }
    match Command::new("netsh")
        .args(["interface", "ipv4", "show", "interfaces"])
        .output()
    {
        Ok(output) => {
            snapshot.interfaces_exit_success = Some(output.status.success());
            snapshot.interfaces_exit_code = output.status.code();
            snapshot.interfaces_stdout = Some(tun_runtime_smoke_command_output(&output.stdout));
            snapshot.interfaces_stderr = Some(tun_runtime_smoke_command_output(&output.stderr));
        }
        Err(error) => {
            snapshot.interfaces_error = Some(format!("run interface list snapshot: {error}"));
        }
    }
    snapshot
}

