fn write_default_core_certification_json_report(
    writer: &mut impl Write,
    report: &DefaultCoreCertificationReport,
) -> Result<(), String> {
    let value = default_core_certification_json_value(report);
    serde_json::to_writer_pretty(&mut *writer, &value).map_err(|error| error.to_string())?;
    writeln!(writer).map_err(|error| error.to_string())
}

fn default_core_takeover_system_proxy_passed(report: &DefaultCoreCertificationReport) -> bool {
    report.include_system_proxy_smoke
        && report
            .system_proxy_smoke
            .as_ref()
            .is_some_and(|smoke| smoke.passed)
}

fn default_core_takeover_tun_runtime_passed(report: &DefaultCoreCertificationReport) -> bool {
    report.include_tun_runtime_smoke
        && report
            .tun_runtime_smoke
            .as_ref()
            .is_some_and(|smoke| smoke.passed)
}

fn default_core_takeover_coverage_missing_evidence(
    report: &DefaultCoreCertificationReport,
) -> Vec<&'static str> {
    let mut missing = Vec::new();
    if !report.include_system_proxy_smoke {
        missing.push("system-proxy-smoke");
    }
    if !report.include_tun_runtime_smoke {
        missing.push("tun-runtime-smoke");
    }
    missing
}

fn default_core_takeover_coverage_failed_evidence(
    report: &DefaultCoreCertificationReport,
) -> Vec<&'static str> {
    let mut failed = Vec::new();
    if report.include_system_proxy_smoke && !default_core_takeover_system_proxy_passed(report) {
        failed.push("system-proxy-smoke");
    }
    if report.include_tun_runtime_smoke && !default_core_takeover_tun_runtime_passed(report) {
        failed.push("tun-runtime-smoke");
    }
    failed
}

fn default_core_takeover_coverage_complete(report: &DefaultCoreCertificationReport) -> bool {
    default_core_takeover_system_proxy_passed(report)
        && default_core_takeover_tun_runtime_passed(report)
}

fn default_core_machine_takeover_smokes_requested(report: &DefaultCoreCertificationReport) -> bool {
    report.include_system_proxy_smoke && report.include_tun_runtime_smoke
}

fn default_core_takeover_coverage_status(report: &DefaultCoreCertificationReport) -> &'static str {
    if !default_core_takeover_coverage_failed_evidence(report).is_empty() {
        "failed"
    } else if default_core_takeover_coverage_complete(report) {
        "passed"
    } else if report.include_system_proxy_smoke || report.include_tun_runtime_smoke {
        "partial"
    } else {
        "not-run"
    }
}

fn default_core_promotion_machine_takeover_ready(report: &DefaultCoreCertificationReport) -> bool {
    report.ready_for_default_core && default_core_takeover_coverage_complete(report)
}

fn default_core_promotion_local_core_default_allowed(
    report: &DefaultCoreCertificationReport,
) -> bool {
    report.ready_for_default_core
}

fn default_core_promotion_machine_takeover_default_allowed(
    report: &DefaultCoreCertificationReport,
) -> bool {
    default_core_promotion_machine_takeover_ready(report)
}

fn default_core_promotion_status(report: &DefaultCoreCertificationReport) -> &'static str {
    if !report.ready_for_default_core {
        "blocked"
    } else if default_core_promotion_machine_takeover_ready(report) {
        "machine-takeover-ready"
    } else if !default_core_takeover_coverage_failed_evidence(report).is_empty() {
        "machine-takeover-failed"
    } else {
        "core-ready"
    }
}

fn default_core_promotion_safe_default_scope(
    report: &DefaultCoreCertificationReport,
) -> &'static str {
    if default_core_promotion_machine_takeover_ready(report) {
        "machine-takeover"
    } else if default_core_promotion_local_core_default_allowed(report) {
        "local-core-only"
    } else {
        "none"
    }
}

fn default_core_promotion_blockers(report: &DefaultCoreCertificationReport) -> Vec<&'static str> {
    let mut blockers = Vec::new();
    if !report.ready_for_default_core {
        blockers.push("readiness-gates");
    }
    for failed in default_core_takeover_coverage_failed_evidence(report) {
        blockers.push(failed);
    }
    blockers
}

fn default_core_promotion_next_actions(
    report: &DefaultCoreCertificationReport,
) -> Vec<&'static str> {
    let mut actions = Vec::new();
    if !report.ready_for_default_core {
        actions.push("fix-readiness-blockers");
    }
    if !report.include_system_proxy_smoke {
        actions.push("run-with-include-system-proxy-smoke");
    }
    if !report.include_tun_runtime_smoke {
        actions.push("run-with-include-tun-runtime-smoke");
    }
    if !default_core_takeover_coverage_failed_evidence(report).is_empty() {
        actions.push("fix-machine-takeover-smoke-failures");
    }
    actions
}

fn default_core_release_gate_passed(report: &DefaultCoreCertificationReport) -> bool {
    default_core_release_gate_machine_takeover_passed(report)
        && default_core_release_gate_stability_passed(report)
}

fn default_core_release_gate_machine_takeover_passed(
    report: &DefaultCoreCertificationReport,
) -> bool {
    !report.require_machine_takeover_ready || default_core_promotion_machine_takeover_ready(report)
}

fn default_core_release_gate_stability_passed(report: &DefaultCoreCertificationReport) -> bool {
    default_core_release_gate_stability_window_passed(report)
        && default_core_release_gate_stability_connections_passed(report)
}

fn default_core_release_gate_stability_window_passed(
    report: &DefaultCoreCertificationReport,
) -> bool {
    let Some(required_window) = report.required_stability_window else {
        return true;
    };
    let local_soak_passed = default_core_release_gate_local_soak_complete(report)
        && report.soak_min_duration >= required_window;
    let tun_runtime_passed = !report.include_tun_runtime_smoke
        || (report.tun_runtime_smoke_min_duration >= required_window
            && report
                .tun_runtime_smoke
                .as_ref()
                .map(|smoke| smoke.duration_target_met)
                .unwrap_or(false));

    local_soak_passed && tun_runtime_passed
}

fn default_core_release_gate_stability_connections_passed(
    report: &DefaultCoreCertificationReport,
) -> bool {
    let Some(required_connections) = report.required_stability_connections else {
        return true;
    };
    default_core_release_gate_local_soak_complete(report)
        && report.soak_connections >= required_connections
}

fn default_core_release_gate_stability_required(report: &DefaultCoreCertificationReport) -> bool {
    report.required_stability_window.is_some() || report.required_stability_connections.is_some()
}

fn default_core_release_gate_required(report: &DefaultCoreCertificationReport) -> bool {
    report.require_machine_takeover_ready || default_core_release_gate_stability_required(report)
}

fn default_core_release_gate_status(report: &DefaultCoreCertificationReport) -> &'static str {
    if !default_core_release_gate_required(report) {
        "not-required"
    } else if default_core_release_gate_passed(report) {
        "passed"
    } else {
        "failed"
    }
}

fn default_core_release_gate_required_scope(
    report: &DefaultCoreCertificationReport,
) -> &'static str {
    match (
        report.require_machine_takeover_ready,
        default_core_release_gate_stability_required(report),
    ) {
        (false, false) => "none",
        (true, false) => "machine-takeover",
        (false, true) => "stability",
        (true, true) => "machine-takeover+stability",
    }
}

fn default_core_release_gate_blockers(
    report: &DefaultCoreCertificationReport,
) -> Vec<&'static str> {
    let mut blockers = Vec::new();
    if report.require_machine_takeover_ready {
        if !report.ready_for_default_core {
            blockers.push("readiness-gates");
        }
        if !default_core_machine_takeover_smokes_requested(report) {
            blockers.push("machine-takeover-smokes-not-requested");
        }
        for failed in default_core_takeover_coverage_failed_evidence(report) {
            blockers.push(failed);
        }
    }
    if let Some(required_window) = report.required_stability_window {
        if report.soak_min_duration < required_window {
            blockers.push("local-soak-stability-window-too-short");
        }
        if !default_core_release_gate_local_soak_complete(report) {
            blockers.push("local-soak-stability-window-not-passed");
        }
        if report.include_tun_runtime_smoke {
            if report.tun_runtime_smoke_min_duration < required_window {
                blockers.push("tun-runtime-stability-window-too-short");
            }
            if report
                .tun_runtime_smoke
                .as_ref()
                .map(|smoke| smoke.duration_target_met)
                != Some(true)
            {
                blockers.push("tun-runtime-stability-window-not-passed");
            }
        }
    }
    if let Some(required_connections) = report.required_stability_connections {
        if report.soak_connections < required_connections {
            blockers.push("local-soak-stability-connections-too-low");
        }
        if !default_core_release_gate_local_soak_complete(report) {
            blockers.push("local-soak-stability-connections-not-passed");
        }
    }
    blockers
}

fn default_core_release_gate_error(report: &DefaultCoreCertificationReport) -> String {
    format!(
        "default-core-certify {} release gate failed: blockers={}",
        default_core_release_gate_required_scope(report),
        comma_list_or_dash(default_core_release_gate_blockers(report))
    )
}

fn default_core_release_gate_local_soak_complete(report: &DefaultCoreCertificationReport) -> bool {
    readiness_gate_status_label(&report.readiness, "mixed-soak-socks5") == "passed"
        && readiness_gate_status_label(&report.readiness, "mixed-soak-http-connect") == "passed"
}

fn readiness_gate_status_label(
    report: &DefaultCoreReadinessReport,
    name: &'static str,
) -> &'static str {
    report
        .gates
        .iter()
        .find(|gate| gate.name == name)
        .map(|gate| gate.status.label())
        .unwrap_or("missing")
}

fn comma_list_or_dash(items: Vec<&'static str>) -> String {
    if items.is_empty() {
        "-".to_string()
    } else {
        items.join(",")
    }
}

fn duration_millis_option_or_dash(duration: Option<Duration>) -> String {
    duration
        .map(|duration| duration_millis_for_report(duration).to_string())
        .unwrap_or_else(|| "-".to_string())
}

fn usize_option_or_dash(value: Option<usize>) -> String {
    value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "-".to_string())
}

fn bool_option_or_dash(value: Option<bool>) -> String {
    value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "-".to_string())
}

fn default_core_takeover_coverage_json_value(
    report: &DefaultCoreCertificationReport,
) -> serde_json::Value {
    let missing_evidence = default_core_takeover_coverage_missing_evidence(report);
    let failed_evidence = default_core_takeover_coverage_failed_evidence(report);
    serde_json::json!({
        "status": default_core_takeover_coverage_status(report),
        "complete": default_core_takeover_coverage_complete(report),
        "machine_takeover_smokes_requested": default_core_machine_takeover_smokes_requested(report),
        "system_proxy_smoke_included": report.include_system_proxy_smoke,
        "system_proxy_smoke_status": system_proxy_smoke_status_label(
            report.include_system_proxy_smoke,
            report.system_proxy_smoke.as_ref()
        ),
        "system_proxy_smoke_passed": if report.include_system_proxy_smoke {
            report.system_proxy_smoke.as_ref().map(|smoke| smoke.passed)
        } else {
            None
        },
        "tun_runtime_smoke_included": report.include_tun_runtime_smoke,
        "tun_runtime_smoke_status": tun_runtime_smoke_status_label(
            report.include_tun_runtime_smoke,
            report.tun_runtime_smoke.as_ref()
        ),
        "tun_runtime_smoke_min_duration_ms": duration_millis_for_report(
            report.tun_runtime_smoke_min_duration
        ),
        "tun_runtime_smoke_passed": if report.include_tun_runtime_smoke {
            report.tun_runtime_smoke.as_ref().map(|smoke| smoke.passed)
        } else {
            None
        },
        "missing_evidence_count": missing_evidence.len(),
        "missing_evidence": missing_evidence,
        "failed_evidence_count": failed_evidence.len(),
        "failed_evidence": failed_evidence,
    })
}

fn default_core_promotion_json_value(report: &DefaultCoreCertificationReport) -> serde_json::Value {
    let blockers = default_core_promotion_blockers(report);
    let next_actions = default_core_promotion_next_actions(report);
    let blocker_count = blockers.len();
    let next_action_count = next_actions.len();
    serde_json::json!({
        "status": default_core_promotion_status(report),
        "safe_default_scope": default_core_promotion_safe_default_scope(report),
        "core_gates_ready": report.ready_for_default_core,
        "machine_takeover_ready": default_core_promotion_machine_takeover_ready(report),
        "machine_takeover_smokes_requested": default_core_machine_takeover_smokes_requested(report),
        "local_core_default_allowed": default_core_promotion_local_core_default_allowed(report),
        "machine_takeover_default_allowed":
            default_core_promotion_machine_takeover_default_allowed(report),
        "takeover_coverage_status": default_core_takeover_coverage_status(report),
        "missing_takeover_evidence": default_core_takeover_coverage_missing_evidence(report),
        "failed_takeover_evidence": default_core_takeover_coverage_failed_evidence(report),
        "next_actions": next_actions,
        "next_action_count": next_action_count,
        "blockers": blockers,
        "blocker_count": blocker_count,
    })
}

fn default_core_release_gate_json_value(
    report: &DefaultCoreCertificationReport,
) -> serde_json::Value {
    let blockers = default_core_release_gate_blockers(report);
    let blocker_count = blockers.len();
    serde_json::json!({
        "status": default_core_release_gate_status(report),
        "required_scope": default_core_release_gate_required_scope(report),
        "passed": default_core_release_gate_passed(report),
        "require_machine_takeover_ready": report.require_machine_takeover_ready,
        "require_stability_window": report.required_stability_window.is_some(),
        "required_stability_window_ms": report
            .required_stability_window
            .map(duration_millis_for_report),
        "require_stability_connections": report.required_stability_connections.is_some(),
        "required_stability_connections": report.required_stability_connections,
        "machine_takeover_ready": default_core_promotion_machine_takeover_ready(report),
        "machine_takeover_smokes_requested": default_core_machine_takeover_smokes_requested(report),
        "takeover_coverage_status": default_core_takeover_coverage_status(report),
        "missing_takeover_evidence": default_core_takeover_coverage_missing_evidence(report),
        "failed_takeover_evidence": default_core_takeover_coverage_failed_evidence(report),
        "stability": default_core_release_gate_stability_json_value(report),
        "blockers": blockers,
        "blocker_count": blocker_count,
    })
}

fn default_core_release_gate_stability_json_value(
    report: &DefaultCoreCertificationReport,
) -> serde_json::Value {
    let required_window = report.required_stability_window;
    let local_soak_required_window_met = required_window.map(|required_window| {
        report.soak_min_duration >= required_window
            && default_core_release_gate_local_soak_complete(report)
    });
    let required_connections = report.required_stability_connections;
    let local_soak_required_connections_met = required_connections
        .map(|_| default_core_release_gate_stability_connections_passed(report));
    let tun_runtime_required_window_met = if report.include_tun_runtime_smoke {
        required_window.map(|required_window| {
            report.tun_runtime_smoke_min_duration >= required_window
                && report
                    .tun_runtime_smoke
                    .as_ref()
                    .map(|smoke| smoke.duration_target_met)
                    .unwrap_or(false)
        })
    } else {
        None
    };
    serde_json::json!({
        "required_window_ms": required_window.map(duration_millis_for_report),
        "required_window_met": default_core_release_gate_stability_window_passed(report),
        "required_connections": required_connections,
        "required_connections_met": local_soak_required_connections_met,
        "local_soak_connections": report.soak_connections,
        "local_soak_min_duration_ms": duration_millis_for_report(report.soak_min_duration),
        "local_soak_duration_required": report.soak_min_duration > Duration::from_millis(0),
        "local_soak_complete": default_core_release_gate_local_soak_complete(report),
        "local_soak_required_window_met": local_soak_required_window_met,
        "local_soak_required_connections_met": local_soak_required_connections_met,
        "local_soak_socks5_status": readiness_gate_status_label(
            &report.readiness,
            "mixed-soak-socks5"
        ),
        "local_soak_http_connect_status": readiness_gate_status_label(
            &report.readiness,
            "mixed-soak-http-connect"
        ),
        "tun_runtime_smoke_min_duration_ms": duration_millis_for_report(
            report.tun_runtime_smoke_min_duration
        ),
        "tun_runtime_smoke_included": report.include_tun_runtime_smoke,
        "tun_runtime_duration_target_met": report
            .tun_runtime_smoke
            .as_ref()
            .map(|smoke| smoke.duration_target_met),
        "tun_runtime_required_window_met": tun_runtime_required_window_met,
    })
}

